/* global HTMLImageElement */

import type {JSX} from "react";

import {fontSmallImage} from "../image/font-image";
import {Text} from "./text";
import type {TextPropsType} from "./text-type";

export function SmallText(props: TextPropsType): JSX.Element {
    const {text, className, scale, padStart, padEnd, animation} = props;

    return (
        <Text
            animation={animation}
            className={className}
            fontHeight={7}
            localImageMap={fontSmallImage}
            padEnd={padEnd}
            padStart={padStart}
            scale={scale}
            text={text}
        />
    );
}
