export function getRandomNumber(fromNumber = 0, toNumber = 1e9): number {
    return Math.floor(Math.random() * (toNumber - fromNumber) + fromNumber);
}

// Deterministic pseudo-random number in [0, 1) derived from an integer seed (a single mulberry32 step).
// The same seed always yields the same value, so a caller that seeds from the current game state gets
// variety turn to turn and game to game while staying fully reproducible for tests and replays.
export function getPseudoRandomNumber(seed: number): number {
    /* eslint-disable no-bitwise */
    let state: number = (seed + 0x6d_2b_79_f5) | 0;

    state = Math.imul(state ^ (state >>> 15), state | 1);
    state ^= state + Math.imul(state ^ (state >>> 7), state | 61);
    return ((state ^ (state >>> 14)) >>> 0) / 4_294_967_296;
    /* eslint-enable no-bitwise */
}
