import type {SizeType} from "../../map/map-type";
import type {GameStateType} from "../game-type";
import {getLandscapeSize, getUnitBonusArmorByMoveType} from "../landscape/landscape-helper";
import {getPlayerMaxUnitLevel, getPlayerUnitLevelStep} from "../player/player-helper";
import {getIsEqualPoint, getIsPointInList} from "../point/point-helper";
import type {PointType} from "../point/point-type";
import {
    defaultUnitData,
    unitUnderPoisonArmorReduce,
    unitUnderPoisonAttackReduce,
    unitUnderWispAuraArmorBonus,
    unitUnderWispAuraAttackBonus,
} from "./unit-const";
import {getUnitInfoByUnit} from "./unit-helper";
import {getUnitLevelData, levelUnitData} from "./unit-level";
import {getMaxSquareByMoveSize} from "./unit-path";
import {getIsUnitPoisoned, getIsUnitUnderWispAura} from "./unit-state";
import type {UnitToUnitAttackResultType} from "./unit-to-unit-attack-type";
import {type GameUnitType, GameUnitTypeEnum} from "./unit-type";

export function getUnitAllAvailableAttackPointList(unit: GameUnitType, gameState: GameStateType): Array<PointType> {
    const {x, y, movedCount, raisedSkeletonCount, didFixBuilding, didOccupyBuilding} = unit;
    const {attack, canAttackAfterMove, canMeleeAttack} = getUnitInfoByUnit(unit);
    const {landscape} = gameState;
    const mapSize: SizeType = getLandscapeSize(landscape);

    // Category-independent "busy" gates that block ALL attacks. The per-turn attack limits (and the unit/building
    // cross-block) are applied by the specific callers (getUnitAvailableUnitToUnitAttack / ...UnitToBuildingAttack),
    // so this shared geometry stays reusable for the bot's threat computation.
    if (didFixBuilding || didOccupyBuilding || raisedSkeletonCount > 0) {
        return [];
    }

    if (movedCount > 0 && canAttackAfterMove === false) {
        return [];
    }

    const maxPointList = getMaxSquareByMoveSize({x, y}, mapSize, attack.range);

    if (canMeleeAttack) {
        return maxPointList;
    }

    const meleePointList: Array<PointType> = [
        {x: x + 1, y},
        {x: x - 1, y},
        {x, y: y + 1},
        {x, y: y - 1},
    ];

    return maxPointList.filter<PointType>((point: PointType): point is PointType => {
        return !getIsPointInList(point, meleePointList);
    });
}

export function getBonusArmorByLevel(damageGiven: number, maxUnitLevel: number, levelStep: number): number {
    return getUnitLevelData(damageGiven, maxUnitLevel, levelStep).level * levelUnitData.additionalArmor;
}

export function getBonusAttackByLevel(damageGiven: number, maxUnitLevel: number, levelStep: number): number {
    return getUnitLevelData(damageGiven, maxUnitLevel, levelStep).level * levelUnitData.additionalAttack;
}

export function getUnitArmorValue(unit: GameUnitType, gameState: GameStateType): number {
    const {landscape, buildingList, playerList, stepCount, unitList} = gameState;
    const maxUnitLevel: number = getPlayerMaxUnitLevel(unit.gamePlayerId, playerList);
    const {damageGiven} = unit;
    const unitInfo = getUnitInfoByUnit(unit);

    const bonusArmorByPlaceAndMoveType: number = getUnitBonusArmorByMoveType(unit, landscape, buildingList);
    const defaultUnitArmor: number = unitInfo.armor;
    const isUnderPoison = getIsUnitPoisoned(unit, stepCount);
    const isUnderWispAura = getIsUnitUnderWispAura(unit, playerList, unitList, getLandscapeSize(landscape));
    const bonusArmorByLevel = getBonusArmorByLevel(
        damageGiven,
        maxUnitLevel,
        getPlayerUnitLevelStep(unit.gamePlayerId, playerList)
    );

    return (
        bonusArmorByPlaceAndMoveType +
        defaultUnitArmor +
        (isUnderWispAura ? unitUnderWispAuraArmorBonus : 0) +
        bonusArmorByLevel +
        (isUnderPoison ? -unitUnderPoisonArmorReduce : 0)
    );
}

function getSelfAttack(units: Record<"aggressor" | "defender", GameUnitType>, gameState: GameStateType): number {
    const {aggressor, defender} = units;
    const {landscape, playerList, stepCount, unitList} = gameState;
    const aggressorUnitInfo = getUnitInfoByUnit(aggressor);
    const defenderUnitInfo = getUnitInfoByUnit(defender);
    const minMaxDelta = Math.abs(aggressorUnitInfo.attack.max - aggressorUnitInfo.attack.min);

    if (minMaxDelta === 0) {
        return Math.floor(aggressorUnitInfo.attack.min);
    }

    const minMaxRandom =
        (landscape.length +
            playerList.length +
            unitList.length +
            aggressorUnitInfo.attack.min +
            aggressorUnitInfo.attack.max +
            defenderUnitInfo.attack.min +
            defenderUnitInfo.attack.max +
            aggressor.x +
            aggressor.y +
            defender.x +
            defender.y +
            aggressor.damageGiven +
            aggressor.damageReceived +
            defender.damageGiven +
            defender.damageReceived +
            aggressor.health +
            defender.health +
            stepCount) %
        (minMaxDelta + 1);

    return Math.floor(minMaxRandom + aggressorUnitInfo.attack.min);
}

export function getUnitAttackValue(
    units: Record<"aggressor" | "defender", GameUnitType>,
    gameState: GameStateType
): number {
    const {aggressor, defender} = units;
    const {landscape, playerList, stepCount, unitList} = gameState;
    const maxUnitLevel: number = getPlayerMaxUnitLevel(aggressor.gamePlayerId, playerList);
    const aggressorUnitInfo = getUnitInfoByUnit(aggressor);
    const defenderUnitInfo = getUnitInfoByUnit(defender);

    const unitSelfAttack = getSelfAttack(units, gameState);
    const bonusAttackByLevel = getBonusAttackByLevel(
        aggressor.damageGiven,
        maxUnitLevel,
        getPlayerUnitLevelStep(aggressor.gamePlayerId, playerList)
    );
    const isUnderWispAura = getIsUnitUnderWispAura(aggressor, playerList, unitList, getLandscapeSize(landscape));
    const isUnderPoison = getIsUnitPoisoned(aggressor, stepCount);
    const bonusAttackByMoveType = aggressorUnitInfo.bonusAttackVersus[defenderUnitInfo.moveType];
    const bonusAttackVersusSkeleton =
        defender.unitType === GameUnitTypeEnum.skeleton ? aggressorUnitInfo.bonusAttackVersusSkeleton : 0;

    return (
        unitSelfAttack +
        bonusAttackByLevel +
        (isUnderWispAura ? unitUnderWispAuraAttackBonus : 0) +
        (isUnderPoison ? -unitUnderPoisonAttackReduce : 0) +
        bonusAttackByMoveType +
        bonusAttackVersusSkeleton
    );
}

function getUnitToUnitAttackedUnit(
    units: Record<"aggressor" | "defender", GameUnitType>,
    config: Record<"isStrikeBack", boolean>,
    gameState: GameStateType
): GameUnitType {
    const {isStrikeBack} = config;
    const minDamage = 1;

    const {aggressor, defender} = units;
    const aggressorUnitInfo = getUnitInfoByUnit(aggressor);
    const {stepCount} = gameState;
    const defenderArmor = getUnitArmorValue(defender, gameState);
    const aggressorAttack = getUnitAttackValue({aggressor, defender}, gameState);

    const aggressorAttackScale = aggressor.health / defaultUnitData.health;
    const damage = Math.max(Math.floor((aggressorAttack - defenderArmor) * aggressorAttackScale), minDamage);

    return {
        ...defender,
        health: defender.health - damage,
        poisonTurnCount:
            aggressorUnitInfo.attackPoisonCount > 0 && isStrikeBack === false
                ? stepCount + aggressorUnitInfo.attackPoisonCount
                : defender.poisonTurnCount,
    };
}

