function getCanStrikeBack(units: Record<"fromUnit" | "toUnit", GameUnitType>): boolean {
    const {fromUnit, toUnit} = units;
    const fromUnitInfo = getUnitInfoByUnit(fromUnit);
    const toUnitPoint: PointType = {x: toUnit.x, y: toUnit.y};

    const meleePointList: Array<PointType> = [
        {x: fromUnit.x + 1, y: fromUnit.y},
        {x: fromUnit.x - 1, y: fromUnit.y},
        {x: fromUnit.x, y: fromUnit.y + 1},
        {x: fromUnit.x, y: fromUnit.y - 1},
    ];

    if (fromUnitInfo.canMeleeAttack) {
        return meleePointList.some((attackPoint: PointType): boolean => {
            return getIsEqualPoint(attackPoint, toUnitPoint);
        });
    }

    return false;
}

export function getUnitToUnitAttackResult(
    units: Record<"aggressor" | "defender", GameUnitType>,
    gameState: GameStateType
): UnitToUnitAttackResultType {
    const {aggressor, defender} = units;

    const hasDefenderStrikeBackByDistance = getCanStrikeBack({fromUnit: defender, toUnit: aggressor});

    const defenderUnitAfterAttack: GameUnitType = getUnitToUnitAttackedUnit(
        {aggressor, defender},
        {isStrikeBack: false},
        gameState
    );

    if (defenderUnitAfterAttack.health <= 0 || hasDefenderStrikeBackByDistance === false) {
        return {
            aggressor: {
                ...aggressor,
                attackedUnitCount: aggressor.attackedUnitCount + 1,
                damageGiven: aggressor.damageGiven + (defender.health - defenderUnitAfterAttack.health),
            },
            defender: {
                ...defenderUnitAfterAttack,
                damageReceived:
                    defenderUnitAfterAttack.damageReceived + (defender.health - defenderUnitAfterAttack.health),
            },
            hasStrikeBack: false,
        };
    }

    const aggressorStateAfterStrikeBack: GameUnitType = getUnitToUnitAttackedUnit(
        {aggressor: defenderUnitAfterAttack, defender: aggressor},
        {isStrikeBack: true},
        gameState
    );

    return {
        aggressor: {
            ...aggressorStateAfterStrikeBack,
            attackedUnitCount: aggressor.attackedUnitCount + 1,
            damageGiven: aggressor.damageGiven + (defender.health - defenderUnitAfterAttack.health),
            damageReceived: aggressor.damageReceived + (aggressor.health - aggressorStateAfterStrikeBack.health),
        },
        defender: {
            ...defenderUnitAfterAttack,
            damageGiven: defender.damageGiven + (aggressor.health - aggressorStateAfterStrikeBack.health),
            damageReceived: defender.damageReceived + (defender.health - defenderUnitAfterAttack.health),
        },
        hasStrikeBack: true,
    };
}
