import {type JSX, useState} from "react";
import {generatePath, Link} from "react-router-dom";

import {appRoute} from "../../../../app/app-route";
import {SpoilerContent} from "../../../../layout/spoiler/spoiler-content";
import {uiButtonImage} from "../../../../layout/ui-button/image/ui-button-image";
import {UiButton} from "../../../../layout/ui-button/ui-button";
import {UiLink} from "../../../../layout/ui-button/ui-link";
import {getLandscapeSize} from "../../../../model/game/landscape/landscape-helper";
import {type GameMapType, MapSourceEnum} from "../../../../model/map/map-type";
import {useLocale} from "../../../../provider/locale/locale-context";
import {testId} from "../../../../test-id";
import {ClientSkirmishMapPreview} from "../client-skirmish-map-preview/client-skirmish-map-preview";
import * as clientSkirmishMapItemStyle from "./client-skirmish-map-item.scss";

interface ClientSkirmishMapItemPropsType {
    readonly map: GameMapType;
}

const mapSourceSuffix: Record<MapSourceEnum, string> = {
    [MapSourceEnum.ae1]: " (AE1)",
    [MapSourceEnum.ae2]: " (AE2)",
    [MapSourceEnum.ae3]: " (AE3)",
    [MapSourceEnum.unknown]: "",
};

export function ClientSkirmishMapItem(props: ClientSkirmishMapItemPropsType): JSX.Element {
    const {getLocalizedString} = useLocale();
    const {map} = props;
    const {mapId, mapName, landscape, mapNameLangKey, source} = map;
    const mapSize = getLandscapeSize(landscape);
    const href: string = generatePath<typeof appRoute.setupMap.path>(appRoute.setupMap.path, {mapId});
    // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
    const mapLocalizedName: string = getLocalizedString(mapNameLangKey)?.trim() || "";
    const [isShowMap, setIsShowMap] = useState<boolean>(false);

    return (
        <div
            className={clientSkirmishMapItemStyle.client_skirmish_map_item}
            data-map-id={mapId}
            data-testid={testId.skirmishPage.mapItem}
        >
            <div className={clientSkirmishMapItemStyle.client_skirmish_map_item__main_content}>
                <div className={clientSkirmishMapItemStyle.client_skirmish_map_item__left}>
                    {/*
                <span className={clientSkirmishMapItemStyle.client_skirmish_map_item__player_count}>
                    ({getMaxPlayerByMap(map)})
                </span>
*/}
                    <Link className={clientSkirmishMapItemStyle.client_skirmish_map_item__map_name} to={href}>
                        {(mapLocalizedName || mapName) + mapSourceSuffix[source]}
                    </Link>
                </div>
                <div className={clientSkirmishMapItemStyle.client_skirmish_map_item__right}>
                    <UiButton
                        iconSrc={uiButtonImage.earth.src}
                        isSquared
                        onClick={(): undefined => {
                            setIsShowMap(!isShowMap);
                        }}
                    >
                        {mapSize.width}&times;{mapSize.height}
                    </UiButton>
                    <UiLink href={href} iconSrc={uiButtonImage.sword.src} isSquared langKey="SETUP_SKIRMISH__FIGHT" />
                </div>
            </div>
            <SpoilerContent isOpen={isShowMap}>
                <div className={clientSkirmishMapItemStyle.client_skirmish_map_item__map_preview_wrapper}>
                    <div className={clientSkirmishMapItemStyle.client_skirmish_map_item__map_preview}>
                        <ClientSkirmishMapPreview isShow={isShowMap} map={map} />
                    </div>
                </div>
            </SpoilerContent>
        </div>
    );
}
