import type {JSX} from "react";

import type {GameBuildingType} from "../../../../model/game/building/building-type";
import type {GameLandscapeThemeEnum} from "../../../../model/game/landscape/landscape-type";
import {useGameContext} from "../../../../provider/game/game-context";
import * as clientGameBuildingStyle from "./client-game-building.scss";
import {ClientGameBuildingItem} from "./client-game-building-item";

interface ClientGameBuildingPropsType {
    // The theme to force on every building, or null to take each building's theme from the cell it sits on.
    readonly forcedTheme: GameLandscapeThemeEnum | null;
}

export function ClientGameBuilding(props: ClientGameBuildingPropsType): JSX.Element {
    const {forcedTheme} = props;
    const {gameState} = useGameContext();
    const {buildingList} = gameState;

    return (
        <div className={clientGameBuildingStyle.building_layer}>
            {buildingList.map((building: GameBuildingType): JSX.Element => {
                return (
                    <ClientGameBuildingItem
                        building={building}
                        forcedTheme={forcedTheme}
                        key={`${building.x}-${building.y}`}
                    />
                );
            })}
        </div>
    );
}
