import {type JSX, useCallback} from "react";

import {getBuildingByPoint} from "../../../../model/game/building/building-helper";
import {
    GameBuildingStateEnum,
    type GameBuildingType,
    GameBuildingTypeEnum,
} from "../../../../model/game/building/building-type";
import type {GameStateType} from "../../../../model/game/game-type";
import {getGraveByPoint, removeGraveByPoint} from "../../../../model/game/grave/grave-helper";
import {getLandscapePointList, normalizeLandscapeThemeMap} from "../../../../model/game/landscape/landscape-helper";
import {GameLandscapeItemEnum, type GameLandscapeThemeMapType} from "../../../../model/game/landscape/landscape-type";
import {GamePlayerIdEnum} from "../../../../model/game/player/player-type";
import type {PointType} from "../../../../model/game/point/point-type";
import {defaultUnitData} from "../../../../model/game/unit/unit-const";
import {getUnitByPoint} from "../../../../model/game/unit/unit-helper";
import type {GameGraveType, GameUnitType} from "../../../../model/game/unit/unit-type";
import {useGameContext} from "../../../../provider/game/game-context";
import {arrayShuffle} from "../../../../util/array";
import {cls} from "../../../../util/css";
import {getRandomStringWithPrefix} from "../../../../util/string";
import {getMapEditorPlayerIdByColor} from "../map-editor-helper";
import {type MapEditorDrawPanelStateType, MapEditorTabEnum} from "../map-editor-type";
import * as mapEditorClickHunterStyle from "./map-editor-click-hunter.scss";

interface MapEditorClickHunterPropsType {
    readonly drawPanelState: MapEditorDrawPanelStateType;
    readonly isGridShow: boolean;
}

export function MapEditorClickHunter(props: MapEditorClickHunterPropsType): JSX.Element {
    const {drawPanelState, isGridShow} = props;
    const {gameState, setGameState} = useGameContext();

    const handleOnClick = useCallback(
        (point: PointType) => {
            const {
                activeTab,
                activeTerrainList,
                activeTerrainTheme,
                activeBuilding,
                activeBuildingState,
                activeBuildingColor,
                activeUnitColor,
                activeUnit,
                isGraveActive,
            } = drawPanelState;
            const {x, y} = point;

            if (activeTab === MapEditorTabEnum.terrain) {
                setGameState((currentGameState: GameStateType): GameStateType => {
                    const {landscape} = currentGameState;
                    const landscapeRow = landscape[y];

                    if (!landscapeRow) {
                        return {...currentGameState};
                    }

                    landscapeRow[x] = arrayShuffle(activeTerrainList).at(0) ?? GameLandscapeItemEnum.tr0;

                    // Paint the tile's theme in parallel, keeping the theme grid aligned with the landscape.
                    const landscapeThemeMap: GameLandscapeThemeMapType = normalizeLandscapeThemeMap(
                        landscape,
                        currentGameState.landscapeThemeMap
                    );
                    const themeRow = landscapeThemeMap[y];

                    if (themeRow) {
                        themeRow[x] = activeTerrainTheme;
                    }

                    return {...currentGameState, landscapeThemeMap};
                });
            }

            if (activeTab === MapEditorTabEnum.building && activeBuilding !== null) {
                setGameState((currentGameState: GameStateType): GameStateType => {
                    const buildingList: Array<GameBuildingType> = [...currentGameState.buildingList];
                    const building = getBuildingByPoint(point, buildingList);

                    const updatedBuilding: GameBuildingType = [
                        GameBuildingTypeEnum.castle,
                        GameBuildingTypeEnum.farm,
                    ].includes(activeBuilding)
                        ? {
                              buildingType: activeBuilding,
                              gamePlayerId:
                                  activeBuildingState === GameBuildingStateEnum.buildingOk
                                      ? getMapEditorPlayerIdByColor(activeBuildingColor)
                                      : GamePlayerIdEnum.playerEmpty,
                              state: activeBuildingState,
                              x,
                              y,
                          }
                        : {
                              buildingType: activeBuilding,
                              gamePlayerId: GamePlayerIdEnum.playerEmpty,
                              state: GameBuildingStateEnum.buildingOk,
                              x,
                              y,
                          };

                    if (building) {
                        buildingList[buildingList.indexOf(building)] = updatedBuilding;
                    } else {
                        buildingList.push(updatedBuilding);
                    }

                    return {
                        ...currentGameState,
                        buildingList,
                    };
                });
            }

            if (activeTab === MapEditorTabEnum.building && activeBuilding === null) {
                setGameState((currentGameState: GameStateType): GameStateType => {
                    return {
                        ...currentGameState,
                        buildingList: currentGameState.buildingList.filter<GameBuildingType>(
                            (buildingInList: GameBuildingType): buildingInList is GameBuildingType => {
                                return buildingInList.x !== x || buildingInList.y !== y;
                            }
                        ),
                    };
                });
            }

            if (activeTab === MapEditorTabEnum.unit && isGraveActive) {
                setGameState((currentGameState: GameStateType): GameStateType => {
                    const graveList: Array<GameGraveType> = [...currentGameState.graveList];
                    const grave = getGraveByPoint(point, graveList);

                    const updatedGrave: GameGraveType = {
                        createdStepCount: currentGameState.stepCount,
                        x,
                        y,
                    };

                    if (grave) {
                        graveList[graveList.indexOf(grave)] = updatedGrave;
                    } else {
                        graveList.push(updatedGrave);
                    }

                    return {
                        ...currentGameState,
                        graveList,
                    };
                });
            }

            if (activeTab === MapEditorTabEnum.unit && !isGraveActive && activeUnit !== null) {
                setGameState((currentGameState: GameStateType): GameStateType => {
                    const unitList: Array<GameUnitType> = [...currentGameState.unitList];
                    const unit = getUnitByPoint(point, unitList);

                    const updatedUnit: GameUnitType = {
                        ...defaultUnitData,
                        gamePlayerId: getMapEditorPlayerIdByColor(activeUnitColor),
                        unitId: getRandomStringWithPrefix(activeUnit),
                        unitType: activeUnit,
                        x,
                        y,
                    };

                    if (unit) {
                        unitList[unitList.indexOf(unit)] = updatedUnit;
                    } else {
                        unitList.push(updatedUnit);
                    }

                    return {
                        ...currentGameState,
                        unitList,
                    };
                });
            }

            if (activeTab === MapEditorTabEnum.unit && !isGraveActive && activeUnit === null) {
                setGameState((currentGameState: GameStateType): GameStateType => {
                    return {
                        ...currentGameState,
                        graveList: removeGraveByPoint(point, currentGameState.graveList),
                        unitList: currentGameState.unitList.filter<GameUnitType>(
                            (unitInList: GameUnitType): unitInList is GameUnitType => {
                                return unitInList.x !== x || unitInList.y !== y;
                            }
                        ),
                    };
                });
            }
        },
        [drawPanelState, setGameState]
    );

    return (
        <div
            className={cls(mapEditorClickHunterStyle.map_editor__click_hunter_layer, {
                [mapEditorClickHunterStyle.map_editor__click_hunter_layer__with_grid]: isGridShow,
            })}
        >
            {getLandscapePointList(gameState.landscape).map<JSX.Element>((landscapePoint: PointType): JSX.Element => {
                return (
                    <button
                        className={mapEditorClickHunterStyle.map_editor__click_hunter_layer__cell}
                        key={`${landscapePoint.x.toString(16)}-${landscapePoint.y.toString(16)}`}
                        onClick={(): undefined => {
                            handleOnClick(landscapePoint);
                        }}
                        type="button"
                    />
                );
            })}
        </div>
    );
}
