/* global IS_PRODUCTION */

import {type JSX, useState} from "react";

import {squareSize} from "../../../../../../css/style";
import {IsRender} from "../../../../../../layout/is-render/is-render";
import type {PointType} from "../../../../../../model/game/point/point-type";
import {useGameContext} from "../../../../../../provider/game/game-context";
import {clientGameClickHunterImage} from "../../image/client-game-click-hunter-image";
import * as clientGameClickHunterCellStyle from "../client-game-click-hunter-cell.scss";

interface ClientGameClickHunterCellSelectPropsType {
    readonly buttonList: Array<JSX.Element>;
    readonly point: PointType;
}

export function ClientGameClickHunterCellSelect(props: ClientGameClickHunterCellSelectPropsType): JSX.Element {
    const {buttonList, point} = props;
    const {x, y} = point;
    const {mapSize} = useGameContext();
    const isPopupToRight = x < mapSize.width / 2;
    // Dev-only inert coordinate attributes, matching the single-action cells (see the cell component).
    const cellCoordinateProps = IS_PRODUCTION === false ? {"data-cell-x": x, "data-cell-y": y} : {};

    const [isOpen, setIsOpen] = useState<boolean>(false);

    const popupStyle = isPopupToRight
        ? {
              left: (x + 1) * squareSize,
          }
        : {
              left: (x + 2) * squareSize - buttonList.length * squareSize,
          };

    return (
        <div className={clientGameClickHunterCellStyle.client_game_click_hunter_cell_select} {...cellCoordinateProps}>
            <button
                className={clientGameClickHunterCellStyle.client_game_click_hunter_cell_select_open_button}
                key="button-open"
                onClick={(): undefined => {
                    setIsOpen(!isOpen);
                }}
                type="button"
            >
                <img
                    alt="+/-"
                    className={clientGameClickHunterCellStyle.client_game_click_hunter_cell_select_open_button__image}
                    src={
                        isOpen ? clientGameClickHunterImage.actionMinus.src : clientGameClickHunterImage.actionPlus.src
                    }
                />
            </button>
            <IsRender isRender={isOpen && isPopupToRight}>
                <div
                    className={clientGameClickHunterCellStyle.client_game_click_hunter_cell_select_button_list}
                    style={{
                        ...popupStyle,
                        top: y * squareSize,
                        transformOrigin: "left center",
                        width: buttonList.length * squareSize,
                    }}
                >
                    {buttonList}
                </div>
            </IsRender>
            <IsRender isRender={isOpen && !isPopupToRight}>
                <div
                    className={clientGameClickHunterCellStyle.client_game_click_hunter_cell_select_button_list}
                    style={{
                        ...popupStyle,
                        top: y * squareSize,
                        transformOrigin: "right center",
                        width: buttonList.length * squareSize,
                    }}
                >
                    {buttonList}
                </div>
            </IsRender>
        </div>
    );
}
