import type {GameActionType} from "../../../provider/game/game-context-type";
import type {GameStateType} from "../game-type";
import type {GamePlayerIdEnum} from "../player/player-type";
import type {PointType} from "../point/point-type";
import type {GameUnitTypeEnum} from "../unit/unit-type";

export enum GameTriggerConditionEnum {
    allEnemyUnitDied = "all-enemy-unit-died",
    allEnemyUnitDiedAndHasAllCastles = "all-enemy-unit-died-and-has-all-castles",
    allHeroesDied = "all-heroes-died",
    anyHeroDied = "any-hero-died",
    oneHeroLivesOnly = "one-hero-lives-only",
    skirmishDefeat = "skirmish-defeat",
    turnCount = "turn-count",
    unitOnRectanglePlace = "unit-on-rectangle-place",
    anyUnitDied = "anu-unit-died",
    unitDied = "unit-died",
    occupyCastle = "occupy-castle", // Check castle length
    occupyFarm = "occupy-farm", // Check farm length
    trainNewUnit = "train-new-unit", // Check unit length, and money decrease
}

export interface GameTriggerPlaceType {
    rectangleList: Array<[PointType, PointType]>;
    unitTypeList: Array<GameUnitTypeEnum>;
}

export interface GameTriggerType {
    action: GameActionType;
    conditionName: GameTriggerConditionEnum;
    dependentTriggerIdList: Array<string>;
    forPlayerId: GamePlayerIdEnum;
    placeList: GameTriggerPlaceType;
    triggerId: string;
    turnCount: number;
}

export interface TriggerCallbackArgumentType {
    trigger: GameTriggerType;
    prevGameState: GameStateType;
    gameState: GameStateType;
}

export type TriggerCallbackType = (triggerArgument: TriggerCallbackArgumentType) => boolean;
