/**
 * Centralized `data-testid` values shared between the application code and the
 * Playwright end-to-end tests.
 *
 * Best practice: never hard-code a test id string inline. Add it here, reference
 * `testId.*` from the component via the `dataTestId` prop, and import the same
 * constant from the test. This keeps the app and the tests in sync and makes
 * every selectable element discoverable from a single place.
 */
export const testId = {
    homePage: {
        root: "home-page",
        playButton: "home-page__play-button",
        settingsButton: "home-page__settings-button",
        mapEditorButton: "home-page__map-editor-button",
        instructionsButton: "home-page__instructions-button",
        aboutButton: "home-page__about-button",
    },
    skirmishPage: {
        mapItem: "skirmish-page__map-item",
    },
    companiesPage: {
        // A campaign mission row; carries `data-map-id` so a test can address a specific mission.
        missionItem: "companies-page__mission-item",
        missionFightButton: "companies-page__mission-fight-button",
    },
    gamePage: {
        // Rendered on the unit node only in dev builds. The node also carries `data-unit-id`
        // (the unit id) and `data-unit` (the full unit state as a JSON string) for tests.
        unit: "game-page__unit",
        // The end-turn button. It is enabled only when it is genuinely the human player's turn
        // and nothing is animating, so `toBeEnabled()` on it is the signal that the bot finished.
        endTurnButton: "game-page__end-turn-button",
        startGamePopupFightButton: "game-page__start-game-popup-fight-button",
        // Close button of the campaign story popup shown before the first briefing.
        storyPopupCloseButton: "game-page__story-popup-close-button",
        // Close button of a faced-briefing snackbar item (campaign dialogue lines).
        facedSnackbarCloseButton: "game-page__faced-snackbar-close-button",
        // Campaign end-game popup: the header carries `data-end-game-result` ("victory" / "defeat"),
        // the OK button navigates back to the missions screen.
        companiesEndGamePopupHeader: "game-page__companies-end-game-popup-header",
        companiesEndGamePopupOkButton: "game-page__companies-end-game-popup-ok-button",
        // Hidden dev-only node exposing `data-step-count` and `data-active-player-id` so tests
        // can deterministically detect when the bot has finished its turn (step count advances).
        debug: "game-page__debug",
    },
    setupPage: {
        player: "setup-page__player",
        playerTypeSelect: "setup-page__player-type-select",
        playerDifficultySelect: "setup-page__player-difficulty-select",
        fightButton: "setup-page__fight-button",
        // Per-building settings row (carries `data-building-type`) and its heal-amount select.
        buildingRow: "setup-page__building-row",
        buildingHealSelect: "setup-page__building-heal-select",
    },
} as const;
