/* global IS_PRODUCTION */

import {cloneElement, type JSX, useCallback, useMemo} from "react";
import {useNavigate} from "react-router-dom";

import {fullPathToUnitStore} from "../../../../../app/app-route";
import {squareSize} from "../../../../../css/style";
import {FrameByFrame} from "../../../../../layout/frame-by-frame/frame-by-frame";
import {getPlayerByPlayerId} from "../../../../../model/game/player/player-helper";
import {GamePlayerTypeEnum} from "../../../../../model/game/player/player-type";
import {getIsEqualPoint, getPointByPoint} from "../../../../../model/game/point/point-helper";
import type {PointType} from "../../../../../model/game/point/point-type";
import {getUnitByPoint, getUnitByUnitId} from "../../../../../model/game/unit/unit-helper";
import {getMovePathFromToByPathList} from "../../../../../model/game/unit/unit-path";
import type {GameUnitType} from "../../../../../model/game/unit/unit-type";
import {useGameContext} from "../../../../../provider/game/game-context";
import {GameActionTypeEnum} from "../../../../../provider/game/game-context-type";
import {useSettingContext} from "../../../../../provider/setting/setting-context";
import {throwError} from "../../../../../util/error";
import {getCanOpenStoreByPoint} from "../../unit-store/unit-store-helper";
import {
    attackSrcList,
    clientGameClickHunterImage,
    destroyBuildingSrcList,
    fixBuildingSrcList,
    occupyBuildingSrcList,
    openStoreSrcList,
    raiseSkeletonSrcList,
} from "../image/client-game-click-hunter-image";
import * as clientGameClickHunterCellStyle from "./client-game-click-hunter-cell.scss";
// eslint-disable-next-line max-len
import {ClientGameClickHunterCellSelect} from "./client-game-click-hunter-cell-select/client-game-click-hunter-cell-select";

interface ClientGameClickHunterCellPropsType {
    readonly handleShowAvailableActions: (point: PointType) => void;
    readonly x: number;
    readonly y: number;
}

// Dev-only inert attribute naming the action a cell button performs (attack-unit / move / occupy-building
// / …), so e2e tests can find "every cell I can move to" or "every enemy I can attack" for the selected
// unit. Same pattern as the data-cell-x / data-cell-y coordinates below.
function getCellActionProps(cellAction: string): Record<string, string> {
    return IS_PRODUCTION === false ? {"data-cell-action": cellAction} : {};
}

// Debug helper: log the clicked unit's full data as formatted JSON (dev builds only).
function logClickedUnitData(point: PointType, unitList: Array<GameUnitType>): void {
    // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
    if (IS_PRODUCTION) {
        return;
    }

    const clickedUnit: GameUnitType | null = getUnitByPoint(point, unitList);

    if (clickedUnit) {
        console.log(
            `%cunit [${point.x.toString(10)}, ${point.y.toString(10)}] — ${clickedUnit.unitType}`,
            "font-weight: bold; font-size: 14px;"
        );
        console.log(JSON.stringify(clickedUnit, null, 4));
    }
}

// eslint-disable-next-line complexity, max-statements
export function ClientGameClickHunterCell(props: ClientGameClickHunterCellPropsType): JSX.Element {
    const {
        setting: {
            numberSetting: {animationStepTime},
        },
    } = useSettingContext();
    const {pushAction, gameState, setActivePoint, availableActions, unitOverUnit} = useGameContext();
    const navigate = useNavigate();
    const {
        setting: {
            booleanSetting: {isActionIconAnimation},
        },
    } = useSettingContext();
    const {y, x, handleShowAvailableActions} = props;
    // Dev-only inert coordinate attributes so e2e tests can address a board cell by (x, y).
    // Applied to the same button that is rendered anyway, so the dev and prod DOM are structurally
    // identical (only these inert data-* attributes differ) — same pattern as `data-unit`.
    const cellCoordinateProps = IS_PRODUCTION === false ? {"data-cell-x": x, "data-cell-y": y} : {};
    // const {moveBackAction} = availableActions;
    // const moveBackPoint = moveBackAction?.movePointList.at(-1) ?? {x: -1, y: -1};
    const currentPoint: PointType = useMemo<PointType>((): PointType => {
        return {x, y};
    }, [x, y]);
    const {activeGamePlayerId, playerList, unitList} = gameState;
    const activePlayer = getPlayerByPlayerId(activeGamePlayerId, playerList);

    // Buttons
    const canOpenStoreByPoint =
        getCanOpenStoreByPoint(currentPoint, gameState) && !getUnitByPoint(currentPoint, unitList);
    const canOpenStoreByUnit: boolean =
        availableActions.canOpenStore && getIsEqualPoint(currentPoint, availableActions.unitCurrentPoint);
    const moveActionPoint: PointType | null = getPointByPoint(currentPoint, availableActions.movePointList);
    const moveOnAllyPoint: PointType | null = getPointByPoint(currentPoint, availableActions.moveOnAllyPointList);
    const attackUnitToUnitActionPoint: PointType | null = getPointByPoint(
        currentPoint,
        availableActions.attackUnitToUnitPointList
    );
    const attackUnitToBuildingActionPoint: PointType | null = getPointByPoint(
        currentPoint,
        availableActions.attackUnitToBuildingPointList
    );

    const canOccupyBuilding: boolean =
        availableActions.canOccupyBuilding && getIsEqualPoint(currentPoint, availableActions.unitCurrentPoint);

    const canFixBuilding: boolean =
        availableActions.canFixBuilding && getIsEqualPoint(currentPoint, availableActions.unitCurrentPoint);

    const raiseSkeletonPoint: PointType | null = getPointByPoint(currentPoint, availableActions.raiseSkeletonPointList);

    const actionButtonList: Array<JSX.Element> = [];

    const emptyCellCallBack = useCallback(() => {
        if (unitOverUnit) {
            const [, wrongUnit] = unitOverUnit;
            const wrongUnitPoint: PointType = {x: wrongUnit.x, y: wrongUnit.y};

            logClickedUnitData(wrongUnitPoint, unitList);
            setActivePoint(wrongUnitPoint);
            handleShowAvailableActions(wrongUnitPoint);
            return;
        }
        logClickedUnitData(currentPoint, unitList);
        setActivePoint(currentPoint);
        handleShowAvailableActions(currentPoint);
    }, [currentPoint, handleShowAvailableActions, setActivePoint, unitOverUnit, unitList]);
    const unitOnPoint: GameUnitType | null = getUnitByUnitId(availableActions.unitId, unitList);
    const isCurrentPlayerUnit = unitOnPoint?.gamePlayerId === activeGamePlayerId;
    const isAnotherUnit = Boolean(unitOnPoint && unitOnPoint.gamePlayerId !== activeGamePlayerId);

    if (activePlayer?.playerType !== GamePlayerTypeEnum.human) {
        return (
            <button
                className={clientGameClickHunterCellStyle.click_hunter_empty_cell}
                key="default-click-hunter-cell"
                type="button"
                {...cellCoordinateProps}
            />
        );
    }

    /*
    if (moveBackAction && getIsEqualPoint(moveBackPoint, currentPoint)) {
        actionButtonList.push(
            <button
                className={clientGameClickHunterCellStyle.click_hunter_cell}
                key="moveBackPoint"
                onClick={(): undefined => {
                    void pushAction(moveBackAction);
                    setActivePoint(moveBackPoint);
                }}
                type="button"
            >
                <img
                    alt="move back place"
                    className={clientGameClickHunterCellStyle.click_hunter_cell__image}
                    src={clientGameClickHunterImage.moveBack.src}
                />
            </button>
        );
    }
*/

    if ((canOpenStoreByUnit || canOpenStoreByPoint) && moveActionPoint === null) {
        actionButtonList.push(
            <button
                className={clientGameClickHunterCellStyle.click_hunter_cell_animated}
                key="openStore"
                {...getCellActionProps("open-store")}
                onClick={(): undefined => {
                    setActivePoint(currentPoint);
                    navigate(fullPathToUnitStore)?.catch(throwError);
                }}
                type="button"
            >
                <FrameByFrame
                    duration={openStoreSrcList.length * animationStepTime}
                    frameList={openStoreSrcList}
                    height={squareSize}
                    isAnimated={isActionIconAnimation}
                    staticFrameIndex={1}
                    width={squareSize}
                />
            </button>
        );
    }

    if (isCurrentPlayerUnit) {
        if (raiseSkeletonPoint) {
            actionButtonList.push(
                <button
                    className={clientGameClickHunterCellStyle.click_hunter_cell_animated}
                    key="raiseSkeletonPoint"
                    {...getCellActionProps("raise-skeleton")}
                    onClick={(): void => {
                        setActivePoint(currentPoint);
                        void pushAction({
                            actionType: GameActionTypeEnum.raiseSkeleton,
                            addUnitList: [],
                            briefing: null,
                            buyUnitType: null,
                            movePointList: [],
                            toPoint: currentPoint,
                            unitCurrentPoint: availableActions.unitCurrentPoint,
                            unitId: "",
                        });
                    }}
                    type="button"
                >
                    <FrameByFrame
                        duration={raiseSkeletonSrcList.length * animationStepTime}
                        frameList={raiseSkeletonSrcList}
                        height={squareSize}
                        isAnimated={isActionIconAnimation}
                        staticFrameIndex={1}
                        width={squareSize}
                    />
                </button>
            );
        }

        if (canOccupyBuilding) {
            actionButtonList.push(
                <button
                    className={clientGameClickHunterCellStyle.click_hunter_cell_animated}
                    key="canOccupyBuilding"
                    {...getCellActionProps("occupy-building")}
                    onClick={(): void => {
                        setActivePoint(currentPoint);
                        void pushAction({
                            actionType: GameActionTypeEnum.occupyBuilding,
                            addUnitList: [],
                            briefing: null,
                            buyUnitType: null,
                            movePointList: [],
                            toPoint: currentPoint,
                            unitCurrentPoint: availableActions.unitCurrentPoint,
                            unitId: "",
                        });
                    }}
                    type="button"
                >
                    <FrameByFrame
                        duration={occupyBuildingSrcList.length * animationStepTime}
                        frameList={occupyBuildingSrcList}
                        height={squareSize}
                        isAnimated={isActionIconAnimation}
                        staticFrameIndex={1}
                        width={squareSize}
                    />
                </button>
            );
        }

        if (canFixBuilding) {
            actionButtonList.push(
                <button
                    className={clientGameClickHunterCellStyle.click_hunter_cell_animated}
                    key="canFixBuilding"
                    {...getCellActionProps("fix-building")}
                    onClick={(): void => {
                        setActivePoint(currentPoint);
                        void pushAction({
                            actionType: GameActionTypeEnum.fixBuilding,
                            addUnitList: [],
                            briefing: null,
                            buyUnitType: null,
                            movePointList: [],
                            toPoint: currentPoint,
                            unitCurrentPoint: availableActions.unitCurrentPoint,
                            unitId: "",
                        });
                    }}
                    type="button"
                >
                    <FrameByFrame
                        duration={fixBuildingSrcList.length * animationStepTime}
                        frameList={fixBuildingSrcList}
                        height={squareSize}
                        isAnimated={isActionIconAnimation}
                        staticFrameIndex={1}
                        width={squareSize}
                    />
                </button>
            );
        }

        if (attackUnitToBuildingActionPoint) {
            actionButtonList.push(
                <button
                    className={clientGameClickHunterCellStyle.click_hunter_cell_animated}
                    key="attackUnitToBuildingActionPoint"
                    {...getCellActionProps("attack-building")}
                    onClick={(): void => {
                        setActivePoint(currentPoint);
                        void pushAction({
                            actionType: GameActionTypeEnum.unitToBuildingAttack,
                            addUnitList: [],
                            briefing: null,
                            buyUnitType: null,
                            movePointList: [],
                            toPoint: currentPoint,
                            unitCurrentPoint: availableActions.unitCurrentPoint,
                            unitId: "",
                        });
                    }}
                    type="button"
                >
                    <FrameByFrame
                        duration={destroyBuildingSrcList.length * animationStepTime}
                        frameList={destroyBuildingSrcList}
                        height={squareSize}
                        isAnimated={isActionIconAnimation}
                        staticFrameIndex={1}
                        width={squareSize}
                    />
                </button>
            );
        }

        if (attackUnitToUnitActionPoint) {
            actionButtonList.push(
                <button
                    className={clientGameClickHunterCellStyle.click_hunter_cell_animated}
                    key="attackUnitToUnitActionPoint"
                    {...getCellActionProps("attack-unit")}
                    onClick={(): void => {
                        setActivePoint(currentPoint);
                        void pushAction({
                            actionType: GameActionTypeEnum.unitToUnitAttack,
                            addUnitList: [],
                            briefing: null,
                            buyUnitType: null,
                            movePointList: [],
                            toPoint: currentPoint,
                            unitCurrentPoint: availableActions.unitCurrentPoint,
                            unitId: "",
                        });
                    }}
                    type="button"
                >
                    <FrameByFrame
                        duration={attackSrcList.length * animationStepTime}
                        frameList={attackSrcList}
                        height={squareSize}
                        isAnimated={isActionIconAnimation}
                        staticFrameIndex={1}
                        width={squareSize}
                    />
                </button>
            );
        }

        if (moveActionPoint) {
            actionButtonList.push(
                <button
                    className={clientGameClickHunterCellStyle.click_hunter_cell}
                    key="moveActionPoint"
                    {...getCellActionProps("move")}
                    onClick={(): void => {
                        setActivePoint(currentPoint);
                        void pushAction({
                            actionType: GameActionTypeEnum.unitMove,
                            addUnitList: [],
                            briefing: null,
                            buyUnitType: null,
                            movePointList: getMovePathFromToByPathList(
                                availableActions.unitCurrentPoint,
                                currentPoint,
                                availableActions.movePathList
                            ),
                            toPoint: currentPoint,
                            unitCurrentPoint: availableActions.unitCurrentPoint,
                            unitId: availableActions.unitId,
                        });
                    }}
                    type="button"
                >
                    <img
                        alt="move"
                        className={clientGameClickHunterCellStyle.click_hunter_cell__image}
                        src={clientGameClickHunterImage.move.src}
                    />
                </button>
            );
        }

        if (moveOnAllyPoint && !moveActionPoint) {
            actionButtonList.push(
                <button
                    className={clientGameClickHunterCellStyle.click_hunter_cell}
                    key="moveOnAllyPoint"
                    {...getCellActionProps("select")}
                    onClick={emptyCellCallBack}
                    type="button"
                >
                    <img
                        alt="move"
                        className={clientGameClickHunterCellStyle.click_hunter_cell__image}
                        src={clientGameClickHunterImage.moveOverUnit.src}
                    />
                </button>
            );
        }
    }

    if (isAnotherUnit) {
        if (moveOnAllyPoint && !moveActionPoint) {
            actionButtonList.push(
                <button
                    className={clientGameClickHunterCellStyle.click_hunter_cell}
                    key="moveOnAllyPoint"
                    {...getCellActionProps("select")}
                    onClick={emptyCellCallBack}
                    type="button"
                >
                    <img
                        alt="move"
                        className={clientGameClickHunterCellStyle.click_hunter_cell__image}
                        src={clientGameClickHunterImage.moveOverUnitEnemy.src}
                    />
                </button>
            );
        }

        if (moveActionPoint && getPointByPoint(currentPoint, availableActions.attackUnitToUnitPointList)) {
            actionButtonList.push(
                <button
                    className={clientGameClickHunterCellStyle.click_hunter_cell}
                    key="moveAndAttackPoint"
                    {...getCellActionProps("select")}
                    onClick={emptyCellCallBack}
                    type="button"
                >
                    <img
                        alt="move-and-attack"
                        className={clientGameClickHunterCellStyle.click_hunter_cell__image}
                        src={clientGameClickHunterImage.moveAndAttackEnemy.src}
                    />
                </button>
            );
        }

        if (moveActionPoint) {
            actionButtonList.push(
                <button
                    className={clientGameClickHunterCellStyle.click_hunter_cell}
                    key="moveActionPoint"
                    {...getCellActionProps("select")}
                    onClick={emptyCellCallBack}
                    type="button"
                >
                    <img
                        alt="move"
                        className={clientGameClickHunterCellStyle.click_hunter_cell__image}
                        src={clientGameClickHunterImage.moveEnemy.src}
                    />
                </button>
            );
        }

        if (getPointByPoint(currentPoint, availableActions.attackUnitToUnitPointList)) {
            actionButtonList.push(
                <button
                    className={clientGameClickHunterCellStyle.click_hunter_cell}
                    key="attackActionPoint"
                    {...getCellActionProps("select")}
                    onClick={emptyCellCallBack}
                    type="button"
                >
                    <img
                        alt="attack"
                        className={clientGameClickHunterCellStyle.click_hunter_cell__image}
                        src={clientGameClickHunterImage.attackEnemy.src}
                    />
                </button>
            );
        }

        if (actionButtonList.length > 0) {
            const [firstActionButton] = actionButtonList;

            if (firstActionButton) {
                return cloneElement(firstActionButton, cellCoordinateProps);
            }
        }
    }

    if (actionButtonList.length === 1) {
        const [firstActionButton] = actionButtonList;

        if (firstActionButton) {
            return cloneElement(firstActionButton, cellCoordinateProps);
        }
    }

    if (actionButtonList.length > 1) {
        return <ClientGameClickHunterCellSelect buttonList={actionButtonList} point={currentPoint} />;
    }

    return (
        <button
            className={clientGameClickHunterCellStyle.click_hunter_empty_cell}
            key="default-click-hunter-cell"
            onClick={emptyCellCallBack}
            type="button"
            {...cellCoordinateProps}
        />
    );
}
