import {type JSX, useState} from "react";

import {Page} from "../../../layout/page/page";
import {PageContent} from "../../../layout/page/page-content/page-content";
import {UiButton} from "../../../layout/ui-button/ui-button";
import {usePlayTitleTheme} from "../../../media/play-media";
import {getLandscapeSize} from "../../../model/game/landscape/landscape-helper";
import {GameLandscapeThemeEnum} from "../../../model/game/landscape/landscape-type";
import {skirmishMapList} from "../../../model/map/map-const";
import {getMaxPlayerByMap} from "../../../model/map/map-helper";
import type {GameMapType, SizeType} from "../../../model/map/map-type";
import {allLocalesData} from "../../../provider/locale/locale-context-const";
import {LocaleNameEnum} from "../../../provider/locale/locale-context-type";
import * as clientDevMapsStyle from "./client-dev-maps.scss";
import {DevMapPreview} from "./dev-map-preview";
import {DevPageHeader} from "./dev-page-header";

const themeList: Array<GameLandscapeThemeEnum> = Object.values(GameLandscapeThemeEnum);
const localeNameList: Array<LocaleNameEnum> = Object.values(LocaleNameEnum);

// Dev-only page. Intentionally not localized - all text is Swedish.
export function ClientDevMaps(): JSX.Element {
    usePlayTitleTheme();

    const [activeTheme, setActiveTheme] = useState<GameLandscapeThemeEnum>(GameLandscapeThemeEnum.ae2);

    return (
        <Page>
            <DevPageHeader title="Alla kartor" />
            <PageContent className={clientDevMapsStyle.client_dev_maps__content}>
                <div className={clientDevMapsStyle.client_dev_maps__theme_switcher}>
                    <span className={clientDevMapsStyle.client_dev_maps__theme_switcher_label}>Tema:</span>
                    {themeList.map((theme: GameLandscapeThemeEnum): JSX.Element => {
                        return (
                            <UiButton
                                isActive={theme === activeTheme}
                                isSquared
                                key={theme}
                                onClick={(): void => {
                                    setActiveTheme(theme);
                                }}
                            >
                                {theme}
                            </UiButton>
                        );
                    })}
                </div>

                {skirmishMapList.map((map: GameMapType): JSX.Element => {
                    const {mapId, mapNameLangKey} = map;
                    const mapSize: SizeType = getLandscapeSize(map.landscape);

                    return (
                        <div className={clientDevMapsStyle.client_dev_maps__item} key={mapId}>
                            <div className={clientDevMapsStyle.client_dev_maps__preview}>
                                <DevMapPreview map={map} theme={activeTheme} />
                            </div>
                            <dl className={clientDevMapsStyle.client_dev_maps__info}>
                                <dt>Id:</dt>
                                <dd>{mapId}</dd>
                                <dt>Lang-nyckel:</dt>
                                <dd>{mapNameLangKey}</dd>
                                <dt>Storlek:</dt>
                                <dd>
                                    {mapSize.width}&times;{mapSize.height}
                                </dd>
                                <dt>Antal spelare:</dt>
                                <dd>{getMaxPlayerByMap(map)}</dd>
                                <dt>Namn:</dt>
                                <dd>
                                    {localeNameList.map((localeName: LocaleNameEnum): JSX.Element => {
                                        return (
                                            <span
                                                className={clientDevMapsStyle.client_dev_maps__name_line}
                                                key={localeName}
                                            >
                                                {localeName}: {allLocalesData[localeName][mapNameLangKey]}
                                            </span>
                                        );
                                    })}
                                </dd>
                            </dl>
                        </div>
                    );
                })}
            </PageContent>
        </Page>
    );
}
