/* global HTMLSelectElement */

import type {Dispatch, JSX, SetStateAction, SyntheticEvent} from "react";

import {serviceStyle} from "../../../../css/style";
import {IsRender} from "../../../../layout/is-render/is-render";
import {SpoilerContent} from "../../../../layout/spoiler/spoiler-content";
import {UiButtonSimple} from "../../../../layout/ui-button/ui-button-simple";
import {saveBotDifficult} from "../../../../model/game/bot/bot-helper";
import {
    defaultMaxUnitLevel,
    defaultStartedMoney,
    defaultUnitLimit,
    maxUnitLevelList,
    startedMoneyList,
    unitLimitList,
} from "../../../../model/game/game-const";
import {
    defaultMaxUnitHealth,
    defaultUnitLevelStep,
    gamePlayerTeamIdList,
    maxUnitHealthList,
    unitLevelStepList,
} from "../../../../model/game/player/player-const";
import {getPlayerCommander} from "../../../../model/game/player/player-helper";
import {
    GamePlayerColorIdEnum,
    GamePlayerTeamIdEnum,
    type GamePlayerType,
    GamePlayerTypeEnum,
} from "../../../../model/game/player/player-type";
import {availableToBuyUnitTypeList, commanderUnitTypeList} from "../../../../model/game/unit/unit-const";
import {getSortedUnitTypeListAsc} from "../../../../model/game/unit/unit-helper";
import type {GameUnitTypeEnum} from "../../../../model/game/unit/unit-type";
import {getMapById} from "../../../../model/map/map-helper";
import type {GameMapType} from "../../../../model/map/map-type";
import {Locale} from "../../../../provider/locale/locale-context";
import {BotDifficultEnum} from "../../../../provider/setting/setting-type";
import {testId} from "../../../../test-id";
import {removeByValue} from "../../../../util/array";
import {cls} from "../../../../util/css";
import {getEnumValue, getEnumValueEnsure} from "../../../../util/enum";
import {getUnitImageSource} from "../../client-game/client-game-unit/image/unit-image";
import * as clientLocalGameSetupStyle from "../client-local-game-setup.scss";
import * as clientLocalGameSetupPlayerStyle from "./client-local-game-setup-player.scss";
import {colorImage, colorImageKeyLangMap} from "./image/image-color";

interface ClientLocalGameSetupPlayerType {
    readonly player: GamePlayerType;
    readonly setPlayerList: Dispatch<SetStateAction<Array<GamePlayerType>>>;
    readonly mapId: string;
}

export function ClientLocalGameSetupPlayer(props: ClientLocalGameSetupPlayerType): JSX.Element {
    const {player, setPlayerList, mapId} = props;
    const gameMap: GameMapType | null = getMapById(mapId);
    const unitList = gameMap?.unitList ?? [];
    const cemetery = gameMap?.cemetery ?? [];
    const {gamePlayerColorId, gamePlayerTeamId, playerType, playerDifficulty} = player;
    // TODO: remove me in future, current date is 2024-12-22, should be like this -> `playerDifficulty: BotDifficultEnum`
    const defaultBotDifficult: BotDifficultEnum = getEnumValueEnsure<BotDifficultEnum>(
        BotDifficultEnum,
        playerDifficulty,
        BotDifficultEnum.easy
    );
    const isBotPlayer = player.playerType === GamePlayerTypeEnum.bot;
    const isNonePlayer = player.playerType === GamePlayerTypeEnum.none;
    const commander = getPlayerCommander(player.gamePlayerId, {cemetery, unitList});
    // A commander can be switched only when the map places one of the interchangeable commanders
    // (not an objective-only hero like the crystal).
    const isCommanderSelectable = commander !== null && commanderUnitTypeList.includes(commander.unitType);
    const commanderUnitType = player.commanderUnitType ?? commander?.unitType ?? null;
    const commanderImageSrc =
        commanderUnitType === null ? "" : getUnitImageSource(commanderUnitType, gamePlayerColorId);

    function cycleCommander(): void {
        if (!isCommanderSelectable || commanderUnitType === null) {
            return;
        }

        const currentIndex = commanderUnitTypeList.indexOf(commanderUnitType);
        const nextCommanderUnitType =
            commanderUnitTypeList[(currentIndex + 1) % commanderUnitTypeList.length] ?? commanderUnitType;

        setPlayerList((currentPlayerList: Array<GamePlayerType>): Array<GamePlayerType> => {
            const updatedPlayerList = [...currentPlayerList];

            updatedPlayerList[updatedPlayerList.indexOf(player)] = {
                ...player,
                commanderUnitType: nextCommanderUnitType,
            };
            return updatedPlayerList;
        });
    }

    return (
        <div
            className={clientLocalGameSetupPlayerStyle.client_local_game_setup_player}
            data-player-id={player.gamePlayerId}
            data-testid={testId.setupPage.player}
        >
            <div className={clientLocalGameSetupPlayerStyle.client_local_game_setup_player__right}>
                <img
                    alt={gamePlayerColorId}
                    className={clientLocalGameSetupPlayerStyle.client_local_game_setup_player__color_point}
                    src={colorImage[gamePlayerColorId].src}
                />
                <p className={clientLocalGameSetupPlayerStyle.client_local_game_setup_player__color_name}>
                    <Locale stringKey={colorImageKeyLangMap[gamePlayerColorId]} />
                </p>
            </div>

            <div className={clientLocalGameSetupPlayerStyle.client_local_game_setup_player__right}>
                <select
                    className={serviceStyle.input__select}
                    data-testid={testId.setupPage.playerTypeSelect}
                    defaultValue={playerType}
                    onChange={(evt: SyntheticEvent<HTMLSelectElement>): undefined => {
                        const updatedPlayerType = getEnumValue<GamePlayerTypeEnum>(
                            GamePlayerTypeEnum,
                            evt.currentTarget.value
                        );

                        // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
                        if (!updatedPlayerType) {
                            console.error("Can not change player type");
                            return;
                        }

                        setPlayerList((currentPlayerList: Array<GamePlayerType>): Array<GamePlayerType> => {
                            const updatedPlayerList = [...currentPlayerList];

                            updatedPlayerList[updatedPlayerList.indexOf(player)] = {
                                ...player,
                                playerType: updatedPlayerType,
                            };
                            return updatedPlayerList;
                        });
                    }}
                >
                    <option value={GamePlayerTypeEnum.human}>
                        <Locale stringKey="SETUP_SKIRMISH__PLAYER" />
                    </option>
                    <option value={GamePlayerTypeEnum.bot}>
                        <Locale stringKey="SETUP_SKIRMISH__BOT" />
                    </option>
                    <option value={GamePlayerTypeEnum.none}>
                        <Locale stringKey="SETUP_SKIRMISH__NONE" />
                    </option>
                </select>

                <SpoilerContent isOpen={!isNonePlayer}>
                    <select
                        className={serviceStyle.input__select}
                        defaultValue={gamePlayerTeamId}
                        disabled={isNonePlayer}
                        onChange={(evt: SyntheticEvent<HTMLSelectElement>): undefined => {
                            const updatedPlayerTeamId = getEnumValue<GamePlayerTeamIdEnum>(
                                GamePlayerTeamIdEnum,
                                evt.currentTarget.value
                            );

                            // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
                            if (!updatedPlayerTeamId) {
                                console.error("Can not change player team id");
                                return;
                            }

                            setPlayerList((currentPlayerList: Array<GamePlayerType>): Array<GamePlayerType> => {
                                const updatedPlayerList = [...currentPlayerList];

                                updatedPlayerList[updatedPlayerList.indexOf(player)] = {
                                    ...player,
                                    gamePlayerTeamId: updatedPlayerTeamId,
                                };
                                return updatedPlayerList;
                            });
                        }}
                    >
                        {gamePlayerTeamIdList.map<JSX.Element>(
                            (teamId: GamePlayerTeamIdEnum, index: number): JSX.Element => {
                                return (
                                    <option key={teamId} value={teamId}>
                                        <Locale stringKey="SETUP_SKIRMISH__TEAM" valueMap={{number: index + 1}} />
                                    </option>
                                );
                            }
                        )}
                    </select>
                </SpoilerContent>

                <SpoilerContent isOpen={isBotPlayer}>
                    <select
                        className={serviceStyle.input__select}
                        data-testid={testId.setupPage.playerDifficultySelect}
                        defaultValue={defaultBotDifficult}
                        onChange={(evt: SyntheticEvent<HTMLSelectElement>): undefined => {
                            const botDifficult = getEnumValue<BotDifficultEnum>(
                                BotDifficultEnum,
                                evt.currentTarget.value
                            );

                            // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
                            if (!botDifficult) {
                                console.error("Can not change bot difficult");
                                return;
                            }

                            saveBotDifficult(botDifficult);

                            setPlayerList((currentPlayerList: Array<GamePlayerType>): Array<GamePlayerType> => {
                                const updatedPlayerList = [...currentPlayerList];

                                updatedPlayerList[updatedPlayerList.indexOf(player)] = {
                                    ...player,
                                    playerDifficulty: botDifficult,
                                };
                                return updatedPlayerList;
                            });
                        }}
                    >
                        <option value={BotDifficultEnum.easy}>
                            <Locale stringKey="SETTINGS__AI_DIFFICULT__EASY" />
                        </option>
                        <option value={BotDifficultEnum.normal}>
                            <Locale stringKey="SETTINGS__AI_DIFFICULT__NORMAL" />
                        </option>
                        <option value={BotDifficultEnum.hard}>
                            <Locale stringKey="SETTINGS__AI_DIFFICULT__HARD" />
                        </option>
                    </select>
                </SpoilerContent>
            </div>

            <SpoilerContent isOpen={!isNonePlayer}>
                <div className={clientLocalGameSetupStyle.client_local_game_setup__item}>
                    <p className={clientLocalGameSetupStyle.client_local_game_setup__item_label}>
                        <Locale stringKey="SETUP_SKIRMISH__MONEY" />
                    </p>
                    <select
                        className={serviceStyle.input__select}
                        defaultValue={player.money || defaultStartedMoney}
                        disabled={isNonePlayer}
                        onChange={(evt: SyntheticEvent<HTMLSelectElement>): undefined => {
                            const money = Number.parseInt(evt.currentTarget.value, 10);

                            setPlayerList((currentPlayerList: Array<GamePlayerType>): Array<GamePlayerType> => {
                                const updatedPlayerList = [...currentPlayerList];

                                updatedPlayerList[updatedPlayerList.indexOf(player)] = {
                                    ...player,
                                    money,
                                };
                                return updatedPlayerList;
                            });
                        }}
                    >
                        {startedMoneyList.map<JSX.Element>((money: number): JSX.Element => {
                            return (
                                <option key={money} value={money}>
                                    {money}
                                </option>
                            );
                        })}
                    </select>
                </div>

                <div className={clientLocalGameSetupStyle.client_local_game_setup__item}>
                    <p className={clientLocalGameSetupStyle.client_local_game_setup__item_label}>
                        <Locale stringKey="SETUP_SKIRMISH__MAX_UNIT_HEALTH" />
                    </p>
                    <select
                        className={serviceStyle.input__select}
                        defaultValue={player.maxUnitHealth ?? defaultMaxUnitHealth}
                        disabled={isNonePlayer}
                        onChange={(evt: SyntheticEvent<HTMLSelectElement>): undefined => {
                            const maxUnitHealth = Number.parseInt(evt.currentTarget.value, 10);

                            setPlayerList((currentPlayerList: Array<GamePlayerType>): Array<GamePlayerType> => {
                                const updatedPlayerList = [...currentPlayerList];

                                updatedPlayerList[updatedPlayerList.indexOf(player)] = {
                                    ...player,
                                    maxUnitHealth,
                                };
                                return updatedPlayerList;
                            });
                        }}
                    >
                        {maxUnitHealthList.map<JSX.Element>((maxUnitHealth: number): JSX.Element => {
                            return (
                                <option key={maxUnitHealth} value={maxUnitHealth}>
                                    {maxUnitHealth}&nbsp;
                                </option>
                            );
                        })}
                    </select>
                </div>

                <div className={clientLocalGameSetupStyle.client_local_game_setup__item}>
                    <p className={clientLocalGameSetupStyle.client_local_game_setup__item_label}>
                        <Locale stringKey="SETUP_SKIRMISH__UNIT_LEVEL_STEP" />
                    </p>
                    <select
                        className={serviceStyle.input__select}
                        defaultValue={player.unitLevelStep ?? defaultUnitLevelStep}
                        disabled={isNonePlayer}
                        onChange={(evt: SyntheticEvent<HTMLSelectElement>): undefined => {
                            const unitLevelStep = Number.parseInt(evt.currentTarget.value, 10);

                            setPlayerList((currentPlayerList: Array<GamePlayerType>): Array<GamePlayerType> => {
                                const updatedPlayerList = [...currentPlayerList];

                                updatedPlayerList[updatedPlayerList.indexOf(player)] = {
                                    ...player,
                                    unitLevelStep,
                                };
                                return updatedPlayerList;
                            });
                        }}
                    >
                        {unitLevelStepList.map<JSX.Element>((unitLevelStep: number): JSX.Element => {
                            return (
                                <option key={unitLevelStep} value={unitLevelStep}>
                                    {unitLevelStep}
                                </option>
                            );
                        })}
                    </select>
                </div>

                <div className={clientLocalGameSetupStyle.client_local_game_setup__item}>
                    <p className={clientLocalGameSetupStyle.client_local_game_setup__item_label}>
                        <Locale stringKey="SETUP_SKIRMISH__MAX_UNIT_LEVEL" />
                    </p>
                    <select
                        className={serviceStyle.input__select}
                        defaultValue={player.maxUnitLevel ?? defaultMaxUnitLevel}
                        disabled={isNonePlayer}
                        onChange={(evt: SyntheticEvent<HTMLSelectElement>): undefined => {
                            const maxUnitLevel = Number.parseInt(evt.currentTarget.value, 10);

                            setPlayerList((currentPlayerList: Array<GamePlayerType>): Array<GamePlayerType> => {
                                const updatedPlayerList = [...currentPlayerList];

                                updatedPlayerList[updatedPlayerList.indexOf(player)] = {
                                    ...player,
                                    maxUnitLevel,
                                };
                                return updatedPlayerList;
                            });
                        }}
                    >
                        {maxUnitLevelList.map<JSX.Element>((maxUnitLevel: number): JSX.Element => {
                            return (
                                <option key={maxUnitLevel} value={maxUnitLevel}>
                                    {maxUnitLevel}
                                </option>
                            );
                        })}
                    </select>
                </div>

                <div className={clientLocalGameSetupStyle.client_local_game_setup__item}>
                    <p className={clientLocalGameSetupStyle.client_local_game_setup__item_label}>
                        <Locale stringKey="SETUP_SKIRMISH__UNIT_LIMIT" />
                    </p>
                    <select
                        className={serviceStyle.input__select}
                        defaultValue={player.unitLimit ?? defaultUnitLimit}
                        disabled={isNonePlayer}
                        onChange={(evt: SyntheticEvent<HTMLSelectElement>): undefined => {
                            const unitLimit = Number.parseInt(evt.currentTarget.value, 10);

                            setPlayerList((currentPlayerList: Array<GamePlayerType>): Array<GamePlayerType> => {
                                const updatedPlayerList = [...currentPlayerList];

                                updatedPlayerList[updatedPlayerList.indexOf(player)] = {
                                    ...player,
                                    unitLimit,
                                };
                                return updatedPlayerList;
                            });
                        }}
                    >
                        {unitLimitList.map<JSX.Element>((unitLimit: number): JSX.Element => {
                            return (
                                <option key={unitLimit} value={unitLimit}>
                                    {unitLimit}
                                </option>
                            );
                        })}
                    </select>
                </div>

                <div className={clientLocalGameSetupPlayerStyle.client_local_game_setup_player__unit_list}>
                    <IsRender isRender={commanderImageSrc !== ""}>
                        <UiButtonSimple
                            className={cls(
                                clientLocalGameSetupPlayerStyle.client_local_game_setup_player__unit_item,
                                clientLocalGameSetupPlayerStyle.client_local_game_setup_player__unit_item__commander
                            )}
                            isDisabled={!isCommanderSelectable}
                            onClick={cycleCommander}
                        >
                            <img
                                alt={commanderUnitType ?? ""}
                                className={clientLocalGameSetupPlayerStyle.client_local_game_setup_player__unit_image}
                                src={commanderImageSrc}
                            />
                        </UiButtonSimple>
                    </IsRender>

                    {availableToBuyUnitTypeList.map((unitType: GameUnitTypeEnum): JSX.Element => {
                        return (
                            <label
                                className={clientLocalGameSetupPlayerStyle.client_local_game_setup_player__unit_item}
                                key={unitType}
                            >
                                <input
                                    className={
                                        clientLocalGameSetupPlayerStyle.client_local_game_setup_player__unit__checkbox
                                    }
                                    defaultChecked={player.availableToBuyUnitList?.includes(unitType) ?? false}
                                    onChange={(): void => {
                                        setPlayerList(
                                            (currentPlayerList: Array<GamePlayerType>): Array<GamePlayerType> => {
                                                const updatedPlayerList = [...currentPlayerList];

                                                const currentPlayer = updatedPlayerList.at(
                                                    updatedPlayerList.indexOf(player)
                                                );

                                                if (!currentPlayer) {
                                                    console.error("Can not found curren player");
                                                    return updatedPlayerList;
                                                }

                                                const updatedAvailableToBuyUnitList =
                                                    currentPlayer.availableToBuyUnitList ?? [];

                                                if (updatedAvailableToBuyUnitList.includes(unitType)) {
                                                    currentPlayer.availableToBuyUnitList = getSortedUnitTypeListAsc(
                                                        removeByValue<GameUnitTypeEnum>(
                                                            updatedAvailableToBuyUnitList,
                                                            unitType
                                                        )
                                                    );
                                                } else {
                                                    currentPlayer.availableToBuyUnitList = getSortedUnitTypeListAsc([
                                                        ...updatedAvailableToBuyUnitList,
                                                        unitType,
                                                    ]);
                                                }

                                                updatedPlayerList[updatedPlayerList.indexOf(player)] = {
                                                    ...currentPlayer,
                                                };
                                                return updatedPlayerList;
                                            }
                                        );
                                    }}
                                    type="checkbox"
                                />

                                <IsRender isRender={Boolean(player.availableToBuyUnitList?.includes(unitType))}>
                                    <img
                                        alt={unitType}
                                        className={
                                            clientLocalGameSetupPlayerStyle.client_local_game_setup_player__unit_image
                                        }
                                        src={getUnitImageSource(unitType, gamePlayerColorId)}
                                    />
                                </IsRender>
                                <IsRender isRender={player.availableToBuyUnitList?.includes(unitType) === false}>
                                    <img
                                        alt={unitType}
                                        className={
                                            // eslint-disable-next-line max-len
                                            clientLocalGameSetupPlayerStyle.client_local_game_setup_player__unit_image__disabled
                                        }
                                        src={getUnitImageSource(unitType, GamePlayerColorIdEnum.gray)}
                                    />
                                </IsRender>
                            </label>
                        );
                    })}
                </div>
            </SpoilerContent>
        </div>
    );
}
