import {type JSX, type RefObject, useCallback, useEffect, useRef, useState} from "react";
import {useBlocker, useNavigate} from "react-router-dom";

import type {UseGestureHookType} from "../../../hook/use-gesture/use-gesture-type";
import {Page} from "../../../layout/page/page";
import {PageContent} from "../../../layout/page/page-content/page-content";
import {PageHeader} from "../../../layout/page/page-header/page-header";
import {RateApp} from "../../../layout/rate-app/rate-app";
import {usePlayTitleTheme} from "../../../media/play-media";
import type {GameStateType} from "../../../model/game/game-type";
import type {GameMapType} from "../../../model/map/map-type";
import {useGameContext} from "../../../provider/game/game-context";
import {usePromptContext} from "../../../provider/prompt/prompt-context";
import {throwError} from "../../../util/error";
import {noop} from "../../../util/function";
import {getRandomString} from "../../../util/string";
import {ClientGameBuilding} from "../client-game/client-game-building/client-game-building";
import {ClientGameBuildingEffect} from "../client-game/client-game-building-effect/client-game-building-effect";
import {ClientGameGrave} from "../client-game/client-game-grave/client-game-grave";
import {ClientGameLandscape} from "../client-game/client-game-landscape/client-game-landscape";
import {ClientGameUnit} from "../client-game/client-game-unit/client-game-unit";
import {ClientGameViewContainer} from "../client-game/client-game-view-container/client-game-view-container";
import * as mapEditorStyle from "./map-editor.scss";
import {MapEditorBottomBar} from "./map-editor-bottom-bar/map-editor-bottom-bar";
import {MapEditorClickHunter} from "./map-editor-click-hunter/map-editor-click-hunter";
import {MapEditorDrawPanel} from "./map-editor-draw-panel/map-editor-draw-panel";
import {defaultDrawPanelState} from "./map-editor-draw-panel/map-editor-draw-panel-const";
import {getDefaultMapEditorGameState, getMapEditorDefaultMap} from "./map-editor-helper";
import type {MapEditorDrawPanelStateType} from "./map-editor-type";

export function MapEditor(): JSX.Element {
    const navigate = useNavigate();
    const {prompt} = usePromptContext();
    const {setGameState, resetState, gameState} = useGameContext();
    const [drawPanelState, setDrawPanelState] = useState<MapEditorDrawPanelStateType>({
        ...defaultDrawPanelState,
    });
    const [defaultMapName, setDefaultMapName] = useState<string>(getMapEditorDefaultMap().mapName);
    const [drawPanelKey, setDrawPanelKey] = useState<string>(getRandomString());
    const useGestureRef: RefObject<UseGestureHookType | null> = useRef<UseGestureHookType | null>(null);
    const [isBlockToExit, setIsBlockToExit] = useState<boolean>(true);
    const [isUnitShow, setIsUnitShow] = useState<boolean>(true);
    const [isBuildingShow, setIsBuildingShow] = useState<boolean>(true);
    const [isGridShow, setIsGridShow] = useState<boolean>(true);

    useBlocker(() => {
        if (!isBlockToExit) {
            return false;
        }

        prompt({
            header: "MAP_EDITOR__ARE_YOU_SURE_TO_LEAVE_MAP_EDITOR",
            index: 0,
            onNo: noop,
            onYes: () => {
                setIsBlockToExit(false);
                navigate(-1)?.catch(throwError);
            },
            text: "MAP_EDITOR__UNSAVED_MAP_PROGRESS_WILL_BE_LOST",
        });

        return isBlockToExit;
    });

    useEffect(() => {
        setGameState(getDefaultMapEditorGameState());

        return resetState;
    }, [setGameState, resetState]);

    usePlayTitleTheme();

    const loadMap = useCallback(
        (mapToLoad: GameMapType): undefined => {
            setDefaultMapName(mapToLoad.mapName);
            setGameState((currentGameState: GameStateType): GameStateType => {
                return {
                    ...currentGameState,
                    buildingList: [...mapToLoad.buildingList],
                    graveList: [...mapToLoad.graveList],
                    landscape: [...mapToLoad.landscape],
                    landscapeThemeMap: mapToLoad.landscapeThemeMap,
                    mapId: mapToLoad.mapId,
                    unitList: [...mapToLoad.unitList],
                };
            });
            setDrawPanelKey(getRandomString());
        },
        [setGameState]
    );

    useEffect(() => {
        setGameState((currentGameState: GameStateType): GameStateType => {
            return {
                ...currentGameState,
                landscape: getMapEditorDefaultMap().landscape,
            };
        });
    }, [setGameState]);

    return (
        <Page>
            <PageHeader langKey="UI__BUTTON__MAP_EDITOR" />

            <PageContent
                className={mapEditorStyle.map_editor__page}
                contentClassName={mapEditorStyle.map_editor__page_content}
            >
                <MapEditorDrawPanel
                    defaultMapName={defaultMapName}
                    isBuildingShow={isBuildingShow}
                    isGridShow={isGridShow}
                    isUnitShow={isUnitShow}
                    key={drawPanelKey}
                    setDrawPanelState={setDrawPanelState}
                    setIsBuildingShow={setIsBuildingShow}
                    setIsGridShow={setIsGridShow}
                    setIsUnitShow={setIsUnitShow}
                />

                <ClientGameViewContainer
                    className={mapEditorStyle.map_editor__game_view_container}
                    useGestureRef={useGestureRef}
                >
                    <ClientGameLandscape
                        forcedTheme={null}
                        landscape={gameState.landscape}
                        landscapeThemeMap={gameState.landscapeThemeMap}
                    />
                    {isBuildingShow ? <ClientGameBuilding forcedTheme={null} /> : null}
                    {isUnitShow ? <ClientGameGrave forcedTheme={null} /> : null}
                    {isUnitShow ? <ClientGameUnit isMapEditor /> : null}
                    {isBuildingShow ? <ClientGameBuildingEffect /> : null}
                    <MapEditorClickHunter drawPanelState={drawPanelState} isGridShow={isGridShow} />
                </ClientGameViewContainer>
            </PageContent>

            <MapEditorBottomBar drawPanelState={drawPanelState} loadMap={loadMap} />
            <RateApp />
        </Page>
    );
}
