import {getBuildingByPoint} from "../../../model/game/building/building-helper";
import type {GameBuildingType} from "../../../model/game/building/building-type";
import type {GameStateType} from "../../../model/game/game-type";
import {applyOccupyBuilding} from "../../../model/game/reducer/game-reducer";
import {getUnitByPoint} from "../../../model/game/unit/unit-helper";
import type {GameUnitType} from "../../../model/game/unit/unit-type";
import type {PromiseResolveType} from "../../../util/promise";
import {waitForNextFrame} from "../../../util/time";
import type {ActionArgumentType, GameAnimationType} from "../game-context-type";

export async function occupyBuildingAction(data: ActionArgumentType): Promise<void> {
    const {removeAnimationByAction, action, setAnimationList, setGameState, gameState} = data;
    const unitNewOwner: GameUnitType | null = getUnitByPoint(action.unitCurrentPoint, gameState.unitList);
    const buildingToOccupy: GameBuildingType | null = getBuildingByPoint(
        action.unitCurrentPoint,
        gameState.buildingList
    );

    if (!buildingToOccupy || !unitNewOwner) {
        return waitForNextFrame();
    }

    return new Promise<void>((resolve: PromiseResolveType<void>) => {
        setAnimationList((animList: Array<GameAnimationType>): Array<GameAnimationType> => {
            return [
                ...animList,
                {
                    action,
                    animationOnFinish: (): void => {
                        void (async (): Promise<void> => {
                            setGameState((currentGameState: GameStateType): GameStateType => {
                                return applyOccupyBuilding(currentGameState, action);
                            });
                            removeAnimationByAction(action);
                            await waitForNextFrame();
                            resolve();
                        })();
                    },
                },
            ];
        });
    });
}
