import type {GamePlayerIdEnum} from "../player/player-type";
import type {PointType} from "../point/point-type";
import {defaultUnitData, unitInfoMap} from "./unit-const";
import type {GameUnitType, GameUnitTypeEnum, UnitInfoType} from "./unit-type";

export function getUnitInfoByType(unitType: GameUnitTypeEnum): UnitInfoType {
    return unitInfoMap[unitType];
}

export function getUnitInfoByUnit(unit: GameUnitType): UnitInfoType {
    return getUnitInfoByType(unit.unitType);
}

export function getUnitByPoint(point: PointType, unitList: Array<GameUnitType>): GameUnitType | null {
    return (
        unitList.find<GameUnitType>((unit: GameUnitType): unit is GameUnitType => {
            return unit.x === point.x && unit.y === point.y;
        }) ?? null
    );
}

export function getUnitByUnitId(unitId: string, unitList: Array<GameUnitType>): GameUnitType | null {
    return (
        unitList.find<GameUnitType>((unit: GameUnitType): unit is GameUnitType => {
            return unit.unitId === unitId;
        }) ?? null
    );
}

export function getUnitOverUnit(unitList: Array<GameUnitType>): [GameUnitType, GameUnitType] | null {
    const unitListReversed: Array<GameUnitType> = [...unitList].reverse();

    for (const unit of unitList) {
        const unitPoint: PointType = {x: unit.x, y: unit.y};
        const lastUnitByPoint = getUnitByPoint(unitPoint, unitListReversed);

        if (lastUnitByPoint && lastUnitByPoint !== unit) {
            return [unit, lastUnitByPoint];
        }
    }

    return null;
}

export function addHealthToUnit(
    unitHealth: number,
    healthToAdd: number,
    maxHealth: number = defaultUnitData.health
): number {
    return Math.min(maxHealth, Math.round(unitHealth + healthToAdd));
}

export function getUnitListByPlayerId(
    gamePlayerId: GamePlayerIdEnum,
    unitList: Array<GameUnitType>
): Array<GameUnitType> {
    return unitList.filter<GameUnitType>((unitInList: GameUnitType): unitInList is GameUnitType => {
        return unitInList.gamePlayerId === gamePlayerId;
    });
}

export function getSortedUnitTypeListAsc(array: Array<GameUnitTypeEnum>): Array<GameUnitTypeEnum> {
    return array.sort((unitTypeA: GameUnitTypeEnum, unitTypeB: GameUnitTypeEnum): number => {
        return getUnitInfoByType(unitTypeA).sortOrder - getUnitInfoByType(unitTypeB).sortOrder;
    });
}
