import {type JSX, useEffect, useMemo, useRef, useState} from "react";

import {squareSize} from "../../../css/style";
import {getLandscapeSize} from "../../../model/game/landscape/landscape-helper";
import type {GameLandscapeThemeEnum} from "../../../model/game/landscape/landscape-type";
import type {GameMapType, SizeType} from "../../../model/map/map-type";
import {getMapPreviewCanvas} from "../client-game/client-game-landscape/helper/map-preview";
import * as devMapPreviewStyle from "./dev-map-preview.scss";

interface DevMapPreviewPropsType {
    readonly map: GameMapType;
    readonly theme: GameLandscapeThemeEnum;
}

// Renders a skirmish map forced into a single theme (ignores the map's own per-cell theme).
// The heavy canvas rendering is lazy: it only runs once the preview scrolls near the viewport.
export function DevMapPreview(props: DevMapPreviewPropsType): JSX.Element {
    const {map, theme} = props;
    const {width, height}: SizeType = getLandscapeSize(map.landscape);
    const wrapperRef = useRef<HTMLDivElement | null>(null);
    const [isVisible, setIsVisible] = useState<boolean>(false);

    useEffect((): (() => void) => {
        const wrapperNode: HTMLDivElement | null = wrapperRef.current;

        if (!wrapperNode) {
            return (): void => {
                // Nothing to clean up when the node is not mounted yet.
            };
        }

        const observer = new IntersectionObserver(
            (entryList: Array<IntersectionObserverEntry>): void => {
                const isNowVisible: boolean = entryList.some((entry: IntersectionObserverEntry): boolean => {
                    return entry.isIntersecting;
                });

                if (isNowVisible) {
                    setIsVisible(true);
                    observer.disconnect();
                }
            },
            {rootMargin: "300px"}
        );

        observer.observe(wrapperNode);

        return (): void => {
            observer.disconnect();
        };
    }, []);

    const mapImage: JSX.Element | null = useMemo<JSX.Element | null>((): JSX.Element | null => {
        if (!isVisible) {
            return null;
        }

        const {landscape, unit, building} = getMapPreviewCanvas(map, theme);

        return (
            <>
                <img alt="landscape" className={devMapPreviewStyle.dev_map_preview_image} src={landscape} />
                <img alt="building" className={devMapPreviewStyle.dev_map_preview_image} src={building} />
                <img alt="unit" className={devMapPreviewStyle.dev_map_preview_image} src={unit} />
            </>
        );
    }, [isVisible, map, theme]);

    return (
        <div className={devMapPreviewStyle.dev_map_preview} ref={wrapperRef}>
            <canvas
                className={devMapPreviewStyle.dev_map_preview_image__frame}
                height={height * squareSize}
                width={width * squareSize}
            />
            {mapImage}
        </div>
    );
}
