import {type JSX, useState} from "react";

import {appRoute} from "../../../app/app-route";
import {Markdown} from "../../../layout/markdown/markdown";
import {Page} from "../../../layout/page/page";
import {PageContent} from "../../../layout/page/page-content/page-content";
import {PageHeader} from "../../../layout/page/page-header/page-header";
import {UiLink} from "../../../layout/ui-button/ui-link";
import {usePlayTitleTheme} from "../../../media/play-media";
import {useLocale} from "../../../provider/locale/locale-context";
import * as clientAboutStyle from "./client-about.scss";

// Number of taps on the title that reveals the hidden developer page link.
const devPageTapCount = 10;

export function ClientAbout(): JSX.Element {
    const {getLocalizedString} = useLocale();
    const [tapCount, setTapCount] = useState<number>(0);

    usePlayTitleTheme();

    const localizedString: string = [getLocalizedString("ABOUT_TEXT__ABOUT_TEXT")].join("\n\n");
    const isDevLinkVisible: boolean = tapCount >= devPageTapCount;

    return (
        <Page>
            <PageHeader langKey="UI__BUTTON__ABOUT" />
            <PageContent hasBorder>
                {/* eslint-disable-next-line jsx-a11y/no-static-element-interactions, jsx-a11y/click-events-have-key-events */}
                <div
                    onClick={(): void => {
                        setTapCount((currentCount: number): number => {
                            return currentCount + 1;
                        });
                    }}
                >
                    <Markdown className={clientAboutStyle.client_about__markdown__header} mdInput={localizedString} />
                </div>

                <p className={clientAboutStyle.client_about__main_text}>
                    Web site:
                    <br />
                    webbestmaster.github.io
                </p>

                <p className={clientAboutStyle.client_about__main_text}>
                    E-mail:
                    <br />
                    ae.fan.game@gmail.com
                </p>

                {/*<hr />*/}
                {/*
                <p className={clientAboutStyle.client_about__main_text}>
                    WebAssembly enabled: {isWasmInitialized ? "Yes" : "No"}
                </p>
*/}

                {isDevLinkVisible ? (
                    <div className={clientAboutStyle.client_about__dev_link_wrapper}>
                        <UiLink href={appRoute.dev.path}>Utvecklare</UiLink>
                    </div>
                ) : null}
            </PageContent>
        </Page>
    );
}
