/* global HTMLInputElement */
/* eslint-disable react/jsx-max-depth */
import {type Dispatch, Fragment, type JSX, type SetStateAction, type SyntheticEvent, useEffect, useState} from "react";

import {IsRender} from "../../../../layout/is-render/is-render";
import {SpoilerContent} from "../../../../layout/spoiler/spoiler-content";
import {UiButton} from "../../../../layout/ui-button/ui-button";
import {GameBuildingStateEnum, GameBuildingTypeEnum} from "../../../../model/game/building/building-type";
import {
    defaultLandscapeTheme,
    GameLandscapeItemEnum,
    GameLandscapeThemeEnum,
} from "../../../../model/game/landscape/landscape-type";
import {GamePlayerColorIdEnum} from "../../../../model/game/player/player-type";
import {GameUnitTypeEnum} from "../../../../model/game/unit/unit-type";
import {useGameContext} from "../../../../provider/game/game-context";
import {Locale} from "../../../../provider/locale/locale-context";
import type {LangKeyType} from "../../../../provider/locale/translation/type";
import {cls} from "../../../../util/css";
import {getHash} from "../../../../util/string";
import {getBuildingImageMap, getFarmBrokenImage} from "../../client-game/client-game-building/image/building-image";
import {getGraveImage} from "../../client-game/client-game-grave/image/client-game-grave-image";
import {getIsTerraBasedTile} from "../../client-game/client-game-landscape/helper/client-game-landscape-canvas";
import {getLandscapeImage} from "../../client-game/client-game-landscape/image/landscape-image";
import {getUnitImageSource} from "../../client-game/client-game-unit/image/unit-image";
import {colorImage} from "../../client-local-game-setup/client-local-game-setup-player/image/image-color";
import {getRandomForestImage, getRandomWaterImage, mapEditorImage} from "../image/map-editor-image";
import {changeMapSize, ChangeMapSizeEnum} from "../map-editor-helper";
import {type MapEditorDrawPanelStateType, MapEditorTabEnum} from "../map-editor-type";
import * as mapEditorDrawPanelStyle from "./map-editor-draw-panel.scss";
import {defaultDrawPanelState} from "./map-editor-draw-panel-const";

const {br0, br1, wt0, st0, tr0, hl0, fr1, rd0, fr0, wt1, wt2} = GameLandscapeItemEnum;

// The single-tile palette, shared by every theme section.
// terra1..terra4 are intentionally excluded — their buttons must not appear in the map editor.
const terrainTileList: Array<GameLandscapeItemEnum> = [rd0, tr0, hl0, fr0, fr1, st0, wt0, wt1, wt2, br0, br1];
const randomForestList: Array<GameLandscapeItemEnum> = [fr0, fr1];
const randomWaterList: Array<GameLandscapeItemEnum> = [wt0, wt1, wt2];

// One palette section per theme (see step 5 of the graphics-theme feature).
const terrainThemeSectionList: Array<{langKey: LangKeyType; theme: GameLandscapeThemeEnum}> = [
    {langKey: "SETTINGS__LANDSCAPE_THEME__AE_2", theme: GameLandscapeThemeEnum.ae2},
    {langKey: "SETTINGS__LANDSCAPE_THEME__SUMMER", theme: GameLandscapeThemeEnum.summer},
    {langKey: "SETTINGS__LANDSCAPE_THEME__SUMMER_2", theme: GameLandscapeThemeEnum.summer2},
    {langKey: "SETTINGS__LANDSCAPE_THEME__DESERT", theme: GameLandscapeThemeEnum.desert},
    {langKey: "SETTINGS__LANDSCAPE_THEME__AE_1", theme: GameLandscapeThemeEnum.ae1},
];

// Building palette icons are theme-neutral (a building's real theme comes from the cell it sits on), so use ae2.
const buildingImage = getBuildingImageMap(GameLandscapeThemeEnum.ae2);
const farmBrokenImage = getFarmBrokenImage(GameLandscapeThemeEnum.ae2);
// The grave palette icon is theme-neutral (a grave's real theme comes from the cell it sits on), so use ae2.
const graveImage = getGraveImage(GameLandscapeThemeEnum.ae2);

const {blue, red, gray, green, black} = GamePlayerColorIdEnum;
const {castle, farm, well, temple} = GameBuildingTypeEnum;
const {buildingBroken, buildingOk} = GameBuildingStateEnum;

const {
    galamar,
    valadorn,
    demonLord,
    saeth,

    soldier,
    archer,
    elemental,
    sorceress,
    wisp,
    direWolf,
    golem,
    catapult,
    dragon,

    skeleton,
} = GameUnitTypeEnum;

interface MapEditorDrawPanelPropsType {
    readonly defaultMapName: string;
    readonly isBuildingShow: boolean;
    readonly isGridShow: boolean;
    readonly isUnitShow: boolean;
    readonly setDrawPanelState: Dispatch<SetStateAction<MapEditorDrawPanelStateType>>;
    readonly setIsBuildingShow: Dispatch<SetStateAction<boolean>>;
    readonly setIsGridShow: Dispatch<SetStateAction<boolean>>;
    readonly setIsUnitShow: Dispatch<SetStateAction<boolean>>;
}

export function MapEditorDrawPanel(props: MapEditorDrawPanelPropsType): JSX.Element {
    const minSize = 3;
    const maxSize = 32;
    const maxMapNameLength = 250;

    const {gameState, setGameState, mapSize} = useGameContext();
    const {
        setDrawPanelState,
        defaultMapName,
        isUnitShow,
        setIsUnitShow,
        isBuildingShow,
        setIsBuildingShow,
        isGridShow,
        setIsGridShow,
    } = props;
    const [mapName, setMapName] = useState<string>(defaultMapName);
    const [activeTab, setActiveTab] = useState<MapEditorTabEnum>(defaultDrawPanelState.activeTab);
    const [activeUnitColor, setActiveUnitColor] = useState<GamePlayerColorIdEnum>(
        defaultDrawPanelState.activeUnitColor
    );
    const [activeBuildingColor, setActiveBuildingColor] = useState<GamePlayerColorIdEnum>(
        defaultDrawPanelState.activeBuildingColor
    );
    const [activeTerrainList, setActiveTerrainList] = useState<Array<GameLandscapeItemEnum>>(
        defaultDrawPanelState.activeTerrainList
    );
    const [activeTerrainTheme, setActiveTerrainTheme] = useState<GameLandscapeThemeEnum>(
        defaultDrawPanelState.activeTerrainTheme
    );
    const [openThemeList, setOpenThemeList] = useState<Array<GameLandscapeThemeEnum>>([defaultLandscapeTheme]);
    const [isMapSizeOpen, setIsMapSizeOpen] = useState<boolean>(true);
    const [activeBuilding, setActiveBuilding] = useState<GameBuildingTypeEnum | null>(
        defaultDrawPanelState.activeBuilding
    );
    const [activeBuildingState, setActiveBuildingState] = useState<GameBuildingStateEnum>(
        defaultDrawPanelState.activeBuildingState
    );

    const [activeUnit, setActiveUnit] = useState<GameUnitTypeEnum | null>(defaultDrawPanelState.activeUnit);
    const [isGraveActive, setIsGraveActive] = useState<boolean>(defaultDrawPanelState.isGraveActive);

    useEffect(() => {
        setDrawPanelState({
            activeBuilding,
            activeBuildingColor,
            activeBuildingState,
            activeTab,
            activeTerrainList,
            activeTerrainTheme,
            activeUnit,
            activeUnitColor,
            isGraveActive,
            mapId: getHash(mapName),
            mapName,
        });
    }, [
        setDrawPanelState,
        activeBuilding,
        activeBuildingColor,
        activeBuildingState,
        activeTab,
        activeTerrainList,
        activeTerrainTheme,
        activeUnit,
        activeUnitColor,
        isGraveActive,
        mapName,
    ]);

    return (
        <div className={mapEditorDrawPanelStyle.map_editor_draw_panel}>
            <label className={mapEditorDrawPanelStyle.map_editor_draw_panel__map_name__label}>
                <p className={mapEditorDrawPanelStyle.map_editor_draw_panel__map_name__input_name}>
                    <Locale stringKey="MAP_EDITOR__MAP_NAME" />
                </p>
                <input
                    className={mapEditorDrawPanelStyle.map_editor_draw_panel__map_name__input}
                    defaultValue={defaultMapName}
                    maxLength={maxMapNameLength}
                    onInput={(evt: SyntheticEvent<HTMLInputElement>): undefined => {
                        setMapName(evt.currentTarget.value);
                    }}
                    type="text"
                />
            </label>
            <div className={mapEditorDrawPanelStyle.map_editor_draw_panel__tab_button_list}>
                <UiButton
                    hotKey={{
                        code: "Digit1",
                        isDisableWhenInputActive: true,
                    }}
                    iconSrc={mapEditorImage.terrain.src}
                    isActive={activeTab === MapEditorTabEnum.terrain}
                    isSquared
                    onClick={(): undefined => {
                        setActiveTab(MapEditorTabEnum.terrain);
                    }}
                />
                <UiButton
                    hotKey={{
                        code: "Digit2",
                        isDisableWhenInputActive: true,
                    }}
                    iconSrc={mapEditorImage.building.src}
                    isActive={activeTab === MapEditorTabEnum.building}
                    isSquared
                    onClick={(): undefined => {
                        setActiveTab(MapEditorTabEnum.building);
                    }}
                />
                <UiButton
                    hotKey={{
                        code: "Digit3",
                        isDisableWhenInputActive: true,
                    }}
                    iconSrc={mapEditorImage.unit.src}
                    isActive={activeTab === MapEditorTabEnum.unit}
                    isSquared
                    onClick={(): undefined => {
                        setActiveTab(MapEditorTabEnum.unit);
                    }}
                />
            </div>
            <IsRender isRender={activeTab === MapEditorTabEnum.terrain}>
                <div className={mapEditorDrawPanelStyle.map_editor_draw_panel__tab_list_content}>
                    {terrainThemeSectionList.map(
                        (themeSection: {langKey: LangKeyType; theme: GameLandscapeThemeEnum}) => {
                            const {theme, langKey} = themeSection;
                            const themeImage = getLandscapeImage(theme);
                            const isThemeActive = activeTerrainTheme === theme;
                            const isThemeOpen = openThemeList.includes(theme);

                            return (
                                <Fragment key={theme}>
                                    <UiButton
                                        className={mapEditorDrawPanelStyle.map_editor_draw_panel__theme_button}
                                        isActive={isThemeOpen}
                                        isSquared
                                        langKey={langKey}
                                        onClick={(): undefined => {
                                            setOpenThemeList(
                                                (
                                                    prevList: Array<GameLandscapeThemeEnum>
                                                ): Array<GameLandscapeThemeEnum> => {
                                                    if (prevList.includes(theme)) {
                                                        return prevList.filter(
                                                            (themeInList: GameLandscapeThemeEnum): boolean => {
                                                                return themeInList !== theme;
                                                            }
                                                        );
                                                    }

                                                    return [...prevList, theme];
                                                }
                                            );
                                        }}
                                    />
                                    <SpoilerContent isOpen={isThemeOpen}>
                                        <div className={mapEditorDrawPanelStyle.map_editor_draw_panel__tab_content}>
                                            {terrainTileList.map<JSX.Element>(
                                                (terrainInList: GameLandscapeItemEnum): JSX.Element => {
                                                    return (
                                                        <UiButton
                                                            iconSrc={themeImage[terrainInList].src}
                                                            iconSrcBackground={
                                                                getIsTerraBasedTile(terrainInList)
                                                                    ? themeImage[tr0].src
                                                                    : ""
                                                            }
                                                            isActive={
                                                                isThemeActive &&
                                                                activeTerrainList.toString() ===
                                                                    terrainInList.toString()
                                                            }
                                                            isSquared
                                                            key={terrainInList}
                                                            onClick={(): undefined => {
                                                                setActiveTerrainList([terrainInList]);
                                                                setActiveTerrainTheme(theme);
                                                            }}
                                                        />
                                                    );
                                                }
                                            )}

                                            <div
                                                className={mapEditorDrawPanelStyle.map_editor_draw_panel__random_button}
                                            >
                                                <UiButton
                                                    iconSrc={getRandomForestImage(theme).src}
                                                    isActive={
                                                        isThemeActive &&
                                                        activeTerrainList.toString() === randomForestList.toString()
                                                    }
                                                    isSquared
                                                    key="random-forest"
                                                    onClick={(): undefined => {
                                                        setActiveTerrainList(randomForestList);
                                                        setActiveTerrainTheme(theme);
                                                    }}
                                                />

                                                <UiButton
                                                    iconSrc={getRandomWaterImage(theme).src}
                                                    isActive={
                                                        isThemeActive &&
                                                        activeTerrainList.toString() === randomWaterList.toString()
                                                    }
                                                    isSquared
                                                    key="random-water"
                                                    onClick={(): undefined => {
                                                        setActiveTerrainList(randomWaterList);
                                                        setActiveTerrainTheme(theme);
                                                    }}
                                                />
                                            </div>
                                        </div>
                                    </SpoilerContent>
                                </Fragment>
                            );
                        }
                    )}
                    <div className={mapEditorDrawPanelStyle.map_editor_draw_panel__map_additional_settings}>
                        <UiButton
                            className={mapEditorDrawPanelStyle.map_editor_draw_panel__theme_button}
                            isActive={isMapSizeOpen}
                            isSquared
                            onClick={(): undefined => {
                                setIsMapSizeOpen((prevIsOpen: boolean): boolean => {
                                    return !prevIsOpen;
                                });
                            }}
                        >
                            <Locale stringKey="MAP_EDITOR__SIZE" /> {mapSize.width}&times;{mapSize.height}
                        </UiButton>
                        <SpoilerContent isOpen={isMapSizeOpen}>
                            <div
                                className={cls(
                                    mapEditorDrawPanelStyle.map_editor_draw_panel__tab_content,
                                    mapEditorDrawPanelStyle.map_editor_draw_panel__tab_content__two_columns
                                )}
                            >
                                <UiButton
                                    iconSrc={mapEditorImage.topMinus.src}
                                    isDisabled={mapSize.height <= minSize}
                                    isSquared
                                    onClick={(): undefined => {
                                        setGameState(changeMapSize(ChangeMapSizeEnum.topMinus, gameState));
                                    }}
                                />
                                <UiButton
                                    iconSrc={mapEditorImage.topPlus.src}
                                    isDisabled={mapSize.height >= maxSize}
                                    isSquared
                                    onClick={(): undefined => {
                                        setGameState(changeMapSize(ChangeMapSizeEnum.topPlus, gameState));
                                    }}
                                />
                                <UiButton
                                    iconSrc={mapEditorImage.bottomMinus.src}
                                    isDisabled={mapSize.height <= minSize}
                                    isSquared
                                    onClick={(): undefined => {
                                        setGameState(changeMapSize(ChangeMapSizeEnum.bottomMinus, gameState));
                                    }}
                                />
                                <UiButton
                                    iconSrc={mapEditorImage.bottomPlus.src}
                                    isDisabled={mapSize.height >= maxSize}
                                    isSquared
                                    onClick={(): undefined => {
                                        setGameState(changeMapSize(ChangeMapSizeEnum.bottomPlus, gameState));
                                    }}
                                />
                                <UiButton
                                    iconSrc={mapEditorImage.leftMinus.src}
                                    isDisabled={mapSize.width <= minSize}
                                    isSquared
                                    onClick={(): undefined => {
                                        setGameState(changeMapSize(ChangeMapSizeEnum.leftMinus, gameState));
                                    }}
                                />
                                <UiButton
                                    iconSrc={mapEditorImage.leftPlus.src}
                                    isDisabled={mapSize.width >= maxSize}
                                    isSquared
                                    onClick={(): undefined => {
                                        setGameState(changeMapSize(ChangeMapSizeEnum.leftPlus, gameState));
                                    }}
                                />
                                <UiButton
                                    iconSrc={mapEditorImage.rightMinus.src}
                                    isDisabled={mapSize.width <= minSize}
                                    isSquared
                                    onClick={(): undefined => {
                                        setGameState(changeMapSize(ChangeMapSizeEnum.rightMinus, gameState));
                                    }}
                                />
                                <UiButton
                                    iconSrc={mapEditorImage.rightPlus.src}
                                    isDisabled={mapSize.width >= maxSize}
                                    isSquared
                                    onClick={(): undefined => {
                                        setGameState(changeMapSize(ChangeMapSizeEnum.rightPlus, gameState));
                                    }}
                                />
                            </div>
                        </SpoilerContent>
                        <UiButton
                            className={mapEditorDrawPanelStyle.map_editor_draw_panel__theme_button}
                            isActive={isGridShow}
                            isSquared
                            langKey={isGridShow ? "MAP_EDITOR__GRID_ON" : "MAP_EDITOR__GRID_OFF"}
                            onClick={(): undefined => {
                                setIsGridShow((prevIsShow: boolean): boolean => {
                                    return !prevIsShow;
                                });
                            }}
                        />
                    </div>
                </div>
            </IsRender>
            <IsRender isRender={activeTab === MapEditorTabEnum.building}>
                <div className={mapEditorDrawPanelStyle.map_editor_draw_panel__tab_list_content}>
                    <div
                        className={cls(
                            mapEditorDrawPanelStyle.map_editor_draw_panel__tab_content,
                            mapEditorDrawPanelStyle.map_editor_draw_panel__tab_content__zero_shrink
                        )}
                    >
                        <UiButton
                            iconSrc={mapEditorImage.buildingHalf.src}
                            isActive={isBuildingShow}
                            isSquared
                            onClick={(): undefined => {
                                setIsBuildingShow(!isBuildingShow);
                            }}
                        />
                        {[blue, red, green, black, gray].map<JSX.Element>(
                            (colorInList: GamePlayerColorIdEnum): JSX.Element => {
                                return (
                                    <UiButton
                                        iconSrc={colorImage[colorInList].src}
                                        isActive={activeBuildingColor === colorInList}
                                        isSquared
                                        key={colorInList}
                                        onClick={(): undefined => {
                                            setActiveBuildingColor(colorInList);
                                        }}
                                    />
                                );
                            }
                        )}
                    </div>

                    <div className={mapEditorDrawPanelStyle.map_editor_draw_panel__tab_content}>
                        <UiButton
                            iconSrc={buildingImage[castle][activeBuildingColor].src}
                            iconSrcClassName={mapEditorDrawPanelStyle.map_editor_draw_panel__button__castle}
                            isActive={activeBuilding === castle && activeBuildingState === buildingOk}
                            isSquared
                            onClick={(): undefined => {
                                setActiveBuilding(castle);
                                setActiveBuildingState(buildingOk);
                            }}
                        />
                        <UiButton
                            iconSrc={buildingImage[farm][activeBuildingColor].src}
                            isActive={activeBuilding === farm && activeBuildingState === buildingOk}
                            isSquared
                            onClick={(): undefined => {
                                setActiveBuilding(farm);
                                setActiveBuildingState(buildingOk);
                            }}
                        />
                        <UiButton
                            iconSrc={farmBrokenImage.src}
                            isActive={activeBuilding === farm && activeBuildingState === buildingBroken}
                            isSquared
                            onClick={(): undefined => {
                                setActiveBuilding(farm);
                                setActiveBuildingState(buildingBroken);
                            }}
                        />
                        <UiButton
                            iconSrc={buildingImage[temple].src}
                            isActive={activeBuilding === temple}
                            isSquared
                            onClick={(): undefined => {
                                setActiveBuilding(temple);
                            }}
                        />
                        <UiButton
                            iconSrc={buildingImage[well].src}
                            isActive={activeBuilding === well}
                            isSquared
                            onClick={(): undefined => {
                                setActiveBuilding(well);
                            }}
                        />
                        <UiButton
                            iconSrc={mapEditorImage.eraser.src}
                            isActive={activeBuilding === null}
                            isSquared
                            onClick={(): undefined => {
                                setActiveBuilding(null);
                            }}
                        />
                        <p className={mapEditorDrawPanelStyle.map_editor_draw_panel__text}>
                            <Locale stringKey="MAP_EDITOR__BUILDING_THEME_FROM_CELL" />
                        </p>
                    </div>
                </div>
            </IsRender>
            <IsRender isRender={activeTab === MapEditorTabEnum.unit}>
                <div className={mapEditorDrawPanelStyle.map_editor_draw_panel__tab_list_content}>
                    <div
                        className={cls(
                            mapEditorDrawPanelStyle.map_editor_draw_panel__tab_content,
                            mapEditorDrawPanelStyle.map_editor_draw_panel__tab_content__zero_shrink
                        )}
                    >
                        <UiButton
                            iconSrc={mapEditorImage.unitHalf.src}
                            isActive={isUnitShow}
                            isSquared
                            onClick={(): undefined => {
                                setIsUnitShow(!isUnitShow);
                            }}
                        />
                        {[blue, red, green, black].map<JSX.Element>(
                            (colorInList: GamePlayerColorIdEnum): JSX.Element => {
                                return (
                                    <UiButton
                                        iconSrc={colorImage[colorInList].src}
                                        isActive={activeUnitColor === colorInList}
                                        isSquared
                                        key={colorInList}
                                        onClick={(): undefined => {
                                            setActiveUnitColor(colorInList);
                                        }}
                                    />
                                );
                            }
                        )}
                    </div>

                    <div className={mapEditorDrawPanelStyle.map_editor_draw_panel__tab_content}>
                        {[
                            galamar,
                            valadorn,
                            demonLord,
                            saeth,

                            soldier,
                            archer,
                            elemental,
                            sorceress,
                            wisp,
                            direWolf,
                            golem,
                            catapult,
                            dragon,

                            skeleton,
                        ].map<JSX.Element>((unitInList: GameUnitTypeEnum): JSX.Element => {
                            return (
                                <UiButton
                                    iconSrc={getUnitImageSource(unitInList, activeUnitColor)}
                                    isActive={activeUnit === unitInList && !isGraveActive}
                                    isSquared
                                    key={unitInList}
                                    onClick={(): undefined => {
                                        setActiveUnit(unitInList);
                                        setIsGraveActive(false);
                                    }}
                                />
                            );
                        })}
                        {/* Grave, unit and eraser are mutually exclusive tools (only one active at a time). A placed grave
                        still coexists with a unit on the same cell — placing one never removes the other. */}
                        <UiButton
                            iconSrc={graveImage.src}
                            isActive={isGraveActive}
                            isSquared
                            onClick={(): undefined => {
                                setActiveUnit(null);
                                setIsGraveActive(true);
                            }}
                        />
                        <UiButton
                            iconSrc={mapEditorImage.eraser.src}
                            isActive={activeUnit === null && !isGraveActive}
                            isSquared
                            onClick={(): undefined => {
                                setActiveUnit(null);
                                setIsGraveActive(false);
                            }}
                        />
                    </div>
                </div>
            </IsRender>
        </div>
    );
}
