import {makeRange} from "../../../util/array";
import type {SizeType} from "../../map/map-type";
import {buildingArmor} from "../building/building-const";
import {getBuildingByPoint} from "../building/building-helper";
import type {GameBuildingType} from "../building/building-type";
import {GamePlayerIdEnum} from "../player/player-type";
import type {PointType} from "../point/point-type";
import {getUnitInfoByUnit} from "../unit/unit-helper";
import {GameUnitMoveTypeEnum, type GameUnitType} from "../unit/unit-type";
import {landscapeArmorCostMap, waterLandscapeList} from "./landscape-const";
import {
    defaultLandscapeTheme,
    GameLandscapeItemEnum,
    GameLandscapeThemeEnum,
    type GameLandscapeThemeMapType,
    type GameLandscapeType,
} from "./landscape-type";

export function getLandscapeSize(landscape: GameLandscapeType): SizeType {
    const height: number = Math.max(landscape.length, 1);
    const width: number = Math.max(landscape.at(0)?.length ?? 0, 1);

    return {height, width};
}

export function getLandscapePointList(landscape: GameLandscapeType): Array<PointType> {
    const pointList: Array<PointType> = [];
    const mapSize: SizeType = getLandscapeSize(landscape);

    makeRange(mapSize.height).forEach((y: number) => {
        makeRange(mapSize.width).forEach((x: number) => {
            pointList.push({x, y});
        });
    });

    return pointList;
}

export function getLandscapeInLine(landscape: GameLandscapeType): Array<GameLandscapeItemEnum> {
    return landscape.flat();
}

export function getLandscapeByPoint(point: PointType, landscape: GameLandscapeType): GameLandscapeItemEnum | null {
    const {x, y} = point;

    if (x < 0 || y < 0) {
        return null;
    }

    return landscape.at(y)?.at(x) ?? null;
}

export function getTileTheme(
    point: PointType,
    landscapeThemeMap: GameLandscapeThemeMapType | undefined
): GameLandscapeThemeEnum {
    const {x, y} = point;

    if (!landscapeThemeMap || x < 0 || y < 0) {
        return defaultLandscapeTheme;
    }

    return landscapeThemeMap.at(y)?.at(x) ?? defaultLandscapeTheme;
}

// Builds a theme grid matching the landscape dimensions, filling any missing cell with the default (ae2) theme.
export function normalizeLandscapeThemeMap(
    landscape: GameLandscapeType,
    landscapeThemeMap: GameLandscapeThemeMapType | undefined
): GameLandscapeThemeMapType {
    const {width, height} = getLandscapeSize(landscape);

    return makeRange(height).map((y: number): Array<GameLandscapeThemeEnum> => {
        return makeRange(width).map((x: number): GameLandscapeThemeEnum => {
            return getTileTheme({x, y}, landscapeThemeMap);
        });
    });
}

export function getIsAllDefaultLandscapeTheme(landscapeThemeMap: GameLandscapeThemeMapType | undefined): boolean {
    if (!landscapeThemeMap) {
        return true;
    }

    return landscapeThemeMap.every((themeRow: Array<GameLandscapeThemeEnum>): boolean => {
        return themeRow.every((theme: GameLandscapeThemeEnum): boolean => {
            return theme === defaultLandscapeTheme;
        });
    });
}

// Resolves the theme actually used to draw a tile: the forced override when set, otherwise the tile's own theme.
export function getEffectiveTileTheme(
    point: PointType,
    landscapeThemeMap: GameLandscapeThemeMapType | undefined,
    themeOverride: GameLandscapeThemeEnum | null
): GameLandscapeThemeEnum {
    return themeOverride ?? getTileTheme(point, landscapeThemeMap);
}

export function getIsWaterLandscape(landscapeItem: GameLandscapeItemEnum): boolean {
    return waterLandscapeList.includes(landscapeItem);
}

export function getIsDynamicWater(landscapeItem: GameLandscapeItemEnum, theme: GameLandscapeThemeEnum | null): boolean {
    const isAe1Theme = theme === GameLandscapeThemeEnum.ae1;

    if (isAe1Theme && getIsWaterLandscape(landscapeItem)) {
        return true;
    }

    return landscapeItem === GameLandscapeItemEnum.wt1 || landscapeItem === GameLandscapeItemEnum.wt2;
}

export function getWalkSquareArmorByPoint(
    point: PointType,
    landscape: GameLandscapeType,
    buildingList: Array<GameBuildingType>
): number {
    const {x, y} = point;
    const building: GameBuildingType | null = getBuildingByPoint(point, buildingList);

    if (building) {
        return buildingArmor;
    }

    const squareType: GameLandscapeItemEnum | null = getLandscapeByPoint({x, y}, landscape);

    // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
    if (!squareType) {
        return 0;
    }

    return landscapeArmorCostMap[GameUnitMoveTypeEnum.walk][squareType];
}

export function getUnitBonusArmorByMoveType(
    unit: GameUnitType,
    landscape: GameLandscapeType,
    buildingList: Array<GameBuildingType>
): number {
    const {x, y} = unit;
    const unitInfo = getUnitInfoByUnit(unit);
    const {moveType} = unitInfo;

    const building: GameBuildingType | null = getBuildingByPoint({x, y}, buildingList);

    if (building) {
        return buildingArmor;
    }

    const squareType: GameLandscapeItemEnum | null = getLandscapeByPoint({x, y}, landscape);

    // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
    if (!squareType) {
        return 0;
    }

    return landscapeArmorCostMap[moveType][squareType];
}

export function getLandscapeCenter(landscape: GameLandscapeType): PointType {
    const mapSize: SizeType = getLandscapeSize(landscape);

    return {
        x: Math.round((mapSize.width - 1) / 2),
        y: Math.round((mapSize.height - 1) / 2),
    };
}

export function getHeroPoint(unitList: Array<GameUnitType>): PointType | null {
    const hero = unitList.find<GameUnitType>((checkForHero: GameUnitType): checkForHero is GameUnitType => {
        return checkForHero.gamePlayerId === GamePlayerIdEnum.player1 && getUnitInfoByUnit(checkForHero).isHero;
    });

    return hero ? {x: hero.x, y: hero.y} : null;
}
