/* global document, HTMLDivElement */
import {type JSX, type ReactNode, type RefObject, useEffect, useImperativeHandle, useRef, useState} from "react";

import {squareSize} from "../../../../css/style";
import {useGesture} from "../../../../hook/use-gesture/use-gesture";
import type {UseGestureConfigStateType, UseGestureHookType} from "../../../../hook/use-gesture/use-gesture-type";
import {useGameContext} from "../../../../provider/game/game-context";
import {cls} from "../../../../util/css";
import * as clientGameViewContainerStyle from "./client-game-view-container.scss";
import {defaultGestureState} from "./client-game-view-container-const";
import {getGestureState, saveGestureState} from "./client-game-view-container-helper";

interface ClientGameViewContainerPropsType {
    readonly children: ReactNode;

    readonly className?: string;
    readonly useGestureRef: RefObject<UseGestureHookType | null>;
}

export function ClientGameViewContainer(props: ClientGameViewContainerPropsType): JSX.Element {
    const {children, className, useGestureRef} = props;
    const {mapSize} = useGameContext();
    const wrapperDivRef: RefObject<HTMLDivElement> = useRef<HTMLDivElement>(document.createElement("div"));
    const childDivRef: RefObject<HTMLDivElement> = useRef<HTMLDivElement>(document.createElement("div"));
    const [defaultStateGestureState] = useState<UseGestureConfigStateType>((): UseGestureConfigStateType => {
        return {
            ...getGestureState(),
            x: defaultGestureState.x,
            y: defaultGestureState.y,
        };
    });

    const gestureApi: UseGestureHookType = useGesture({
        childRef: childDivRef,
        defaultState: defaultStateGestureState,
        limit: {
            multiplier: 0.2,
            point: {
                max: {
                    x: 0,
                    y: 0,
                },
                min: {
                    x: 0,
                    y: 0,
                },
            },
            zoom: {max: 4, min: 1},
        },
        wrapperRef: wrapperDivRef,
    });

    const {currentState} = gestureApi;

    useImperativeHandle(useGestureRef, (): UseGestureHookType => {
        return gestureApi;
    }, [gestureApi]);

    useEffect(() => {
        if (currentState.zoom !== getGestureState().zoom) {
            saveGestureState(currentState);
        }
    }, [currentState]);

    return (
        <div className={cls(clientGameViewContainerStyle.client_game_view_container, className)} ref={wrapperDivRef}>
            <div className={clientGameViewContainerStyle.client_game_view_container__animated_div} ref={childDivRef}>
                <div
                    className={clientGameViewContainerStyle.child_wrapper}
                    style={{height: `${mapSize.height * squareSize}px`, width: `${mapSize.width * squareSize}px`}}
                >
                    {children}
                </div>
            </div>
        </div>
    );
}
