/* global HTMLSelectElement */
/* eslint-disable react/jsx-max-depth */

import {type JSX, useCallback, useEffect, useMemo, useState} from "react";
import {useNavigate, useParams} from "react-router-dom";

import {appRoute} from "../../../app/app-route";
import {LandscapeThemeSetting} from "../../../layout/landscape-theme-setting/landscape-theme-setting";
import {Page} from "../../../layout/page/page";
import {PageContent} from "../../../layout/page/page-content/page-content";
import {PageFooter} from "../../../layout/page/page-footer/page-footer";
import {PageHeader} from "../../../layout/page/page-header/page-header";
import {SpoilerContent} from "../../../layout/spoiler/spoiler-content";
import {uiButtonImage} from "../../../layout/ui-button/image/ui-button-image";
import {UiButton} from "../../../layout/ui-button/ui-button";
import {usePlayTitleTheme} from "../../../media/play-media";
import {type GameBuildingType, GameBuildingTypeEnum} from "../../../model/game/building/building-type";
import {defaultBuildingSettings, defaultStartedMoney} from "../../../model/game/game-const";
import type {BuildingGameSettingsType} from "../../../model/game/game-type";
import {getLandscapeSize} from "../../../model/game/landscape/landscape-helper";
import {
    getIsNotNonePlayer,
    getPlayerByPlayerId,
    getPlayerMaxUnitHealth,
} from "../../../model/game/player/player-helper";
import {GamePlayerIdEnum, type GamePlayerType} from "../../../model/game/player/player-type";
import {commanderUnitTypeList} from "../../../model/game/unit/unit-const";
import {getUnitInfoByUnit} from "../../../model/game/unit/unit-helper";
import type {GameUnitType} from "../../../model/game/unit/unit-type";
import {extractPlayerListByMap, getMapById, getMaxPlayerByMap} from "../../../model/map/map-helper";
import type {GameMapType} from "../../../model/map/map-type";
import {useGameContext} from "../../../provider/game/game-context";
import {defaultStepCount} from "../../../provider/game/game-context-helper";
import {useLocale} from "../../../provider/locale/locale-context";
import {testId} from "../../../test-id";
import {throwError} from "../../../util/error";
import type {ExtractPathKeysType} from "../../../util/url";
import * as clientSkirmishMapItemStyle from "../client-skirmish/client-skirmish-map-item/client-skirmish-map-item.scss";
import {ClientSkirmishMapPreview} from "../client-skirmish/client-skirmish-map-preview/client-skirmish-map-preview";
import * as clientLocalGameSetupStyle from "./client-local-game-setup.scss";
import {ClientLocalGameSetupBuildingRow} from "./client-local-game-setup-building/client-local-game-setup-building-row";
import {ClientLocalGameSetupPlayer} from "./client-local-game-setup-player/client-local-game-setup-player";

export function ClientLocalGameSetup(): JSX.Element {
    const {setGameState, resetState} = useGameContext();
    const navigate = useNavigate();
    const {getLocalizedString} = useLocale();
    const {mapId = ""} = useParams<ExtractPathKeysType<typeof appRoute.setupMap.path>>();
    const gameMap: GameMapType | null = getMapById(mapId);
    const [playerList, setPlayerList] = useState<Array<GamePlayerType>>(gameMap ? extractPlayerListByMap(gameMap) : []);
    const [buildingSettings, setBuildingSettings] =
        useState<Record<GameBuildingTypeEnum, BuildingGameSettingsType>>(defaultBuildingSettings);
    const [isShowMap, setIsShowMap] = useState<boolean>(false);
    const mapSize = getLandscapeSize(gameMap?.landscape ?? [[]]);

    usePlayTitleTheme();

    useEffect(resetState, [resetState]);

    const playerIdList: Array<GamePlayerIdEnum> = useMemo<Array<GamePlayerIdEnum>>(() => {
        return playerList
            .filter<GamePlayerType>(getIsNotNonePlayer)
            .map<GamePlayerIdEnum>((player: GamePlayerType): GamePlayerIdEnum => {
                return player.gamePlayerId;
            });
    }, [playerList]);

    const handleBuildingSettingChange = useCallback(
        (buildingType: GameBuildingTypeEnum, buildingSetting: BuildingGameSettingsType): void => {
            setBuildingSettings(
                (
                    currentSettings: Record<GameBuildingTypeEnum, BuildingGameSettingsType>
                ): Record<GameBuildingTypeEnum, BuildingGameSettingsType> => {
                    return {...currentSettings, [buildingType]: buildingSetting};
                }
            );
        },
        [setBuildingSettings]
    );

    const handleStartGame = useCallback(() => {
        if (!gameMap) {
            console.error(`can not find map by id: ${mapId}`);
            return;
        }

        const firstPlayerId: GamePlayerIdEnum | undefined = playerIdList.at(0);

        // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
        if (!firstPlayerId) {
            console.error("can not get first player id");
            return;
        }

        setGameState({
            activeGamePlayerId: firstPlayerId,
            buildingList: gameMap.buildingList.map<GameBuildingType>((building: GameBuildingType): GameBuildingType => {
                if (playerIdList.includes(building.gamePlayerId)) {
                    return building;
                }
                return {
                    ...building,
                    gamePlayerId: GamePlayerIdEnum.playerEmpty,
                };
            }),
            cemetery: gameMap.cemetery,
            // TODO: check only local player (not actual because all players are local)
            clientGamePlayerIdList: playerList
                .filter<GamePlayerType>(getIsNotNonePlayer)
                .map<GamePlayerIdEnum>((player: GamePlayerType): GamePlayerIdEnum => {
                    return player.gamePlayerId;
                }),
            doneTriggerIsList: [],
            gameSettings: {
                buildingSettings,
            },
            graveList: gameMap.graveList,
            landscape: gameMap.landscape,
            landscapeThemeMap: gameMap.landscapeThemeMap,
            mapId: gameMap.mapId,
            playerList: playerList
                .filter<GamePlayerType>(getIsNotNonePlayer)
                .map<GamePlayerType>((playerInList: GamePlayerType): GamePlayerType => {
                    return {
                        ...playerInList,
                        // money === 0 means the player never touched the select (the initial value from
                        // defaultPlayerData), so we fall back to the default. There is no 0 option in the
                        // money select, so a real choice is never overwritten.
                        // const startedMoneyList: Readonly<Array<number>> = [defaultStartedMoney, 1e3, 2e3, 5e3, 10e3, 25e3] as const;
                        money: playerInList.money || defaultStartedMoney,
                    };
                }),
            stepCount: defaultStepCount,
            telefragList: [],
            unitList: gameMap.unitList
                .filter<GameUnitType>((unit: GameUnitType): unit is GameUnitType => {
                    return playerIdList.includes(unit.gamePlayerId);
                })
                .map<GameUnitType>((unit: GameUnitType): GameUnitType => {
                    const owner: GamePlayerType | null = getPlayerByPlayerId(unit.gamePlayerId, playerList);
                    // Apply the commander chosen on the setup screen, but only to interchangeable
                    // commanders (not objective-only heroes such as the crystal).
                    const isSelectableCommander =
                        getUnitInfoByUnit(unit).isHero && commanderUnitTypeList.includes(unit.unitType);
                    const commanderOverride: GameUnitType["unitType"] | null = owner?.commanderUnitType ?? null;
                    const unitType =
                        isSelectableCommander && commanderOverride !== null ? commanderOverride : unit.unitType;

                    return {
                        ...unit,
                        health: Math.min(unit.health, getPlayerMaxUnitHealth(unit.gamePlayerId, playerList)),
                        unitType,
                    };
                }),
        });
        navigate(appRoute.clientGame.path)?.catch(throwError);
    }, [playerIdList, mapId, playerList, setGameState, navigate, gameMap, buildingSettings]);

    if (!gameMap) {
        return (
            <Page>
                <PageHeader langKey="UI__BUTTON__SKIRMISH" />
                <PageContent hasBorder>NO MAP</PageContent>
            </Page>
        );
    }

    return (
        <Page>
            <PageHeader langKey="UI__BUTTON__SKIRMISH" />

            <PageContent hasBorder>
                <div className={clientLocalGameSetupStyle.client_local_game_setup__content}>
                    <div>
                        <div className={clientLocalGameSetupStyle.client_local_game_setup__header}>
                            <h3 className={clientLocalGameSetupStyle.client_local_game_setup__map_name}>
                                {getLocalizedString(gameMap.mapNameLangKey).trim() || gameMap.mapName}
                            </h3>
                            <UiButton
                                iconSrc={uiButtonImage.earth.src}
                                isSquared
                                onClick={(): undefined => {
                                    setIsShowMap(!isShowMap);
                                }}
                            >
                                {mapSize.width}&times;{mapSize.height}
                            </UiButton>
                        </div>

                        <SpoilerContent isOpen={isShowMap}>
                            <div className={clientSkirmishMapItemStyle.client_skirmish_map_item__map_preview_wrapper}>
                                <div className={clientSkirmishMapItemStyle.client_skirmish_map_item__map_preview}>
                                    <ClientSkirmishMapPreview isShow={isShowMap} map={gameMap} />
                                </div>
                            </div>
                        </SpoilerContent>
                    </div>
                    {playerList
                        .slice(0, getMaxPlayerByMap(gameMap))
                        .map<JSX.Element>((playerInList: GamePlayerType): JSX.Element => {
                            return (
                                <ClientLocalGameSetupPlayer
                                    key={playerInList.gamePlayerId}
                                    mapId={mapId}
                                    player={playerInList}
                                    setPlayerList={setPlayerList}
                                />
                            );
                        })}
                    <table className={clientLocalGameSetupStyle.client_local_game_setup__table}>
                        <thead>
                            <tr>
                                <th>&nbsp;</th>
                                <th>
                                    <p className={clientLocalGameSetupStyle.client_local_game_setup__item_label__right}>
                                        {getLocalizedString("SETUP_SKIRMISH__HEAL")}
                                    </p>
                                </th>
                                <th>
                                    <p className={clientLocalGameSetupStyle.client_local_game_setup__item_label__right}>
                                        {getLocalizedString("SETUP_SKIRMISH__MONEY")}
                                    </p>
                                </th>
                            </tr>
                        </thead>
                        <tbody>
                            {Object.values(GameBuildingTypeEnum).map<JSX.Element>(
                                (buildingType: GameBuildingTypeEnum) => {
                                    return (
                                        <ClientLocalGameSetupBuildingRow
                                            buildingType={buildingType}
                                            key={buildingType}
                                            onChange={handleBuildingSettingChange}
                                            setting={buildingSettings[buildingType]}
                                        />
                                    );
                                }
                            )}
                        </tbody>
                    </table>

                    <div className={clientLocalGameSetupStyle.client_local_game_setup__landscape_theme_setting}>
                        <LandscapeThemeSetting
                            titleClassName={clientLocalGameSetupStyle.client_local_game_setup__item_label}
                        />
                    </div>
                </div>
            </PageContent>

            <PageFooter className={clientLocalGameSetupStyle.client_local_game_setup__footer}>
                <UiButton
                    dataTestId={testId.setupPage.fightButton}
                    iconSrc={uiButtonImage.sword.src}
                    isDisabled={playerIdList.length < 2}
                    langKey="SETUP_SKIRMISH__FIGHT"
                    onClick={handleStartGame}
                />
            </PageFooter>
        </Page>
    );
}
