import type {JSX} from "react";

import type {GameUnitType} from "../../../../model/game/unit/unit-type";
import {useGameContext} from "../../../../provider/game/game-context";
import * as clientGameUnitStyle from "./client-game-unit.scss";
import {ClientGameUnitItem} from "./client-game-unit-item/client-game-unit-item";

interface ClientGameUnitPropsType {
    readonly isMapEditor: boolean;
}

export function ClientGameUnit(props: ClientGameUnitPropsType): JSX.Element {
    const {isMapEditor} = props;
    const {gameState} = useGameContext();
    const {unitList} = gameState;

    return (
        <div className={clientGameUnitStyle.unit_layer}>
            {unitList.map((unit: GameUnitType): JSX.Element => {
                return <ClientGameUnitItem isMapEditor={isMapEditor} key={unit.unitId} unit={unit} />;
            })}
        </div>
    );
}
