/*
 * The bot's shopping brain: what unit to buy next (getRecommendedToBuyUnitType) and the full buy
 * action with its store choice and the dead-hero re-buy rules (getBuyUnitMovedAction). Split out of
 * bot-rate.ts, which keeps the move / attack rating; both sides read the live coefficients through
 * getBotRateConfig, so tournament overrides reach the buy logic too.
 */
import {getCanOpenStoreByPoint, getUnitPriceList} from "../../../page/client/client-game/unit-store/unit-store-helper";
import type {UnitPriceItemType} from "../../../page/client/client-game/unit-store/unit-store-type";
import {GameActionTypeEnum, type MovedGameActionType} from "../../../provider/game/game-context-type";
import type {BotDifficultEnum} from "../../../provider/setting/setting-type";
import {getMinInList} from "../../../util/array";
import {getPseudoRandomNumber} from "../../../util/number";
import {getHash, getRandomStringWithPrefix} from "../../../util/string";
import {getAvailableToBuyUnitList, getMapById} from "../../map/map-helper";
import type {GameMapType} from "../../map/map-type";
import {type GameBuildingType, GameBuildingTypeEnum} from "../building/building-type";
import type {GameStateType} from "../game-type";
import {
    getIsWaterLandscape,
    getLandscapeCenter,
    getLandscapeInLine,
    getLandscapePointList,
} from "../landscape/landscape-helper";
import type {GameLandscapeItemEnum, GameLandscapeType} from "../landscape/landscape-type";
import {
    getEnemyUnitListByPlayerId,
    getEnemyUnitOnBuildingListByPlayerId,
    getPlayerByPlayerId,
    getPlayerUnitLimit,
    getTeamIdByPlayerId,
} from "../player/player-helper";
import {GamePlayerIdEnum, type GamePlayerTeamIdEnum, type GamePlayerType} from "../player/player-type";
import {getStepsBetweenPoints} from "../point/point-helper";
import type {PointType} from "../point/point-type";
import {availableToBuyUnitTypeList, defaultUnitData} from "../unit/unit-const";
import {getUnitInfoByType, getUnitInfoByUnit, getUnitListByPlayerId} from "../unit/unit-helper";
import {GameUnitMoveTypeEnum, type GameUnitType, GameUnitTypeEnum} from "../unit/unit-type";
import {getBotDifficultMap, getBotPathDistance, getSeedFromNumberList, getStringCharSum} from "./bot-helper";
import {getBotRateConfig} from "./bot-rate-config";

const {buyUnit} = GameActionTypeEnum;

// Minimal count of cheap occupier soldiers to keep, by bot difficulty.
function getMinSoldierNeededCount(botDifficult?: BotDifficultEnum): number {
    const {isBotNormal, isBotEasy} = getBotDifficultMap(botDifficult);

    if (isBotEasy) {
        return getBotRateConfig().minSoldierNeededCount.easy;
    }

    if (isBotNormal) {
        return getBotRateConfig().minSoldierNeededCount.normal;
    }

    return getBotRateConfig().minSoldierNeededCount.hard;
}

// Base chance to bank gold instead of buying a growth unit, by bot difficulty.
function getSaveGoldBaseChance(botDifficult?: BotDifficultEnum): number {
    const {isBotNormal, isBotEasy} = getBotDifficultMap(botDifficult);

    if (isBotEasy) {
        return getBotRateConfig().saveGoldBaseChance.easy;
    }

    if (isBotNormal) {
        return getBotRateConfig().saveGoldBaseChance.normal;
    }

    return getBotRateConfig().saveGoldBaseChance.hard;
}

export function getCanBuyUnitFloatMoveType(landscape: GameLandscapeType): boolean {
    const landscapeSquareList: Array<GameLandscapeItemEnum> = getLandscapeInLine(landscape);
    const floatSquareCount: number = landscapeSquareList.reduce<number>(
        (waterCount: number, landscapeItem: GameLandscapeItemEnum): number => {
            if (getIsWaterLandscape(landscapeItem)) {
                return waterCount + 1;
            }

            return waterCount;
        },
        0
    );

    return floatSquareCount / landscapeSquareList.length >= getBotRateConfig().minimumWaterOnMapPart;
}

function getPlayerUnitTypeCount(playerUnitList: Array<GameUnitType>, unitType: GameUnitTypeEnum): number {
    return playerUnitList.filter((unitInList: GameUnitType): boolean => {
        return unitInList.unitType === unitType;
    }).length;
}

function makeUnitToBuy(unitType: GameUnitTypeEnum): UnitPriceItemType {
    return {
        cost: getUnitInfoByType(unitType).cost,
        isHero: false,
        unitId: getRandomStringWithPrefix(unitType),
        unitType,
    };
}

interface BuyContextType {
    availableUnitTypeList: Array<GameUnitTypeEnum>;
    landscape: GameLandscapeType;
    money: number;
}

// A unit type is buyable when the map allows it, the bot can afford it, and it is not a float unit on
// a map with too little water to make one worthwhile.
function getIsUnitTypeBuyable(unitType: GameUnitTypeEnum, buyContext: BuyContextType): boolean {
    const {money, availableUnitTypeList, landscape} = buyContext;

    if (!availableUnitTypeList.includes(unitType)) {
        return false;
    }

    const unitInfo = getUnitInfoByType(unitType);

    if (unitInfo.cost > money) {
        return false;
    }

    return !(unitInfo.moveType === GameUnitMoveTypeEnum.float && !getCanBuyUnitFloatMoveType(landscape));
}

// Number of farms the given team currently holds (its gold income, hence how much it can afford to wait
// and save for a stronger unit instead of spending on cheap ones right away).
function getTeamFarmCount(
    buildingList: Array<GameBuildingType>,
    teamId: GamePlayerTeamIdEnum,
    playerList: Array<GamePlayerType>
): number {
    return buildingList.reduce<number>((count: number, building: GameBuildingType): number => {
        const isTeamFarm: boolean =
            building.buildingType === GameBuildingTypeEnum.farm &&
            building.gamePlayerId !== GamePlayerIdEnum.playerEmpty &&
            getTeamIdByPlayerId(building.gamePlayerId, playerList) === teamId;

        return count + (isTeamFarm ? 1 : 0);
    }, 0);
}

// Seed the pseudo-random buy pick from the current board: it shifts turn to turn (stepCount, gold,
// army and building counts) and differs per bot (active player id), yet is reproducible for a given state.
function getBuyDecisionSeed(gameState: GameStateType): number {
    const {stepCount, activeGamePlayerId, unitList, buildingList, playerList} = gameState;
    const activePlayer: GamePlayerType | null = getPlayerByPlayerId(activeGamePlayerId, playerList);
    const money: number = activePlayer?.money ?? 0;

    return getSeedFromNumberList([
        stepCount,
        unitList.length,
        buildingList.length,
        money,
        getStringCharSum(activeGamePlayerId),
    ]);
}

// Seed for the save-or-spend decision. Deliberately built ONLY from turn-stable inputs (turn number and
// player id): the board changes after every single bot action inside a turn, and a per-state seed would
// re-roll "do I bank my gold this turn?" again and again until it eventually lands on "spend" — killing
// the whole point of saving. One seed per turn makes the decision stick for the entire turn.
function getSaveGoldDecisionSeed(gameState: GameStateType): number {
    return getSeedFromNumberList([gameState.stepCount, getStringCharSum(gameState.activeGamePlayerId)]);
}

// Bias a [0, 1) draw toward the front of a cost-sorted (strongest-first) list: the strongest unit is the
// likeliest pick, but cheaper ones still come up, so the bot grows a varied yet sensible army.
function getBiasedRandomIndex(count: number, randomValue: number): number {
    if (count <= 1) {
        return 0;
    }

    return Math.min(count - 1, Math.floor(randomValue * randomValue * count));
}

// Pick one unit type from a list, biased toward the strongest (cost-sorted, see getBiasedRandomIndex) but
// with real variety, reproducibly from the passed draw.
function pickBiasedBuyType(unitTypeList: Array<GameUnitTypeEnum>, buyRandomValue: number): UnitPriceItemType {
    const sortedTypeList: Array<GameUnitTypeEnum> = [...unitTypeList].sort(
        (typeA: GameUnitTypeEnum, typeB: GameUnitTypeEnum): number => {
            return getUnitInfoByType(typeB).cost - getUnitInfoByType(typeA).cost;
        }
    );

    const pickIndex: number = getBiasedRandomIndex(sortedTypeList.length, buyRandomValue);

    return makeUnitToBuy(sortedTypeList[pickIndex] ?? GameUnitTypeEnum.soldier);
}

/*
 * What the bot should buy next, given its gold and the enemy army. Two always-bought tiers followed by a
 * randomised growth tier:
 *
 * A. essential bootstrap — a minimal melee line of soldiers (the configured minimum), so the bot never
 *    starts a game empty-handed;
 * B. counters (situational, always worth it) — archers to dislodge enemies sitting on buildings AND answer
 *    flyers, a wisp per two enemy skeletons, one catapult if the enemy holds farms it can raze;
 * C. growth — expand the soldier / archer line toward a farm-scaled target OR splurge on a stronger unit.
 *    This tier is where cheap-unit spam used to come from, so it is deliberately not automatic: the bot
 *    may instead bank its gold this turn (chance scales with the farms its team owns), and when it does
 *    buy, a state-seeded pseudo-random draw picks among the affordable candidates — biased toward the
 *    strongest but with real variety — instead of always grabbing the single strongest.
 * D. fallback — if tier C has no preferred candidate (line targets met, nothing stronger affordable) AND
 *    no stronger unit is even available to save for (e.g. the game settings restrict the shop to a unit
 *    the bot already has enough of), spend the idle gold on the best affordable allowed unit rather than
 *    banking it forever.
 *
 * Two independent draws, both reproducible; tests pass explicit values to force a branch:
 *   - `saveGoldRandomValue` decides save-vs-spend and is seeded per TURN (see getSaveGoldDecisionSeed),
 *     so the bot cannot re-roll its way out of a "save this turn" decision as the board shifts;
 *   - `buyRandomValue` picks the growth unit and is seeded from the full board state, so what it buys
 *     still varies action to action.
 */
// eslint-disable-next-line max-statements, complexity, @typescript-eslint/max-params
export function getRecommendedToBuyUnitType(
    gameState: GameStateType,
    buyRandomValue: number = getPseudoRandomNumber(getBuyDecisionSeed(gameState)),
    saveGoldRandomValue: number = getPseudoRandomNumber(getSaveGoldDecisionSeed(gameState)),
    botDifficult?: BotDifficultEnum
): UnitPriceItemType | null {
    const {activeGamePlayerId, playerList, unitList, buildingList, graveList, mapId, landscape} = gameState;
    const activePlayer: GamePlayerType | null = getPlayerByPlayerId(activeGamePlayerId, playerList);

    if (!activePlayer) {
        console.error(`can not get player by id: ${activeGamePlayerId}`);
        return null;
    }

    const map: GameMapType | null = getMapById(mapId);
    const availableToBuyUnitByMapList: Array<GameUnitTypeEnum> = getAvailableToBuyUnitList({
        byDefault: availableToBuyUnitTypeList,
        byMap: map?.availableToBuyUnitList,
        byPlayer: activePlayer.availableToBuyUnitList,
    });
    const {money} = activePlayer;
    const unitLimit: number = getPlayerUnitLimit(activeGamePlayerId, playerList);
    const playerUnitList: Array<GameUnitType> = getUnitListByPlayerId(activeGamePlayerId, unitList);
    const buyContext: BuyContextType = {availableUnitTypeList: availableToBuyUnitByMapList, landscape, money};
    const activeTeamId: GamePlayerTeamIdEnum = getTeamIdByPlayerId(activeGamePlayerId, playerList);

    // --- tier A: essential bootstrap (always bought, never saved past) ---
    const soldierCount: number = getPlayerUnitTypeCount(playerUnitList, GameUnitTypeEnum.soldier);
    const minSoldierNeededCount: number = getMinSoldierNeededCount(botDifficult);

    if (soldierCount < minSoldierNeededCount && getIsUnitTypeBuyable(GameUnitTypeEnum.soldier, buyContext)) {
        return makeUnitToBuy(GameUnitTypeEnum.soldier);
    }

    // --- tier B: counters (always bought — situational and worth it) ---
    const enemyUnitList: Array<GameUnitType> = getEnemyUnitListByPlayerId(activeGamePlayerId, playerList, unitList);
    const enemyOnBuildingList: Array<GameUnitType> = getEnemyUnitOnBuildingListByPlayerId(
        activeGamePlayerId,
        playerList,
        unitList,
        buildingList
    );
    const enemyFlyingCount: number = enemyUnitList.filter((enemyUnit: GameUnitType): boolean => {
        return getUnitInfoByUnit(enemyUnit).moveType === GameUnitMoveTypeEnum.fly;
    }).length;

    // essential ranged floor plus one archer per two enemies on buildings and per two flyers.
    const counterArcherCount: number =
        minSoldierNeededCount + Math.ceil(enemyOnBuildingList.length / 2) + Math.ceil(enemyFlyingCount / 2);

    if (
        getPlayerUnitTypeCount(playerUnitList, GameUnitTypeEnum.archer) < counterArcherCount &&
        getIsUnitTypeBuyable(GameUnitTypeEnum.archer, buyContext)
    ) {
        return makeUnitToBuy(GameUnitTypeEnum.archer);
    }

    const enemySkeletonCount: number = enemyUnitList.filter((enemyUnit: GameUnitType): boolean => {
        return enemyUnit.unitType === GameUnitTypeEnum.skeleton;
    }).length;

    if (
        enemySkeletonCount > 0 &&
        getPlayerUnitTypeCount(playerUnitList, GameUnitTypeEnum.wisp) < Math.ceil(enemySkeletonCount / 2) &&
        getIsUnitTypeBuyable(GameUnitTypeEnum.wisp, buyContext)
    ) {
        return makeUnitToBuy(GameUnitTypeEnum.wisp);
    }

    // A battlefield full of graves is free skeletons waiting for a sorceress: keep one sorceress per
    // graveCountPerSorceress graves currently on the board (graves expire, so the target follows the fight).
    const sorceressTargetCount: number = Math.floor(graveList.length / getBotRateConfig().graveCountPerSorceress);

    if (
        getPlayerUnitTypeCount(playerUnitList, GameUnitTypeEnum.sorceress) < sorceressTargetCount &&
        getIsUnitTypeBuyable(GameUnitTypeEnum.sorceress, buyContext)
    ) {
        return makeUnitToBuy(GameUnitTypeEnum.sorceress);
    }

    const enemyFarmCount: number = buildingList.reduce<number>((count: number, building: GameBuildingType): number => {
        const isEnemyFarm: boolean =
            building.buildingType === GameBuildingTypeEnum.farm &&
            building.gamePlayerId !== GamePlayerIdEnum.playerEmpty &&
            getTeamIdByPlayerId(building.gamePlayerId, playerList) !== activeTeamId;

        return count + (isEnemyFarm ? 1 : 0);
    }, 0);

    if (
        enemyFarmCount >= getBotRateConfig().minEnemyFarmCountForCatapult &&
        getPlayerUnitTypeCount(playerUnitList, GameUnitTypeEnum.catapult) === 0 &&
        getIsUnitTypeBuyable(GameUnitTypeEnum.catapult, buyContext)
    ) {
        return makeUnitToBuy(GameUnitTypeEnum.catapult);
    }

    // --- tier C: growth (farm-driven, randomised, may save instead) ---
    const fullFarmCount: number = buildingList.reduce<number>((count: number, building: GameBuildingType): number => {
        return count + (building.buildingType === GameBuildingTypeEnum.farm ? 1 : 0);
    }, 0);

    // Total farms on the map / 3 (capped by the unit limit) is the target basic line the economy can feed.
    const lineTargetCount: number = Math.floor(Math.max(Math.min(fullFarmCount, unitLimit) / 3, minSoldierNeededCount));

    // Candidate growth buys, cost-sorted strongest-first: expand the basic line toward the farm target, then
    // every affordable stronger unit (duplicates allowed, so the bot keeps growing instead of banking forever).
    const growthTypeList: Array<GameUnitTypeEnum> = [];

    if (soldierCount < lineTargetCount && getIsUnitTypeBuyable(GameUnitTypeEnum.soldier, buyContext)) {
        growthTypeList.push(GameUnitTypeEnum.soldier);
    }

    if (
        getPlayerUnitTypeCount(playerUnitList, GameUnitTypeEnum.archer) < lineTargetCount &&
        getIsUnitTypeBuyable(GameUnitTypeEnum.archer, buyContext)
    ) {
        growthTypeList.push(GameUnitTypeEnum.archer);
    }

    availableToBuyUnitByMapList.forEach((unitType: GameUnitTypeEnum) => {
        if (unitType === GameUnitTypeEnum.soldier || unitType === GameUnitTypeEnum.archer) {
            return;
        }

        if (getIsUnitTypeBuyable(unitType, buyContext)) {
            growthTypeList.push(unitType);
        }
    });

    if (growthTypeList.length > 0) {
        // The more farms the bot's own team holds, the more readily it banks gold this turn to save for a
        // bigger unit rather than spamming another cheap one.
        const ownedFarmCount: number = getTeamFarmCount(buildingList, activeTeamId, playerList);
        const saveGoldChance: number = Math.min(
            getSaveGoldBaseChance(botDifficult) + ownedFarmCount * getBotRateConfig().saveGoldChancePerOwnedFarm,
            getBotRateConfig().saveGoldMaxChance
        );

        if (saveGoldRandomValue < saveGoldChance) {
            return null;
        }

        return pickBiasedBuyType(growthTypeList, buyRandomValue);
    }

    // No preferred growth buy left: the soldier / archer line targets are met and every stronger unit is
    // either unavailable or not yet affordable. Banking gold is only worth it when there IS a stronger unit
    // to save for — if the game settings restrict the shop to units the bot has already filled its target of
    // (e.g. soldiers only), saving would idle the gold forever. So when nothing better can ever be bought,
    // spend on the best affordable available unit instead of stalling.
    const hasStrongerToSaveFor: boolean = availableToBuyUnitByMapList.some((unitType: GameUnitTypeEnum): boolean => {
        const unitInfo = getUnitInfoByType(unitType);
        const isFloatBlocked: boolean =
            unitInfo.moveType === GameUnitMoveTypeEnum.float && !getCanBuyUnitFloatMoveType(landscape);

        // A unit worth saving for: allowed on this map, not float-blocked, just not affordable yet.
        return !isFloatBlocked && unitInfo.cost > money;
    });

    if (hasStrongerToSaveFor) {
        return null;
    }

    const affordableTypeList: Array<GameUnitTypeEnum> = availableToBuyUnitByMapList.filter<GameUnitTypeEnum>(
        (unitType: GameUnitTypeEnum): unitType is GameUnitTypeEnum => {
            return getIsUnitTypeBuyable(unitType, buyContext);
        }
    );

    if (affordableTypeList.length === 0) {
        return null;
    }

    return pickBiasedBuyType(affordableTypeList, buyRandomValue);
}

// eslint-disable-next-line max-statements
export function getBuyUnitMovedAction(
    gameState: GameStateType,
    botDifficult?: BotDifficultEnum
): MovedGameActionType | null {
    const {landscape, activeGamePlayerId, playerList, cemetery, unitList} = gameState;
    const playerById = getPlayerByPlayerId(activeGamePlayerId, playerList);

    if (!playerById) {
        console.error(`can not get player by id: ${activeGamePlayerId}`);
        return null;
    }

    const playerUnitList = getUnitListByPlayerId(activeGamePlayerId, unitList);
    const unitLimit: number = getPlayerUnitLimit(activeGamePlayerId, playerList);

    if (playerUnitList.length >= unitLimit) {
        return null;
    }

    const storePointList: Array<PointType> = getLandscapePointList(landscape).filter<PointType>(
        (point: PointType): point is PointType => {
            return getCanOpenStoreByPoint(point, gameState);
        }
    );

    const centerPoint: PointType = getLandscapeCenter(landscape);
    const enemyUnitList: Array<GameUnitType> = getEnemyUnitListByPlayerId(activeGamePlayerId, playerList, unitList);

    // Deploy new units at the store closest to the fight, so reinforcements do not appear in the rear;
    // with no enemies on the board fall back to the store closest to the map centre. "Closest" is the
    // real walking distance of a ground unit — a straight-line pick can sit across a wall or water.
    // Self-play (2026-07): strength-neutral on the open-duel pool (0.500 mirror, no wins flipped,
    // ladder vs NORMAL 0.563), kept for the obstacle maps the pool underrepresents.
    const walkerForPath: GameUnitType = {...defaultUnitData, unitType: GameUnitTypeEnum.soldier};
    const storePoint: PointType | null = getMinInList<PointType>(
        storePointList,
        (storePointInList: PointType): number => {
            const closeEnemyDistance: number | null =
                enemyUnitList.length > 0
                    ? Math.min(
                          ...enemyUnitList.map<number>((enemyUnit: GameUnitType): number => {
                              return getBotPathDistance(
                                  storePointInList,
                                  {x: enemyUnit.x, y: enemyUnit.y},
                                  walkerForPath,
                                  gameState
                              );
                          })
                      )
                    : null;

            return closeEnemyDistance ?? getStepsBetweenPoints(centerPoint, storePointInList);
        }
    );

    if (!storePoint) {
        return null;
    }

    const deadHeroList: Array<UnitPriceItemType> = getUnitPriceList(
        activeGamePlayerId,
        [],
        cemetery
    ).filter<UnitPriceItemType>((unitPriceItem: UnitPriceItemType): unitPriceItem is UnitPriceItemType => {
        return unitPriceItem.isHero;
    });

    const deadCheapHero: UnitPriceItemType | null = getMinInList<UnitPriceItemType>(
        deadHeroList,
        (heroPriceItem: UnitPriceItemType): number => {
            return heroPriceItem.cost;
        }
    );

    if (deadCheapHero) {
        if (playerById.money >= deadCheapHero.cost) {
            return {
                gameAction: {
                    actionType: buyUnit,
                    addUnitList: [],
                    briefing: null,
                    buyUnitType: deadCheapHero.unitType,
                    movePointList: [],
                    toPoint: storePoint,
                    unitCurrentPoint: storePoint,
                    unitId: deadCheapHero.unitId,
                },
                moveFrom: storePoint,
                movePathList: [],
                moveTo: storePoint,
            };
        }
        // if unit count almost reach limit - wait for more money to buy hero
        if (playerUnitList.length >= unitLimit - 3) {
            return null;
        }

        // Hard only: bank for the hero re-buy instead of burning 150 every turn on the tier-A soldier
        // floor — the rebuy spiral feeds the enemy hero XP one soldier at a time while the dead hero
        // (the strongest unit) never returns. Only while an ENEMY hero is alive (it is what farms the
        // soldier stream; with no enemy hero the trickle is harmless and banking just costs tempo),
        // and one emergency soldier is still allowed on an empty line.
        const hasAliveEnemyHero: boolean = getEnemyUnitListByPlayerId(activeGamePlayerId, playerList, unitList).some(
            (enemyUnit: GameUnitType): boolean => {
                return getUnitInfoByUnit(enemyUnit).isHero;
            }
        );

        if (
            getBotDifficultMap(botDifficult).isBotHard &&
            hasAliveEnemyHero &&
            getPlayerUnitTypeCount(playerUnitList, GameUnitTypeEnum.soldier) >= 1
        ) {
            return null;
        }
    }

    const recommendedUnitToBuy: UnitPriceItemType | null = getRecommendedToBuyUnitType(
        gameState,
        getPseudoRandomNumber(getBuyDecisionSeed(gameState)),
        getPseudoRandomNumber(getSaveGoldDecisionSeed(gameState)),
        botDifficult
    );

    if (recommendedUnitToBuy && playerById.money >= recommendedUnitToBuy.cost) {
        // A reproducible id (the goalless-move fallback seeds from the unitId, so a random id here
        // would make self-play games diverge between identical runs). A store CAN sell several units
        // per turn (each one steps aside), so the pre-buy unitList hash disambiguates; the id must
        // NOT hash the whole gameState — clientGamePlayerIdList stores the seating order, which
        // would make ids (and games) depend on who sits where.
        const boughtUnitId: string = [
            recommendedUnitToBuy.unitType,
            activeGamePlayerId,
            `turn-${String(gameState.stepCount)}`,
            `x${String(storePoint.x)}-y${String(storePoint.y)}`,
            getHash(gameState.unitList),
        ].join("-");

        return {
            gameAction: {
                actionType: buyUnit,
                addUnitList: [],
                briefing: null,
                buyUnitType: recommendedUnitToBuy.unitType,
                movePointList: [],
                toPoint: storePoint,
                unitCurrentPoint: storePoint,
                unitId: boughtUnitId,
            },
            moveFrom: storePoint,
            movePathList: [],
            moveTo: storePoint,
        };
    }

    return null;
}
