/* global HTMLImageElement, HTMLSelectElement */

import {type JSX, type SyntheticEvent, useEffect, useMemo, useState} from "react";

import {serviceStyle, squareSize} from "../../css/style";
import {getLandscapeSize} from "../../model/game/landscape/landscape-helper";
import {defaultLandscapeTheme, type GameLandscapeThemeEnum} from "../../model/game/landscape/landscape-type";
import type {SizeType} from "../../model/map/map-type";
import {getMapPreviewCanvas} from "../../page/client/client-game/client-game-landscape/helper/map-preview";
import {getLandscapeImage} from "../../page/client/client-game/client-game-landscape/image/landscape-image";
import {Locale} from "../../provider/locale/locale-context";
import {
    defaultLandscapeThemeOverride,
    landscapeThemeSettingList,
    landscapeThemeSettingValueMap,
} from "../../provider/setting/setting-const";
import {useSettingContext} from "../../provider/setting/setting-context";
import {
    landscapeThemeAsIs,
    type LandscapeThemeSettingItemType,
    type LandscapeThemeSettingType,
    type SettingContextSettingType,
} from "../../provider/setting/setting-type";
import {cls} from "../../util/css";
import {getEnumValueEnsure} from "../../util/enum";
import {landscapeThemeExampleMap} from "./landscape-theme-example-map";
import * as landscapeThemeSettingStyle from "./landscape-theme-setting.scss";

interface LandscapeThemeSettingPropsType {
    readonly isDisabled?: boolean;
    readonly titleClassName?: string;
}

export function LandscapeThemeSetting(props: LandscapeThemeSettingPropsType): JSX.Element {
    const {isDisabled = false, titleClassName = ""} = props;
    const {setting, setSetting} = useSettingContext();

    // The preview mirrors exactly what the select shows: a locked (campaign) select is always "as designed".
    const selectedTheme: LandscapeThemeSettingType = isDisabled ? landscapeThemeAsIs : setting.landscapeThemeOverride;
    const themeOverride: GameLandscapeThemeEnum | null = selectedTheme === landscapeThemeAsIs ? null : selectedTheme;

    const {width, height}: SizeType = getLandscapeSize(landscapeThemeExampleMap.landscape);

    // The landscape canvas is drawn (and cached) synchronously, so on a cold load — before the theme's image
    // atlas has decoded — it would cache a blank tile. Track which theme atlases have decoded and only draw
    // a theme once its atlas is ready (per-theme, so switching themes never caches a blank canvas).
    const [readyThemeSet, setReadyThemeSet] = useState<ReadonlySet<GameLandscapeThemeEnum>>(
        (): ReadonlySet<GameLandscapeThemeEnum> => {
            return new Set<GameLandscapeThemeEnum>();
        }
    );
    const atlasTheme: GameLandscapeThemeEnum = themeOverride ?? defaultLandscapeTheme;
    const isAtlasReady: boolean = readyThemeSet.has(atlasTheme);

    useEffect((): (() => void) => {
        let isCancelled = false;

        if (!isAtlasReady) {
            const imageList: Array<HTMLImageElement> = Object.values(getLandscapeImage(atlasTheme));

            // Each decode is caught individually, so this Promise.all never rejects.
            void Promise.all(
                imageList.map(async (image: HTMLImageElement): Promise<void> => {
                    try {
                        await image.decode();
                    } catch {
                        // A failed/aborted decode must not block the rest of the atlas from rendering.
                    }
                })
            ).then((): void => {
                if (!isCancelled) {
                    setReadyThemeSet(
                        (currentSet: ReadonlySet<GameLandscapeThemeEnum>): ReadonlySet<GameLandscapeThemeEnum> => {
                            return new Set<GameLandscapeThemeEnum>(currentSet).add(atlasTheme);
                        }
                    );
                }
            });
        }

        return (): void => {
            isCancelled = true;
        };
    }, [atlasTheme, isAtlasReady]);

    const previewImage: JSX.Element | null = useMemo<JSX.Element | null>((): JSX.Element | null => {
        if (!isAtlasReady) {
            return null;
        }

        const {landscape, unit, building} = getMapPreviewCanvas(landscapeThemeExampleMap, themeOverride);

        return (
            <>
                <img
                    alt="landscape"
                    className={landscapeThemeSettingStyle.landscape_theme_setting__preview_image}
                    src={landscape}
                />
                <img
                    alt="building"
                    className={landscapeThemeSettingStyle.landscape_theme_setting__preview_image}
                    src={building}
                />
                <img
                    alt="unit"
                    className={landscapeThemeSettingStyle.landscape_theme_setting__preview_image}
                    src={unit}
                />
            </>
        );
    }, [themeOverride, isAtlasReady]);

    return (
        <>
            <label className={serviceStyle.input__select__label}>
                <p className={cls(serviceStyle.input__select__text, titleClassName)}>
                    <Locale stringKey="SETTINGS__LANDSCAPE_THEME" />
                </p>
                <select
                    className={cls(
                        serviceStyle.input__select,
                        landscapeThemeSettingStyle.landscape_theme_setting__select,
                        {
                            [serviceStyle.input__select__disabled]: isDisabled,
                        }
                    )}
                    defaultValue={selectedTheme}
                    disabled={isDisabled}
                    key={selectedTheme}
                    onChange={(evt: SyntheticEvent<HTMLSelectElement>): undefined => {
                        const rawValue: string = evt.currentTarget.value;

                        setSetting((currentSetting: SettingContextSettingType): SettingContextSettingType => {
                            return {
                                ...currentSetting,
                                landscapeThemeOverride: getEnumValueEnsure<LandscapeThemeSettingType>(
                                    landscapeThemeSettingValueMap,
                                    rawValue,
                                    defaultLandscapeThemeOverride
                                ),
                            };
                        });
                    }}
                >
                    {landscapeThemeSettingList.map((themeSettingItem: LandscapeThemeSettingItemType): JSX.Element => {
                        return (
                            <option key={themeSettingItem.value} value={themeSettingItem.value}>
                                <Locale stringKey={themeSettingItem.langKey} />
                            </option>
                        );
                    })}
                </select>
            </label>

            <div className={landscapeThemeSettingStyle.landscape_theme_setting__preview_wrapper}>
                <div className={landscapeThemeSettingStyle.landscape_theme_setting__preview}>
                    <canvas
                        className={landscapeThemeSettingStyle.landscape_theme_setting__preview_image__frame}
                        height={height * squareSize}
                        width={width * squareSize}
                    />
                    {previewImage}
                </div>
            </div>
        </>
    );
}
