import type {GameLandscapeThemeEnum} from "../../../../../model/game/landscape/landscape-type";
import type {GamePlayerType} from "../../../../../model/game/player/player-type";
import {extractPlayerListByMap} from "../../../../../model/map/map-helper";
import type {GameMapType} from "../../../../../model/map/map-type";
import {getBuildingListCanvas} from "./client-game-building-canvas";
import {getLandscapeCanvas} from "./client-game-landscape-canvas";
import {getUnitListCanvas} from "./client-game-unit-canvas";

export function getMapPreviewCanvas(
    map: GameMapType,
    themeOverride: GameLandscapeThemeEnum | null
): Record<"building" | "landscape" | "unit", string> {
    const {landscape, landscapeThemeMap, unitList, buildingList} = map;
    const playerList: Array<GamePlayerType> = extractPlayerListByMap(map);

    return {
        building: getBuildingListCanvas(landscape, playerList, buildingList, landscapeThemeMap, themeOverride),
        landscape: getLandscapeCanvas(landscape, landscapeThemeMap, {themeOverride, useDynamicWater: false}),
        unit: getUnitListCanvas(landscape, playerList, unitList),
    };
}
