/* global HTMLImageElement */
import type {JSX} from "react";

import {SmallText} from "../../../../../layout/game-font/text/small-text";
import {getByPoint} from "../../../../../model/game/game-state/game-state";
import type {PointDataType} from "../../../../../model/game/game-type";
import {getEffectiveTileTheme, getWalkSquareArmorByPoint} from "../../../../../model/game/landscape/landscape-helper";
import {GameLandscapeItemEnum} from "../../../../../model/game/landscape/landscape-type";
import {useGameContext} from "../../../../../provider/game/game-context";
import {resolveLandscapeThemeOverride} from "../../../../../provider/setting/landscape-theme-override-helper";
import {useSettingContext} from "../../../../../provider/setting/setting-context";
import {getBuildingImage} from "../../client-game-building/client-game-building-helper";
import {getLandscapeImage, type LandscapeImageMapType} from "../../client-game-landscape/image/landscape-image";
import * as clientSquareInfoStyle from "./client-square-info.scss";

export function ClientSquareInfo(): JSX.Element {
    const {activePoint, gameState} = useGameContext();
    const {
        setting: {landscapeThemeOverride},
    } = useSettingContext();
    const pointData: PointDataType = getByPoint(activePoint, gameState);
    const {landscapeItem, building} = pointData;
    const armorByPoint: number = getWalkSquareArmorByPoint(activePoint, gameState.landscape, gameState.buildingList);
    const themeOverride = resolveLandscapeThemeOverride(gameState.mapId, landscapeThemeOverride);
    const effectiveTheme = getEffectiveTileTheme(activePoint, gameState.landscapeThemeMap, themeOverride);
    const landscapeImage: LandscapeImageMapType = getLandscapeImage(effectiveTheme);
    const landscapeItemImage: HTMLImageElement =
        // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
        landscapeItem && landscapeItem in landscapeImage
            ? landscapeImage[landscapeItem]
            : landscapeImage[GameLandscapeItemEnum.tr0];

    const buildingImage: HTMLImageElement | null = building
        ? getBuildingImage(building, gameState.playerList, effectiveTheme)
        : null;
    const endImage: HTMLImageElement = buildingImage ?? landscapeItemImage;

    console.log(landscapeItemImage);
    console.log(landscapeItemImage.src);

    return (
        <div className={clientSquareInfoStyle.client_square_info}>
            <div className={clientSquareInfoStyle.client_square_info__border} />
            <img alt="square info" className={clientSquareInfoStyle.client_square_info__image} src={endImage.src} />
            <img
                alt="landscape - terra-0"
                className={clientSquareInfoStyle.client_square_info__image__landscape}
                src={landscapeImage[GameLandscapeItemEnum.tr0].src}
            />
            <img
                alt="landscape - current"
                className={clientSquareInfoStyle.client_square_info__image__landscape}
                src={landscapeItemImage.src}
            />
            <SmallText
                className={clientSquareInfoStyle.client_square_info__armor_text}
                scale={2}
                text={`a${armorByPoint}`}
            />
        </div>
    );
}
