import type {LangKeyType} from "../../../provider/locale/translation/type";
import {type GameUnitTypeEnum, unitRankMap} from "./unit-type";

export const levelUnitData = {
    additionalArmor: 2,
    additionalAttack: 2,
    base: 200,
    experience: {
        destroyBuilding: 60,
    },
    // max: 9,
    min: 0,
} as const;

export interface GameUnitLevelDataType {
    experience: {
        // from: number;
        // part: number;
        // percent: number;
        // size: number;
        to: number;
        value: number;
    };
    level: number;
}

export function getUnitLevelData(
    damageGiven: number,
    maxLevel: number,
    levelBase: number = levelUnitData.base
): GameUnitLevelDataType {
    const experience = damageGiven;

    let experienceTo = 0;

    for (let level = 0; level < maxLevel; level += 1) {
        const experienceFrom = level * levelBase;
        experienceTo = (level + 1) * levelBase;

        if (experience >= experienceFrom && experience < experienceTo) {
            return {
                experience: {
                    // from: experienceFrom,
                    // part: experience - experienceFrom,
                    // percent: ((experience - experienceFrom) / (experienceTo - experienceFrom)) * 100,
                    // size: experienceTo - experienceFrom,
                    to: experienceTo,
                    value: experience,
                },
                level,
            };
        }
    }

    return {
        experience: {
            // from: experienceFrom,
            // part: experience - experienceFrom,
            // percent: ((experience - experienceFrom) / (experienceTo - experienceFrom)) * 100,
            // size: experienceTo - experienceFrom,
            to: experienceTo,
            value: experience,
        },
        level: maxLevel,
    };
}

export function getUnitRank(unitType: GameUnitTypeEnum, level: number, maxLevel: number): LangKeyType {
    const [rank0, rank1, rank2, rank3] = unitRankMap[unitType];
    // Split the [0, maxLevel] range into 4 equal rank bands so ranks scale with the current max level.
    const rankBandSize = Math.max(1, Math.floor(maxLevel / 4));

    if (level >= rankBandSize * 3) {
        return rank3;
    }

    if (level >= rankBandSize * 2) {
        return rank2;
    }

    if (level >= rankBandSize) {
        return rank1;
    }

    return rank0;
}

