/* global HTMLImageElement */

import {type JSX, useEffect, useState} from "react";

import {useSettingContext} from "../../../provider/setting/setting-context";
import {animate, type AnimateCallbackDataType} from "../../../util/animation/animate";
import {easingFunction} from "../../../util/animation/easing-function";
import {cls} from "../../../util/css";
import {fontBigImage} from "../image/font-image";
import * as textStyle from "./text.scss";
import type {TextPropsType} from "./text-type";

type BaseTextPropsType = TextPropsType & {
    fontHeight: number;
    localImageMap: Readonly<Record<string, HTMLImageElement>>;
};

export function Text(props: BaseTextPropsType): JSX.Element {
    const {
        text,
        className,
        scale = 1,
        padStart = [0, ""],
        padEnd = [0, ""],
        animation,
        fontHeight,
        localImageMap,
    } = props;
    const [padEndLength, padEndFillString] = padEnd;
    const [padStartLength, padStartFillString] = padStart;
    const {useAnimate = false, timeMultiply = 1, easing = easingFunction.linear.inOut} = animation ?? {};
    const endNumberPart: number = Number.parseInt(text.toString(10).replace(/[^-\d+]/iu, ""), 10);
    const [animatedNumberPart, setAnimatedNumberPart] = useState<number>(endNumberPart);
    const {
        setting: {
            numberSetting: {animationStepTime},
        },
    } = useSettingContext();

    useEffect(() => {
        if (animatedNumberPart === endNumberPart) {
            return;
        }

        if (!useAnimate) {
            // eslint-disable-next-line react-hooks/set-state-in-effect
            setAnimatedNumberPart(endNumberPart);
            return;
        }

        animate(
            {
                begin: animatedNumberPart,
                easing,
                end: endNumberPart,
                periodMs: animationStepTime * timeMultiply,
            },
            (data: AnimateCallbackDataType): void => {
                setAnimatedNumberPart(Math.round(data.value));
            }
        ).play();
    }, [animatedNumberPart, animationStepTime, endNumberPart, text, easing, timeMultiply, useAnimate]);

    return (
        <div className={cls(textStyle.text_wrapper, className)}>
            {text
                .toString(10)
                .replace(endNumberPart.toString(10), animatedNumberPart.toString(10))
                .padEnd(padEndLength, padEndFillString)
                .padStart(padStartLength, padStartFillString)
                .split("")
                .map<JSX.Element>((letter: string, index: number): JSX.Element => {
                    const imageUrl: string = localImageMap[letter]?.src ?? fontBigImage[" "].src;

                    return (
                        <img
                            alt={letter}
                            className={textStyle.text_item}
                            height={`${fontHeight * scale}px`}
                            key={`${imageUrl}-${index.toString(16)}`}
                            src={imageUrl}
                        />
                    );
                })}
        </div>
    );
}
