/* global document, HTMLImageElement, CanvasRenderingContext2D */

import {squareSize} from "../../../../../css/style";
import {
    getIsDynamicWater,
    getLandscapeByPoint,
    getLandscapeSize,
    getTileTheme,
} from "../../../../../model/game/landscape/landscape-helper";
import {
    GameLandscapeItemEnum,
    GameLandscapeThemeEnum,
    type GameLandscapeThemeMapType,
    type GameLandscapeType,
} from "../../../../../model/game/landscape/landscape-type";
import type {PointType} from "../../../../../model/game/point/point-type";
import type {SizeType} from "../../../../../model/map/map-type";
import {getLandscapeImage, type LandscapeImageMapType} from "../image/landscape-image";

export interface LandscapeCanvasOptionsType {
    // Forces every tile to a single theme. null/undefined keeps each tile's own theme (the "as is" mode).
    themeOverride?: GameLandscapeThemeEnum | null;
    useDynamicWater: boolean;
}

type Landscape3x3Type = [
    GameLandscapeItemEnum,
    GameLandscapeItemEnum,
    GameLandscapeItemEnum,
    GameLandscapeItemEnum,
    GameLandscapeItemEnum,
    GameLandscapeItemEnum,
    GameLandscapeItemEnum,
    GameLandscapeItemEnum,
    GameLandscapeItemEnum,
];

type AngleImageListType = [
    HTMLImageElement,
    HTMLImageElement,
    HTMLImageElement,
    HTMLImageElement,
    HTMLImageElement,
    HTMLImageElement,
    HTMLImageElement,
    HTMLImageElement,
    HTMLImageElement,
    HTMLImageElement,
    HTMLImageElement,
    HTMLImageElement,
];

const {br0, wt0, st0, tr0, hl0, fr1, rd0, tr1, tr2, fr0, tr3, tr4, wt1, wt2, br1} = GameLandscapeItemEnum;
const landscapeCache: Record<string, string> = {};

function getMainImageMap(themeImage: LandscapeImageMapType): Record<GameLandscapeItemEnum, HTMLImageElement> {
    return {
        [br0]: themeImage.bridge0,
        [br1]: themeImage.bridge1,
        [fr0]: themeImage.forest0,
        [fr1]: themeImage.forest1,
        [hl0]: themeImage.hill0,
        [rd0]: themeImage.road0,
        [st0]: themeImage.stone0,
        [tr0]: themeImage.terra0,
        [tr1]: themeImage.terra1,
        [tr2]: themeImage.terra2,
        [tr3]: themeImage.terra3,
        [tr4]: themeImage.terra4,
        [wt0]: themeImage.water0,
        [wt1]: themeImage.water1,
        [wt2]: themeImage.water2,
    };
}

function getAngleImageList(themeImage: LandscapeImageMapType, isRoadTile: boolean): AngleImageListType {
    return isRoadTile
        ? [
              themeImage.angleRoad1,
              themeImage.angleRoad2,
              themeImage.angleRoad3,
              themeImage.angleRoad4,
              themeImage.angleRoad6,
              themeImage.angleRoad7,
              themeImage.angleRoad8,
              themeImage.angleRoad9,
              themeImage.angleRoad1s,
              themeImage.angleRoad3s,
              themeImage.angleRoad7s,
              themeImage.angleRoad9s,
          ]
        : [
              themeImage.angleWater1,
              themeImage.angleWater2,
              themeImage.angleWater3,
              themeImage.angleWater4,
              themeImage.angleWater6,
              themeImage.angleWater7,
              themeImage.angleWater8,
              themeImage.angleWater9,
              themeImage.angleWater1s,
              themeImage.angleWater3s,
              themeImage.angleWater7s,
              themeImage.angleWater9s,
          ];
}

function get3x3landscape(point: PointType, landscape: GameLandscapeType): Landscape3x3Type {
    const {x, y} = point;
    const centerTile: GameLandscapeItemEnum = getLandscapeByPoint(point, landscape) ?? rd0;

    const leftUpTile: GameLandscapeItemEnum = getLandscapeByPoint({x: x - 1, y: y - 1}, landscape) ?? centerTile;
    const upTile: GameLandscapeItemEnum = getLandscapeByPoint({x, y: y - 1}, landscape) ?? centerTile;
    const rightUpTile: GameLandscapeItemEnum = getLandscapeByPoint({x: x + 1, y: y - 1}, landscape) ?? centerTile;

    const leftTile: GameLandscapeItemEnum = getLandscapeByPoint({x: x - 1, y}, landscape) ?? centerTile;
    const rightTile: GameLandscapeItemEnum = getLandscapeByPoint({x: x + 1, y}, landscape) ?? centerTile;

    const leftBottomTile: GameLandscapeItemEnum = getLandscapeByPoint({x: x - 1, y: y + 1}, landscape) ?? centerTile;
    const bottomTile: GameLandscapeItemEnum = getLandscapeByPoint({x, y: y + 1}, landscape) ?? centerTile;
    const rightBottomTile: GameLandscapeItemEnum = getLandscapeByPoint({x: x + 1, y: y + 1}, landscape) ?? centerTile;

    return [
        leftUpTile,
        upTile,
        rightUpTile,
        leftTile,
        centerTile,
        rightTile,
        leftBottomTile,
        bottomTile,
        rightBottomTile,
    ];
}

function getIsBridge(tileName: GameLandscapeItemEnum): boolean {
    return tileName === br0 || tileName === br1;
}

function getIsNotBridge(tileName: GameLandscapeItemEnum): boolean {
    return !getIsBridge(tileName);
}

function getIsEqualType(tileNameA: GameLandscapeItemEnum, tileNameB: GameLandscapeItemEnum): boolean {
    return tileNameA.replace(/\d+/giu, "").toLowerCase() === tileNameB.replace(/\d+/giu, "").toLowerCase();
}

function getIsNotEqualType(tileNameA: GameLandscapeItemEnum, tileNameB: GameLandscapeItemEnum): boolean {
    return !getIsEqualType(tileNameA, tileNameB);
}

// eslint-disable-next-line @typescript-eslint/max-params
function getIsNeedSmallAngle(
    baseTile: GameLandscapeItemEnum,
    baseTileA: GameLandscapeItemEnum,
    baseTileB: GameLandscapeItemEnum,
    testTitle: GameLandscapeItemEnum
): boolean {
    return (
        (getIsEqualType(baseTile, baseTileA) || getIsBridge(baseTileA)) &&
        (getIsEqualType(baseTile, baseTileB) || getIsBridge(baseTileB)) &&
        getIsNotEqualType(baseTile, testTitle) &&
        getIsNotBridge(testTitle)
    );
}

export function getIsNeedBigAngle(
    baseTile: GameLandscapeItemEnum,
    baseTileA: GameLandscapeItemEnum,
    baseTileB: GameLandscapeItemEnum
): boolean {
    return (
        getIsNotEqualType(baseTile, baseTileA) &&
        getIsNotEqualType(baseTile, baseTileB) &&
        getIsNotBridge(baseTileA) &&
        getIsNotBridge(baseTileB)
    );
}

function getIsRoadTile(tileName: GameLandscapeItemEnum): boolean {
    return tileName === rd0;
}

function getIsWaterTile(tileName: GameLandscapeItemEnum): boolean {
    return [wt0, wt1, wt2].includes(tileName);
}

export function getIsTerraBasedTile(tileName: GameLandscapeItemEnum): boolean {
    return [fr0, fr1, hl0, st0, tr0, tr1, tr2, tr3, tr4].includes(tileName);
}

// eslint-disable-next-line max-statements, @typescript-eslint/max-params
function drawAngles(
    canvasContext: CanvasRenderingContext2D,
    landscape3x3: Landscape3x3Type,
    point: PointType,
    themeImage: LandscapeImageMapType
): undefined {
    const [
        leftUpTile,
        upTile,
        rightUpTile,
        leftTile,
        centerTile,
        rightTile,
        leftBottomTile,
        bottomTile,
        rightBottomTile,
    ] = landscape3x3;
    const isRoadTile = getIsRoadTile(centerTile);
    const {x, y} = point;
    const angleList: AngleImageListType = getAngleImageList(themeImage, isRoadTile);
    const [
        angleImage0,
        angleImage1,
        angleImage2,
        angleImage3,
        angleImage4,
        angleImage5,
        angleImage6,
        angleImage7,
        angleImage8,
        angleImage9,
        angleImage10,
        angleImage11,
    ] = angleList;

    if (getIsNotBridge(upTile) && getIsNotEqualType(centerTile, upTile)) {
        canvasContext.drawImage(angleImage1, x * squareSize, y * squareSize);
    }
    if (getIsNotBridge(leftTile) && getIsNotEqualType(centerTile, leftTile)) {
        canvasContext.drawImage(angleImage3, x * squareSize, y * squareSize);
    }
    if (getIsNotBridge(rightTile) && getIsNotEqualType(centerTile, rightTile)) {
        canvasContext.drawImage(angleImage4, x * squareSize + squareSize / 2, y * squareSize);
    }
    if (getIsNotBridge(bottomTile) && getIsNotEqualType(centerTile, bottomTile)) {
        canvasContext.drawImage(angleImage6, x * squareSize, y * squareSize + squareSize / 2);
    }

    // draw small \ and / --
    // --> draw small \ and / - for left-top
    if (getIsNeedSmallAngle(centerTile, upTile, leftTile, leftUpTile)) {
        canvasContext.drawImage(angleImage8, x * squareSize, y * squareSize);
    }

    // --> draw small \ and / - for right-top
    if (getIsNeedSmallAngle(centerTile, upTile, rightTile, rightUpTile)) {
        canvasContext.drawImage(angleImage9, x * squareSize + squareSize / 2, y * squareSize);
    }

    // --> draw small \ and / - for left-bottom
    if (getIsNeedSmallAngle(centerTile, leftTile, bottomTile, leftBottomTile)) {
        canvasContext.drawImage(angleImage10, x * squareSize, y * squareSize + squareSize / 2);
    }

    // --> draw small \ and / - for right-bottom
    if (getIsNeedSmallAngle(centerTile, rightTile, bottomTile, rightBottomTile)) {
        canvasContext.drawImage(angleImage11, x * squareSize + squareSize / 2, y * squareSize + squareSize / 2);
    }

    // draw big \ and / --
    // --> draw big \ and / - for left-top
    if (getIsNeedBigAngle(centerTile, upTile, leftTile)) {
        canvasContext.drawImage(angleImage0, x * squareSize, y * squareSize);
    }

    // --> draw big \ and / - for right-top
    if (getIsNeedBigAngle(centerTile, upTile, rightTile)) {
        canvasContext.drawImage(angleImage2, x * squareSize + squareSize / 2, y * squareSize);
    }

    // --> draw big \ and / - for left-bottom
    if (getIsNeedBigAngle(centerTile, leftTile, bottomTile)) {
        canvasContext.drawImage(angleImage5, x * squareSize, y * squareSize + squareSize / 2);
    }

    // --> draw big \ and / - for right-bottom
    if (getIsNeedBigAngle(centerTile, rightTile, bottomTile)) {
        canvasContext.drawImage(angleImage7, x * squareSize + squareSize / 2, y * squareSize + squareSize / 2);
    }
}

// eslint-disable-next-line max-statements, @typescript-eslint/max-params
function drawTerraAngles(
    canvasContext: CanvasRenderingContext2D,
    landscape3x3: Landscape3x3Type,
    point: PointType,
    themeImage: LandscapeImageMapType
): undefined {
    const [
        leftUpTile,
        upTile,
        rightUpTile,
        leftTile,
        centerTile,
        rightTile,
        leftBottomTile,
        bottomTile,
        rightBottomTile,
    ] = landscape3x3;

    console.log(
        leftUpTile,
        upTile,
        rightUpTile,
        leftTile,
        centerTile,
        rightTile,
        leftBottomTile,
        bottomTile,
        rightBottomTile
    );
    // const isRoadTile = getIsRoadTile(centerTile);
    const {x, y} = point;
    const {angleTerra1, angleTerra2, angleTerra3, angleTerra4, angleTerra6, angleTerra7, angleTerra8, angleTerra9} =
        themeImage;

    let hasUpBorder = false;
    let hasBottonBorder = false;
    let hasLeftBorder = false;
    let hasRightBorder = false;

    if (getIsNotBridge(upTile) && !getIsTerraBasedTile(upTile)) {
        canvasContext.drawImage(angleTerra2, x * squareSize, y * squareSize);
        hasUpBorder = true;
    }

    if (getIsNotBridge(leftTile) && !getIsTerraBasedTile(leftTile)) {
        canvasContext.drawImage(angleTerra4, x * squareSize, y * squareSize);
        hasLeftBorder = true;
    }

    if (getIsNotBridge(rightTile) && !getIsTerraBasedTile(rightTile)) {
        canvasContext.drawImage(angleTerra6, x * squareSize + squareSize / 2, y * squareSize);
        hasRightBorder = true;
    }

    if (getIsNotBridge(bottomTile) && !getIsTerraBasedTile(bottomTile)) {
        canvasContext.drawImage(angleTerra8, x * squareSize, y * squareSize + squareSize / 2);
        hasBottonBorder = true;
    }

    if (hasUpBorder && hasLeftBorder) {
        canvasContext.drawImage(angleTerra1, x * squareSize, y * squareSize);
    }

    if (hasUpBorder && hasRightBorder) {
        canvasContext.drawImage(angleTerra3, x * squareSize + squareSize / 2, y * squareSize);
    }

    if (hasBottonBorder && hasLeftBorder) {
        canvasContext.drawImage(angleTerra7, x * squareSize, y * squareSize + squareSize / 2);
    }

    if (hasBottonBorder && hasRightBorder) {
        canvasContext.drawImage(angleTerra9, x * squareSize + squareSize / 2, y * squareSize + squareSize / 2);
    }
}

// eslint-disable-next-line @typescript-eslint/max-params, max-params
function drawSquare(
    point: PointType,
    landscape: GameLandscapeType,
    landscapeItem: GameLandscapeItemEnum,
    canvasContext: CanvasRenderingContext2D,
    options: LandscapeCanvasOptionsType,
    theme: GameLandscapeThemeEnum
): undefined {
    const isAe1Theme = theme === GameLandscapeThemeEnum.ae1;
    // const useDynamicWater = options.useDynamicWater || isAe1Theme;
    const {x, y} = point;
    const themeImage: LandscapeImageMapType = getLandscapeImage(theme);
    const tile3x3: Landscape3x3Type = get3x3landscape(point, landscape);

    const drawOnTr0List: Array<GameLandscapeItemEnum> = isAe1Theme
        ? [GameLandscapeItemEnum.st0, GameLandscapeItemEnum.fr0, GameLandscapeItemEnum.fr1, GameLandscapeItemEnum.hl0]
        : [];

    canvasContext.drawImage(getMainImageMap(themeImage)[landscapeItem], x * squareSize, y * squareSize);

    // additional draw for stone, because stone can have transparent background
    if (drawOnTr0List.includes(landscapeItem)) {
        canvasContext.drawImage(getMainImageMap(themeImage)[GameLandscapeItemEnum.tr0], x * squareSize, y * squareSize);
    }

    if (getIsTerraBasedTile(landscapeItem)) {
        drawTerraAngles(canvasContext, tile3x3, point, themeImage);
    }

    if (drawOnTr0List.includes(landscapeItem)) {
        canvasContext.drawImage(getMainImageMap(themeImage)[landscapeItem], x * squareSize, y * squareSize);
    }

    if (getIsDynamicWater(landscapeItem, theme) && options.useDynamicWater) {
        canvasContext.clearRect(x * squareSize + 1, y * squareSize + 1, squareSize - 2, squareSize - 2);
    }

    // draw angles for water, road and terra only
    if (!getIsRoadTile(landscapeItem) && !getIsWaterTile(landscapeItem)) {
        console.log("draw angles for water, road and terra only");
        return;
    }

    drawAngles(canvasContext, tile3x3, point, themeImage);
}

// Every sprite the given landscape needs: the full image set of every theme used by its tiles.
export function getLandscapeThemeImageList(
    landscape: GameLandscapeType,
    landscapeThemeMap: GameLandscapeThemeMapType | undefined,
    themeOverride: GameLandscapeThemeEnum | null
): Array<HTMLImageElement> {
    const themeSet = new Set<GameLandscapeThemeEnum>();

    landscape.forEach((landscapeList: Array<GameLandscapeItemEnum>, y: number): void => {
        landscapeList.forEach((_landscapeItem: GameLandscapeItemEnum, x: number): void => {
            themeSet.add(themeOverride ?? getTileTheme({x, y}, landscapeThemeMap));
        });
    });

    return [...themeSet].flatMap((theme: GameLandscapeThemeEnum): Array<HTMLImageElement> => {
        return Object.values(getLandscapeImage(theme));
    });
}

function getIsImageReady(image: HTMLImageElement): boolean {
    return image.complete && image.naturalWidth > 0;
}

export function getLandscapeCanvas(
    landscape: GameLandscapeType,
    landscapeThemeMap: GameLandscapeThemeMapType | undefined,
    options: LandscapeCanvasOptionsType
): string {
    const mapSize: SizeType = getLandscapeSize(landscape);
    const landscapeKey = JSON.stringify({landscape, landscapeThemeMap, options});

    const cachedCanvas = landscapeCache[landscapeKey];

    if (typeof cachedCanvas === "string") {
        return cachedCanvas;
    }

    const canvas = document.createElement("canvas");
    const canvasContext = canvas.getContext("2d");

    canvas.width = mapSize.width * squareSize;
    canvas.height = mapSize.height * squareSize;

    if (!canvasContext) {
        console.error("canvasContext is not defined");
        return "";
    }

    landscape.forEach((landscapeList: Array<GameLandscapeItemEnum>, y: number): void => {
        landscapeList.forEach((landscapeItem: GameLandscapeItemEnum, x: number): void => {
            const theme: GameLandscapeThemeEnum = options.themeOverride ?? getTileTheme({x, y}, landscapeThemeMap);

            drawSquare({x, y}, landscape, landscapeItem, canvasContext, options, theme);
        });
    });

    // canvasContext.drawImage(landscapeImage.water1, 50, 50, 50, 50);

    const result: string = canvas.toDataURL("image/png", 1);

    // A draw made before every sprite finished loading is incomplete (drawImage silently skips
    // pending images) — return it for now but never cache it, so a later render can redraw.
    const isEverySpriteReady = getLandscapeThemeImageList(
        landscape,
        landscapeThemeMap,
        options.themeOverride ?? null
    ).every(getIsImageReady);

    if (isEverySpriteReady) {
        landscapeCache[landscapeKey] = result;
    }

    return result;
}
