/* global HTMLImageElement */
import {GameLandscapeThemeEnum} from "../../../../../model/game/landscape/landscape-type";
import {buildingImageAe1, farmBrokenImageAe1} from "./building-image-ae1";
import {buildingImageAe2, type BuildingImageMapType, farmBrokenImageAe2} from "./building-image-ae2";
import {buildingImageDesert, farmBrokenImageDesert} from "./building-image-desert";
import {buildingImageSummer, farmBrokenImageSummer} from "./building-image-summer";
import {buildingImageSummer2, farmBrokenImageSummer2} from "./building-image-summer2";

export type {BuildingImageMapType} from "./building-image-ae2";

const buildingImageByTheme: Record<GameLandscapeThemeEnum, BuildingImageMapType> = {
    [GameLandscapeThemeEnum.ae1]: buildingImageAe1,
    [GameLandscapeThemeEnum.ae2]: buildingImageAe2,
    [GameLandscapeThemeEnum.desert]: buildingImageDesert,
    [GameLandscapeThemeEnum.summer]: buildingImageSummer,
    [GameLandscapeThemeEnum.summer2]: buildingImageSummer2,
};

const farmBrokenImageByTheme: Record<GameLandscapeThemeEnum, HTMLImageElement> = {
    [GameLandscapeThemeEnum.ae1]: farmBrokenImageAe1,
    [GameLandscapeThemeEnum.ae2]: farmBrokenImageAe2,
    [GameLandscapeThemeEnum.desert]: farmBrokenImageDesert,
    [GameLandscapeThemeEnum.summer]: farmBrokenImageSummer,
    [GameLandscapeThemeEnum.summer2]: farmBrokenImageSummer2,
};

export function getBuildingImageMap(theme: GameLandscapeThemeEnum): BuildingImageMapType {
    return buildingImageByTheme[theme];
}

export function getFarmBrokenImage(theme: GameLandscapeThemeEnum): HTMLImageElement {
    return farmBrokenImageByTheme[theme];
}
