import type {JSX} from "react";

import {serviceStyle} from "../css/style";
import {parseColor} from "./color";

type ColorMatrixPropsType = Readonly<{
    toColor: string;
    fromColor: string;
    colorId: string;
}>;

export function ColorMatrix(props: ColorMatrixPropsType): JSX.Element {
    const {toColor, fromColor, colorId} = props;

    const {red, green, blue} = parseColor(toColor);
    const {red: fromRed, green: fromGreen, blue: fromBlue} = parseColor(fromColor);

    // Per-channel scaling maps the source fill (fromRed,fromGreen,fromBlue)
    // -> (red,green,blue) exactly, keeps black at black and leaves alpha untouched.
    const redScale = red / fromRed;
    const greenScale = green / fromGreen;
    const blueScale = blue / fromBlue;

    const values = [`${redScale} 0 0 0 0`, `0 ${greenScale} 0 0 0`, `0 0 ${blueScale} 0 0`, `0 0 0 1 0`].join(" ");

    return (
        <svg className={serviceStyle.none}>
            <filter colorInterpolationFilters="sRGB" id={colorId}>
                <feColorMatrix type="matrix" values={values} />
            </filter>
        </svg>
    );
}
