import type {BotDifficultEnum} from "../../../provider/setting/setting-type";
import type {GameUnitTypeEnum} from "../unit/unit-type";

export enum GamePlayerIdEnum {
    "player1" = "player1",
    "player2" = "player2",
    "player3" = "player3",
    "player4" = "player4",
    "playerEmpty" = "playerEmpty",
}

export enum GamePlayerTeamIdEnum {
    "team1" = "team1",
    "team2" = "team2",
    "team3" = "team3",
    "team4" = "team4",
    "teamEmpty" = "teamEmpty",
}

export enum GamePlayerColorIdEnum {
    black = "black",
    blue = "blue",
    gray = "gray",
    green = "green",
    red = "red",
}

export enum GamePlayerTypeEnum {
    bot = "bot",
    human = "human",
    none = "none",
}

export interface GamePlayerType {
    availableToBuyUnitList?: Array<GameUnitTypeEnum> | null;
    // Overrides the commander unit type placed on the map (chosen on the game setup screen).
    commanderUnitType?: GameUnitTypeEnum | null;
    gamePlayerColorId: GamePlayerColorIdEnum;
    gamePlayerId: GamePlayerIdEnum;
    gamePlayerTeamId: GamePlayerTeamIdEnum;
    maxUnitHealth?: number;
    maxUnitLevel?: number;
    money: number;
    // TODO: remove me in future, current date is 2024-12-22, should be like this -> `playerDifficulty: BotDifficultEnum`
    playerDifficulty?: BotDifficultEnum;
    playerType: GamePlayerTypeEnum;
    unitLevelStep?: number;
    unitLimit?: number;
}
