import type {JSX} from "react";

import {squareSize} from "../../../../css/style";
import {getEffectiveTileTheme} from "../../../../model/game/landscape/landscape-helper";
import type {GameLandscapeThemeEnum} from "../../../../model/game/landscape/landscape-type";
import type {GameGraveType} from "../../../../model/game/unit/unit-type";
import {useGameContext} from "../../../../provider/game/game-context";
import * as clientGameGraveStyle from "./client-game-grave.scss";
import {getGraveImage} from "./image/client-game-grave-image";

interface ClientGameGravePropsType {
    // The theme to force on every grave, or null to take the theme from the cell the grave sits on.
    readonly forcedTheme: GameLandscapeThemeEnum | null;
}

export function ClientGameGrave(props: ClientGameGravePropsType): JSX.Element {
    const {forcedTheme} = props;
    const {gameState} = useGameContext();
    const {graveList} = gameState;

    return (
        <div className={clientGameGraveStyle.grave_layer}>
            {graveList.map((grave: GameGraveType, index: number): JSX.Element => {
                const theme = getEffectiveTileTheme({x: grave.x, y: grave.y}, gameState.landscapeThemeMap, forcedTheme);

                return (
                    <img
                        alt={`grave-${grave.createdStepCount.toString(10)}`}
                        className={clientGameGraveStyle.grave_square}
                        key={`${grave.x}-${grave.y}-${index.toString(16)}-${grave.createdStepCount.toString(16)}`}
                        src={getGraveImage(theme).src}
                        style={{left: grave.x * squareSize, top: grave.y * squareSize}}
                    />
                );
            })}
        </div>
    );
}
