import {type JSX, useEffect, useMemo, useState} from "react";

import {squareSize} from "../../../../css/style";
import {getLandscapeSize} from "../../../../model/game/landscape/landscape-helper";
import type {GameMapType, SizeType} from "../../../../model/map/map-type";
import {resolveLandscapeThemeOverride} from "../../../../provider/setting/landscape-theme-override-helper";
import {useSettingContext} from "../../../../provider/setting/setting-context";
import {getMapPreviewCanvas} from "../../client-game/client-game-landscape/helper/map-preview";
import * as clientSkirmishMapPreviewStyle from "./client-skirmish-map-preview.scss";

interface ClientSkirmishMapPreviewPropsType {
    readonly map: GameMapType;
    readonly isShow: boolean;
}

export function ClientSkirmishMapPreview(props: ClientSkirmishMapPreviewPropsType): JSX.Element {
    const {map, isShow} = props;
    const {
        setting: {landscapeThemeOverride},
    } = useSettingContext();
    const [isWasShow, setIsWasShow] = useState<boolean>(isShow);
    const {width, height}: SizeType = getLandscapeSize(map.landscape);
    const themeOverride = resolveLandscapeThemeOverride(map.mapId, landscapeThemeOverride);

    useEffect(() => {
        if (isShow) {
            // eslint-disable-next-line react-hooks/set-state-in-effect
            setIsWasShow(true);
        }
    }, [isShow]);

    const mapImage: JSX.Element | null = useMemo<JSX.Element | null>((): JSX.Element | null => {
        if (!isShow && !isWasShow) {
            return null;
        }

        const {landscape, unit, building} = getMapPreviewCanvas(map, themeOverride);

        return (
            <>
                <img alt="landscape" className={clientSkirmishMapPreviewStyle.map_preview_image} src={landscape} />
                <img alt="building" className={clientSkirmishMapPreviewStyle.map_preview_image} src={building} />
                <img alt="unit" className={clientSkirmishMapPreviewStyle.map_preview_image} src={unit} />
            </>
        );
    }, [isShow, isWasShow, map, themeOverride]);

    return (
        <div className={clientSkirmishMapPreviewStyle.map_preview}>
            <canvas
                className={clientSkirmishMapPreviewStyle.map_preview_image__frame}
                height={height * squareSize}
                width={width * squareSize}
            />
            {mapImage}
        </div>
    );
}
