import type {Dispatch, SetStateAction} from "react";

import type {AudioPlayerAudioRowEnum} from "../../hook/audio-player-hook/audio-player-type";
import type {GameLandscapeThemeEnum} from "../../model/game/landscape/landscape-type";
import type {LangKeyType} from "../locale/translation/type";

export interface BooleanSettingDataType {
    isActionIconAnimation: boolean;
    isAutoSaveEnable: boolean;
    isEndTurnConfirmationEnable: boolean;
    isHitUnitAnimationEnable: boolean;
    isNumberAnimationEnable: boolean;
    isOnlyOriginalMapsEnable: boolean;
    isSmokeFromHousesEnable: boolean;
    isUnitFightAnimationEnable: boolean;
    isUnitIdleAnimationEnable: boolean;
    isUnitSpawnAnimationEnable: boolean;
    isWaterAnimationEnable: boolean;
}

export interface NumberSettingDataType {
    animationStepTime: number;
    fightAnimationFrameTime: number;
}

export enum BotDifficultEnum {
    easy = "easy",
    hard = "hard",
    normal = "normal",
}

// Player-facing landscape theme choice = every GameLandscapeThemeEnum value (force that theme on every tile)
// plus `asIs` (keep each tile's own theme, as authored in the map editor). Built on top of GameLandscapeThemeEnum
// so there is a single source of truth: a new theme added to that enum becomes a valid setting automatically.
export const landscapeThemeAsIs = "asIs";

export type LandscapeThemeSettingType = GameLandscapeThemeEnum | typeof landscapeThemeAsIs;

export interface SettingContextSettingType {
    booleanSetting: BooleanSettingDataType;
    // BotDifficult: BotDifficultEnum;
    landscapeThemeOverride: LandscapeThemeSettingType;
    numberSetting: NumberSettingDataType;
}

export interface SettingContextType {
    setBoolean: (key: keyof BooleanSettingDataType, value: boolean) => void;
    setNumber: (key: keyof NumberSettingDataType, value: number) => void;
    setSetting: Dispatch<SetStateAction<SettingContextSettingType>>;
    setting: SettingContextSettingType;
}

export interface BooleanSettingItemType {
    key: keyof BooleanSettingDataType;
    langKey: LangKeyType;
}

export interface SoundSettingItemType {
    audioRowName: AudioPlayerAudioRowEnum;
    langKey: LangKeyType;
}

export interface LandscapeThemeSettingItemType {
    langKey: LangKeyType;
    value: LandscapeThemeSettingType;
}
