interface FightFieldRawImagesType {
    bridge: string;
    building: string;
    forest: string;
    hill: string;
    road: string;
    stone: string;
    terra: string;
    water: string;
}

interface FightFieldThemeImagesType {
    building: string;
    terra: Record<GameLandscapeItemEnum, string>;
}

function makeFightFieldThemeImages(rawImages: FightFieldRawImagesType): FightFieldThemeImagesType {
    const {bridge, building, forest, hill, road, stone, terra, water} = rawImages;

    return {
        building: getImage(building).src,
        terra: {
            [br0]: getImage(bridge).src,
            [br1]: getImage(bridge).src,
            [fr0]: getImage(forest).src,
            [fr1]: getImage(forest).src,
            [hl0]: getImage(hill).src,
            [rd0]: getImage(road).src,
            [st0]: getImage(stone).src,
            [tr0]: getImage(terra).src,
            [tr1]: getImage(terra).src,
            [tr2]: getImage(terra).src,
            [tr3]: getImage(terra).src,
            [tr4]: getImage(terra).src,
            [wt0]: getImage(water).src,
            [wt1]: getImage(water).src,
            [wt2]: getImage(water).src,
        },
    };
}

const fightFieldImageByTheme: Record<GameLandscapeThemeEnum, FightFieldThemeImagesType> = {
    [GameLandscapeThemeEnum.ae1]: makeFightFieldThemeImages({
        bridge: bridgeAe1,
        building: buildingAe1,
        forest: forestAe1,
        hill: hillAe1,
        road: roadAe1,
        stone: stoneAe1,
        terra: terraAe1,
        water: waterAe1,
    }),
    [GameLandscapeThemeEnum.ae2]: makeFightFieldThemeImages({
        bridge: bridgeAe2,
        building: buildingAe2,
        forest: forestAe2,
        hill: hillAe2,
        road: roadAe2,
        stone: stoneAe2,
        terra: terraAe2,
        water: waterAe2,
    }),
    [GameLandscapeThemeEnum.desert]: makeFightFieldThemeImages({
        bridge: bridgeDesert,
        building: buildingDesert,
        forest: forestDesert,
        hill: hillDesert,
        road: roadDesert,
        stone: stoneDesert,
        terra: terraDesert,
        water: waterDesert,
    }),
    [GameLandscapeThemeEnum.summer]: makeFightFieldThemeImages({
        bridge: bridgeSummer,
        building: buildingSummer,
        forest: forestSummer,
        hill: hillSummer,
        road: roadSummer,
        stone: stoneSummer,
        terra: terraSummer,
        water: waterSummer,
    }),
    [GameLandscapeThemeEnum.summer2]: makeFightFieldThemeImages({
        bridge: bridgeSummer2,
        building: buildingSummer2,
        forest: forestSummer2,
        hill: hillSummer2,
        road: roadSummer2,
        stone: stoneSummer2,
        terra: terraSummer2,
        water: waterSummer2,
    }),
};

export function getTerraUnitFightAnimationImage(
    theme: GameLandscapeThemeEnum,
    terraType: GameLandscapeItemEnum
): string {
    return fightFieldImageByTheme[theme].terra[terraType];
}

export function getBuildingUnitFightAnimationImage(theme: GameLandscapeThemeEnum): string {
    return fightFieldImageByTheme[theme].building;
}
