/* global document, setTimeout, IS_PRODUCTION */

import "markdown-pro/dist/style.css";
import "react-audio-player-pro/dist/style.css";

import {type JSX, StrictMode} from "react";
import {createRoot} from "react-dom/client";

import {App} from "./app/app";
import {selector} from "./const";
import {onAppLoaded} from "./util/android-app-loaded";
import {registerServiceWorker} from "./util/service-worker";

// eslint-disable-next-line jest/require-hook
(function main(): undefined {
    const nodeWrapper = document.querySelector(selector.appWrapper);

    if (!nodeWrapper) {
        throw new Error("[main]: Can not find appWrapper");
    }

    const appNode: JSX.Element = (
        <StrictMode>
            <App defaultThemeName={null} />
        </StrictMode>
    );

    createRoot(nodeWrapper).render(appNode);

    setTimeout(onAppLoaded, 500);

    registerServiceWorker();

    // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
    if (!IS_PRODUCTION) {
        // Dev-only (a separate lazy chunk): the wasm-vs-JS pathfinding parity hook for the e2e test.
        import("./model/game/unit/unit-path-parity")
            .then((parityModule): null => {
                parityModule.registerPathfindingParityHook();
                return null;
            })
            .catch(console.error);
    }
})();
