import {getUnitImageSource} from "../../../page/client/client-game/client-game-unit/image/unit-image";
import {getBotDifficultImage} from "../../../provider/setting/setting-helper";
import {BotDifficultEnum} from "../../../provider/setting/setting-type";
import {getBuildingByPoint, getBuildingMoneyIncome, getHasPlayerStore} from "../building/building-helper";
import {GameBuildingStateEnum, type GameBuildingType} from "../building/building-type";
import {defaultMaxUnitLevel, defaultUnitLimit} from "../game-const";
import type {GameSettingsType, GameStateType} from "../game-type";
import {defaultUnitData} from "../unit/unit-const";
import {getUnitInfoByUnit, getUnitListByPlayerId} from "../unit/unit-helper";
import {levelUnitData} from "../unit/unit-level";
import {type GameUnitType, GameUnitTypeEnum} from "../unit/unit-type";
import {
    GamePlayerColorIdEnum,
    type GamePlayerIdEnum,
    GamePlayerTeamIdEnum,
    type GamePlayerType,
    GamePlayerTypeEnum,
} from "./player-type";

export function getPlayerHeroList(playerId: GamePlayerIdEnum, unitList: Array<GameUnitType>): Array<GameUnitType> {
    return getUnitListByPlayerId(playerId, unitList).filter<GameUnitType>(
        (unitInList: GameUnitType): unitInList is GameUnitType => {
            return getUnitInfoByUnit(unitInList).isHero;
        }
    );
}

export function getHasPlayerHero(playerId: GamePlayerIdEnum, unitList: Array<GameUnitType>): boolean {
    return getPlayerHeroList(playerId, unitList).length > 0;
}

export function getPlayerByPlayerId(
    gamePlayerId: GamePlayerIdEnum,
    playerList: Array<GamePlayerType>
): GamePlayerType | null {
    return (
        playerList.find((player: GamePlayerType): boolean => {
            return player.gamePlayerId === gamePlayerId;
        }) ?? null
    );
}

// Per-player cap on unit health, falling back to the global default (100) when unset.
export function getPlayerMaxUnitHealth(gamePlayerId: GamePlayerIdEnum, playerList: Array<GamePlayerType>): number {
    const player: GamePlayerType | null = getPlayerByPlayerId(gamePlayerId, playerList);

    return Math.min(defaultUnitData.health, player?.maxUnitHealth ?? defaultUnitData.health);
}

// Per-player experience step per unit level, falling back to the global default when unset.
export function getPlayerUnitLevelStep(gamePlayerId: GamePlayerIdEnum, playerList: Array<GamePlayerType>): number {
    const player: GamePlayerType | null = getPlayerByPlayerId(gamePlayerId, playerList);

    return player?.unitLevelStep ?? levelUnitData.base;
}

// Per-player unit count limit, falling back to the global default when unset (e.g. company mode).
export function getPlayerUnitLimit(gamePlayerId: GamePlayerIdEnum, playerList: Array<GamePlayerType>): number {
    const player: GamePlayerType | null = getPlayerByPlayerId(gamePlayerId, playerList);

    return player?.unitLimit ?? defaultUnitLimit;
}

// Per-player max unit level, falling back to the global default when unset (e.g. company mode).
export function getPlayerMaxUnitLevel(gamePlayerId: GamePlayerIdEnum, playerList: Array<GamePlayerType>): number {
    const player: GamePlayerType | null = getPlayerByPlayerId(gamePlayerId, playerList);

    return player?.maxUnitLevel ?? defaultMaxUnitLevel;
}

export function getTeamIdByPlayerId(
    gamePlayerId: GamePlayerIdEnum,
    playerList: Array<GamePlayerType>
): GamePlayerTeamIdEnum {
    const playerByPlayerId: GamePlayerType | null = getPlayerByPlayerId(gamePlayerId, playerList);

    return playerByPlayerId ? playerByPlayerId.gamePlayerTeamId : GamePlayerTeamIdEnum.teamEmpty;
}

export function getEnemyUnitListByPlayerId(
    gamePlayerId: GamePlayerIdEnum,
    gamePlayerList: Array<GamePlayerType>,
    unitList: Array<GameUnitType>
): Array<GameUnitType> {
    const playerTeamId: GamePlayerTeamIdEnum = getTeamIdByPlayerId(gamePlayerId, gamePlayerList);

    return unitList.filter<GameUnitType>((unitInList: GameUnitType): unitInList is GameUnitType => {
        return playerTeamId !== getTeamIdByPlayerId(unitInList.gamePlayerId, gamePlayerList);
    });
}

// eslint-disable-next-line @typescript-eslint/max-params, id-length
export function getEnemyUnitOnBuildingListByPlayerId(
    gamePlayerId: GamePlayerIdEnum,
    gamePlayerList: Array<GamePlayerType>,
    unitList: Array<GameUnitType>,
    buildingList: Array<GameBuildingType>
): Array<GameUnitType> {
    const enemyUnitList: Array<GameUnitType> = getEnemyUnitListByPlayerId(gamePlayerId, gamePlayerList, unitList);

    return enemyUnitList.filter<GameUnitType>((enemyUnit: GameUnitType): enemyUnit is GameUnitType => {
        const buildingUnderUnit: GameBuildingType | null = getBuildingByPoint(
            {
                x: enemyUnit.x,
                y: enemyUnit.y,
            },
            buildingList
        );
        return Boolean(buildingUnderUnit);
    });
}

export function getPlayerColorIdByPlayerId(
    gamePlayerId: GamePlayerIdEnum,
    playerList: Array<GamePlayerType>
): GamePlayerColorIdEnum {
    const playerByPlayerId: GamePlayerType | undefined = playerList.find((player: GamePlayerType): boolean => {
        return player.gamePlayerId === gamePlayerId;
    });

    return playerByPlayerId ? playerByPlayerId.gamePlayerColorId : GamePlayerColorIdEnum.gray;
}

export function getPlayerTurnIncome(
    playerId: GamePlayerIdEnum,
    buildingList: Array<GameBuildingType>,
    gameSettings: GameSettingsType
): number {
    return buildingList.reduce<number>((income: number, building: GameBuildingType) => {
        if (building.gamePlayerId !== playerId || building.state !== GameBuildingStateEnum.buildingOk) {
            return income;
        }

        return income + getBuildingMoneyIncome(building.buildingType, gameSettings);
    }, 0);
}

export function getTeamInGameCount(playerList: Array<GamePlayerType>): number {
    const allTeamIdList = playerList.map<GamePlayerTeamIdEnum>((player: GamePlayerType): GamePlayerTeamIdEnum => {
        return player.gamePlayerTeamId;
    });

    return new Set(allTeamIdList).size;
}

export function getIsSkirmishEnd(playerList: Array<GamePlayerType>): boolean {
    const teamCount = getTeamInGameCount(playerList);

    return teamCount <= 1;
}

export function getIsSkirmishDefeatedPlayer(
    playerId: GamePlayerIdEnum,
    buildingList: Array<GameBuildingType>,
    unitList: Array<GameUnitType>
): boolean {
    return !getHasPlayerStore(playerId, buildingList) && !getHasPlayerHero(playerId, unitList);
}

export function skirmishGetPlayerListToRemove(gameState: GameStateType): Array<GamePlayerIdEnum> {
    const {buildingList, unitList, playerList} = gameState;

    return playerList
        .filter<GamePlayerType>((player: GamePlayerType): player is GamePlayerType => {
            return getIsSkirmishDefeatedPlayer(player.gamePlayerId, buildingList, unitList);
        })
        .map<GamePlayerIdEnum>((player: GamePlayerType): GamePlayerIdEnum => {
            return player.gamePlayerId;
        });
}

export function getIsNotNonePlayer(player: GamePlayerType): player is GamePlayerType {
    return player.playerType !== GamePlayerTypeEnum.none;
}

export function getPlayerCommander(
    playerId: GamePlayerIdEnum,
    unitData: Record<"unitList" | "cemetery", Array<GameUnitType>>
): GameUnitType | null {
    return (
        [...unitData.unitList, ...unitData.cemetery].find<GameUnitType>(
            (unitInList: GameUnitType): unitInList is GameUnitType => {
                return unitInList.gamePlayerId === playerId && getUnitInfoByUnit(unitInList).isHero;
            }
        ) ?? null
    );
}

export function getPlayerStatusBarIcon(
    player: GamePlayerType | null,
    unitData: Record<"unitList" | "cemetery", Array<GameUnitType>>
): string {
    if (!player) {
        return getUnitImageSource(GameUnitTypeEnum.skeleton, GamePlayerColorIdEnum.gray);
    }

    if (player.playerType === GamePlayerTypeEnum.bot) {
        // TODO: remove me in future, current date is 2024-12-22, should be like this -> `playerDifficulty: BotDifficultEnum`
        return getBotDifficultImage(player.playerDifficulty ?? BotDifficultEnum.easy, player.gamePlayerColorId);
    }

    const commander = getPlayerCommander(player.gamePlayerId, unitData);

    if (commander) {
        return getUnitImageSource(commander.unitType, player.gamePlayerColorId);
    }

    return getUnitImageSource(GameUnitTypeEnum.skeleton, GamePlayerColorIdEnum.gray);
}
