import type {GameFacedSnackbarType} from "../../layout/game-faced-snackbar-list/game-faced-snackbar-type";
import type {CompanyStateType} from "../../page/client/client-companies/client-companies-type";
import type {LangKeyType} from "../../provider/locale/translation/type";
import type {GameBuildingType} from "../game/building/building-type";
import type {GameLandscapeThemeMapType, GameLandscapeType} from "../game/landscape/landscape-type";
import type {GameTriggerType} from "../game/trigger/trigger-type";
import type {GameGraveType, GameUnitType, GameUnitTypeEnum} from "../game/unit/unit-type";

export enum MapTypeEnum {
    companies = "companies",
    skirmish = "skirmish",
}

// Which original game the map came from, see _res/original-game/extracted-maps
export enum MapSourceEnum {
    ae1 = "ae1",
    ae2 = "ae2",
    ae3 = "ae3",
    unknown = "unknown",
}

export interface SizeType {
    height: number;
    width: number;
}

export interface GameMapType {
    availableToBuyUnitList: Array<GameUnitTypeEnum> | null;
    briefingList: Array<GameFacedSnackbarType>;
    // activeGamePlayerId: GamePlayerIdEnum;
    buildingList: Array<GameBuildingType>;
    cemetery: Array<GameUnitType>;
    graveList: Array<GameGraveType>;
    landscape: GameLandscapeType;
    // Optional per-tile visual theme layer. Absent on legacy maps/saves, which fall back to the ae2 theme.
    landscapeThemeMap?: GameLandscapeThemeMapType | undefined;
    mapId: string;
    mapName: string;
    mapNameLangKey: LangKeyType;
    mapObjectiveLangKey: LangKeyType;
    mapType: MapTypeEnum;
    source: MapSourceEnum;
    storyMarkdownLangKeyList: Array<LangKeyType>;
    // nameLangKey: string;
    // playerList: Array<GamePlayerType>;
    // triggerEndGame: GameTriggerType;
    triggerList: Array<GameTriggerType>;
    unitList: Array<GameUnitType>;
    // version: number;
    // versionName: string;
}

export interface CompanyItemType {
    companyState: CompanyStateType;
    map: GameMapType;
}
