const botDifficultLocalStorageKey = "bot-difficult-1.0";

export function saveBotDifficult(botDifficult: BotDifficultEnum): void {
    localStorage.setItem(botDifficultLocalStorageKey, botDifficult);
}

export function getSavedBotDifficult(): BotDifficultEnum {
    return getEnumValueEnsure<BotDifficultEnum>(
        BotDifficultEnum,
        localStorage.getItem(botDifficultLocalStorageKey),
        BotDifficultEnum.easy
    );
}

function getMovedActionList(moveFrom: PointType, availableAction: GameAllActionsType): Array<MovedGameActionType> {
    const {
        attackUnitToBuildingPointList,
        attackUnitToUnitPointList,
        movePointList,
        raiseSkeletonPointList,
        canOccupyBuilding,
        canFixBuilding,
        unitId,
        movePathList,
        unitCurrentPoint,
        // moveOnAllyPointList,
        // canOpenStore,
    } = availableAction;
    const moveTo: PointType = unitCurrentPoint;
    const gameActionList: Array<MovedGameActionType> = [];

    attackUnitToBuildingPointList.forEach((point: PointType) => {
        gameActionList.push({
            gameAction: {
                actionType: GameActionTypeEnum.unitToBuildingAttack,
                addUnitList: [],
                briefing: null,
                buyUnitType: null,
                movePointList: [],
                toPoint: point,
                unitCurrentPoint,
                unitId,
            },
            moveFrom,
            movePathList,
            moveTo,
        });
    });

    attackUnitToUnitPointList.forEach((point: PointType) => {
        gameActionList.push({
            gameAction: {
                actionType: GameActionTypeEnum.unitToUnitAttack,
                addUnitList: [],
                briefing: null,
                buyUnitType: null,
                movePointList: [],
                toPoint: point,
                unitCurrentPoint,
                unitId,
            },
            moveFrom,
            movePathList,
            moveTo,
        });
    });

    raiseSkeletonPointList.forEach((point: PointType) => {
        gameActionList.push({
            gameAction: {
                actionType: GameActionTypeEnum.raiseSkeleton,
                addUnitList: [],
                briefing: null,
                buyUnitType: null,
                movePointList: [],
                toPoint: point,
                unitCurrentPoint,
                unitId,
            },
            moveFrom,
            movePathList,
            moveTo,
        });
    });

    movePointList.forEach((point: PointType) => {
        gameActionList.push({
            gameAction: {
                actionType: GameActionTypeEnum.unitMove,
                addUnitList: [],
                briefing: null,
                buyUnitType: null,
                movePointList: getMovePathFromToByPathList(unitCurrentPoint, point, movePathList),
                toPoint: point,
                unitCurrentPoint,
                unitId,
            },
            moveFrom,
            movePathList,
            moveTo: point,
        });
    });

    if (canOccupyBuilding) {
        gameActionList.push({
            gameAction: {
                actionType: GameActionTypeEnum.occupyBuilding,
                addUnitList: [],
                briefing: null,
                buyUnitType: null,
                movePointList: [],
                toPoint: unitCurrentPoint,
                unitCurrentPoint,
                unitId,
            },
            moveFrom,
            movePathList,
            moveTo,
        });
    }

    if (canFixBuilding) {
        gameActionList.push({
            gameAction: {
                actionType: GameActionTypeEnum.fixBuilding,
                addUnitList: [],
                briefing: null,
                buyUnitType: null,
                movePointList: [],
                toPoint: unitCurrentPoint,
                unitCurrentPoint,
                unitId,
            },
            moveFrom,
            movePathList,
            moveTo,
        });
    }

    return gameActionList;
}

export function getPointActionList(
    gameState: GameStateType,
    moveBackAction: GameActionType | null
): Array<MovedGameActionType> {
    // move every unit by each available action and get GameAllActionsType for each point
    const {unitList, activeGamePlayerId} = gameState;
    const playerUnitList: Array<GameUnitType> = getUnitListByPlayerId(activeGamePlayerId, unitList);
    const actionList: Array<MovedGameActionType> = [];

    playerUnitList.forEach((unitInList: GameUnitType) => {
        // get actions by current place
        // get move action list
        const hasAction = getHasUnitAvailableAction(unitInList, gameState, moveBackAction);

        if (!hasAction) {
            return;
        }

        const actionByCurrentPlace: GameAllActionsType = getUnitAvailableActionsData(
            unitInList,
            gameState,
            moveBackAction
        );
        const {movePointList, movePathList} = actionByCurrentPlace;

        const unitAllActionList: Array<GameAllActionsType> = [actionByCurrentPlace];

        movePointList.forEach((availableUnitPoint: PointType) => {
            const isolatedUnit: GameUnitType = {
                ...unitInList,
                movedCount: unitInList.movedCount + 1,
                x: availableUnitPoint.x,
                y: availableUnitPoint.y,
            };
            const isolatedUnitList: Array<GameUnitType> = [...unitList];

            const indexInUnitInList: number = isolatedUnitList.indexOf(unitInList);

            if (indexInUnitInList < 0) {
                console.error("can get index unit in list", unitInList);
                return;
            }

            isolatedUnitList[indexInUnitInList] = isolatedUnit;

            const isolatedGameState: GameStateType = {
                ...gameState,
                unitList: isolatedUnitList,
            };

            if (getUnitOverUnit(isolatedUnitList)) {
                return;
            }

            const actionByMovePoint: GameAllActionsType = getUnitAvailableActionsData(
                isolatedUnit,
                isolatedGameState,
                moveBackAction
            );

            unitAllActionList.push({
                ...actionByMovePoint,
                movePathList,
            });
        });

        const moveFrom: PointType = {x: unitInList.x, y: unitInList.y};

        unitAllActionList.forEach((unitPointActionInList: GameAllActionsType) => {
            const pushedActionList: Array<MovedGameActionType> = getMovedActionList(moveFrom, unitPointActionInList);

            actionList.push(...pushedActionList);
        });

        // add move to current position, i.e. - stay on current place
        actionList.push({
            gameAction: {
                actionType: GameActionTypeEnum.unitMove,
                addUnitList: [],
                briefing: null,
                buyUnitType: null,
                movePointList: getMovePathFromToByPathList(moveFrom, moveFrom, movePathList),
                toPoint: moveFrom,
                unitCurrentPoint: moveFrom,
                unitId: unitInList.unitId,
            },
            moveFrom,
            movePathList,
            moveTo: moveFrom,
        });
    });

    return actionList;
}

export function getIsOnBuilding(
    unitToRate: Readonly<GameUnitType>,
    moveToPoint: PointType,
    gameState: Readonly<GameStateType>
): MovedActionOnBuildingStateType {
    const defaultResult: MovedActionOnBuildingStateType = {
        isOnAvailableToOccupyBuilding: false,
        isOnEnemyBuilding: false,
        isOnHealsBuilding: false,
        isOnSelfBuilding: false,
        isOnTeamBuilding: false,
    } as const;

    const building = getBuildingByPoint(moveToPoint, gameState.buildingList);

    if (!building) {
        return defaultResult;
    }

    if (getBuildingInfo(building).canHealthAll) {
        return {
            ...defaultResult,
            isOnHealsBuilding: true,
        };
    }

    if (building.gamePlayerId === unitToRate.gamePlayerId) {
        return {
            ...defaultResult,
            isOnSelfBuilding: true,
        };
    }

    if (
        getTeamIdByPlayerId(building.gamePlayerId, gameState.playerList) ===
        getTeamIdByPlayerId(unitToRate.gamePlayerId, gameState.playerList)
    ) {
        return {
            ...defaultResult,
            isOnTeamBuilding: true,
        };
    }

    if (building.gamePlayerId === GamePlayerIdEnum.playerEmpty) {
        return {
            ...defaultResult,
            isOnAvailableToOccupyBuilding: true,
        };
    }

    return {
        ...defaultResult,
        isOnEnemyBuilding: true,
    };
}

// Key a tile for the threat / distance maps.
function getThreatKey(point: PointType): string {
    return `${point.x}/${point.y}`;
}

type UnitAvailableMoveType = Pick<GameAllActionsType, "moveOnAllyPointList" | "movePathList" | "movePointList">;

/*
 * One bot evaluation asks for the same enemy's reachable squares several times (threat map,
 * building-sitter penalty, occupation-prevention scan), each time with the enemy isolated on the board.
 * The result only depends on the game state and the enemy, so it is memoized per state object: every
 * action produces a fresh state, which naturally invalidates the cache.
 */
const enemyIsolatedMoveCache = new WeakMap<GameStateType, Map<string, UnitAvailableMoveType>>();

export function getEnemyIsolatedAvailableMove(
    enemyUnit: GameUnitType,
    gameState: GameStateType
): UnitAvailableMoveType {
    const cacheByUnitId: Map<string, UnitAvailableMoveType> =
        enemyIsolatedMoveCache.get(gameState) ?? new Map<string, UnitAvailableMoveType>();

    enemyIsolatedMoveCache.set(gameState, cacheByUnitId);

    const cachedMove: UnitAvailableMoveType | undefined = cacheByUnitId.get(enemyUnit.unitId);

    if (cachedMove) {
        return cachedMove;
    }

    const availableMove: UnitAvailableMoveType = getUnitAvailableMove(enemyUnit, {
        ...gameState,
        unitList: [enemyUnit],
    });

    cacheByUnitId.set(enemyUnit.unitId, availableMove);

    return availableMove;
}

interface DistanceQueueType {
    bucketList: Array<Array<PointType>>;
    distanceGrid: Array<Array<number>>;
}

// Relax the four neighbours of `point`: walking from a neighbour onto `point` costs the terrain under
// `point`, so a neighbour whose known distance is longer gets updated and queued into its bucket.
function relaxNeighbourList(point: PointType, costGrid: Array<Array<number>>, queue: DistanceQueueType): void {
    const {bucketList, distanceGrid} = queue;
    const distance: number = distanceGrid[point.y]?.[point.x] ?? Number.POSITIVE_INFINITY;
    const stepCost: number = costGrid[point.y]?.[point.x] ?? Number.POSITIVE_INFINITY;

    const neighbourList: Array<PointType> = [
        {x: point.x, y: point.y - 1},
        {x: point.x, y: point.y + 1},
        {x: point.x - 1, y: point.y},
        {x: point.x + 1, y: point.y},
    ];

    for (const neighbour of neighbourList) {
        const neighbourLine = distanceGrid[neighbour.y];
        const knownDistance: number = neighbourLine?.[neighbour.x] ?? Number.NEGATIVE_INFINITY;
        const updatedDistance: number = distance + stepCost;

        if (neighbourLine && updatedDistance < knownDistance) {
            neighbourLine[neighbour.x] = updatedDistance;

            const targetBucket: Array<PointType> = bucketList[updatedDistance] ?? [];

            bucketList[updatedDistance] = targetBucket;
            targetBucket.push(neighbour);
        }
    }
}

// Travel cost from every tile to the target over the real terrain costs of the unit's move type.
// Blocking by units is deliberately ignored: the field guides multi-turn marches, and units drift away.
function computeDistanceField(targetPoint: PointType, costGrid: Array<Array<number>>): Map<string, number> {
    const distanceGrid: Array<Array<number>> = costGrid.map<Array<number>>((line: Array<number>): Array<number> => {
        return line.map<number>((): number => {
            return Number.POSITIVE_INFINITY;
        });
    });

    const targetLine = distanceGrid[targetPoint.y];

    if (!targetLine || typeof targetLine[targetPoint.x] !== "number") {
        console.error(`computeDistanceField: target is out of the map: ${JSON.stringify(targetPoint)}`);
        return new Map<string, number>();
    }

    targetLine[targetPoint.x] = 0;

    // Dijkstra with a bucket queue: step costs are small integers, so buckets are indexed by distance.
    const bucketList: Array<Array<PointType>> = [[targetPoint]];
    const queue: DistanceQueueType = {bucketList, distanceGrid};

    for (let distance = 0; distance < bucketList.length; distance += 1) {
        const bucket: Array<PointType> = bucketList[distance] ?? [];

        for (const point of bucket) {
            // skip an outdated queue entry, a shorter path was found already
            if (distanceGrid[point.y]?.[point.x] === distance) {
                relaxNeighbourList(point, costGrid, queue);
            }
        }
    }

    const fieldMap = new Map<string, number>();

    distanceGrid.forEach((line: Array<number>, y: number) => {
        line.forEach((distance: number, x: number) => {
            fieldMap.set(getThreatKey({x, y}), distance);
        });
    });

    return fieldMap;
}

// Distance fields per (move type, target) computed within one bot evaluation; the per-state WeakMap
// key means a fresh state after every action naturally drops stale fields.
const distanceFieldCache = new WeakMap<GameStateType, Map<string, Map<string, number>>>();

function getDistanceField(targetPoint: PointType, unit: GameUnitType, gameState: GameStateType): Map<string, number> {
    const {moveType} = getUnitInfoByUnit(unit);
    const fieldKey = `${moveType}:${targetPoint.x}/${targetPoint.y}`;
    const cacheByFieldKey: Map<string, Map<string, number>> = distanceFieldCache.get(gameState) ??
    new Map<string, Map<string, number>>();

    distanceFieldCache.set(gameState, cacheByFieldKey);

    const cachedField: Map<string, number> | undefined = cacheByFieldKey.get(fieldKey);

    if (cachedField) {
        return cachedField;
    }

    const costGrid: Array<Array<number>> = landscapeToNumbers(unit, gameState.landscape, gameState.buildingList, []);
    const field: Map<string, number> = computeDistanceField(targetPoint, costGrid);

    cacheByFieldKey.set(fieldKey, field);

    return field;
}

/*
 * The real travel cost between two tiles for the given unit: unlike a straight-line estimate it respects
 * the terrain (forests and hills slow a walker down, water nearly stops it), so the bot picks targets it
 * can actually reach quickly instead of ones that are close only as the crow flies.
 */
// eslint-disable-next-line @typescript-eslint/max-params
export function getBotPathDistance(
    fromPoint: PointType,
    targetPoint: PointType,
    unit: GameUnitType,
    gameState: GameStateType
): number {
    const field: Map<string, number> = getDistanceField(targetPoint, unit, gameState);

    return field.get(getThreatKey(fromPoint)) ?? getStepsBetweenPoints(fromPoint, targetPoint);
}

// `onlyHealBuilding` narrows the danger to enemies fortified on a HEALING building specifically (they
// also heal every turn, so trading into them is the worst) — used by the attack picker; the default
// (false) keeps the broader heal/own/team coverage the move rating has always avoided.
export function getLowPriorityPointList(gameState: GameStateType, onlyHealBuilding = false): Array<PointType> {
    const lowPriorityPointList: Array<PointType> = [];

    const enemyUnitList: Array<GameUnitType> = getEnemyUnitListByPlayerId(
        gameState.activeGamePlayerId,
        gameState.playerList,
        gameState.unitList
    );

    enemyUnitList.forEach((enemyUnit: GameUnitType) => {
        const enemyUnitInfo = getUnitInfoByUnit(enemyUnit);
        const fromPointAttackList: Array<PointType> = [];

        if (enemyUnitInfo.canAttackAfterMove) {
            const {moveOnAllyPointList} = getEnemyIsolatedAvailableMove(enemyUnit, gameState);

            fromPointAttackList.push(...moveOnAllyPointList, {x: enemyUnit.x, y: enemyUnit.y});
        } else {
            fromPointAttackList.push({x: enemyUnit.x, y: enemyUnit.y});
        }

        const enemyOnBuildingPointList: Array<PointType> = fromPointAttackList.filter<PointType>(
            (pointToMove: PointType): pointToMove is PointType => {
                const {isOnHealsBuilding, isOnSelfBuilding, isOnTeamBuilding} = getIsOnBuilding(
                    enemyUnit,
                    pointToMove,
                    gameState
                );

                if (onlyHealBuilding) {
                    return isOnHealsBuilding;
                }

                return isOnHealsBuilding || isOnSelfBuilding || isOnTeamBuilding;
            }
        );

        enemyOnBuildingPointList.forEach((pointFromAttack: PointType) => {
            const dangerPointList: Array<PointType> = getUnitAllAvailableAttackPointList(
                {
                    ...enemyUnit,
                    ...pointFromAttack,
                },
                gameState
            );

            lowPriorityPointList.push(...dangerPointList);
        });
    });

    return lowPriorityPointList;
}

/*
 * Expected incoming pressure on every tile: for each enemy, how hard it hits (attack.max) added to
 * every square it can strike this turn (from where it stands, plus every move-then-attack square for
 * units that can attack after moving). Contributions from different enemies stack, so a square covered
 * by concentrated or high-damage fire scores far higher than one grazed by a single weak unit.
 *
 * The bot uses this to avoid stepping into fire without a reason: the penalty is damage-scaled, so a
 * chip threat barely registers while a kill-zone is strongly repelled, and — because it varies per
 * tile — it also breaks ties toward the least-exposed square when a unit is boxed in with no safe move.
 */
export function getThreatMap(gameState: GameStateType): Map<string, number> {
    const threatMap = new Map<string, number>();
    const enemyUnitList: Array<GameUnitType> = getEnemyUnitListByPlayerId(
        gameState.activeGamePlayerId,
        gameState.playerList,
        gameState.unitList
    );

    enemyUnitList.forEach((enemyUnit: GameUnitType) => {
        // Enemies entrenched on a healing / own / team building already have a dedicated, precise penalty
        // (getLowPriorityPointList). Skip them here so their threat is not double-counted, which would
        // otherwise push the bot to hang back further than that tuned building-sitter zone.
        const {isOnHealsBuilding, isOnSelfBuilding, isOnTeamBuilding} = getIsOnBuilding(
            enemyUnit,
            {x: enemyUnit.x, y: enemyUnit.y},
            gameState
        );

        if (isOnHealsBuilding || isOnSelfBuilding || isOnTeamBuilding) {
            return;
        }

        const enemyUnitInfo = getUnitInfoByUnit(enemyUnit);
        const fromPointList: Array<PointType> = [{x: enemyUnit.x, y: enemyUnit.y}];

        if (enemyUnitInfo.canAttackAfterMove) {
            const {moveOnAllyPointList} = getEnemyIsolatedAvailableMove(enemyUnit, gameState);

            fromPointList.push(...moveOnAllyPointList);
        }

        // Count each enemy at most once per tile, even if it can reach that tile from several squares.
        const countedKeySet = new Set<string>();

        fromPointList.forEach((fromPoint: PointType) => {
            const coveredPointList: Array<PointType> = getUnitAllAvailableAttackPointList(
                {...enemyUnit, ...fromPoint},
                gameState
            );

            coveredPointList.forEach((coveredPoint: PointType) => {
                const key: string = getThreatKey(coveredPoint);

                if (countedKeySet.has(key)) {
                    return;
                }

                countedKeySet.add(key);
                threatMap.set(key, (threatMap.get(key) ?? 0) + enemyUnitInfo.attack.max);
            });
        });
    });

    return threatMap;
}

// Incoming pressure on a single tile (0 when nothing threatens it).
export function getThreatAtPoint(point: PointType, threatMap: Map<string, number>): number {
    return threatMap.get(getThreatKey(point)) ?? 0;
}

export function getBotDifficultMap(
    botDifficultRaw?: BotDifficultEnum
): Record<"isBotEasy" | "isBotHard" | "isBotNormal", boolean> {
    // TODO: remove me in future, current date is 2024-12-22, should be like this -> `playerDifficulty: BotDifficultEnum`
    const botDifficult: BotDifficultEnum = getEnumValueEnsure<BotDifficultEnum>(
        BotDifficultEnum,
        botDifficultRaw,
        getSavedBotDifficult()
    );

    return {
        isBotEasy: botDifficult === BotDifficultEnum.easy,
        isBotHard: botDifficult === BotDifficultEnum.hard,
        isBotNormal: botDifficult === BotDifficultEnum.normal,
    };
}

// XOR-fold a list of numbers into a 32-bit seed for getPseudoRandomNumber; the prime multipliers keep
// close inputs (x vs x+1, neighbouring tiles) from colliding.
export function getSeedFromNumberList(numberList: Array<number>): number {
    const primeList: Array<number> = [73_856_093, 19_349_663, 83_492_791, 2_654_435_761, 40_503];

    /* eslint-disable no-bitwise */
    let seed = 0;

    numberList.forEach((value: number, index: number) => {
        seed ^= Math.imul(value + 1, primeList[index % primeList.length] ?? 1);
    });

    return seed >>> 0;
    /* eslint-enable no-bitwise */
}

export function getStringCharSum(value: string): number {
    let charSum = 0;

    for (let charIndex = 0; charIndex < value.length; charIndex += 1) {
        charSum += value.charCodeAt(charIndex);
    }

    return charSum;
}
