import {type JSX, useMemo} from "react";
import {useScreenSize} from "react-system-hook";

import {fightAnimationViewSize} from "../../../../../layout/unit-fight-animation/unit-fight-animation-const";
import {getFightAnimationScale} from "../../../../../layout/unit-fight-animation/unit-fight-animation-helper";
import {getBuildingByPoint} from "../../../../../model/game/building/building-helper";
import {getEffectiveTileTheme, getLandscapeByPoint} from "../../../../../model/game/landscape/landscape-helper";
import {GameLandscapeItemEnum} from "../../../../../model/game/landscape/landscape-type";
import type {PointType} from "../../../../../model/game/point/point-type";
import type {SizeType} from "../../../../../model/map/map-type";
import {useGameContext} from "../../../../../provider/game/game-context";
import {resolveLandscapeThemeOverride} from "../../../../../provider/setting/landscape-theme-override-helper";
import {useSettingContext} from "../../../../../provider/setting/setting-context";
import * as clientGameUnitFightFieldStyle from "./client-game-unit-fight-field.scss";
import {
    getBuildingUnitFightAnimationImage,
    getTerraUnitFightAnimationImage,
} from "./client-game-unit-fight-field-const";

interface ClientGameUnitFightFieldPropsType {
    readonly isRight: boolean;
    readonly point: PointType;
}

export function ClientGameUnitFightField(props: ClientGameUnitFightFieldPropsType): JSX.Element {
    const {isRight, point} = props;
    const {gameState} = useGameContext();
    const {
        setting: {landscapeThemeOverride},
    } = useSettingContext();
    const {landscape, buildingList} = gameState;
    const screenSize: SizeType = useScreenSize();
    const scale = getFightAnimationScale(screenSize);
    const terraType = getLandscapeByPoint(point, landscape) ?? GameLandscapeItemEnum.rd0;
    const isBuilding = Boolean(getBuildingByPoint(point, buildingList));
    const theme = getEffectiveTileTheme(
        point,
        gameState.landscapeThemeMap,
        resolveLandscapeThemeOverride(gameState.mapId, landscapeThemeOverride)
    );

    const firstImageStyle = {
        transform: `scale(${scale})`,
        width: `${fightAnimationViewSize.width / 2}px`,
        zIndex: 1,
    };
    const secondImageStyle = {
        transform: `scale(${scale}) translateY(74%)`,
        width: `${fightAnimationViewSize.width / 2}px`,
        zIndex: 0,
    };

    const backgroundImageSrc: string = useMemo((): string => {
        return isBuilding
            ? getBuildingUnitFightAnimationImage(theme)
            : getTerraUnitFightAnimationImage(theme, terraType);
    }, [isBuilding, terraType, theme]);

    return (
        <div
            className={
                isRight
                    ? clientGameUnitFightFieldStyle.client_game_unit_fight_field__right
                    : clientGameUnitFightFieldStyle.client_game_unit_fight_field
            }
        >
            <img
                alt="background"
                className={clientGameUnitFightFieldStyle.client_game_unit_fight_field_image}
                src={backgroundImageSrc}
                style={firstImageStyle}
            />
            <img
                alt="background"
                className={clientGameUnitFightFieldStyle.client_game_unit_fight_field_image}
                src={backgroundImageSrc}
                style={secondImageStyle}
            />
        </div>
    );
}
