import {type JSX, type ReactNode, useCallback} from "react";

import {usePlayClick} from "../../media/play-media";
import {Locale} from "../../provider/locale/locale-context";
import type {LangKeyType} from "../../provider/locale/translation/type";
import {cls} from "../../util/css";
import {throwError} from "../../util/error";
import {useHotKey, type UseHotKeyArgumentType} from "../../util/use-hot-key";
import * as uiButtonStyle from "./ui-button.scss";

interface UiButtonPropsType {
    readonly children?: ReactNode;

    readonly className?: string;
    readonly dataTestId?: string;
    readonly iconSrc?: string;
    readonly iconSrcClassName?: string;
    readonly iconSrcBackground?: string;
    readonly isActive?: boolean;
    readonly isDisabled?: boolean;
    readonly isSquared?: boolean;
    readonly isTextToCenter?: boolean;
    readonly langKey?: LangKeyType;
    readonly onClick: () => unknown;
    readonly hotKey?: Omit<UseHotKeyArgumentType, "handleHotKey">;
}

export function UiButton(props: UiButtonPropsType): JSX.Element {
    const {play: playClick} = usePlayClick();
    const {
        isActive,
        isTextToCenter,
        onClick,
        isDisabled,
        iconSrc,
        iconSrcClassName,
        iconSrcBackground,
        langKey,
        children,
        isSquared,

        className,
        dataTestId,
        hotKey = {
            code: "",
            isCheckActiveInput: false,
            isEnable: false,
            isShowLog: false,
            modifierList: [],
        },
    } = props;

    const handleOnClick = useCallback(() => {
        Promise.all([playClick(), onClick()]).catch(throwError);
    }, [onClick, playClick]);

    useHotKey({...hotKey, handleHotKey: handleOnClick});

    return (
        <button
            className={cls(
                uiButtonStyle.ui_button,
                {
                    [uiButtonStyle.ui_button__disabled]: isDisabled,
                    [uiButtonStyle.ui_button__squared]: isSquared,
                    [uiButtonStyle.ui_button__with_image]: iconSrc,
                    [uiButtonStyle.ui_button__active]: isActive,
                    // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
                    [uiButtonStyle.ui_button__squared__image_only]: !children && !langKey,
                },
                className
            )}
            data-testid={dataTestId}
            onClick={handleOnClick}
            title={[hotKey.code, ...(hotKey.modifierList ?? [])].join("+")}
            type="button"
        >
            {
                // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
                iconSrcBackground ? (
                    <img
                        alt={langKey}
                        className={cls(uiButtonStyle.ui_button__icon__background)}
                        src={iconSrcBackground}
                    />
                ) : null
            }
            {
                // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
                iconSrc ? (
                    <img alt={langKey} className={cls(uiButtonStyle.ui_button__icon, iconSrcClassName)} src={iconSrc} />
                ) : null
            }
            <span
                className={cls(uiButtonStyle.ui_button__text, {
                    [uiButtonStyle.ui_button__text__align_center]: isTextToCenter,
                })}
            >
                {langKey ? <Locale stringKey={langKey} /> : null}
                {children}
            </span>
        </button>
    );
}
