import {type JSX, useEffect, useMemo, useRef} from "react";

import {appRoute} from "../../../app/app-route";
import {serviceStyle} from "../../../css/style";
import {Page} from "../../../layout/page/page";
import * as pageStyle from "../../../layout/page/page.scss";
import {uiButtonImage} from "../../../layout/ui-button/image/ui-button-image";
import {UiLink} from "../../../layout/ui-button/ui-link";
import {usePlayTitleTheme} from "../../../media/play-media";
import {useDevModeContext} from "../../../provider/dev-mode/dev-mode-context";
import {useGameContext} from "../../../provider/game/game-context";
import {testId} from "../../../test-id";
import {cls} from "../../../util/css";
import * as clientHomeStyle from "./client-home.scss";
import logoImage from "./image/logo.png";

export function ClientHome(): JSX.Element {
    const {resetState} = useGameContext();
    const {isDevModeEnable, setIsDevModeEnable} = useDevModeContext();
    const devModeClickCounter = useRef<number>(0);

    usePlayTitleTheme();

    useEffect(resetState, [resetState]);

    const imageLogo: JSX.Element = useMemo(() => {
        if (isDevModeEnable) {
            return <img alt="logo" className={clientHomeStyle.logo_image__dev_mode_enabled} src={logoImage} />;
        }

        return (
            // eslint-disable-next-line jsx-a11y/no-noninteractive-element-interactions ,jsx-a11y/click-events-have-key-events
            <img
                alt="logo"
                className={clientHomeStyle.logo_image}
                onClick={() => {
                    devModeClickCounter.current += 1;
                    if (devModeClickCounter.current > 20) {
                        setIsDevModeEnable(true);
                    }
                }}
                src={logoImage}
            />
        );
    }, [isDevModeEnable, setIsDevModeEnable]);

    return (
        <Page
            className={cls(
                serviceStyle.double_block_wrapper,
                pageStyle.page__background_image__magical_castle_fantasy_landscape
            )}
        >
            <div className={serviceStyle.double_block_child}>{imageLogo}</div>
            <div className={serviceStyle.double_block_child}>
                <div className={serviceStyle.double_block_child__button_wrapper} data-testid={testId.homePage.root}>
                    <UiLink
                        dataTestId={testId.homePage.playButton}
                        href={appRoute.play.path}
                        iconSrc={uiButtonImage.sword.src}
                        langKey="UI__BUTTON__PLAY"
                    />
                    <UiLink
                        dataTestId={testId.homePage.settingsButton}
                        href={appRoute.settings.path}
                        iconSrc={uiButtonImage.hammer.src}
                        langKey="UI__BUTTON__SETTINGS"
                    />
                    <UiLink
                        dataTestId={testId.homePage.mapEditorButton}
                        href={appRoute.mapEditor.path}
                        iconSrc={uiButtonImage.earth.src}
                        langKey="UI__BUTTON__MAP_EDITOR"
                    />
                    <UiLink
                        dataTestId={testId.homePage.instructionsButton}
                        href={appRoute.instructions.path}
                        iconSrc={uiButtonImage.book.src}
                        langKey="UI__BUTTON__INSTRUCTIONS"
                    />
                    <UiLink
                        dataTestId={testId.homePage.aboutButton}
                        href={appRoute.about.path}
                        iconSrc={uiButtonImage.info.src}
                        langKey="UI__BUTTON__ABOUT"
                    />
                </div>
            </div>
        </Page>
    );
}
