export enum GameLandscapeItemEnum {
    br0 = "bridge0",
    br1 = "bridge1",
    fr0 = "forest0",
    fr1 = "forest1",
    hl0 = "hill0",
    rd0 = "road0",
    st0 = "stone0",
    tr0 = "terra0",
    tr1 = "terra1",
    tr2 = "terra2",
    tr3 = "terra3",
    tr4 = "terra4",
    wt0 = "water0",
    wt1 = "water1",
    wt2 = "water2",
}

export type GameLandscapeType = Array<Array<GameLandscapeItemEnum>>;

export enum GameLandscapeThemeEnum {
    ae1 = "ae1",
    ae2 = "ae2",
    desert = "desert",
    summer = "summer",
    summer2 = "summer2",
}

// The visual theme of every landscape tile. Runs in parallel with GameLandscapeType and shares its dimensions.
// A missing map/cell defaults to the ae2 theme, keeping saved games backward compatible.
export type GameLandscapeThemeMapType = Array<Array<GameLandscapeThemeEnum>>;

export const defaultLandscapeTheme: GameLandscapeThemeEnum = GameLandscapeThemeEnum.ae2;
