import type {JSX} from "react";

import {squareSize} from "../../../../../css/style";
import {
    getEffectiveTileTheme,
    getIsDynamicWater,
    getLandscapeByPoint,
    getLandscapePointList,
} from "../../../../../model/game/landscape/landscape-helper";
import {
    GameLandscapeThemeEnum,
    type GameLandscapeThemeMapType,
    type GameLandscapeType,
} from "../../../../../model/game/landscape/landscape-type";
import type {PointType} from "../../../../../model/game/point/point-type";
import {arrayShuffle} from "../../../../../util/array";
import * as clientGameUnitItemStyle from "../../client-game-unit/client-game-unit-item/client-game-unit-item.scss";
import * as clientGameLandscapeStyle from "../client-game-landscape.scss";
import {getLandscapeImage} from "../image/landscape-image";

interface ClientGameLandscapeWaterPropsType {
    readonly landscape: GameLandscapeType;
    readonly landscapeThemeMap?: GameLandscapeThemeMapType | undefined;
    readonly themeOverride: GameLandscapeThemeEnum | null;
}

export function ClientGameLandscapeWater(props: ClientGameLandscapeWaterPropsType): JSX.Element {
    const {landscape, landscapeThemeMap, themeOverride} = props;

    const pointList = getLandscapePointList(landscape);

    return (
        <div className={clientGameLandscapeStyle.landscape_water_layer}>
            {pointList.map<JSX.Element | null>((point: PointType): JSX.Element | null => {
                const landscapeByPoint = getLandscapeByPoint(point, landscape);
                // The theme lives per cell (campaign maps carry their own landscapeThemeMap while
                // themeOverride stays null), so dynamic-water detection must use the tile theme,
                // same as the landscape canvas does.
                const tileTheme = getEffectiveTileTheme(point, landscapeThemeMap, themeOverride);
                const isAe1Theme = tileTheme === GameLandscapeThemeEnum.ae1;

                const themeImage = getLandscapeImage(tileTheme);
                const [water0, water1] = isAe1Theme
                    ? [themeImage.water1.src, themeImage.water2.src]
                    : arrayShuffle<string>([themeImage.water1.src, themeImage.water2.src]);

                // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
                if (!landscapeByPoint || !getIsDynamicWater(landscapeByPoint, tileTheme)) {
                    return null;
                }

                return (
                    <div
                        className={clientGameLandscapeStyle.landscape_water_layer__square}
                        key={`x-${point.x}-y-${point.y}`}
                        style={{
                            left: point.x * squareSize,
                            top: point.y * squareSize,
                        }}
                    >
                        <div className={clientGameUnitItemStyle.water_image_wrapper}>
                            <img alt="water" className={clientGameUnitItemStyle.unit_image} src={water0} />
                            <img alt="water" className={clientGameUnitItemStyle.unit_image} src={water1} />
                        </div>
                    </div>
                );
            })}
        </div>
    );
}
