import {hasListInList} from "../../../util/array";
import {getMapById} from "../../map/map-helper";
import type {GameMapType} from "../../map/map-type";
import {getBuildingInfo, getBuildingListByPlayerIdAndType, getStoreListByPlayerId} from "../building/building-helper";
import {type GameBuildingType, GameBuildingTypeEnum} from "../building/building-type";
import type {GameStateType} from "../game-type";
import {getEnemyUnitListByPlayerId, getPlayerByPlayerId, getPlayerHeroList} from "../player/player-helper";
import {getUnitListByPlayerId} from "../unit/unit-helper";
import type {GameUnitType} from "../unit/unit-type";
import {getIsPointOnPlace} from "./trigger-helper";
import {
    GameTriggerConditionEnum,
    type GameTriggerType,
    type TriggerCallbackArgumentType,
    type TriggerCallbackType,
} from "./trigger-type";

export const triggerConditionMap: Record<GameTriggerConditionEnum, TriggerCallbackType> = {
    [GameTriggerConditionEnum.allHeroesDied]: (triggerArgument: TriggerCallbackArgumentType): boolean => {
        const {gameState, trigger} = triggerArgument;
        return getPlayerHeroList(trigger.forPlayerId, gameState.unitList).length === 0;
    },
    [GameTriggerConditionEnum.anyHeroDied]: (triggerArgument: TriggerCallbackArgumentType): boolean => {
        const {gameState, trigger} = triggerArgument;
        const map: GameMapType | null = getMapById(gameState.mapId);
        const initialHeroCount: number = map ? getPlayerHeroList(trigger.forPlayerId, map.unitList).length : 0;

        // Defeat as soon as the player has fewer heroes alive than the mission started with.
        return getPlayerHeroList(trigger.forPlayerId, gameState.unitList).length < initialHeroCount;
    },
    [GameTriggerConditionEnum.oneHeroLivesOnly]: (triggerArgument: TriggerCallbackArgumentType): boolean => {
        const {gameState, trigger} = triggerArgument;
        return getPlayerHeroList(trigger.forPlayerId, gameState.unitList).length === 1;
    },
    [GameTriggerConditionEnum.unitOnRectanglePlace]: (triggerArgument: TriggerCallbackArgumentType): boolean => {
        const {gameState, trigger} = triggerArgument;
        const unitByPlayer: Array<GameUnitType> = getUnitListByPlayerId(trigger.forPlayerId, gameState.unitList);

        return unitByPlayer.some((unitInList: GameUnitType): boolean => {
            return getIsPointOnPlace(unitInList, trigger.placeList);
        });
    },
    [GameTriggerConditionEnum.skirmishDefeat]: (triggerArgument: TriggerCallbackArgumentType): boolean => {
        const {gameState, trigger} = triggerArgument;
        const isAllHeroesDie: boolean = getPlayerHeroList(trigger.forPlayerId, gameState.unitList).length === 0;
        const hasNoCastle: boolean = getStoreListByPlayerId(trigger.forPlayerId, gameState.buildingList).length === 0;

        return isAllHeroesDie && hasNoCastle;
    },
    [GameTriggerConditionEnum.allEnemyUnitDiedAndHasAllCastles]: (
        triggerArgument: TriggerCallbackArgumentType
    ): boolean => {
        const {gameState, trigger} = triggerArgument;
        const storeByPlayerIdList: Array<GameBuildingType> = getStoreListByPlayerId(
            trigger.forPlayerId,
            gameState.buildingList
        );
        const allStoryList: Array<GameBuildingType> = gameState.buildingList.filter<GameBuildingType>(
            (building: GameBuildingType): building is GameBuildingType => {
                return getBuildingInfo(building).canBeStore;
            }
        );

        const hasAllCastle: boolean = storeByPlayerIdList.length === allStoryList.length;
        const enemyUnitList: Array<GameUnitType> = getEnemyUnitListByPlayerId(
            trigger.forPlayerId,
            gameState.playerList,
            gameState.unitList
        );
        const isAllEnemyUnitDied: boolean = enemyUnitList.length === 0;

        return hasAllCastle && isAllEnemyUnitDied;
    },
    [GameTriggerConditionEnum.allEnemyUnitDied]: (triggerArgument: TriggerCallbackArgumentType): boolean => {
        const {gameState, trigger} = triggerArgument;
        return getEnemyUnitListByPlayerId(trigger.forPlayerId, gameState.playerList, gameState.unitList).length === 0;
    },
    [GameTriggerConditionEnum.turnCount]: (triggerArgument: TriggerCallbackArgumentType): boolean => {
        const {gameState, trigger} = triggerArgument;
        return trigger.turnCount === gameState.stepCount;
    },
    [GameTriggerConditionEnum.anyUnitDied]: (triggerArgument: TriggerCallbackArgumentType): boolean => {
        const {gameState, prevGameState} = triggerArgument;
        return prevGameState.unitList.length > gameState.unitList.length;
    },
    [GameTriggerConditionEnum.unitDied]: (triggerArgument: TriggerCallbackArgumentType): boolean => {
        const {gameState, prevGameState, trigger} = triggerArgument;
        const unitList = getUnitListByPlayerId(trigger.forPlayerId, gameState.unitList);
        const prevUnitList = getUnitListByPlayerId(trigger.forPlayerId, prevGameState.unitList);

        return prevUnitList.length > unitList.length;
    },
    [GameTriggerConditionEnum.occupyCastle]: (triggerArgument: TriggerCallbackArgumentType): boolean => {
        const {gameState, prevGameState, trigger} = triggerArgument;
        const castleList = getBuildingListByPlayerIdAndType(
            trigger.forPlayerId,
            GameBuildingTypeEnum.castle,
            gameState.buildingList
        );
        const prevCastleList = getBuildingListByPlayerIdAndType(
            trigger.forPlayerId,
            GameBuildingTypeEnum.castle,
            prevGameState.buildingList
        );

        return castleList.length > prevCastleList.length;
    },
    [GameTriggerConditionEnum.occupyFarm]: (triggerArgument: TriggerCallbackArgumentType): boolean => {
        const {gameState, prevGameState, trigger} = triggerArgument;
        const farmList = getBuildingListByPlayerIdAndType(
            trigger.forPlayerId,
            GameBuildingTypeEnum.farm,
            gameState.buildingList
        );
        const prevFarmList = getBuildingListByPlayerIdAndType(
            trigger.forPlayerId,
            GameBuildingTypeEnum.farm,
            prevGameState.buildingList
        );

        return farmList.length > prevFarmList.length;
    },
    [GameTriggerConditionEnum.trainNewUnit]: (triggerArgument: TriggerCallbackArgumentType): boolean => {
        const {gameState, prevGameState, trigger} = triggerArgument;
        const unitList = getUnitListByPlayerId(trigger.forPlayerId, gameState.unitList);
        const prevUnitList = getUnitListByPlayerId(trigger.forPlayerId, prevGameState.unitList);

        const playerMoney: number = getPlayerByPlayerId(trigger.forPlayerId, gameState.playerList)?.money ?? 0;
        const prevPlayerMoney: number = getPlayerByPlayerId(trigger.forPlayerId, prevGameState.playerList)?.money ?? 0;

        const isUnitCountIncreased: boolean = unitList.length > prevUnitList.length;
        const isMoneyDecreased: boolean = prevPlayerMoney > playerMoney;

        return isUnitCountIncreased && isMoneyDecreased;
    },
} as const;

export function getSuitTriggerList(
    gameStateMap: Record<"gameState" | "prevGameState", GameStateType>
): Array<GameTriggerType> {
    const {gameState, prevGameState} = gameStateMap;
    const {mapId, doneTriggerIsList} = gameState;

    const map: GameMapType | null = getMapById(mapId);

    if (!map) {
        console.error(`can not get map by id: ${mapId}`);
        return [];
    }

    const {triggerList} = map;

    return triggerList.filter<GameTriggerType>((trigger: GameTriggerType): trigger is GameTriggerType => {
        const {conditionName, triggerId, dependentTriggerIdList} = trigger;

        if (doneTriggerIsList.includes(triggerId)) {
            return false;
        }

        // All dependentTriggerIdList should be done
        if (!hasListInList({big: doneTriggerIsList, small: dependentTriggerIdList})) {
            return false;
        }

        return triggerConditionMap[conditionName]({gameState, prevGameState, trigger});
    });
}
