export const emptySprite: SpriteType = {
    height: 1,
    imgSrc: getImage(emptyPixel).src,
    offsetLeft: 0,
    offsetTop: 0,
    scaleX: 1,
    scaleY: 1,
    width: 1,
};

function getSprite(imgSrc: string, height: number, width: number): SpriteType {
    return {
        height,
        imgSrc: getImage(imgSrc).src,
        offsetLeft: 0,
        offsetTop: 0,
        scaleX: 1,
        scaleY: 1,
        width,
    };
}

export const spriteSmoke0: SpriteType = getSprite(smoke0, 20, 24);
