/* global localStorage */

import {type GameMapType, MapSourceEnum} from "./map-type";

const userMapListKey = "user-map-list-v.1.0";

export function getUserMapList(): Array<GameMapType> {
    const userMapListRaw: string = localStorage.getItem(userMapListKey) ?? "[]";
    // Maps saved before the source field existed have no source
    type StoredUserMapType = Omit<GameMapType, "source"> & {source?: MapSourceEnum | undefined};
    // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
    const userMapList: Array<StoredUserMapType> = JSON.parse(userMapListRaw);

    return userMapList.map<GameMapType>((userMap: StoredUserMapType): GameMapType => {
        return {...userMap, source: userMap.source ?? MapSourceEnum.unknown};
    });
}

export function getUserMapById(mapId: string, userMapList: Array<GameMapType>): GameMapType | null {
    return (
        userMapList.find<GameMapType>((userMap: GameMapType): userMap is GameMapType => {
            return userMap.mapId === mapId;
        }) ?? null
    );
}

export function saveUserMap(map: GameMapType): undefined {
    const userMapList: Array<GameMapType> = [...getUserMapList(), map];

    localStorage.setItem(userMapListKey, JSON.stringify(userMapList));
}

export function updateUserMap(idToUpdate: string, updatedMap: GameMapType): undefined {
    const userMapList: Array<GameMapType> = getUserMapList();
    const foundUserMap: GameMapType | null = getUserMapById(idToUpdate, userMapList);

    if (foundUserMap) {
        userMapList[userMapList.indexOf(foundUserMap)] = {
            ...updatedMap,
            mapId: idToUpdate,
        };
    }

    localStorage.setItem(userMapListKey, JSON.stringify(userMapList));
}

export function deleteUserMap(idToDelete: string): undefined {
    const userMapList: Array<GameMapType> = getUserMapList().filter<GameMapType>(
        (userMap: GameMapType): userMap is GameMapType => {
            return userMap.mapId !== idToDelete;
        }
    );

    localStorage.setItem(userMapListKey, JSON.stringify(userMapList));
}
