import type {JSX, ReactNode} from "react";

import * as spoilerContentStyle from "./spoiler-content.scss";

interface SpoilerContentPropsType {
    readonly className?: string;
    readonly children: ReactNode;
    readonly isOpen: boolean;
}

export function SpoilerContent(props: SpoilerContentPropsType): JSX.Element {
    const {isOpen, children, className} = props;

    const containerCssClassName: string = isOpen
        ? spoilerContentStyle.spoiler_content__open
        : spoilerContentStyle.spoiler_content;

    const fullCssClassName: string = `${containerCssClassName} ${className ?? ""}`.trim();

    return <div className={fullCssClassName}>{children}</div>;
}
