import type {CSSProperties} from "react";

import {getImage} from "../../util/image";
import type {KeyFrameAnimationIndexType, SpriteType} from "./animation-type";

function generateSpriteList(
    defaultSpriteList: Array<SpriteType>,
    imgSrcList: Array<string>,
    isHorizontalMirror: boolean
): Array<SpriteType> {
    return imgSrcList.flatMap<SpriteType>((imgSrc: string, spriteIndex: number): Array<SpriteType> => {
        const defaultSprite = defaultSpriteList[spriteIndex];

        if (!defaultSprite) {
            return [];
        }

        return [
            {
                ...defaultSprite,
                imgSrc: getImage(imgSrc).src,
                scaleX: isHorizontalMirror ? -1 : 1,
            },
        ];
    });
}

export function generateDoubleSpriteList(
    defaultSpriteList: Array<SpriteType>,
    imgSrcList: Array<string>
): Array<SpriteType> {
    return [
        ...generateSpriteList(defaultSpriteList, imgSrcList, false),
        ...generateSpriteList(defaultSpriteList, imgSrcList, true),
    ];
}

export function getDefaultSpriteStyle(animationList: Array<KeyFrameAnimationIndexType>): CSSProperties {
    const style: CSSProperties = {};

    animationList.forEach((animationIndexInList: KeyFrameAnimationIndexType): void => {
        if (animationIndexInList.frameIndex !== 0) {
            return;
        }

        const zeroStyle = animationIndexInList.keyframeList.at(0);

        if (!zeroStyle) {
            return;
        }

        Object.assign(style, {...zeroStyle});
    });

    return style;
}
