import type {JSX} from "react";

import {UiButton} from "../../../../layout/ui-button/ui-button";
import {useGameContext} from "../../../../provider/game/game-context";
import type {
    GameActionType,
    // GameActionTypeEnum
} from "../../../../provider/game/game-context-type";
import {clientGameImage} from "../image/client-game-image";
import * as clientGameMoveBackButtonStyle from "./client-game-move-back-button.scss";

export function ClientGameMoveBackButton(): JSX.Element {
    const {
        // lastMoveAction,
        pushAction,
        // isEnableEndTurnButton,
        getMoveBackAction,
    } = useGameContext();

    const actionData: GameActionType | null = getMoveBackAction();

    return (
        <UiButton
            className={clientGameMoveBackButtonStyle.client_game_move_back_button}
            iconSrc={clientGameImage.moveRevert.src}
            isDisabled={!actionData}
            isSquared
            langKey="GAME__REVERT_MOVE"
            onClick={async (): Promise<undefined> => {
                if (actionData) {
                    await pushAction(actionData);
                }
            }}
        />
    );
}
