import type {GameStateType} from "../../../model/game/game-type";
import {getPlayerByPlayerId} from "../../../model/game/player/player-helper";
import type {GamePlayerIdEnum, GamePlayerType} from "../../../model/game/player/player-type";
import {applyChangeTurn} from "../../../model/game/reducer/game-reducer";
import type {PromiseResolveType} from "../../../util/promise";
import {waitForNextFrame} from "../../../util/time";
import {getNextPlayerId} from "../game-context-helper";
import type {ActionArgumentType, GameAnimationType} from "../game-context-type";

export async function changeTurnAction(data: ActionArgumentType): Promise<void> {
    const {removeAnimationByAction, action, setAnimationList, setGameState, gameState} = data;
    const {playerList, activeGamePlayerId} = gameState;

    const nextActiveGamePlayerId: GamePlayerIdEnum = getNextPlayerId(activeGamePlayerId, playerList);
    const nextPlayer: GamePlayerType | null = getPlayerByPlayerId(nextActiveGamePlayerId, playerList);

    if (!nextPlayer) {
        console.error("cen not find next player");
        console.error(activeGamePlayerId, "->", nextActiveGamePlayerId);
        return waitForNextFrame();
    }

    // next player's income, unit healing on buildings, grave expiry, step counter
    setGameState((currentGameState: GameStateType): GameStateType => {
        return applyChangeTurn(currentGameState);
    });

    return new Promise<void>((resolve: PromiseResolveType<void>) => {
        setAnimationList((animList: Array<GameAnimationType>): Array<GameAnimationType> => {
            return [
                ...animList,
                {
                    action,
                    animationOnFinish: (): void => {
                        void (async (): Promise<void> => {
                            await waitForNextFrame();
                            removeAnimationByAction(action);
                            await waitForNextFrame();
                            resolve();
                        })();
                    },
                },
            ];
        });
    });
}
