import {type JSX, useCallback, useState} from "react";

import {Page} from "../../../layout/page/page";
import {PageContent} from "../../../layout/page/page-content/page-content";
import {PageHeader} from "../../../layout/page/page-header/page-header";
import {RateApp} from "../../../layout/rate-app/rate-app";
import {SpoilerContent} from "../../../layout/spoiler/spoiler-content";
import {uiButtonImage} from "../../../layout/ui-button/image/ui-button-image";
import {UiButton} from "../../../layout/ui-button/ui-button";
import {usePlayTitleTheme} from "../../../media/play-media";
import {companiesAe1CompanyList, companiesAe2CompanyList, companiesAe3CompanyList} from "../../../model/map/map-const";
import type {CompanyItemType} from "../../../model/map/map-type";
import {type CompanySaveStateType, getCompanySaveState} from "../../../provider/game/action/companies-action";
import {Locale} from "../../../provider/locale/locale-context";
import type {LangKeyType} from "../../../provider/locale/translation/type";
import * as clientCompaniesStyle from "./client-companies.scss";
import {ClientCompaniesBotDifficult} from "./client-companies-bot-difficult/client-companies-bot-difficult";
import {ClientCompanyItem} from "./client-company-item/client-company-item";

export function ClientCompanies(): JSX.Element {
    const companySaveState: CompanySaveStateType = getCompanySaveState();
    const [companyInfoOpenList, setCompanyInfoOpenList] = useState<Set<LangKeyType>>(new Set<LangKeyType>());

    const missionHeaderAe1key: LangKeyType = "MISSION_HEADER__AE1";
    const missionHeaderAe2key: LangKeyType = "MISSION_HEADER__AE2";
    const missionHeaderAe3key: LangKeyType = "MISSION_HEADER__AE3";

    const switchOpenDescription = useCallback((missionKey: LangKeyType) => {
        setCompanyInfoOpenList((currentList: Set<LangKeyType>) => {
            if (currentList.has(missionKey)) {
                currentList.delete(missionKey);
            } else {
                currentList.add(missionKey);
            }
            return new Set<LangKeyType>([...currentList]);
        });
    }, []);

    usePlayTitleTheme();

    return (
        <Page>
            <PageHeader langKey="UI__BUTTON__COMPANIES" />
            <PageContent>
                <ClientCompaniesBotDifficult />
                <div className={clientCompaniesStyle.client_companies__map_list}>
                    <h2 className={clientCompaniesStyle.client_companies__part_header}>
                        <UiButton
                            iconSrc={uiButtonImage.book.src}
                            onClick={() => {
                                switchOpenDescription(missionHeaderAe1key);
                            }}
                        >
                            <Locale stringKey={missionHeaderAe1key} />
                        </UiButton>
                    </h2>
                    <SpoilerContent isOpen={companyInfoOpenList.has(missionHeaderAe1key)}>
                        <p className={clientCompaniesStyle.client_companies__description}>
                            <Locale stringKey="MISSION_DESCRIPTION__AE1" />
                        </p>
                    </SpoilerContent>
                    {companiesAe1CompanyList.map<JSX.Element>(
                        (missionData: CompanyItemType, index: number, list: Array<CompanyItemType>): JSX.Element => {
                            const {map, companyState} = missionData;
                            // Actually first mission in map list, always ready to play

                            if (index === 0) {
                                return (
                                    <ClientCompanyItem
                                        companyState={companyState}
                                        isAvailable
                                        key={map.mapId}
                                        map={map}
                                    />
                                );
                            }

                            const prevCompanyData = list[index - 1];
                            const isPrevMissionDone: boolean = prevCompanyData
                                ? (companySaveState[prevCompanyData.map.mapId]?.isDone ?? false)
                                : false;

                            return (
                                <ClientCompanyItem
                                    companyState={companyState}
                                    isAvailable={isPrevMissionDone}
                                    key={map.mapId}
                                    map={map}
                                />
                            );
                        }
                    )}
                </div>
                <div className={clientCompaniesStyle.client_companies__map_list}>
                    <h2 className={clientCompaniesStyle.client_companies__part_header}>
                        <UiButton
                            iconSrc={uiButtonImage.book.src}
                            onClick={() => {
                                switchOpenDescription(missionHeaderAe2key);
                            }}
                        >
                            <Locale stringKey={missionHeaderAe2key} />
                        </UiButton>
                    </h2>
                    <SpoilerContent isOpen={companyInfoOpenList.has(missionHeaderAe2key)}>
                        <p className={clientCompaniesStyle.client_companies__description}>
                            <Locale stringKey="MISSION_DESCRIPTION__AE2" />
                        </p>
                    </SpoilerContent>
                    {companiesAe2CompanyList.map<JSX.Element>(
                        (missionData: CompanyItemType, index: number, list: Array<CompanyItemType>): JSX.Element => {
                            const {map, companyState} = missionData;
                            // Actually first mission in map list, always ready to play

                            if (index === 0) {
                                return (
                                    <ClientCompanyItem
                                        companyState={companyState}
                                        isAvailable
                                        key={map.mapId}
                                        map={map}
                                    />
                                );
                            }

                            const prevCompanyData = list[index - 1];
                            const isPrevMissionDone: boolean = prevCompanyData
                                ? (companySaveState[prevCompanyData.map.mapId]?.isDone ?? false)
                                : false;

                            return (
                                <ClientCompanyItem
                                    companyState={companyState}
                                    isAvailable={isPrevMissionDone}
                                    key={map.mapId}
                                    map={map}
                                />
                            );
                        }
                    )}
                </div>
                <div className={clientCompaniesStyle.client_companies__map_list}>
                    <h2 className={clientCompaniesStyle.client_companies__part_header}>
                        <UiButton
                            iconSrc={uiButtonImage.book.src}
                            onClick={() => {
                                switchOpenDescription(missionHeaderAe3key);
                            }}
                        >
                            <Locale stringKey={missionHeaderAe3key} />
                        </UiButton>
                    </h2>
                    <SpoilerContent isOpen={companyInfoOpenList.has(missionHeaderAe3key)}>
                        <p className={clientCompaniesStyle.client_companies__description}>
                            <Locale stringKey="MISSION_DESCRIPTION__AE3" />
                        </p>
                    </SpoilerContent>
                    {companiesAe3CompanyList.map<JSX.Element>(
                        (missionData: CompanyItemType, index: number, list: Array<CompanyItemType>): JSX.Element => {
                            const {map, companyState} = missionData;
                            // Actually first mission in map list, always ready to play

                            if (index === 0) {
                                return (
                                    <ClientCompanyItem
                                        companyState={companyState}
                                        isAvailable
                                        key={map.mapId}
                                        map={map}
                                    />
                                );
                            }

                            const prevCompanyData = list[index - 1];
                            const isPrevMissionDone: boolean = prevCompanyData
                                ? (companySaveState[prevCompanyData.map.mapId]?.isDone ?? false)
                                : false;

                            return (
                                <ClientCompanyItem
                                    companyState={companyState}
                                    isAvailable={isPrevMissionDone}
                                    key={map.mapId}
                                    map={map}
                                />
                            );
                        }
                    )}
                </div>
            </PageContent>
            <RateApp />
        </Page>
    );
}
