/* global IS_PRODUCTION */

import type {JSX} from "react";

import {squareSize} from "../../../../css/style";
import {type GameBuildingType, GameBuildingTypeEnum} from "../../../../model/game/building/building-type";
import {getEffectiveTileTheme} from "../../../../model/game/landscape/landscape-helper";
import type {GameLandscapeThemeEnum} from "../../../../model/game/landscape/landscape-type";
import {useGameContext} from "../../../../provider/game/game-context";
import * as clientGameBuildingStyle from "./client-game-building.scss";
import {getBuildingImage} from "./client-game-building-helper";

interface ClientGameBuildingItemPropsType {
    readonly building: GameBuildingType;
    // The theme to force, or null to take the theme from the cell the building sits on.
    readonly forcedTheme: GameLandscapeThemeEnum | null;
}

export function ClientGameBuildingItem(props: ClientGameBuildingItemPropsType): JSX.Element {
    const {building, forcedTheme} = props;
    const {buildingType, x, y} = building;

    const {gameState} = useGameContext();
    const {playerList} = gameState;
    const isCastle: boolean = buildingType === GameBuildingTypeEnum.castle;
    const deltaY: number = isCastle ? -squareSize : 0;
    const theme = getEffectiveTileTheme({x, y}, gameState.landscapeThemeMap, forcedTheme);

    return (
        <img
            alt={buildingType}
            className={isCastle ? clientGameBuildingStyle.building_item__castle : clientGameBuildingStyle.building_item}
            data-building={
                // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
                IS_PRODUCTION ? null : JSON.stringify(building, null, 4)
            }
            key={`${x}-${y}`}
            src={getBuildingImage(building, playerList, theme).src}
            style={{
                left: x * squareSize,

                top: y * squareSize + deltaY,
                zIndex: y,
            }}
        />
    );
}
