/*
 * Pure game reducers: every state transition of the game is a plain (state, action) -> state function
 * with no side effects. The React action layer (www/provider/game/action/*) delegates the state math
 * here and keeps only the UI orchestration (animations, promises, setState wiring), so the same
 * transitions can also run headless — for reducer unit tests and bot self-play.
 */

export function applyUnitMove(gameState: GameStateType, action: GameActionType): GameStateType {
    const isForwardMove: boolean = action.actionType === GameActionTypeEnum.unitMove;
    const unitToMove: GameUnitType | null = getUnitByUnitId(action.unitId, gameState.unitList);

    if (!unitToMove) {
        console.error("[applyUnitMove]: can not find unit to move");
        return gameState;
    }

    const updatedUnitList: Array<GameUnitType> = [...gameState.unitList];

    updatedUnitList[updatedUnitList.indexOf(unitToMove)] = {
        ...unitToMove,
        // A forward move counts once; a move-back reverts exactly the last move, so it decrements
        // (move-back is only offered right after a move, so this stays >= 0).
        movedCount: isForwardMove ? unitToMove.movedCount + 1 : unitToMove.movedCount - 1,
        x: action.toPoint.x,
        y: action.toPoint.y,
    };

    return {...gameState, unitList: updatedUnitList};
}

export function applyUnitToUnitAttack(gameState: GameStateType, action: GameActionType): GameStateType {
    const unitAggressor: GameUnitType | null = getUnitByPoint(action.unitCurrentPoint, gameState.unitList);
    const unitDefender: GameUnitType | null = getUnitByPoint(action.toPoint, gameState.unitList);

    if (!unitAggressor || !unitDefender) {
        console.error("[applyUnitToUnitAttack]: can not find aggressor or defender");
        return gameState;
    }

    const {aggressor, defender} = getUnitToUnitAttackResult(
        {aggressor: unitAggressor, defender: unitDefender},
        gameState
    );

    const updatedUnitList: Array<GameUnitType> = [...gameState.unitList];
    const updatedGraveList: Array<GameGraveType> = [...gameState.graveList];
    const updatedCemetery: Array<GameUnitType> = [...gameState.cemetery];
    const {stepCount} = gameState;

    [aggressor, defender].forEach((unitToUpdate: GameUnitType) => {
        const unitToUpdatePoint: PointType = {x: unitToUpdate.x, y: unitToUpdate.y};
        const unitInListToUpdate: GameUnitType | null = getUnitByPoint(unitToUpdatePoint, updatedUnitList);
        const unitInfo = getUnitInfoByUnit(unitToUpdate);

        if (!unitInListToUpdate) {
            console.error("[applyUnitToUnitAttack]: can not find unit in list to update", unitToUpdate);
            return;
        }

        if (unitToUpdate.health <= 0) {
            updatedUnitList.splice(updatedUnitList.indexOf(unitInListToUpdate), 1);

            if (unitInfo.hasGrave) {
                removeGraveByPointProcedure(unitToUpdatePoint, updatedGraveList);

                const updatedGrave: GameGraveType = {
                    createdStepCount: stepCount,
                    ...unitToUpdatePoint,
                };

                updatedGraveList.push(updatedGrave);
            }

            if (unitInfo.isHero) {
                updatedCemetery.push({
                    ...unitInListToUpdate,
                    deathCount: unitInListToUpdate.deathCount + 1,
                });
            }

            return;
        }

        // unitToUpdate already carries the post-attack state, including the incremented
        // attackedUnitCount for the aggressor (see getUnitToUnitAttackResult).
        updatedUnitList[updatedUnitList.indexOf(unitInListToUpdate)] = {...unitToUpdate};
    });

    return {
        ...gameState,
        cemetery: updatedCemetery,
        graveList: updatedGraveList,
        unitList: updatedUnitList,
    };
}

export function applyUnitToBuildingAttack(gameState: GameStateType, action: GameActionType): GameStateType {
    const unitAggressor: GameUnitType | null = getUnitByPoint(action.unitCurrentPoint, gameState.unitList);
    const buildingToDestroy: GameBuildingType | null = getBuildingByPoint(action.toPoint, gameState.buildingList);

    if (!unitAggressor || !buildingToDestroy) {
        console.error("[applyUnitToBuildingAttack]: can not find aggressor or building");
        return gameState;
    }

    const updatedUnitList: Array<GameUnitType> = [...gameState.unitList];
    const updatedBuildingList: Array<GameBuildingType> = [...gameState.buildingList];

    updatedUnitList[updatedUnitList.indexOf(unitAggressor)] = {
        ...unitAggressor,
        attackedBuildingCount: unitAggressor.attackedBuildingCount + 1,
        damageGiven: unitAggressor.damageGiven + levelUnitData.experience.destroyBuilding,
    };

    updatedBuildingList[updatedBuildingList.indexOf(buildingToDestroy)] = {
        ...buildingToDestroy,
        gamePlayerId: GamePlayerIdEnum.playerEmpty,
        state: GameBuildingStateEnum.buildingBroken,
    };

    return {
        ...gameState,
        buildingList: updatedBuildingList,
        unitList: updatedUnitList,
    };
}

export function applyOccupyBuilding(gameState: GameStateType, action: GameActionType): GameStateType {
    const unitNewOwner: GameUnitType | null = getUnitByPoint(action.unitCurrentPoint, gameState.unitList);
    const buildingToOccupy: GameBuildingType | null = getBuildingByPoint(
        action.unitCurrentPoint,
        gameState.buildingList
    );

    if (!buildingToOccupy || !unitNewOwner) {
        console.error("[applyOccupyBuilding]: can not find unit or building");
        return gameState;
    }

    const updatedBuildingList: Array<GameBuildingType> = [...gameState.buildingList];
    const updatedUnitList: Array<GameUnitType> = [...gameState.unitList];

    updatedBuildingList[updatedBuildingList.indexOf(buildingToOccupy)] = {
        ...buildingToOccupy,
        gamePlayerId: unitNewOwner.gamePlayerId,
    };

    updatedUnitList[updatedUnitList.indexOf(unitNewOwner)] = {
        ...unitNewOwner,
        didOccupyBuilding: true,
    };

    return {
        ...gameState,
        buildingList: updatedBuildingList,
        unitList: updatedUnitList,
    };
}

export function applyFixBuilding(gameState: GameStateType, action: GameActionType): GameStateType {
    const unitFixer: GameUnitType | null = getUnitByPoint(action.unitCurrentPoint, gameState.unitList);
    const buildingToFix: GameBuildingType | null = getBuildingByPoint(action.unitCurrentPoint, gameState.buildingList);

    if (!buildingToFix || !unitFixer) {
        console.error("[applyFixBuilding]: can not find unit or building");
        return gameState;
    }

    const updatedBuildingList: Array<GameBuildingType> = [...gameState.buildingList];
    const updatedUnitList: Array<GameUnitType> = [...gameState.unitList];

    updatedBuildingList[updatedBuildingList.indexOf(buildingToFix)] = {
        ...buildingToFix,
        state: GameBuildingStateEnum.buildingOk,
    };

    updatedUnitList[updatedUnitList.indexOf(unitFixer)] = {
        ...unitFixer,
        didFixBuilding: true,
    };

    return {
        ...gameState,
        buildingList: updatedBuildingList,
        unitList: updatedUnitList,
    };
}

export function applyRaiseSkeleton(gameState: GameStateType, action: GameActionType): GameStateType {
    const sorceress: GameUnitType | null = getUnitByPoint(action.unitCurrentPoint, gameState.unitList);
    const grave: GameGraveType | null = getGraveByPoint(action.toPoint, gameState.graveList);

    if (!sorceress || !grave) {
        console.error("[applyRaiseSkeleton]: can not find sorceress or grave");
        return gameState;
    }

    const updatedUnitList: Array<GameUnitType> = [...gameState.unitList];
    const updatedGraveList: Array<GameGraveType> = [...gameState.graveList];

    updatedUnitList[updatedUnitList.indexOf(sorceress)] = {
        ...sorceress,
        raisedSkeletonCount: sorceress.raisedSkeletonCount + 1,
    };

    removeGraveByPointProcedure({x: grave.x, y: grave.y}, updatedGraveList);

    updatedUnitList.push({
        ...defaultUnitData,
        attackedUnitCount: 1,
        gamePlayerId: sorceress.gamePlayerId,
        health: getPlayerMaxUnitHealth(sorceress.gamePlayerId, gameState.playerList),
        movedCount: 1,
        // A reproducible id derived from the pre-raise board, matching the historical format.
        unitId: [
            getHash(gameState),
            getHash(gameState.unitList),
            getHash(gameState.graveList),
            getHash(gameState.cemetery),
            gameState.stepCount,
        ].join("-"),
        unitType: GameUnitTypeEnum.skeleton,
        x: grave.x,
        y: grave.y,
    });

    return {
        ...gameState,
        graveList: updatedGraveList,
        unitList: updatedUnitList,
    };
}

export function applyChangeTurn(gameState: GameStateType): GameStateType {
    const {playerList, activeGamePlayerId, buildingList, gameSettings, stepCount, graveList, unitList} = gameState;
    const nextActiveGamePlayerId: GamePlayerIdEnum = getNextPlayerId(activeGamePlayerId, playerList);
    const nextPlayer: GamePlayerType | null = getPlayerByPlayerId(nextActiveGamePlayerId, playerList);

    if (!nextPlayer) {
        console.error("[applyChangeTurn]: can not find next player", activeGamePlayerId, "->", nextActiveGamePlayerId);
        return gameState;
    }

    const turnIncome: number = getPlayerTurnIncome(nextActiveGamePlayerId, buildingList, gameSettings);

    const updatedPlayerList: Array<GamePlayerType> = playerList.map<GamePlayerType>(
        (player: GamePlayerType): GamePlayerType => {
            if (player.gamePlayerId !== nextActiveGamePlayerId) {
                return player;
            }

            return {...player, money: player.money + turnIncome};
        }
    );

    const updatedStepCount: number = stepCount + 1;

    return {
        ...gameState,
        activeGamePlayerId: nextActiveGamePlayerId,
        graveList: graveList.filter<GameGraveType>((grave: GameGraveType): grave is GameGraveType => {
            return grave.createdStepCount + graveLiveCount > updatedStepCount;
        }),
        playerList: updatedPlayerList,
        stepCount: updatedStepCount,
        // The heal-on-building pass deliberately reads the PRE-income player list, as it always has.
        unitList: unitList.map<GameUnitType>((unit: GameUnitType): GameUnitType => {
            return getSwitchTurnUnitState(nextActiveGamePlayerId, unit, buildingList, playerList, gameSettings);
        }),
    };
}

export function applyAddUnitList(gameState: GameStateType, action: GameActionType): GameStateType {
    const {addUnitList} = action;
    const {activeGamePlayerId} = gameState;

    if (addUnitList.length === 0) {
        return {...gameState, unitList: [...gameState.unitList]};
    }

    // A unit added on top of an ENEMY unit telefrags it: the old unit is removed and the pair is
    // recorded so the UI can play the effect. Adding on top of an own unit keeps both (unit-over-unit).
    const telefragList: Array<[GameUnitType, GameUnitType]> = [];

    const unitToRemoveList: Array<GameUnitType> = gameState.unitList.filter<GameUnitType>(
        (oldUnit: GameUnitType): oldUnit is GameUnitType => {
            const addedUnitOverOldUit: GameUnitType | undefined = addUnitList.find(
                (addedUnit: GameUnitType): boolean => {
                    return addedUnit.x === oldUnit.x && addedUnit.y === oldUnit.y;
                }
            );

            if (!addedUnitOverOldUit) {
                return false;
            }

            const needToRemove: boolean = activeGamePlayerId !== addedUnitOverOldUit.gamePlayerId;

            if (needToRemove) {
                telefragList.push([addedUnitOverOldUit, oldUnit]);
            }

            return needToRemove;
        }
    );

    const filteredForNewUnitList: Array<GameUnitType> = gameState.unitList.filter<GameUnitType>(
        (unit: GameUnitType): unit is GameUnitType => {
            return !unitToRemoveList.includes(unit);
        }
    );

    return {
        ...gameState,
        telefragList,
        unitList: [...filteredForNewUnitList, ...addUnitList],
    };
}

export function applyBuyUnit(gameState: GameStateType, action: GameActionType): GameStateType {
    const {buyUnitType, toPoint, unitId} = action;
    const {activeGamePlayerId, playerList, unitList, cemetery} = gameState;
    const player: GamePlayerType | null = getPlayerByPlayerId(activeGamePlayerId, playerList);

    if (!player) {
        console.error(`[applyBuyUnit]: can not find player by id: ${activeGamePlayerId}`);
        return gameState;
    }

    // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
    if (!buyUnitType) {
        console.error("[applyBuyUnit]: buyUnitType is null");
        return gameState;
    }

    const deadUnit: GameUnitType | null = getUnitByUnitId(unitId, cemetery);
    const endUnitCost: number = deadUnit
        ? getDeadUnitCost(deadUnit.unitType, deadUnit.deathCount)
        : getUnitInfoByType(buyUnitType).cost;

    const updatedPlayerList: Array<GamePlayerType> = [...playerList];

    updatedPlayerList[updatedPlayerList.indexOf(player)] = {
        ...player,
        money: player.money - endUnitCost,
    };

    // A re-bought hero leaves the cemetery and keeps its battle record (and its raised price via deathCount).
    const updatedUnit: GameUnitType = {
        ...defaultUnitData,
        ...toPoint,
        gamePlayerId: player.gamePlayerId,
        health: getPlayerMaxUnitHealth(player.gamePlayerId, playerList),
        unitId,
        unitType: buyUnitType,
        ...(deadUnit
            ? {
                  damageGiven: deadUnit.damageGiven,
                  damageReceived: deadUnit.damageReceived,
                  deathCount: deadUnit.deathCount,
              }
            : {}),
    };

    const updatedCemetery: Array<GameUnitType> = cemetery.filter<GameUnitType>(
        (deadUnitInList: GameUnitType): deadUnitInList is GameUnitType => {
            return deadUnitInList !== deadUnit;
        }
    );

    return {
        ...gameState,
        cemetery: updatedCemetery,
        playerList: updatedPlayerList,
        unitList: [...unitList, updatedUnit],
    };
}

// The single entry point: fold any game action into the state. UI/meta actions (briefing, company
// win/defeat screens) do not change the board, so they map to identity.
export function applyGameAction(gameState: GameStateType, action: GameActionType): GameStateType {
    switch (action.actionType) {
        case GameActionTypeEnum.unitMove:
        case GameActionTypeEnum.unitMoveRevert: {
            return applyUnitMove(gameState, action);
        }
        case GameActionTypeEnum.unitToUnitAttack: {
            return applyUnitToUnitAttack(gameState, action);
        }
        case GameActionTypeEnum.unitToBuildingAttack: {
            return applyUnitToBuildingAttack(gameState, action);
        }
        case GameActionTypeEnum.occupyBuilding: {
            return applyOccupyBuilding(gameState, action);
        }
        case GameActionTypeEnum.fixBuilding: {
            return applyFixBuilding(gameState, action);
        }
        case GameActionTypeEnum.raiseSkeleton: {
            return applyRaiseSkeleton(gameState, action);
        }
        case GameActionTypeEnum.changeTurn: {
            return applyChangeTurn(gameState);
        }
        case GameActionTypeEnum.addUnitList: {
            return applyAddUnitList(gameState, action);
        }
        case GameActionTypeEnum.buyUnit: {
            return applyBuyUnit(gameState, action);
        }
        case GameActionTypeEnum.companiesForceDefeat:
        case GameActionTypeEnum.companiesForceVictory:
        case GameActionTypeEnum.showBriefing: {
            return gameState;
        }
        default: {
            throw new NeverError(action.actionType);
        }
    }
}
