/* global document, HTMLDivElement */

import {type JSX, type RefObject, useEffect, useRef, useState} from "react";

import {getPlayerColorIdByPlayerId} from "../../model/game/player/player-helper";
import type {GamePlayerColorIdEnum} from "../../model/game/player/player-type";
import type {PointType} from "../../model/game/point/point-type";
import type {GameUnitType} from "../../model/game/unit/unit-type";
import {useGameContext} from "../../provider/game/game-context";
import {arrayShuffle} from "../../util/array";
import {getRandomNumber} from "../../util/number";
import {BigText} from "../game-font/text/big-text";
import {IsHidden} from "../is-hidden/is-hidden";
import * as unitFightAnimationStyle from "./unit-fight-animation.scss";
import {fightAnimationDeltaHealthList, fightAnimationViewSize} from "./unit-fight-animation-const";
import {getFightAnimation, getIsRenderFightAnimationUnit} from "./unit-fight-animation-helper";
import {UnitFightAnimationSingle} from "./unit-fight-animation-single";

interface UnitFightAnimationPropsType {
    readonly frameTimeInterval: number;
    readonly isAggressor: boolean;
    readonly isIdle: boolean;
    readonly unit: GameUnitType;
}

export function UnitFightAnimation(props: UnitFightAnimationPropsType): JSX.Element {
    const {unit, isIdle, frameTimeInterval, isAggressor} = props;
    const {unitType, gamePlayerId} = unit;
    const {gameState} = useGameContext();
    const {playerList} = gameState;
    const unitColor: GamePlayerColorIdEnum = getPlayerColorIdByPlayerId(gamePlayerId, playerList);
    const {unitPositionList: unitPositionListDefault, unitPositionRandom} = getFightAnimation(unitType, unitColor);
    const [unitPositionList] = useState<Array<PointType>>((): Array<PointType> => {
        return arrayShuffle<PointType>(unitPositionListDefault);
    });
    const [unitDeltaPositionList] = useState<Array<PointType>>((): Array<PointType> => {
        return unitPositionList.map<PointType>((): PointType => {
            return {
                x: getRandomNumber(-unitPositionRandom.x, unitPositionRandom.x),
                y: getRandomNumber(-unitPositionRandom.y, unitPositionRandom.y),
            };
        });
    });
    const [delayAnimateList] = useState<Array<number>>((): Array<number> => {
        return unitPositionList.map<number>((): number => {
            return getRandomNumber(0, frameTimeInterval);
        });
    });
    const [initialUnit, setInitialUnit] = useState<GameUnitType>({...unit});
    const [deltaHealth, setDeltaHealth] = useState<number>(0);
    const deltaHealthAnimateRef: RefObject<HTMLDivElement> = useRef<HTMLDivElement>(document.createElement("div"));

    useEffect(() => {
        const {health} = unit;

        if (health === initialUnit.health) {
            return;
        }

        // eslint-disable-next-line react-hooks/set-state-in-effect
        setDeltaHealth(health - initialUnit.health);

        const deltaHealthAnimation = deltaHealthAnimateRef.current.animate(fightAnimationDeltaHealthList, {
            duration: frameTimeInterval * 7,
            easing: "ease-in-out",
            fill: "forwards",
        });

        deltaHealthAnimation.onfinish = (): undefined => {
            setDeltaHealth(0);
        };

        setInitialUnit({...unit});
    }, [unitPositionList, frameTimeInterval, initialUnit, unit]);

    return (
        <>
            {unitPositionList.map<JSX.Element>((unitPoint: PointType, unitIndex: number): JSX.Element => {
                const deltaPoint: PointType = unitDeltaPositionList.at(unitIndex) ?? {x: 0, y: 0};
                const delay = delayAnimateList.at(unitIndex) ?? 0;
                const unitX = Math.round((fightAnimationViewSize.width * (1 + unitPoint.x / 100)) / 2 + deltaPoint.x);
                const unitY = Math.round((fightAnimationViewSize.height * unitPoint.y) / 100 + deltaPoint.y);

                const isAlive = getIsRenderFightAnimationUnit({
                    health: unit.health,
                    index: unitIndex,
                    size: unitPositionList.length,
                });

                return (
                    <UnitFightAnimationSingle
                        delay={delay}
                        frameTimeInterval={frameTimeInterval}
                        isAggressor={isAggressor}
                        isAlive={isAlive}
                        isIdle={isIdle}
                        key={`${unitX}-${unitY}-${unitIndex.toString(10)}`}
                        unit={unit}
                        unitX={unitX}
                        unitY={unitY}
                    />
                );
            })}

            <div
                className={
                    isAggressor
                        ? unitFightAnimationStyle.unit_fight_animation__delta_health__aggressor
                        : unitFightAnimationStyle.unit_fight_animation__delta_health__defender
                }
            >
                <div ref={deltaHealthAnimateRef}>
                    <IsHidden isHidden={deltaHealth === 0}>
                        <BigText padEnd={[3, "S"]} scale={1.5} text={deltaHealth} />
                    </IsHidden>
                </div>
            </div>
        </>
    );
}
