/* global HTMLImageElement */
import {
    GameBuildingStateEnum,
    type GameBuildingType,
    GameBuildingTypeEnum,
} from "../../../../model/game/building/building-type";
import type {GameLandscapeThemeEnum} from "../../../../model/game/landscape/landscape-type";
import {getPlayerByPlayerId} from "../../../../model/game/player/player-helper";
import {GamePlayerColorIdEnum, type GamePlayerType} from "../../../../model/game/player/player-type";
import {type BuildingImageMapType, getBuildingImageMap, getFarmBrokenImage} from "./image/building-image";

const {temple, well} = GameBuildingTypeEnum;
const {gray} = GamePlayerColorIdEnum;

export function getBuildingImage(
    building: GameBuildingType,
    playerList: Array<GamePlayerType>,
    theme: GameLandscapeThemeEnum
): HTMLImageElement {
    const {buildingType, gamePlayerId, state} = building;

    if (state === GameBuildingStateEnum.buildingBroken) {
        return getFarmBrokenImage(theme);
    }

    const buildingImage: BuildingImageMapType = getBuildingImageMap(theme);

    if (buildingType === well || buildingType === temple) {
        return buildingImage[buildingType];
    }

    const player: GamePlayerType | null = getPlayerByPlayerId(gamePlayerId, playerList);

    if (player) {
        return buildingImage[buildingType][player.gamePlayerColorId];
    }

    return buildingImage[buildingType][gray];
}
