import type {JSX} from "react";

import {BigText} from "../../../../layout/game-font/text/big-text";
import {
    getPlayerByPlayerId,
    getPlayerColorIdByPlayerId,
    getPlayerStatusBarIcon,
    getPlayerUnitLimit,
} from "../../../../model/game/player/player-helper";
import type {GamePlayerColorIdEnum} from "../../../../model/game/player/player-type";
import {getUnitListByPlayerId} from "../../../../model/game/unit/unit-helper";
import type {GameUnitType} from "../../../../model/game/unit/unit-type";
import {useGameContext} from "../../../../provider/game/game-context";
import {cls} from "../../../../util/css";
import {colorClassNameMap} from "../../client-local-game-setup/client-local-game-setup-player/image/image-color";
import * as clientGameBottomStatusBarStyle from "./client-game-bottom-status-bar.scss";
import {ClientSquareInfo} from "./client-square-info/client-square-info";

export function ClientGameBottomStatusBar(): JSX.Element {
    const {gameState} = useGameContext();
    const {playerList, activeGamePlayerId, unitList, cemetery} = gameState;
    const player = getPlayerByPlayerId(activeGamePlayerId, playerList);
    const playerColor: GamePlayerColorIdEnum = getPlayerColorIdByPlayerId(activeGamePlayerId, playerList);
    const playerUnitList: Array<GameUnitType> = getUnitListByPlayerId(activeGamePlayerId, unitList);
    const playerMoney: number = player?.money ?? 0;
    const playerUnitCount: number = playerUnitList.length;
    const playerUnitLimit: number = getPlayerUnitLimit(activeGamePlayerId, playerList);

    return (
        <div
            className={cls(clientGameBottomStatusBarStyle.bottom_status_bar, colorClassNameMap[playerColor].bgGradient)}
        >
            <div className={clientGameBottomStatusBarStyle.bottom_status_bar__main_block}>
                <div className={clientGameBottomStatusBarStyle.bottom_status_bar__money_wrapper}>
                    <img
                        alt={player?.gamePlayerId ?? ""}
                        className={clientGameBottomStatusBarStyle.bottom_status_bar__money__user_icon}
                        src={getPlayerStatusBarIcon(player, {cemetery, unitList})}
                    />
                    <BigText scale={2} text={`g  ${playerMoney}`} />
                </div>
                <BigText scale={2} text={`u  ${playerUnitCount}/${playerUnitLimit}`} />
            </div>
            <ClientSquareInfo />
        </div>
    );
}
