import {type JSX, useState} from "react";

import {Page} from "../../../layout/page/page";
import {PageContent} from "../../../layout/page/page-content/page-content";
import {PageHeader} from "../../../layout/page/page-header/page-header";
import {RateApp} from "../../../layout/rate-app/rate-app";
import {UiButton} from "../../../layout/ui-button/ui-button";
import {usePlayTitleTheme} from "../../../media/play-media";
import {skirmishMapList} from "../../../model/map/map-const";
import {type GameMapType, MapSourceEnum} from "../../../model/map/map-type";
import {useLocale} from "../../../provider/locale/locale-context";
import {useSettingContext} from "../../../provider/setting/setting-context";
import {useOnMount} from "../../../service/use-on-mount";
import {throwError} from "../../../util/error";
import {waitForNextFrame} from "../../../util/time";
import * as clientSkirmishStyle from "./client-skirmish.scss";
import {getSeparatedMapByPlayerCount, mapNameSortCallback} from "./client-skirmish-helper";
import {ClientSkirmishMapItem} from "./client-skirmish-map-item/client-skirmish-map-item";
import {ClientSkirmishMapSectionHeader} from "./client-skirmish-map-section-header/client-skirmish-map-section-header";

export function ClientSkirmish(): JSX.Element {
    const {localeName, getLocalizedString} = useLocale();
    const {setting, setBoolean} = useSettingContext();
    const {isOnlyOriginalMapsEnable} = setting.booleanSetting;
    const defaultMinShowMap = 36;
    const [isDidMount, setIsDidMount] = useState<boolean>(isOnlyOriginalMapsEnable);

    useOnMount(() => {
        waitForNextFrame()
            .then(() => {
                setIsDidMount(true);
            })
            .catch(throwError);
    });

    usePlayTitleTheme();

    const filteredMapList: Array<GameMapType> = isOnlyOriginalMapsEnable
        ? skirmishMapList.filter((map: GameMapType): boolean => {
              return map.source !== MapSourceEnum.unknown;
          })
        : skirmishMapList;

    const sortedMapList: Array<GameMapType> = [...filteredMapList].sort(
        (mapA: GameMapType, mapB: GameMapType): number => {
            return mapNameSortCallback(mapA, mapB, localeName, getLocalizedString);
        }
    );

    const {two, three, four} = getSeparatedMapByPlayerCount(sortedMapList);

    return (
        <Page>
            <PageHeader langKey="UI__BUTTON__SKIRMISH" />
            <UiButton
                className={clientSkirmishStyle.client_skirmish_map_list__filter}
                isActive={isOnlyOriginalMapsEnable}
                isSquared
                onClick={(): undefined => {
                    setBoolean("isOnlyOriginalMapsEnable", !isOnlyOriginalMapsEnable);
                }}
            >
                {isOnlyOriginalMapsEnable ? `[X] ` : `[ ] `}
                AE1/AE2
            </UiButton>
            <PageContent className={clientSkirmishStyle.client_skirmish_map_list__content}>
                <div className={clientSkirmishStyle.client_skirmish_map_list}>
                    <ClientSkirmishMapSectionHeader count={2} />
                    {two
                        // eslint-disable-next-line no-undefined
                        .slice(0, isDidMount ? undefined : defaultMinShowMap)
                        .map<JSX.Element>((map: GameMapType): JSX.Element => {
                            return <ClientSkirmishMapItem key={map.mapId} map={map} />;
                        })}

                    {isDidMount ? (
                        <>
                            <ClientSkirmishMapSectionHeader count={3} />
                            {three.map<JSX.Element>((map: GameMapType): JSX.Element => {
                                return <ClientSkirmishMapItem key={map.mapId} map={map} />;
                            })}
                            <ClientSkirmishMapSectionHeader count={4} />
                            {four.map<JSX.Element>((map: GameMapType): JSX.Element => {
                                return <ClientSkirmishMapItem key={map.mapId} map={map} />;
                            })}
                        </>
                    ) : null}
                    <div className={clientSkirmishStyle.client_skirmish_map_list__bottom} />
                </div>
            </PageContent>
            <RateApp />
        </Page>
    );
}
