import {type JSX, useEffect} from "react";

import {ErrorBoundary} from "../layout/error-boundary/error-boundary";
import {symbolBigColor, symbolSmallColor} from "../layout/game-font/image/font-image";
import {DevModeProvider} from "../provider/dev-mode/dev-mode-context";
import {ThemeProvider} from "../provider/theme/theme-context";
import type {ThemeNameEnum} from "../provider/theme/theme-context-type";
import {ColorMatrix} from "../util/color-matrix";
import {AppProvider} from "./app-provider";
import {AppRouting} from "./app-routing";

export interface AppPropsType {
    readonly defaultThemeName: ThemeNameEnum | null;
}

export function App(props: AppPropsType): JSX.Element {
    const {defaultThemeName} = props;

    useEffect(() => {
        window.addEventListener("contextmenu", (evt: PointerEvent): void => {
            evt.preventDefault();
        });
    }, []);

    return (
        <ErrorBoundary errorFallBack={<h1>Front-end error</h1>}>
            <DevModeProvider>
                <ThemeProvider defaultThemeName={defaultThemeName}>
                    <AppProvider>
                        <AppRouting />
                    </AppProvider>
                </ThemeProvider>
            </DevModeProvider>
            <ColorMatrix colorId="unit-level" fromColor={symbolSmallColor} toColor={symbolBigColor} />
        </ErrorBoundary>
    );
}
