import {createContext, type JSX, type ReactNode, useContext, useMemo, useState} from "react";

import {getDefaultDevModeData} from "./dev-mode-helper";
import type {DevModeContextType} from "./dev-mode-type";

export const DevModeContext = createContext<DevModeContextType>(getDefaultDevModeData());

export function useDevModeContext(): DevModeContextType {
    return useContext<DevModeContextType>(DevModeContext);
}

const {Provider: DevModeContextProvider} = DevModeContext;

interface DevModeContextPropsType {
    readonly children: ReactNode;
}

export function DevModeProvider(props: DevModeContextPropsType): JSX.Element {
    const {children} = props;
    const [isDevModeEnable, setIsDevModeEnable] = useState<boolean>(getDefaultDevModeData().isDevModeEnable);

    const providedData: DevModeContextType = useMemo((): DevModeContextType => {
        return {isDevModeEnable, setIsDevModeEnable};
    }, [isDevModeEnable]);

    return <DevModeContextProvider value={providedData}>{children}</DevModeContextProvider>;
}
