import type {JSX} from "react";

import {SmallText} from "../../../../../layout/game-font/text/small-text";
import {buildingNameLangKeyMap} from "../../../../../model/game/building/building-const";
import {getBuildingHealthBonus, getBuildingMoneyIncome} from "../../../../../model/game/building/building-helper";
import {GameBuildingStateEnum} from "../../../../../model/game/building/building-type";
import {getByPoint} from "../../../../../model/game/game-state/game-state";
import type {PointDataType} from "../../../../../model/game/game-type";
import {getEffectiveTileTheme} from "../../../../../model/game/landscape/landscape-helper";
import {useGameContext} from "../../../../../provider/game/game-context";
import {Locale} from "../../../../../provider/locale/locale-context";
import {resolveLandscapeThemeOverride} from "../../../../../provider/setting/landscape-theme-override-helper";
import {useSettingContext} from "../../../../../provider/setting/setting-context";
import {getBuildingImage} from "../../client-game-building/client-game-building-helper";
import * as clientBuildingStatsStyle from "./client-building-stats.scss";
import {buildingStatsIcon} from "./image/client-building-stats-icon";

export function ClientBuildingStats(): JSX.Element | null {
    const {activePoint, gameState} = useGameContext();
    const {
        setting: {landscapeThemeOverride},
    } = useSettingContext();
    const pointData: PointDataType = getByPoint(activePoint, gameState);
    const {building} = pointData;

    if (!building) {
        return null;
    }

    const healthBonus = getBuildingHealthBonus(building.buildingType, gameState.gameSettings);
    const moneyIncome = getBuildingMoneyIncome(building.buildingType, gameState.gameSettings);
    const theme = getEffectiveTileTheme(
        {x: building.x, y: building.y},
        gameState.landscapeThemeMap,
        resolveLandscapeThemeOverride(gameState.mapId, landscapeThemeOverride)
    );
    const buildingImage = getBuildingImage(building, gameState.playerList, theme);
    const buildingNameLangKey = buildingNameLangKeyMap[building.buildingType];

    if (building.state === GameBuildingStateEnum.buildingBroken) {
        return (
            <div className={clientBuildingStatsStyle.client_building_stats__wrapper}>
                <div className={clientBuildingStatsStyle.client_building_stats}>
                    <img
                        alt="building"
                        className={clientBuildingStatsStyle.client_building_stats__building}
                        src={buildingImage.src}
                    />
                    <span className={clientBuildingStatsStyle.client_building_stats__name}>
                        <Locale stringKey={buildingNameLangKey} />
                    </span>
                </div>
                <div className={clientBuildingStatsStyle.client_building_stats}>
                    <img
                        alt="health"
                        className={clientBuildingStatsStyle.client_building_stats__icon}
                        src={buildingStatsIcon.heart.src}
                    />
                    <SmallText className={clientBuildingStatsStyle.client_building_stats__text} scale={2} text="-" />

                    <img
                        alt="attack"
                        className={clientBuildingStatsStyle.client_building_stats__icon}
                        src={buildingStatsIcon.money.src}
                    />
                    <SmallText className={clientBuildingStatsStyle.client_building_stats__text} scale={2} text="-" />
                </div>
            </div>
        );
    }

    return (
        <div className={clientBuildingStatsStyle.client_building_stats__wrapper}>
            <div className={clientBuildingStatsStyle.client_building_stats}>
                <img
                    alt="building"
                    className={clientBuildingStatsStyle.client_building_stats__building}
                    src={buildingImage.src}
                />
                <span className={clientBuildingStatsStyle.client_building_stats__name}>
                    <Locale stringKey={buildingNameLangKey} />
                </span>
            </div>
            <div className={clientBuildingStatsStyle.client_building_stats}>
                <img
                    alt="health"
                    className={clientBuildingStatsStyle.client_building_stats__icon}
                    src={buildingStatsIcon.heart.src}
                />
                <SmallText
                    className={clientBuildingStatsStyle.client_building_stats__text}
                    scale={2}
                    text={`+${healthBonus.toString(10)}`}
                />

                <img
                    alt="attack"
                    className={clientBuildingStatsStyle.client_building_stats__icon}
                    src={buildingStatsIcon.money.src}
                />
                <SmallText
                    className={clientBuildingStatsStyle.client_building_stats__text}
                    scale={2}
                    text={`+${moneyIncome.toString(10)}`}
                />
            </div>
        </div>
    );
}
