import type {GameLandscapeThemeEnum} from "../../model/game/landscape/landscape-type";
import {getIsCompaniesMap} from "../../model/map/map-helper";
import {landscapeThemeAsIs, type LandscapeThemeSettingType} from "./setting-type";

// Resolves the theme override to apply while rendering a map. Campaign missions always render "as
// designed" (null) — each mission uses the per-cell theme authored in its own map file. `asIs` also
// means "no override". Every non-asIs setting value IS a GameLandscapeThemeEnum value, so no mapping
// table is needed.
// Kept out of setting-helper on purpose: importing map-helper there would close an import cycle.
export function resolveLandscapeThemeOverride(
    mapId: string,
    landscapeThemeOverride: LandscapeThemeSettingType
): GameLandscapeThemeEnum | null {
    if (landscapeThemeOverride === landscapeThemeAsIs || getIsCompaniesMap(mapId)) {
        return null;
    }

    return landscapeThemeOverride;
}
