/* global localStorage */

import {getEnumValueEnsure} from "../../../util/enum";
import type {PromiseResolveType} from "../../../util/promise";
import {waitForNextFrame} from "../../../util/time";
import {difficultPointMap} from "../../setting/setting-const";
import {BotDifficultEnum} from "../../setting/setting-type";
import type {ActionArgumentType, GameAnimationType} from "../game-context-type";

const companyProgressDataKey = "company-progress-data-v.1.0";

export interface DoneCompanyStateType {
    isDone: boolean;
    difficult?: BotDifficultEnum;
}

export type CompanySaveStateType = Record<string, DoneCompanyStateType | undefined>;

function getMaxDifficult(difficultA: BotDifficultEnum, difficultB: BotDifficultEnum): BotDifficultEnum {
    const difficultAPoint = difficultPointMap[difficultA];
    const difficultBPoint = difficultPointMap[difficultB];

    return difficultAPoint >= difficultBPoint ? difficultA : difficultB;
}

export function getCompanySaveState(): CompanySaveStateType {
    const companySaveStateRaw: string = localStorage.getItem(companyProgressDataKey) ?? "{}";
    // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
    const companySaveState: CompanySaveStateType = JSON.parse(companySaveStateRaw);

    return companySaveState;
}

export function saveDoneCompany(companyId: string, difficult: BotDifficultEnum): undefined {
    const currentState: CompanySaveStateType = getCompanySaveState();

    const currentSavedDifficult: BotDifficultEnum = getEnumValueEnsure<BotDifficultEnum>(
        BotDifficultEnum,
        currentState[companyId]?.difficult,
        BotDifficultEnum.easy
    );

    currentState[companyId] = {difficult: getMaxDifficult(currentSavedDifficult, difficult), isDone: true};

    localStorage.setItem(companyProgressDataKey, JSON.stringify(currentState));
}

export async function companiesForceDefeatAction(data: ActionArgumentType): Promise<void> {
    const {removeAnimationByAction, action, setAnimationList} = data;

    return new Promise<void>((resolve: PromiseResolveType<void>) => {
        setAnimationList((animList: Array<GameAnimationType>): Array<GameAnimationType> => {
            return [
                ...animList,
                {
                    action,
                    animationOnFinish: (): void => {
                        void (async (): Promise<void> => {
                            removeAnimationByAction(action);
                            await waitForNextFrame();
                            resolve();
                        })();
                    },
                },
            ];
        });
    });
}

export async function companiesForceWinAction(data: ActionArgumentType, difficult: BotDifficultEnum): Promise<void> {
    saveDoneCompany(data.gameState.mapId, difficult);

    return companiesForceDefeatAction(data);
}
