import {type JSX, useEffect, useState} from "react";

import {UiButton} from "../../../../layout/ui-button/ui-button";
import {getSavedBotDifficult, saveBotDifficult} from "../../../../model/game/bot/bot-helper";
import {GamePlayerColorIdEnum} from "../../../../model/game/player/player-type";
import {Locale} from "../../../../provider/locale/locale-context";
import {botDifficultLangKeyMap, botDifficultList} from "../../../../provider/setting/setting-const";
import {getBotDifficultImage} from "../../../../provider/setting/setting-helper";
import type {BotDifficultEnum} from "../../../../provider/setting/setting-type";
import * as clientCompaniesBotDifficultStyle from "./client-companies-bot-difficult.scss";

export function ClientCompaniesBotDifficult(): JSX.Element {
    const [savedBotDifficult, setSavedBotDifficult] = useState<BotDifficultEnum>(getSavedBotDifficult());

    useEffect(() => {
        saveBotDifficult(savedBotDifficult);
    }, [savedBotDifficult]);

    return (
        <div className={clientCompaniesBotDifficultStyle.client_companies_bot_difficult}>
            <span className={clientCompaniesBotDifficultStyle.client_companies_bot_difficult__text}>
                <Locale stringKey="SETTINGS__AI_DIFFICULTY" />
            </span>

            <div className={clientCompaniesBotDifficultStyle.client_companies_bot_difficult__button_list}>
                {botDifficultList.map<JSX.Element>((botDifficult: BotDifficultEnum): JSX.Element => {
                    return (
                        <UiButton
                            iconSrc={getBotDifficultImage(botDifficult, GamePlayerColorIdEnum.blue)}
                            isActive={botDifficult === savedBotDifficult}
                            isSquared
                            key={botDifficult}
                            onClick={() => {
                                setSavedBotDifficult(botDifficult);
                            }}
                        >
                            <Locale stringKey={botDifficultLangKeyMap[botDifficult]} />
                        </UiButton>
                    );
                })}
            </div>
        </div>
    );
}
