import {GameLandscapeThemeEnum} from "../../../../../model/game/landscape/landscape-type";
import {landscapeImageAe1} from "./landscape-image-ae1";
import {landscapeImageAe2, type LandscapeImageMapType} from "./landscape-image-ae2";
import {landscapeImageDesert} from "./landscape-image-desert";
import {landscapeImageSummer} from "./landscape-image-summer";
import {landscapeImageSummer2} from "./landscape-image-summer2";

export type {LandscapeImageMapType} from "./landscape-image-ae2";

const landscapeImageByTheme: Record<GameLandscapeThemeEnum, LandscapeImageMapType> = {
    [GameLandscapeThemeEnum.ae1]: landscapeImageAe1,
    [GameLandscapeThemeEnum.ae2]: landscapeImageAe2,
    [GameLandscapeThemeEnum.desert]: landscapeImageDesert,
    [GameLandscapeThemeEnum.summer]: landscapeImageSummer,
    [GameLandscapeThemeEnum.summer2]: landscapeImageSummer2,
};

export function getLandscapeImage(theme: GameLandscapeThemeEnum): LandscapeImageMapType {
    return landscapeImageByTheme[theme];
}
