// Reproducible stand-in for Math.random() in the goalless-move fallback: varies per unit, per candidate
// square and per turn, yet replays identically for the same board.
function getMoveFallbackRandomValue(movedAction: MovedGameActionType, gameState: GameStateType): number {
    return getPseudoRandomNumber(
        getSeedFromNumberList([
            gameState.stepCount,
            movedAction.moveTo.x,
            movedAction.moveTo.y,
            getStringCharSum(movedAction.gameAction.unitId),
        ])
    );
}

function getPlaceData(movedAction: MovedGameActionType, gameState: GameStateType): MovedActionPlaceDataType {
    const unitToRate: GameUnitType | null = getUnitByUnitId(movedAction.gameAction.unitId, gameState.unitList);

    if (!unitToRate) {
        console.error(`can not get unit to make rating, unit id: ${movedAction.gameAction.unitId}`);
        return {
            // isNeedToHealth: false,
            onBuildingState: {
                isOnAvailableToOccupyBuilding: false,
                isOnEnemyBuilding: false,
                isOnHealsBuilding: false,
                isOnSelfBuilding: false,
                isOnTeamBuilding: false,
            },
            placeArmor: 0,
        };
    }

    const onBuildingState: MovedActionOnBuildingStateType = getIsOnBuilding(unitToRate, movedAction.moveTo, gameState);
    const placeArmor: number = getUnitArmorValue(unitToRate, gameState);

    return {
        // isNeedToHealth,
        onBuildingState,
        placeArmor,
    };
}

function getOnBuildingRate(
    movedAction: MovedGameActionType,
    onBuildingState: MovedActionOnBuildingStateType,
    gameState: GameStateType
): number {
    const unitToRate: GameUnitType | null = getUnitByUnitId(movedAction.gameAction.unitId, gameState.unitList);

    if (!unitToRate) {
        console.error(`can not get unit to make rating, unit id: ${movedAction.gameAction.unitId}`);
        return 0;
    }

    const {isOnEnemyBuilding, isOnHealsBuilding, isOnSelfBuilding, isOnTeamBuilding, isOnAvailableToOccupyBuilding} =
        onBuildingState;

    if (isOnAvailableToOccupyBuilding) {
        return getBotRateConfig().onAvailableToOccupyBuildingBonus;
    }

    if (isOnHealsBuilding || isOnSelfBuilding || isOnTeamBuilding) {
        return getBotRateConfig().onHealsBuildingBonus;
    }

    if (isOnEnemyBuilding) {
        return getBotRateConfig().onEnemyBuildingBonus;
    }

    return 0;
}

function getMovedActionAttackResultRaw(
    movedAction: MovedGameActionType,
    gameState: GameStateType
): MovedActionAttackRateType {
    const unitToRate: GameUnitType | null = getUnitByPoint(movedAction.moveFrom, gameState.unitList);

    if (!unitToRate) {
        console.error("getAttackRate: can not get unit to rate attack");
        console.log(movedAction);
        console.log(gameState);
        return {
            additionalDamageGiven: 0,
            additionalDamageReceived: 0,
            aggressorHealth: 0,
            defenderHealth: 0,
            isDefenderKilled: false,
        };
    }

    if (movedAction.gameAction.actionType !== unitToUnitAttack) {
        return {
            additionalDamageGiven: 0,
            additionalDamageReceived: 0,
            aggressorHealth: unitToRate.health,
            defenderHealth: 0,
            isDefenderKilled: false,
        };
    }

    const defenderBefore = getUnitByPoint(movedAction.gameAction.toPoint, gameState.unitList);

    if (!defenderBefore) {
        console.error(`can not get unit to make rating, unit point: ${JSON.stringify(movedAction.gameAction.toPoint)}`);
        return {
            additionalDamageGiven: 0,
            additionalDamageReceived: 0,
            aggressorHealth: unitToRate.health,
            defenderHealth: 0,
            isDefenderKilled: false,
        };
    }

    const {aggressor, defender} = getUnitToUnitAttackResult(
        {
            aggressor: {
                ...unitToRate,
                ...movedAction.gameAction.unitCurrentPoint,
            },
            defender: defenderBefore,
        },
        gameState
    );

    return {
        additionalDamageGiven: aggressor.damageGiven - unitToRate.damageGiven,
        additionalDamageReceived: aggressor.damageReceived - unitToRate.damageReceived,
        aggressorHealth: aggressor.health,
        defenderHealth: defenderBefore.health,
        isDefenderKilled: defender.health <= 0,
    };
}

/*
 * One evaluation rates the same attack action several times (the advantage filter, the difficulty
 * rating, the siege bonus), and simulating an attack is the priciest part of the rating. Actions are
 * rebuilt from scratch for every evaluation, so caching by the action object is naturally invalidated.
 */
const movedActionAttackResultCache = new WeakMap<MovedGameActionType, MovedActionAttackRateType>();

function getMovedActionAttackResult(
    movedAction: MovedGameActionType,
    gameState: GameStateType
): MovedActionAttackRateType {
    const cachedResult: MovedActionAttackRateType | undefined = movedActionAttackResultCache.get(movedAction);

    if (cachedResult) {
        return cachedResult;
    }

    const attackResult: MovedActionAttackRateType = getMovedActionAttackResultRaw(movedAction, gameState);

    movedActionAttackResultCache.set(movedAction, attackResult);

    return attackResult;
}

function getBuildingListToOccupy(
    gameState: GameStateType
): Record<"buildingListToOccupy" | "buildingListToOccupyNoEnemy", Array<GameBuildingType>> {
    const buildingTypeAvailableForOccupy: Set<GameBuildingTypeEnum> = new Set<GameBuildingTypeEnum>([
        GameBuildingTypeEnum.farm,
        GameBuildingTypeEnum.castle,
    ]);

    const enemyUnitList: Array<GameUnitType> = getEnemyUnitListByPlayerId(
        gameState.activeGamePlayerId,
        gameState.playerList,
        gameState.unitList
    );

    const buildingListToOccupy: Array<GameBuildingType> = gameState.buildingList.filter(
        (buildingInList: GameBuildingType): buildingInList is GameBuildingType => {
            if (!buildingTypeAvailableForOccupy.has(buildingInList.buildingType)) {
                return false;
            }

            return (
                getTeamIdByPlayerId(buildingInList.gamePlayerId, gameState.playerList) !==
                getTeamIdByPlayerId(gameState.activeGamePlayerId, gameState.playerList)
            );
        }
    );

    const buildingListToOccupyNoEnemy: Array<GameBuildingType> = buildingListToOccupy.filter<GameBuildingType>(
        (building: GameBuildingType): building is GameBuildingType => {
            const enemyOnBuilding: GameUnitType | null = getUnitByPoint({x: building.x, y: building.y}, enemyUnitList);

            return !enemyOnBuilding;
        }
    );

    return {
        buildingListToOccupy,
        buildingListToOccupyNoEnemy,
    };
}

// eslint-disable-next-line id-length
function getBuildingListByEnemyOccupyOnNextTurn(gameState: GameStateType): Array<GameBuildingType> {
    const pointToEnemyOccupy: Record<GameBuildingTypeEnum.castle | GameBuildingTypeEnum.farm, Array<PointType>> = {
        [GameBuildingTypeEnum.castle]: [],
        [GameBuildingTypeEnum.farm]: [],
    };

    const enemyUnitList: Array<GameUnitType> = getEnemyUnitListByPlayerId(
        gameState.activeGamePlayerId,
        gameState.playerList,
        gameState.unitList
    );

    enemyUnitList.forEach((enemyUnit: GameUnitType) => {
        const enemyUnitInfo = getUnitInfoByUnit(enemyUnit);

        if (enemyUnitInfo.occupyBuildingList.length === 0) {
            return;
        }

        const {movePointList} = getEnemyIsolatedAvailableMove(enemyUnit, gameState);

        if (enemyUnitInfo.occupyBuildingList.includes(GameBuildingTypeEnum.farm)) {
            pointToEnemyOccupy[GameBuildingTypeEnum.farm].push(...movePointList);
        }

        if (enemyUnitInfo.occupyBuildingList.includes(GameBuildingTypeEnum.castle)) {
            pointToEnemyOccupy[GameBuildingTypeEnum.castle].push(...movePointList);
        }
    });

    const activeTeamId = getTeamIdByPlayerId(gameState.activeGamePlayerId, gameState.playerList);

    const buildingListToEnemyOccupy: Array<GameBuildingType> = gameState.buildingList.filter(
        (buildingInList: GameBuildingType): buildingInList is GameBuildingType => {
            // A building the enemy already owns cannot be "prevented" from occupation — the enemy
            // does not need to re-occupy what it holds, so standing a unit on it is a wasted move.
            // Only neutral buildings and our own team's buildings are worth blocking or holding.
            const isOwnedByEnemy =
                buildingInList.gamePlayerId !== GamePlayerIdEnum.playerEmpty &&
                getTeamIdByPlayerId(buildingInList.gamePlayerId, gameState.playerList) !== activeTeamId;

            if (isOwnedByEnemy) {
                return false;
            }

            if (
                buildingInList.buildingType === GameBuildingTypeEnum.farm &&
                getPointByPoint(
                    {
                        x: buildingInList.x,
                        y: buildingInList.y,
                    },
                    pointToEnemyOccupy[GameBuildingTypeEnum.farm]
                )
            ) {
                return true;
            }

            if (
                buildingInList.buildingType === GameBuildingTypeEnum.castle &&
                getPointByPoint(
                    {
                        x: buildingInList.x,
                        y: buildingInList.y,
                    },
                    pointToEnemyOccupy[GameBuildingTypeEnum.castle]
                )
            ) {
                return true;
            }

            return false;
        }
    );

    return buildingListToEnemyOccupy;
}

// How much health the unit would actually regain at the building (capped by its max health).
function getBuildingHealForUnit(building: GameBuildingType, unit: GameUnitType, gameState: GameStateType): number {
    const healthBonus: number = getBuildingHealthBonus(building.buildingType, gameState.gameSettings);

    return (
        addHealthToUnit(unit.health, healthBonus, getPlayerMaxUnitHealth(unit.gamePlayerId, gameState.playerList)) -
        unit.health
    );
}

/*
 * Extra value for an enemy that is entrenched on a building, so the bot concentrates fire on it
 * instead of trading blows in the open. Two things make such an enemy worth dislodging:
 *
 * 1. The building may HEAL it every turn (mirrors getSwitchTurnUnitState: a buildingOk square that
 *    heals everyone — temple / well — or belongs to the enemy's own team). That heal is bonus HP the
 *    bot must grind through, which is exactly why a lone chip is normally rejected as unprofitable;
 *    here it becomes a reason to gang up rather than to give up.
 * 2. More importantly, the building may BANKROLL the enemy team (a castle / farm owned by a team that
 *    is not the bot's). Killing the occupant is the only way to later raze or capture that income,
 *    since a unit standing on a building cannot be destroyed by a unit-to-building attack.
 *
 * Returns 0 when the enemy is not on a building, when the building neither heals it right now nor
 * feeds the enemy economy (e.g. a neutral square, our own building, or a full-health unit on a
 * heal-only building), so open-field targets keep their ordinary rating.
 */
// The two things that make an entrenched enemy special: how much HP its building heals back to it next
// turn (temple / well heal everyone; a team's own building heals its owner) and how much income that
// building feeds the enemy team (a castle / farm owned by a team that is not the bot's). Both are 0
// when the enemy is not on a relevant building.
function getEntrenchedComponents(
    unit: GameUnitType,
    gameState: GameStateType
): Record<"enemyIncome" | "healBack", number> {
    const building: GameBuildingType | null = getBuildingByPoint({x: unit.x, y: unit.y}, gameState.buildingList);

    if (building?.state !== GameBuildingStateEnum.buildingOk) {
        return {enemyIncome: 0, healBack: 0};
    }

    const botTeamId = getTeamIdByPlayerId(gameState.activeGamePlayerId, gameState.playerList);
    const buildingTeamId = getTeamIdByPlayerId(building.gamePlayerId, gameState.playerList);

    // How much the building actually restores to THIS enemy unit next turn (0 when it does not heal it
    // or the unit is already at full health).
    const isHealedByBuilding: boolean =
        getBuildingInfo(building).canHealthAll ||
        buildingTeamId === getTeamIdByPlayerId(unit.gamePlayerId, gameState.playerList);
    const healBack: number = isHealedByBuilding ? getBuildingHealForUnit(building, unit, gameState) : 0;

    // Money the enemy team pockets from this building (0 for neutral squares or our own team's buildings).
    const enemyIncome: number =
        building.gamePlayerId !== GamePlayerIdEnum.playerEmpty && buildingTeamId !== botTeamId
            ? getBuildingMoneyIncome(building.buildingType, gameState.gameSettings)
            : 0;

    return {enemyIncome, healBack};
}

export function getEntrenchedEnemyRate(unit: GameUnitType, gameState: GameStateType): number {
    const {healBack, enemyIncome} = getEntrenchedComponents(unit, gameState);

    if (healBack <= 0 && enemyIncome <= 0) {
        return 0;
    }

    const {siegeEntrenchedBonus, siegeHealWeight, siegeIncomeWeight} = getBotRateConfig();

    return siegeEntrenchedBonus + healBack * siegeHealWeight + enemyIncome * siegeIncomeWeight;
}

// The defender of a would-be attack, but only for a NON-LETHAL strike that actually lands damage — the
// shared precondition of both siege terms below (a kill removes the occupant, so neither term applies,
// and a fully-mitigated hit makes no progress worth weighing). Null otherwise.
function getChipTargetDefender(movedAction: MovedGameActionType, gameState: GameStateType): GameUnitType | null {
    if (movedAction.gameAction.actionType !== unitToUnitAttack) {
        return null;
    }

    const defender: GameUnitType | null = getUnitByPoint(movedAction.gameAction.toPoint, gameState.unitList);

    if (!defender) {
        return null;
    }

    const attackResult: MovedActionAttackRateType = getMovedActionAttackResult(movedAction, gameState);

    if (attackResult.isDefenderKilled || attackResult.additionalDamageGiven <= 0) {
        return null;
    }

    return defender;
}

/*
 * Strategic value (in the same gold-ish units as the rest of the rating's bonuses) of grinding an enemy
 * a non-lethal strike does not finish this turn: earned ONLY when it sits on an INCOME building, because
 * killing the occupant is the only way to later deny that income (a unit on a building can't be razed by
 * a unit-to-building attack), so the bot should keep chipping it even one hit at a time. A heal building
 * with no income earns nothing here — the wasted damage from its per-turn heal is a separate, HP-valued
 * concern handled by getHealBackWaste, kept out of this term so the two currencies never mix.
 */
function getSiegeTargetRate(movedAction: MovedGameActionType, gameState: GameStateType): number {
    const defender: GameUnitType | null = getChipTargetDefender(movedAction, gameState);

    if (!defender) {
        return 0;
    }

    const {enemyIncome} = getEntrenchedComponents(defender, gameState);

    if (enemyIncome <= 0) {
        return 0;
    }

    const {siegeEntrenchedBonus, siegeIncomeWeight} = getBotRateConfig();

    return siegeEntrenchedBonus + enemyIncome * siegeIncomeWeight;
}

// HP a non-lethal chip WASTES: an enemy on a building that heals it regains ~healBack HP next turn, so
// that much of the damage is undone. Returned as raw HP so the caller can subtract it directly from the
// (also HP-valued) damage progress — an equally-hittable open-field target keeps all its damage and is
// therefore preferred. 0 when the strike does not land damage or the defender does not heal next turn.
function getHealBackWaste(movedAction: MovedGameActionType, gameState: GameStateType): number {
    const defender: GameUnitType | null = getChipTargetDefender(movedAction, gameState);

    if (!defender) {
        return 0;
    }

    return getEntrenchedComponents(defender, gameState).healBack;
}

function getBestBuildingToHealth(
    startPoint: PointType,
    unit: GameUnitType,
    gameState: GameStateType
): GameBuildingType | null {
    const neededBuildingList: Array<GameBuildingType> = gameState.buildingList.filter<GameBuildingType>(
        (buildingInList: GameBuildingType): buildingInList is GameBuildingType => {
            // A building someone else already stands on cannot be reached to heal — the wounded unit
            // would only hover around it; its own square (it is already healing there) stays valid.
            const unitOnBuilding: GameUnitType | null = getUnitByPoint(
                {x: buildingInList.x, y: buildingInList.y},
                gameState.unitList
            );

            if (unitOnBuilding && unitOnBuilding.unitId !== unit.unitId) {
                return false;
            }

            if (getBuildingInfo(buildingInList).canHealthAll) {
                return true;
            }

            return (
                getTeamIdByPlayerId(buildingInList.gamePlayerId, gameState.playerList) ===
                getTeamIdByPlayerId(gameState.activeGamePlayerId, gameState.playerList)
            );
        }
    );

    // Prefer buildings that heal more, while still penalizing the distance to reach them.
    return getMaxInList<GameBuildingType>(neededBuildingList, (buildingInList: GameBuildingType): number => {
        const steps: number = getBotPathDistance(
            startPoint,
            {x: buildingInList.x, y: buildingInList.y},
            unit,
            gameState
        );

        const {healBuildingStepWeight} = getBotRateConfig();

        return getBuildingHealForUnit(buildingInList, unit, gameState) - steps * healBuildingStepWeight;
    });
}

// eslint-disable-next-line @typescript-eslint/max-params
function getCloseEnemyUnit(
    startPoint: PointType,
    enemyUnitList: Array<GameUnitType>,
    unit: GameUnitType,
    gameState: GameStateType
): GameUnitType | null {
    return getMinInList<GameUnitType>(enemyUnitList, (unitInList: GameUnitType): number => {
        return getBotPathDistance(startPoint, {x: unitInList.x, y: unitInList.y}, unit, gameState);
    });
}

// eslint-disable-next-line @typescript-eslint/max-params
function getCloseBuildingListToOccupy(
    startPoint: PointType,
    buildingListToOccupy: Array<GameBuildingType>,
    unit: GameUnitType,
    gameState: GameStateType
): GameBuildingType | null {
    return getMinInList<GameBuildingType>(buildingListToOccupy, (buildingInList: GameBuildingType): number => {
        return getBotPathDistance(startPoint, {x: buildingInList.x, y: buildingInList.y}, unit, gameState);
    });
}

// eslint-disable-next-line @typescript-eslint/max-params
function getBestBuildingToOccupy(
    startPoint: PointType,
    buildingListToOccupy: Array<GameBuildingType>,
    unit: GameUnitType,
    gameState: GameStateType
): GameBuildingType | null {
    // Prefer buildings that bring more money, while still penalizing the distance to reach them.
    return getMaxInList<GameBuildingType>(buildingListToOccupy, (buildingInList: GameBuildingType): number => {
        const steps: number = getBotPathDistance(
            startPoint,
            {x: buildingInList.x, y: buildingInList.y},
            unit,
            gameState
        );
        const moneyIncome: number = getBuildingMoneyIncome(buildingInList.buildingType, gameState.gameSettings);

        return moneyIncome - steps * getBotRateConfig().occupyBuildingStepWeight;
    });
}

function getSortedMovedActionMap(
    movedActionList: Array<MovedGameActionType>,
    deniedMovePointList: Array<PointType>,
    unitList: Array<GameUnitType>
): Record<GameActionTypeEnum, Array<MovedGameActionType>> {
    const unitOverUnit = getUnitOverUnit(unitList);
    let unitOverUnitId: string | null = null;

    if (unitOverUnit) {
        const [, overUnit] = unitOverUnit;

        unitOverUnitId = overUnit.unitId;
    }

    const sortPushAction: Record<GameActionTypeEnum, Array<MovedGameActionType>> = {
        [addUnitList]: [], // no needed for bot
        [buyUnit]: [],
        [changeTurn]: [], // the last action
        [companiesForceDefeat]: [], // no needed for bot
        [companiesForceVictory]: [], // no needed for bot
        [fixBuilding]: [], // +
        [occupyBuilding]: [], // +
        [raiseSkeleton]: [], // +
        [showBriefing]: [], // +
        [unitMove]: [],
        [unitMoveRevert]: [], // no needed for bot
        [unitToBuildingAttack]: [], // +
        [unitToUnitAttack]: [], // +
    };

    const getBuildingTypeList: Set<GameActionTypeEnum> = new Set<GameActionTypeEnum>([occupyBuilding, fixBuilding]);

    movedActionList.forEach((movedActionInList: MovedGameActionType) => {
        // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
        if (unitOverUnitId && unitOverUnitId !== movedActionInList.gameAction.unitId) {
            return;
        }

        if (getBuildingTypeList.has(movedActionInList.gameAction.actionType)) {
            sortPushAction[movedActionInList.gameAction.actionType].push(movedActionInList);
            return;
        }

        const pointFromDeniedForOccupyPointList: boolean = getIsPointInList(
            movedActionInList.moveTo,
            deniedMovePointList
        );

        if (pointFromDeniedForOccupyPointList) {
            return;
        }

        sortPushAction[movedActionInList.gameAction.actionType].push(movedActionInList);
    });

    return sortPushAction;
}

function getDeniedToMovePointList(gameState: GameStateType): Array<PointType> {
    const {activeGamePlayerId, unitList} = gameState;

    const unitOverUnit = getUnitOverUnit(unitList);

    if (unitOverUnit) {
        const [, overUnit] = unitOverUnit;

        return [{x: overUnit.x, y: overUnit.y}];
    }

    const {buildingListToOccupy} = getBuildingListToOccupy(gameState);
    const playerUnitList: Array<GameUnitType> = getUnitListByPlayerId(activeGamePlayerId, unitList);
    const unitCanOccupyList: Array<GameUnitType> = playerUnitList.filter<GameUnitType>(
        (unitInList: GameUnitType): unitInList is GameUnitType => {
            return getUnitInfoByUnit(unitInList).occupyBuildingList.length > 0;
        }
    );

    const pointToOccupyList: Array<PointType> = [];

    unitCanOccupyList.forEach((unitInList: GameUnitType) => {
        const {occupyBuildingList} = getUnitInfoByUnit(unitInList);
        const {moveOnAllyPointList} = getUnitAvailableMove(unitInList, gameState);

        moveOnAllyPointList.forEach((moveOnAllyPoint: PointType) => {
            const buildingUnderPoint: GameBuildingType | null = getBuildingByPoint(
                moveOnAllyPoint,
                buildingListToOccupy
            );

            if (buildingUnderPoint && occupyBuildingList.includes(buildingUnderPoint.buildingType)) {
                pointToOccupyList.push(moveOnAllyPoint);
            }
        });
    });

    return pointToOccupyList;
}

// console.log([3, 2, 1, 4, 5, 4, 3, 2].sort((a, b) => a - b)); // - 1,2,3,4,5...

function getOccupyBuildingMovedAction(
    sortedMovedActionMap: Record<GameActionTypeEnum, Array<MovedGameActionType>>
): MovedGameActionType | null {
    const occupyBuildingList = sortedMovedActionMap[occupyBuilding];

    return getMaxInList<MovedGameActionType>(occupyBuildingList, (movedAction: MovedGameActionType): number => {
        // get the far first
        return getStepsBetweenPoints(movedAction.moveFrom, movedAction.moveTo);
    });
}

// A unit that can DESTROY this building type but cannot OCCUPY (hold) it — for such a unit (e.g. a
// catapult vs a farm) razing a threatened building beats blocking it. Own-team buildings can't be
// destroyed anyway (see getUnitAvailableUnitToBuildingAttack), so in practice this concerns neutral
// buildings the enemy is about to grab.
function getCanRazeNotHold(unit: GameUnitType, buildingType: GameBuildingTypeEnum): boolean {
    const {destroyBuildingList, occupyBuildingList} = getUnitInfoByUnit(unit);

    return destroyBuildingList.includes(buildingType) && !occupyBuildingList.includes(buildingType);
}

// A siege unit razes the very building the enemy is about to capture instead of babysitting it: a
// broken building can't be occupied and the unit stays free. Called AFTER cover / occupy in
// getMaxAction, so the bot still prefers to HOLD or TAKE such a building with a unit that can — razing
// is the fallback when only a destroyer is on hand. Targets a threatened building
// (getBuildingListByEnemyOccupyOnNextTurn) this unit can raze-not-hold.
function getRazeThreatenedMovedAction(
    sortedMovedActionMap: Record<GameActionTypeEnum, Array<MovedGameActionType>>,
    gameState: GameStateType
): MovedGameActionType | null {
    const occupyByEnemyBuildingList = getBuildingListByEnemyOccupyOnNextTurn(gameState);

    if (occupyByEnemyBuildingList.length === 0) {
        return null;
    }

    const razeList: Array<MovedGameActionType> = sortedMovedActionMap[unitToBuildingAttack].filter<MovedGameActionType>(
        (movedAction: MovedGameActionType): movedAction is MovedGameActionType => {
            const targetBuilding = getBuildingByPoint(movedAction.gameAction.toPoint, gameState.buildingList);

            if (!targetBuilding) {
                return false;
            }

            const isThreatened: boolean = occupyByEnemyBuildingList.some((building: GameBuildingType): boolean => {
                return getIsEqualPoint({x: building.x, y: building.y}, movedAction.gameAction.toPoint);
            });

            if (!isThreatened) {
                return false;
            }

            const unit = getUnitByUnitId(movedAction.gameAction.unitId, gameState.unitList);

            return unit ? getCanRazeNotHold(unit, targetBuilding.buildingType) : false;
        }
    );

    // Raze the nearest threatened target first (the readiest shot).
    return getMinInList<MovedGameActionType>(razeList, (movedAction: MovedGameActionType): number => {
        return getStepsBetweenPoints(movedAction.moveFrom, movedAction.gameAction.toPoint);
    });
}

function getMoveToPreventBuildingOccupation(
    sortedMovedActionMap: Record<GameActionTypeEnum, Array<MovedGameActionType>>,
    gameState: GameStateType
): MovedGameActionType | null {
    const occupyByEnemyBuildingList = getBuildingListByEnemyOccupyOnNextTurn(gameState);
    const moveList: Array<MovedGameActionType> = sortedMovedActionMap[unitMove].filter<MovedGameActionType>(
        (gameAction: MovedGameActionType): gameAction is MovedGameActionType => {
            const unit = getUnitByUnitId(gameAction.gameAction.unitId, gameState.unitList);

            if (!unit) {
                console.error("Can not get unit to prevent building occupation");
                return false;
            }

            if (unit.movedCount > 0) {
                return false;
            }

            const targetBuilding = getBuildingByPoint(gameAction.moveTo, gameState.buildingList);

            // A unit that can DESTROY but not HOLD this building type (e.g. a catapult on a farm) never
            // babysits it — it razes it instead (see getRazeThreatenedMovedAction). Standing on
            // it only blocks for one turn and wastes the siege unit; a broken building can't be occupied.
            if (targetBuilding && getCanRazeNotHold(unit, targetBuilding.buildingType)) {
                return false;
            }

            return occupyByEnemyBuildingList.some((building: GameBuildingType): boolean => {
                return getIsEqualPoint({x: building.x, y: building.y}, gameAction.moveTo);
            });
        }
    );

    const maxSizedMoveAction: MovedGameActionType | null = getMaxInList<MovedGameActionType>(
        moveList,
        (movedAction: MovedGameActionType): number => {
            const building = getBuildingByPoint(movedAction.moveTo, gameState.buildingList);
            const storeBonus =
                building && getBuildingInfo(building).canBeStore ? getBotRateConfig().storeBuildingBonus : 0;

            return getStepsBetweenPoints(movedAction.moveFrom, movedAction.moveTo) + storeBonus;
        }
    );

    return maxSizedMoveAction;
}

interface FocusFireCandidateType {
    attackRate: MovedActionAttackRateType;
    movedAction: MovedGameActionType;
}

// The better of two attacks by the SAME unit on the SAME defender (e.g. striking from a safe range-2
// square versus a melee square): a strike the defender cannot answer beats ANY retaliated one — the
// position-dependent damage roll differs by a few points at most and is never worth eating a strike
// back. Within the same class the harder hit wins, retaliation breaks ties.
function getFocusFireCandidateQuality(attackRate: MovedActionAttackRateType): number {
    const noRetaliationBonus: number = attackRate.additionalDamageReceived === 0 ? 1e9 : 0;

    return noRetaliationBonus + attackRate.additionalDamageGiven * 1000 - attackRate.additionalDamageReceived;
}

// Gold-denominated value the attackers lose to retaliation over the whole package: each point of damage
// received costs its share of that attacker's price.
function getFocusFireRetaliationCost(packageList: Array<FocusFireCandidateType>, gameState: GameStateType): number {
    return packageList.reduce<number>((cost: number, candidate: FocusFireCandidateType): number => {
        const attacker: GameUnitType | null = getUnitByUnitId(
            candidate.movedAction.gameAction.unitId,
            gameState.unitList
        );

        if (!attacker) {
            return cost;
        }

        const attackerMaxHealth: number = getPlayerMaxUnitHealth(attacker.gamePlayerId, gameState.playerList);

        return (
            cost +
            (candidate.attackRate.additionalDamageReceived * getUnitInfoByUnit(attacker).cost) / attackerMaxHealth
        );
    }, 0);
}

interface FocusFirePackageType {
    openingAction: MovedGameActionType;
    score: number;
}

// The kill package for ONE defender: the strongest per-attacker hits stacked until they cover its
// health. Returns null when even the whole army cannot finish the defender this turn, or when the kill
// is not worth the retaliation. Single-attack kills never reach this code (see getFocusFireMovedAction).
// eslint-disable-next-line max-statements
function getFocusFirePackage(
    attackListByAttacker: Map<string, FocusFireCandidateType>,
    gameState: GameStateType
): FocusFirePackageType | null {
    const candidateList: Array<FocusFireCandidateType> = [...attackListByAttacker.values()].sort(
        (candidateA: FocusFireCandidateType, candidateB: FocusFireCandidateType): number => {
            return candidateB.attackRate.additionalDamageGiven - candidateA.attackRate.additionalDamageGiven;
        }
    );

    const firstCandidate: FocusFireCandidateType | undefined = candidateList.at(0);

    if (!firstCandidate) {
        return null;
    }

    const defender: GameUnitType | null = getUnitByPoint(
        firstCandidate.movedAction.gameAction.toPoint,
        gameState.unitList
    );

    if (!defender) {
        return null;
    }

    // Stack the strongest hits until the combined damage covers the defender's health.
    const packageList: Array<FocusFireCandidateType> = [];
    let totalDamage = 0;

    for (const candidate of candidateList) {
        if (totalDamage >= defender.health) {
            break;
        }

        packageList.push(candidate);
        totalDamage += candidate.attackRate.additionalDamageGiven;
    }

    if (packageList.length < 2 || totalDamage < defender.health) {
        return null;
    }

    const score: number =
        getUnitInfoByUnit(defender).cost +
        getEntrenchedEnemyRate(defender, gameState) -
        getFocusFireRetaliationCost(packageList, gameState);

    if (score <= 0) {
        return null;
    }

    // Open with a no-retaliation strike when the package has one: the melee attackers then hit an
    // already-weakened defender, whose strike-back scales down with its health.
    const openingCandidate: FocusFireCandidateType | null = getMaxInList<FocusFireCandidateType>(
        packageList,
        (candidate: FocusFireCandidateType): number => {
            const noRetaliationBonus: number = candidate.attackRate.additionalDamageReceived === 0 ? 1e6 : 0;

            return noRetaliationBonus + candidate.attackRate.additionalDamageGiven;
        }
    );

    if (!openingCandidate) {
        return null;
    }

    return {openingAction: openingCandidate.movedAction, score};
}

/*
 * Coordinated focus fire (hard and normal bots): the greedy per-attack rating maximises every strike on
 * its own, so when no single attack kills, damage gets spread across several targets and nothing dies.
 * This instead looks for a combined kill: for each enemy, the best attack of each bot unit against it,
 * stacked strongest-first until the damage covers the enemy's health. The most valuable such kill
 * (defender's cost + its entrenched value, minus the gold value of the retaliation the attackers soak)
 * is committed to by returning its opening attack — the evaluation after that action re-plans on the
 * damaged board, where the same target is now the cheapest kill, so the package completes naturally.
 *
 * Steps aside (returns null) when any single attack already kills: the greedy killBonus handles that
 * with its full positional rating. Attack-square conflicts inside a package (two units wanting the same
 * tile) are also left to the re-planning between actions — the damage estimate is optimistic by at most
 * one blocked attacker, and the following evaluation corrects it.
 */
function getFocusFireMovedAction(
    unitToUnitAttackList: Array<MovedGameActionType>,
    gameState: GameStateType
): MovedGameActionType | null {
    const hasSingleAttackKill: boolean = unitToUnitAttackList.some((movedAction: MovedGameActionType): boolean => {
        return getMovedActionAttackResult(movedAction, gameState).isDefenderKilled;
    });

    if (hasSingleAttackKill) {
        return null;
    }

    // The best attack of each attacker against each defender: defender tile -> attacker id -> candidate.
    const attackListByDefender = new Map<string, Map<string, FocusFireCandidateType>>();

    unitToUnitAttackList.forEach((movedAction: MovedGameActionType) => {
        const attackRate: MovedActionAttackRateType = getMovedActionAttackResult(movedAction, gameState);

        if (attackRate.additionalDamageGiven <= 0) {
            return;
        }

        const {toPoint} = movedAction.gameAction;
        const defenderKey = `${toPoint.x}/${toPoint.y}`;
        const attackListByAttacker: Map<string, FocusFireCandidateType> =
            attackListByDefender.get(defenderKey) ?? new Map<string, FocusFireCandidateType>();

        attackListByDefender.set(defenderKey, attackListByAttacker);

        const attackerId: string = movedAction.gameAction.unitId;
        const knownCandidate: FocusFireCandidateType | undefined = attackListByAttacker.get(attackerId);

        if (
            !knownCandidate ||
            getFocusFireCandidateQuality(attackRate) > getFocusFireCandidateQuality(knownCandidate.attackRate)
        ) {
            attackListByAttacker.set(attackerId, {attackRate, movedAction});
        }
    });

    let bestScore = 0;
    let bestOpeningAction: MovedGameActionType | null = null;

    attackListByDefender.forEach((attackListByAttacker: Map<string, FocusFireCandidateType>) => {
        const focusFirePackage: FocusFirePackageType | null = getFocusFirePackage(attackListByAttacker, gameState);

        if (focusFirePackage && focusFirePackage.score > bestScore) {
            bestScore = focusFirePackage.score;
            bestOpeningAction = focusFirePackage.openingAction;
        }
    });

    return bestOpeningAction;
}

// Front weight of a covered ally: 1 while within auraFrontlineDistance of the nearest enemy (by real
// path distance), hyperbolically less for the rear guard — the aura's +attack only pays off on allies
// that are about to fight, so covering a unit far from any battle is worth little.
function getAuraAllyFrontWeight(
    allyUnit: GameUnitType,
    enemyUnitList: Array<GameUnitType>,
    gameState: GameStateType
): number {
    const allyPoint: PointType = {x: allyUnit.x, y: allyUnit.y};
    const closeEnemyUnit: GameUnitType | null = getCloseEnemyUnit(allyPoint, enemyUnitList, allyUnit, gameState);

    if (!closeEnemyUnit) {
        return 1;
    }

    const enemyDistance: number = getBotPathDistance(
        allyPoint,
        {x: closeEnemyUnit.x, y: closeEnemyUnit.y},
        allyUnit,
        gameState
    );

    return Math.min(1, getBotRateConfig().auraFrontlineDistance / Math.max(enemyDistance, 1));
}

/*
 * Move-rating bonus for an aura carrier (a unit with wispAuraRange > 0, e.g. the wisp): the sum of the
 * front weights of every aura-accepting teammate the candidate square would cover, scaled by
 * auraCoveredAllyRating. Returns 0 for ordinary units, so the term is free for the bulk of the army.
 * Weighting by closeness to the enemy makes the carrier shadow the units that are actually fighting
 * instead of hovering over an equally-sized crowd in the rear.
 */
// eslint-disable-next-line @typescript-eslint/max-params
function getAuraCoverRating(
    unitToRate: GameUnitType,
    moveToPoint: PointType,
    enemyUnitList: Array<GameUnitType>,
    gameState: GameStateType
): number {
    const {wispAuraRange} = getUnitInfoByUnit(unitToRate);

    if (wispAuraRange <= 0) {
        return 0;
    }

    const carrierTeamId: GamePlayerTeamIdEnum = getTeamIdByPlayerId(unitToRate.gamePlayerId, gameState.playerList);

    const coveredAllyWeight: number = gameState.unitList.reduce<number>(
        (weightSum: number, allyUnit: GameUnitType): number => {
            if (allyUnit.unitId === unitToRate.unitId) {
                return weightSum;
            }

            if (!getUnitInfoByUnit(allyUnit).isWispAuraAccept) {
                return weightSum;
            }

            if (getTeamIdByPlayerId(allyUnit.gamePlayerId, gameState.playerList) !== carrierTeamId) {
                return weightSum;
            }

            if (getStepsBetweenPoints(moveToPoint, {x: allyUnit.x, y: allyUnit.y}) > wispAuraRange) {
                return weightSum;
            }

            return weightSum + getAuraAllyFrontWeight(allyUnit, enemyUnitList, gameState);
        },
        0
    );

    return coveredAllyWeight * getBotRateConfig().auraCoveredAllyRating;
}

// Whether the difficulty runs the coordinated focus-fire pass, by bot difficulty.
function getIsFocusFireEnabled(botDifficult?: BotDifficultEnum): boolean {
    const {isBotNormal, isBotEasy} = getBotDifficultMap(botDifficult);
    const {focusFire} = getBotRateConfig();

    if (isBotEasy) {
        return focusFire.easy > 0;
    }

    if (isBotNormal) {
        return focusFire.normal > 0;
    }

    return focusFire.hard > 0;
}

// Minimal health for a unit to pick a fight, by bot difficulty.
function getMinHealthToFight(botDifficult?: BotDifficultEnum): number {
    const {isBotNormal, isBotEasy} = getBotDifficultMap(botDifficult);

    if (isBotEasy) {
        return getBotRateConfig().minHealthToFight.easy;
    }

    if (isBotNormal) {
        return getBotRateConfig().minHealthToFight.normal;
    }

    return getBotRateConfig().minHealthToFight.hard;
}

// groupEngage mode for the difficulty (0 = off). See getIsOutnumberedEngage / groupEngageMode config.
function getGroupEngageMode(botDifficult?: BotDifficultEnum): number {
    const {isBotNormal, isBotEasy} = getBotDifficultMap(botDifficult);
    const {groupEngageMode} = getBotRateConfig();

    if (isBotEasy) {
        return groupEngageMode.easy;
    }

    if (isBotNormal) {
        return groupEngageMode.normal;
    }

    return groupEngageMode.hard;
}

/*
 * "Attack with the numbers" gate: true if `unit` fighting from `engageTile` would be outnumbered by a
 * nearby enemy GROUP without comparable friendly support. Stops the bot feeding a lone unit into 2-3
 * enemies (the classic turn 3-4 suicide) — it commits a unit only when allies are there to trade too.
 * Only combat units count (attack.max > 0), so parked crystals / objectives never skew the tally. The
 * engaging unit counts toward its own support. Exempt when the team has no other fighter (a lone hero
 * must still act); the KILL exemption is handled by the caller (a kill removes one of the group).
 */
function getIsOutnumberedEngage(
    movedAction: MovedGameActionType,
    gameState: GameStateType,
    botDifficult?: BotDifficultEnum
): boolean {
    if (getGroupEngageMode(botDifficult) <= 0) {
        return false;
    }

    const {unitList, playerList, activeGamePlayerId} = gameState;
    const {groupEngageRadius, groupEngageMinEnemyCount, groupEngageSupportPerEnemy} = getBotRateConfig();
    const activeTeamId = getTeamIdByPlayerId(activeGamePlayerId, playerList);
    const engageTile: PointType = movedAction.moveTo;

    function isCombatUnit(unitInList: GameUnitType): boolean {
        return getUnitInfoByUnit(unitInList).attack.max > 0;
    }

    function isNearEngageTile(unitInList: GameUnitType): boolean {
        return getStepsBetweenPoints(engageTile, {x: unitInList.x, y: unitInList.y}) <= groupEngageRadius;
    }

    const enemyGroupCount: number = unitList.filter((unitInList: GameUnitType): boolean => {
        return (
            isCombatUnit(unitInList) &&
            getTeamIdByPlayerId(unitInList.gamePlayerId, playerList) !== activeTeamId &&
            isNearEngageTile(unitInList)
        );
    }).length;

    // A lone duel (or open field) is never gated: single-target aggression is unaffected.
    if (enemyGroupCount < groupEngageMinEnemyCount) {
        return false;
    }

    const teamCombatUnitList: Array<GameUnitType> = unitList.filter<GameUnitType>(
        (unitInList: GameUnitType): unitInList is GameUnitType => {
            return (
                isCombatUnit(unitInList) && getTeamIdByPlayerId(unitInList.gamePlayerId, playerList) === activeTeamId
            );
        }
    );

    // Lone-hero / last-survivor exemption: with no other fighter to bring, the unit must still act.
    if (teamCombatUnitList.length <= 1) {
        return false;
    }

    const allySupportCount: number = teamCombatUnitList.filter((unitInList: GameUnitType): boolean => {
        return unitInList.unitId === movedAction.gameAction.unitId || isNearEngageTile(unitInList);
    }).length;

    return allySupportCount < enemyGroupCount * groupEngageSupportPerEnemy;
}

/*
 * Does this attack pass the difficulty's advantage filter? Shared by the attack picker and by the
 * move rating (fearlessViableAttackOnly): a unit is only fearless when it can actually strike.
 */
function getIsViableAttack(
    movedAction: MovedGameActionType,
    gameState: GameStateType,
    botDifficult?: BotDifficultEnum
): boolean {
    const {isBotNormal, isBotEasy} = getBotDifficultMap(botDifficult);
    const minHealthToFight: number = getMinHealthToFight(botDifficult);
    const attackerUnitId = movedAction.gameAction.unitId;
    const unit = getUnitByUnitId(attackerUnitId, gameState.unitList);

    if (!unit) {
        console.error(`[getIsViableAttack]: can not get unit by unitId: ${attackerUnitId}`);
        return false;
    }

    const attackRate: MovedActionAttackRateType = getMovedActionAttackResult(movedAction, gameState);
    const advantage: number =
        Math.min(attackRate.additionalDamageGiven, attackRate.defenderHealth) - attackRate.additionalDamageReceived;

    // A badly wounded unit retreats to heal instead of trading blows — unless this very
    // attack finishes the defender off, or there is nowhere to heal anyway.
    if (
        !attackRate.isDefenderKilled &&
        unit.health < minHealthToFight &&
        getBestBuildingToHealth({x: unit.x, y: unit.y}, unit, gameState)
    ) {
        return false;
    }

    if (isBotEasy) {
        return advantage >= getBotRateConfig().attackAdvantageThreshold.easy;
    }

    if (isBotNormal) {
        return advantage >= getBotRateConfig().attackAdvantageThreshold.normal;
    }

    return advantage >= getBotRateConfig().attackAdvantageThreshold.hard;
}

// True if this attack ends the unit on a tile an enemy standing on a FORTIFYING building (a heal
// building — extra armor + per-turn healing — or its own team's building — extra armor, and it cannot
// be dislodged by a unit-to-building attack) can hit, and the target is NOT itself such an entrenched
// unit. Attacking the unit ON the building (focus fire, to dislodge it) is deliberately exempt — for
// every fortifying-building kind, so the bot still gangs up on the entrenched enemy itself.
// `fortifiedCoverPointList` is getLowPriorityPointList(gameState), the tiles those fortified enemies
// cover, passed in so it is computed once per turn, not per candidate.
function getIsAttackIntoFortifiedCover(
    movedAction: MovedGameActionType,
    gameState: GameStateType,
    fortifiedCoverPointList: Array<PointType>
): boolean {
    if (!getPointByPoint(movedAction.moveTo, fortifiedCoverPointList)) {
        return false;
    }

    const targetUnit: GameUnitType | null = getUnitByPoint(movedAction.gameAction.toPoint, gameState.unitList);

    if (!targetUnit) {
        return false;
    }

    // Focus fire on the entrenched unit itself is how you break the position — allowed on any
    // fortifying building (heal / own / team), matching the cover set the list is built from.
    const {isOnHealsBuilding, isOnSelfBuilding, isOnTeamBuilding} = getIsOnBuilding(
        targetUnit,
        {x: targetUnit.x, y: targetUnit.y},
        gameState
    );

    return !(isOnHealsBuilding || isOnSelfBuilding || isOnTeamBuilding);
}

function getUnitToUnitAttackMovedAction(
    sortedMovedActionMap: Record<GameActionTypeEnum, Array<MovedGameActionType>>,
    gameState: GameStateType,
    botDifficult?: BotDifficultEnum
): MovedGameActionType | null {
    const isCompaniesMap: boolean = getIsCompaniesMap(gameState.mapId);
    const {isBotNormal, isBotEasy, isBotHard} = getBotDifficultMap(botDifficult);
    const storeList: Array<GameBuildingType> = gameState.buildingList.filter<GameBuildingType>(
        (building: GameBuildingType): building is GameBuildingType => {
            return getBuildingInfo(building).canBeStore;
        }
    );
    const storeCount: number = storeList.length;
    const isUseAllActionList: boolean = isCompaniesMap && storeCount === 0;
    const unitToUnitAttackListFull: Array<MovedGameActionType> = [...sortedMovedActionMap[unitToUnitAttack]];
    // Every tile a fortified enemy (on a heal / own / team building) covers — not only heal buildings:
    // a unit must not step next to ANY entrenched enemy to strike a third party (see getIsAttackIntoFortifiedCover).
    const fortifiedCoverPointList: Array<PointType> = getLowPriorityPointList(gameState);

    const unitToUnitAttackList: Array<MovedGameActionType> = isUseAllActionList
        ? unitToUnitAttackListFull
        : unitToUnitAttackListFull.filter<MovedGameActionType>(
              (movedAction: MovedGameActionType): movedAction is MovedGameActionType => {
                  if (!getIsViableAttack(movedAction, gameState, botDifficult)) {
                      return false;
                  }

                  // Do not step into a fortified enemy's free-hit zone to strike a DIFFERENT target
                  // (e.g. hitting an archer but ending next to a Galamar entrenched on a heal building or
                  // its own castle, who then trades into the unit for free). Focus fire ON the fortified
                  // unit stays allowed, so target selection is untouched — only the attack SQUARE is
                  // constrained: a safe strike tile is kept, and when every reachable one is covered the
                  // strike is declined. Hard and normal; easy stays deliberately dumb (it feeds its units).
                  if (
                      (isBotHard || isBotNormal) &&
                      getIsAttackIntoFortifiedCover(movedAction, gameState, fortifiedCoverPointList)
                  ) {
                      return false;
                  }

                  // "Attack with the numbers": skip a strike that leaves the unit outnumbered by a
                  // nearby enemy group without support — unless it kills (removing one of the group).
                  // The unit still ADVANCES to a staging tile (see getUnitMoveMovedAction), it just
                  // does not commit the lone attack; it strikes once allies have gathered.
                  const isKill: boolean = getMovedActionAttackResult(movedAction, gameState).isDefenderKilled;

                  return isKill || !getIsOutnumberedEngage(movedAction, gameState, botDifficult);
              }
          );

    // Coordinated attacks: a target several units can kill TOGETHER this turn beats any individually
    // higher-scoring strike that would just spread damage around. A HARD-bot skill by default; the
    // normal bot lost it on purpose (see the focusFire config) — players read the gang-up as unfair.
    if (getIsFocusFireEnabled(botDifficult)) {
        const focusFireMovedAction: MovedGameActionType | null = getFocusFireMovedAction(
            unitToUnitAttackList,
            gameState
        );

        if (focusFireMovedAction) {
            return focusFireMovedAction;
        }
    }

    if (isBotEasy) {
        // Deliberately dumb: the easy bot picks the attack where it takes the MOST return damage, so it
        // feeds its units to the player. Do not "fix" this — easy is meant to be beatable by beginners.
        return getMaxInList<MovedGameActionType>(unitToUnitAttackList, (movedAction: MovedGameActionType): number => {
            const movedActionAttackRate: MovedActionAttackRateType = getMovedActionAttackResult(movedAction, gameState);

            return movedActionAttackRate.additionalDamageReceived;
        });
    }

    if (isBotNormal) {
        return getMaxInList<MovedGameActionType>(unitToUnitAttackList, (movedAction: MovedGameActionType): number => {
            const movedActionAttackRate: MovedActionAttackRateType = getMovedActionAttackResult(movedAction, gameState);

            // Like the hard bot, prefer finishing a target off over an equal-damage trade; the siege
            // bonus is dropped on a kill (the occupant is gone) for the same reason as below.
            const killBonus: number = movedActionAttackRate.isDefenderKilled ? getBotRateConfig().killBonus : 0;
            const siegeRate: number = movedActionAttackRate.isDefenderKilled
                ? 0
                : getSiegeTargetRate(movedAction, gameState);
            // Wasted HP a non-lethal chip on a healing target loses to its next-turn heal (0 on a kill).
            const healBackWaste: number = getHealBackWaste(movedAction, gameState);

            return (
                movedActionAttackRate.additionalDamageGiven -
                movedActionAttackRate.additionalDamageReceived +
                killBonus +
                siegeRate -
                healBackWaste
            );
        });
    }

    return getMaxInList<MovedGameActionType>(unitToUnitAttackList, (movedAction: MovedGameActionType): number => {
        const movedActionAttackRate: MovedActionAttackRateType = getMovedActionAttackResult(movedAction, gameState);
        const placeData: MovedActionPlaceDataType = getPlaceData(movedAction, gameState);
        const onBuildingRate: number = getOnBuildingRate(movedAction, placeData.onBuildingState, gameState);

        const killBonus: number = movedActionAttackRate.isDefenderKilled ? getBotRateConfig().killBonus : 0;
        // A kill already removes the occupant (and unlocks the building), so the entrenched bonus is only
        // needed to push the bot to keep grinding a target it cannot finish this turn.
        const siegeRate: number = movedActionAttackRate.isDefenderKilled
            ? 0
            : getSiegeTargetRate(movedAction, gameState);
        // Wasted HP a non-lethal chip on a healing target loses to its next-turn heal (0 on a kill).
        const healBackWaste: number = getHealBackWaste(movedAction, gameState);

        // get max damage and max defend
        return (
            Math.min(movedActionAttackRate.additionalDamageGiven, movedActionAttackRate.defenderHealth) -
            movedActionAttackRate.additionalDamageReceived +
            placeData.placeArmor +
            onBuildingRate +
            killBonus +
            siegeRate -
            healBackWaste
        );
    });
}

function getUnitToBuildingAttackMovedAction(
    sortedMovedActionMap: Record<GameActionTypeEnum, Array<MovedGameActionType>>,
    gameState: GameStateType
): MovedGameActionType | null {
    const unitToBuildingAttackList = sortedMovedActionMap[unitToBuildingAttack]
        // do not destroy no man's building
        .filter((movedAction: MovedGameActionType): movedAction is MovedGameActionType => {
            const building = getBuildingByPoint(movedAction.gameAction.toPoint, gameState.buildingList);

            if (!building) {
                return false;
            }

            return building.gamePlayerId !== GamePlayerIdEnum.playerEmpty;
        });

    return getMaxInList<MovedGameActionType>(unitToBuildingAttackList, (movedAction: MovedGameActionType): number => {
        // get far building
        return getStepsBetweenPoints(movedAction.moveFrom, movedAction.gameAction.toPoint);
    });
}

function getUnitRaiseSkeletonMovedAction(
    sortedMovedActionMap: Record<GameActionTypeEnum, Array<MovedGameActionType>>,
    gameState: GameStateType
): MovedGameActionType | null {
    const unitRaiseSkeletonList = sortedMovedActionMap[raiseSkeleton];

    return getMaxInList<MovedGameActionType>(unitRaiseSkeletonList, (movedAction: MovedGameActionType): number => {
        // get most defended adn close place
        const placeDataA: MovedActionPlaceDataType = getPlaceData(movedAction, gameState);
        const onBuildingRateA: number = getOnBuildingRate(movedAction, placeDataA.onBuildingState, gameState);

        return (
            onBuildingRateA +
            placeDataA.placeArmor -
            getStepsBetweenPoints(movedAction.moveFrom, movedAction.moveTo) /
                getBotRateConfig().raiseSkeletonPathQualification
        );
    });
}

function getUnitFixBuildingMovedAction(
    sortedMovedActionMap: Record<GameActionTypeEnum, Array<MovedGameActionType>>
): MovedGameActionType | null {
    const unitFixBuildingList = sortedMovedActionMap[fixBuilding];

    return getMinInList<MovedGameActionType>(unitFixBuildingList, (movedAction: MovedGameActionType): number => {
        return getStepsBetweenPoints(movedAction.moveFrom, movedAction.moveTo);
    });
}

function getUnitMoveMovedAction(
    sortedMovedActionMap: Record<GameActionTypeEnum, Array<MovedGameActionType>>,
    gameState: GameStateType,
    botDifficult?: BotDifficultEnum
): MovedGameActionType | null {
    const {isBotHard} = getBotDifficultMap(botDifficult);
    const unitMoveList: Array<MovedGameActionType> = sortedMovedActionMap[unitMove];
    const {buildingListToOccupy, buildingListToOccupyNoEnemy} = getBuildingListToOccupy(gameState);
    const enemyUnitList: Array<GameUnitType> = getEnemyUnitListByPlayerId(
        gameState.activeGamePlayerId,
        gameState.playerList,
        gameState.unitList
    );

    const unitDidNotMoveList = unitMoveList.filter<MovedGameActionType>(
        (movedAction: MovedGameActionType): movedAction is MovedGameActionType => {
            const unitToRate = getUnitByUnitId(movedAction.gameAction.unitId, gameState.unitList);

            if (!unitToRate) {
                console.error(`can not get filtered unit by id: ${movedAction.gameAction.unitId}`);
                return false;
            }

            return unitToRate.movedCount === 0;
        }
    );

    const enemyAttackFromHealthBuilding: Array<PointType> = getLowPriorityPointList(gameState);
    // Damage-scaled danger map for the hard bot only, so normal / easy keep their current aggression.
    const threatMap: Map<string, number> | null = isBotHard ? getThreatMap(gameState) : null;

    // Units allowed into the fearless zone: only those with at least one attack passing the advantage
    // filter this turn — never walk into enemy reach without the intent to strike. Units that COULD
    // attack but only at a loss are "hopeless" (see fearlessViableAttackOnly mode 2).
    const viableAttackerIdSet = new Set<string>();
    const hopelessAttackerIdSet = new Set<string>();

    if (threatMap && getBotRateConfig().fearlessViableAttackOnly > 0) {
        sortedMovedActionMap[unitToUnitAttack].forEach((attackAction: MovedGameActionType) => {
            if (getIsViableAttack(attackAction, gameState, botDifficult)) {
                viableAttackerIdSet.add(attackAction.gameAction.unitId);
            } else if (getBotRateConfig().fearlessViableAttackOnly >= 2) {
                hopelessAttackerIdSet.add(attackAction.gameAction.unitId);
            }
        });

        viableAttackerIdSet.forEach((viableUnitId: string) => {
            hopelessAttackerIdSet.delete(viableUnitId);
        });
    }

    const minHealthToFight: number = getMinHealthToFight(botDifficult);

    // eslint-disable-next-line max-statements
    return getMaxInList<MovedGameActionType>(unitDidNotMoveList, (movedAction: MovedGameActionType): number => {
        const unitToRate = getUnitByUnitId(movedAction.gameAction.unitId, gameState.unitList);
        const {healthActionAdditionalRating, occupyBuildingAdditionalRating, enemyUnitAdditionalRating, stepRating} =
            getBotRateConfig();
        const placeRateReducer = stepRating + getBotRateConfig().placeRateReducerOffset;

        if (!unitToRate) {
            console.error(`can not get unit by id: ${movedAction.gameAction.unitId}`);
            return 0;
        }

        const enemyAttackFromHealthBuildingBonus = getPointByPoint(movedAction.moveTo, enemyAttackFromHealthBuilding)
            ? getBotRateConfig().enemyAttackFromHealthBuildingRating
            : 0;
        // A mild, damage-scaled penalty for stepping into any enemy's reach without a goal (hard only).
        // Added to the big building-sitter penalty, it also breaks ties toward the least-exposed tile
        // when every reachable square is covered, so a boxed-in unit stops shuffling deeper into fire.
        const generalThreatPenalty = threatMap
            ? -getBotRateConfig().generalThreatWeight * getThreatAtPoint(movedAction.moveTo, threatMap)
            : 0;
        const dangerPenalty = enemyAttackFromHealthBuildingBonus + generalThreatPenalty;

        const unitInfo = getUnitInfoByUnit(unitToRate);
        const placeData: MovedActionPlaceDataType = getPlaceData(movedAction, gameState);

        // up health
        if (unitToRate.health < minHealthToFight) {
            const closeBuilding = getBestBuildingToHealth(movedAction.moveTo, unitToRate, gameState);

            if (closeBuilding) {
                // reduce by unitToRate.health, less health move priority
                // add building heal amount, prefer buildings that heal more
                return (
                    healthActionAdditionalRating -
                    getBotPathDistance(
                        movedAction.moveTo,
                        {x: closeBuilding.x, y: closeBuilding.y},
                        unitToRate,
                        gameState
                    ) *
                        stepRating -
                    unitToRate.health +
                    getBuildingHealForUnit(closeBuilding, unitToRate, gameState) +
                    placeData.placeArmor / placeRateReducer +
                    enemyAttackFromHealthBuildingBonus
                );
            }
        }

        const onBuildingStateRate = getOnBuildingRate(movedAction, placeData.onBuildingState, gameState);

        // occupy building is available and no enemy on it
        if (buildingListToOccupyNoEnemy.length > 0) {
            const closeBuilding = getBestBuildingToOccupy(
                movedAction.moveFrom,
                buildingListToOccupyNoEnemy,
                unitToRate,
                gameState
            );

            const placeBonus =
                unitToRate.health > minHealthToFight
                    ? 0
                    : (placeData.placeArmor + onBuildingStateRate) / placeRateReducer;

            if (closeBuilding && unitInfo.occupyBuildingList.includes(closeBuilding.buildingType)) {
                // add building money income, prefer buildings that bring more money
                return (
                    occupyBuildingAdditionalRating -
                    getBotPathDistance(
                        movedAction.moveTo,
                        {x: closeBuilding.x, y: closeBuilding.y},
                        unitToRate,
                        gameState
                    ) *
                        stepRating +
                    getBuildingMoneyIncome(closeBuilding.buildingType, gameState.gameSettings) +
                    placeBonus +
                    enemyAttackFromHealthBuildingBonus
                );
            }
        }

        // fight versus enemy
        if (enemyUnitList.length > 0) {
            // Mode 2: a unit that COULD attack this turn but only at a loss has no business walking
            // toward the enemy at all — it takes the safest nearby tile instead (rated far below every
            // goal tier, threat-dominated, random tiebreak); the heal / occupy goals above still win.
            if (hopelessAttackerIdSet.has(movedAction.gameAction.unitId)) {
                return dangerPenalty * 1e4 + (getMoveFallbackRandomValue(movedAction, gameState) - 0.5) * stepRating;
            }

            const closeEnemyUnit = getCloseEnemyUnit(movedAction.moveTo, enemyUnitList, unitToRate, gameState);

            if (closeEnemyUnit) {
                const closeEnemyDistance: number = getBotPathDistance(
                    movedAction.moveTo,
                    {x: closeEnemyUnit.x, y: closeEnemyUnit.y},
                    unitToRate,
                    gameState
                );
                // Close enough to engage -> fearless: the threat penalty would otherwise freeze the
                // unit one tile outside enemy reach (a step gains stepRating, entering a zone costs
                // weight * damage). With fearlessViableAttackOnly the zone is reserved for units that
                // can actually strike this turn. The building-sitter penalty is never waived.
                // "Attack with the numbers": a unit outnumbered at this tile does NOT go fearless — it
                // keeps the threat penalty, so it advances only to a STAGING tile just outside enemy
                // reach and waits there. Allies converge on the same line; once enough have gathered
                // the tile is no longer outnumbered, the zone opens and they commit together (no stall,
                // because the pull toward the enemy still ranks this a fight-tier move).
                const isEngaging: boolean =
                    closeEnemyDistance <= getBotRateConfig().fearlessEngageStepCount &&
                    (getBotRateConfig().fearlessViableAttackOnly === 0 ||
                        viableAttackerIdSet.has(movedAction.gameAction.unitId)) &&
                    !getIsOutnumberedEngage(movedAction, gameState, botDifficult);

                return (
                    enemyUnitAdditionalRating -
                    closeEnemyDistance * stepRating +
                    (placeData.placeArmor + onBuildingStateRate) / placeRateReducer +
                    getAuraCoverRating(unitToRate, movedAction.moveTo, enemyUnitList, gameState) +
                    (isEngaging ? enemyAttackFromHealthBuildingBonus : dangerPenalty)
                );
            }
        }

        // move from occupy able building
        if (buildingListToOccupy.length > 0) {
            const closeBuilding = getCloseBuildingListToOccupy(
                movedAction.moveFrom,
                buildingListToOccupy,
                unitToRate,
                gameState
            );

            if (closeBuilding && !unitInfo.occupyBuildingList.includes(closeBuilding.buildingType)) {
                // move from building
                return (
                    getBotPathDistance(
                        movedAction.moveTo,
                        {x: closeBuilding.x, y: closeBuilding.y},
                        unitToRate,
                        gameState
                    ) -
                    occupyBuildingAdditionalRating +
                    enemyAttackFromHealthBuildingBonus
                );
            }
        }

        // No goal on the board for this unit: shuffle it pseudo-randomly, seeded from the state so the
        // whole game stays reproducible (a real Math.random() here would break replays and tests).
        return (getMoveFallbackRandomValue(movedAction, gameState) - 0.5) * occupyBuildingAdditionalRating;
    });
}

// eslint-disable-next-line max-statements
export function getMaxAction(gameState: GameStateType, botDifficult?: BotDifficultEnum): MovedGameActionType {
    const movedActionList: Array<MovedGameActionType> = getPointActionList(gameState, null);
    const deniedMovePointList: Array<PointType> = getDeniedToMovePointList(gameState);
    const sortedMovedActionMap: Record<GameActionTypeEnum, Array<MovedGameActionType>> = getSortedMovedActionMap(
        movedActionList,
        deniedMovePointList,
        gameState.unitList
    );
    const moveToPreventBuildingOccupation: MovedGameActionType | null = getMoveToPreventBuildingOccupation(
        sortedMovedActionMap,
        gameState
    );
    const {isBotHard, isBotNormal} = getBotDifficultMap(botDifficult);

    // do not prevent if bot is easy
    if (moveToPreventBuildingOccupation) {
        if (isBotHard) {
            return moveToPreventBuildingOccupation;
        }

        // prevent store only
        if (isBotNormal) {
            const building = getBuildingByPoint(moveToPreventBuildingOccupation.moveTo, gameState.buildingList);

            if (!building) {
                console.error(
                    `getMaxAction: can not get building by ${JSON.stringify(moveToPreventBuildingOccupation)}`
                );
                return moveToPreventBuildingOccupation;
            }

            if (getBuildingInfo(building).canBeStore) {
                return moveToPreventBuildingOccupation;
            }
        }

        // the easy bot does not defend its buildings at all
    }

    const occupyBuildingMovedAction = getOccupyBuildingMovedAction(sortedMovedActionMap);

    if (occupyBuildingMovedAction) {
        return occupyBuildingMovedAction;
    }

    // A siege unit razes a building the enemy is about to capture rather than blocking it (cover/occupy
    // above already let a unit that can HOLD the building do so first — this is the destroyer fallback).
    const razeThreatenedMovedAction = getRazeThreatenedMovedAction(sortedMovedActionMap, gameState);

    if (razeThreatenedMovedAction) {
        return razeThreatenedMovedAction;
    }

    const unitRaiseSkeletonMovedAction = getUnitRaiseSkeletonMovedAction(sortedMovedActionMap, gameState);

    if (unitRaiseSkeletonMovedAction) {
        return unitRaiseSkeletonMovedAction;
    }

    const buyUnitMovedAction = getBuyUnitMovedAction(gameState, botDifficult);

    if (buyUnitMovedAction) {
        return buyUnitMovedAction;
    }

    const unitToUnitAttackMovedAction = getUnitToUnitAttackMovedAction(sortedMovedActionMap, gameState, botDifficult);

    if (unitToUnitAttackMovedAction) {
        return unitToUnitAttackMovedAction;
    }

    const unitToBuildingAttackMovedAction = getUnitToBuildingAttackMovedAction(sortedMovedActionMap, gameState);

    if (unitToBuildingAttackMovedAction) {
        return unitToBuildingAttackMovedAction;
    }

    const unitFixBuildingMovedAction = getUnitFixBuildingMovedAction(sortedMovedActionMap);

    if (unitFixBuildingMovedAction) {
        return unitFixBuildingMovedAction;
    }

    const unitMoveMovedAction = getUnitMoveMovedAction(sortedMovedActionMap, gameState, botDifficult);

    if (unitMoveMovedAction) {
        return unitMoveMovedAction;
    }

    const landscapeCenter = getLandscapeCenter(gameState.landscape);

    return {
        gameAction: {
            actionType: changeTurn,
            addUnitList: [],
            briefing: null,
            buyUnitType: null,
            movePointList: [],
            toPoint: landscapeCenter,
            unitCurrentPoint: landscapeCenter,
            unitId: "",
        },
        moveFrom: landscapeCenter,
        movePathList: [],
        moveTo: landscapeCenter,
    };
}
