import {createContext, type JSX, type ReactNode, useCallback, useContext, useEffect, useMemo, useState} from "react";

import {getDefaultSettingContextData, getSavedSettingData, saveSetting} from "./setting-helper";
import type {
    BooleanSettingDataType,
    NumberSettingDataType,
    SettingContextSettingType,
    SettingContextType,
} from "./setting-type";

export const SettingContext = createContext<SettingContextType>(getDefaultSettingContextData());

export function useSettingContext(): SettingContextType {
    return useContext<SettingContextType>(SettingContext);
}

const {Provider: SettingContextProvider} = SettingContext;

interface SettingContextPropsType {
    readonly children: ReactNode;
}

export function SettingProvider(props: SettingContextPropsType): JSX.Element {
    const {children} = props;
    const [setting, setSetting] = useState<SettingContextSettingType>(getSavedSettingData());

    const setBoolean = useCallback((key: keyof BooleanSettingDataType, value: boolean) => {
        setSetting((currentSetting: SettingContextSettingType): SettingContextSettingType => {
            return {
                ...currentSetting,
                booleanSetting: {
                    ...currentSetting.booleanSetting,
                    [key]: value,
                },
            };
        });
    }, []);

    const setNumber = useCallback((key: keyof NumberSettingDataType, value: number) => {
        setSetting((currentSetting: SettingContextSettingType): SettingContextSettingType => {
            return {
                ...currentSetting,
                numberSetting: {
                    ...currentSetting.numberSetting,
                    [key]: value,
                },
            };
        });
    }, []);

    useEffect(() => {
        saveSetting({...setting});
    }, [setting]);

    const providedData: SettingContextType = useMemo((): SettingContextType => {
        return {setBoolean, setNumber, setSetting, setting};
    }, [setBoolean, setNumber, setting]);

    return <SettingContextProvider value={providedData}>{children}</SettingContextProvider>;
}
