import {type JSX, useCallback} from "react";
import {useNavigate} from "react-router-dom";

import * as pageHeaderStyle from "../../../layout/page/page-header/page-header.scss";
import {usePlayClick} from "../../../media/play-media";
import {throwError} from "../../../util/error";

interface DevPageHeaderPropsType {
    // Dev pages are intentionally not localized - the title is plain Swedish text.
    readonly title: string;
}

export function DevPageHeader(props: DevPageHeaderPropsType): JSX.Element {
    const {title} = props;
    const navigate = useNavigate();
    const {play: playClick} = usePlayClick();

    const handleBackButtonClick = useCallback(() => {
        // eslint-disable-next-line @typescript-eslint/no-floating-promises
        playClick();
        navigate(-1)?.catch(throwError);
    }, [playClick, navigate]);

    return (
        <header className={pageHeaderStyle.page_header}>
            <button className={pageHeaderStyle.page_header__back_button} onClick={handleBackButtonClick} type="button">
                &lt;&lt;
            </button>
            <span className={pageHeaderStyle.page_header__text}>{title}</span>
        </header>
    );
}
