import {type JSX, useEffect, useState} from "react";

import type {
    GameLandscapeThemeEnum,
    GameLandscapeThemeMapType,
    GameLandscapeType,
} from "../../../../model/game/landscape/landscape-type";
import {useSettingContext} from "../../../../provider/setting/setting-context";
import * as clientGameLandscapeStyle from "./client-game-landscape.scss";
import {getLandscapeCanvas, getLandscapeThemeImageList} from "./helper/client-game-landscape-canvas";
import {ClientGameLandscapeWater} from "./helper/client-game-landscape-water";

interface ClientGameLandscapePropsType {
    // The theme to force on every tile, or null to render each tile with its own (as-designed) theme.
    readonly forcedTheme: GameLandscapeThemeEnum | null;
    readonly landscape: GameLandscapeType;
    readonly landscapeThemeMap?: GameLandscapeThemeMapType | undefined;
}

export function ClientGameLandscape(props: ClientGameLandscapePropsType): JSX.Element {
    const {landscape, landscapeThemeMap, forcedTheme} = props;
    const {
        setting: {
            booleanSetting: {isWaterAnimationEnable},
        },
    } = useSettingContext();
    // Bumped once the tile sprites finish loading: a mount-time draw made before that is
    // incomplete (see getLandscapeCanvas), so force one more render to redraw the canvas.
    const [spriteReadyCount, setSpriteReadyCount] = useState<number>(0);

    useEffect((): (() => void) => {
        let isCancelled = false;

        function cancel(): void {
            isCancelled = true;
        }

        const imageList = getLandscapeThemeImageList(landscape, landscapeThemeMap, forcedTheme);

        const isEveryImageComplete = imageList.every((image: HTMLImageElement): boolean => {
            return image.complete;
        });

        if (!isEveryImageComplete) {
            Promise.all(
                imageList.map(async (image: HTMLImageElement): Promise<null> => {
                    // A broken sprite must not block the redraw.
                    return image.decode().then(
                        (): null => {
                            return null;
                        },
                        (): null => {
                            return null;
                        }
                    );
                })
            ).then((): void => {
                if (!isCancelled) {
                    setSpriteReadyCount((count: number): number => {
                        return count + 1;
                    });
                }
            }, cancel);
        }

        return cancel;
    }, [landscape, landscapeThemeMap, forcedTheme]);

    return (
        <div className={clientGameLandscapeStyle.landscape_layer}>
            {isWaterAnimationEnable ? (
                <ClientGameLandscapeWater
                    landscape={landscape}
                    landscapeThemeMap={landscapeThemeMap}
                    themeOverride={forcedTheme}
                />
            ) : null}
            <img
                alt="map"
                className={clientGameLandscapeStyle.landscape_layer_image}
                key={spriteReadyCount}
                src={getLandscapeCanvas(landscape, landscapeThemeMap, {
                    themeOverride: forcedTheme,
                    useDynamicWater: isWaterAnimationEnable,
                })}
            />
        </div>
    );
}
