/* global IS_PRODUCTION */

import {throwError} from "../../util/error";
import type {CompanyItemType, GameMapType} from "./map-type";

export const skirmishMapList: Array<GameMapType> = [];
export const companiesAe1CompanyList: Array<CompanyItemType> = [];
export const companiesAe1MapList: Array<GameMapType> = [];
export const companiesAe2CompanyList: Array<CompanyItemType> = [];
export const companiesAe2MapList: Array<GameMapType> = [];
export const companiesAe3CompanyList: Array<CompanyItemType> = [];
export const companiesAe3MapList: Array<GameMapType> = [];

// eslint-disable-next-line jest/require-hook
import("./skirmish-map-list-async" /* webpackChunkName: 'skirmish-map' */)
    .then((data: {skirmishMapListAsync: Array<GameMapType>}) => {
        skirmishMapList.push(...data.skirmishMapListAsync);
    })
    .catch(throwError);

// Dev-only test maps. The `IS_PRODUCTION === false` guard is a compile-time
// constant (webpack DefinePlugin), so this whole branch — including the imported
// chunk — is stripped out of production builds.
if (IS_PRODUCTION === false) {
    import("./skirmish-test-map-list" /* webpackChunkName: 'skirmish-test-map' */)
        .then((data: {skirmishTestMapList: Array<GameMapType>}) => {
            skirmishMapList.push(...data.skirmishTestMapList);
        })
        .catch(throwError);
}

// eslint-disable-next-line jest/require-hook
import("./companies-map-list/companies-ae1-company-list-async" /* webpackChunkName: 'companies-ae2-map' */)
    .then((data: {companiesAe1CompanyListAsync: Array<CompanyItemType>}) => {
        companiesAe1CompanyList.push(...data.companiesAe1CompanyListAsync);
        companiesAe1MapList.push(
            ...data.companiesAe1CompanyListAsync.map<GameMapType>((company: CompanyItemType): GameMapType => {
                return company.map;
            })
        );
    })
    .catch(throwError);

// eslint-disable-next-line jest/require-hook
import("./companies-map-list/companies-ae2-company-list-async" /* webpackChunkName: 'companies-ae2-map' */)
    .then((data: {companiesAe2CompanyListAsync: Array<CompanyItemType>}) => {
        companiesAe2CompanyList.push(...data.companiesAe2CompanyListAsync);
        companiesAe2MapList.push(
            ...data.companiesAe2CompanyListAsync.map<GameMapType>((company: CompanyItemType): GameMapType => {
                return company.map;
            })
        );
    })
    .catch(throwError);

// eslint-disable-next-line jest/require-hook
import("./companies-map-list/companies-ae3-company-list-async" /* webpackChunkName: 'companies-ae3-map' */)
    .then((data: {companiesAe3CompanyListAsync: Array<CompanyItemType>}) => {
        companiesAe3CompanyList.push(...data.companiesAe3CompanyListAsync);
        companiesAe3MapList.push(
            ...data.companiesAe3CompanyListAsync.map<GameMapType>((company: CompanyItemType): GameMapType => {
                return company.map;
            })
        );
    })
    .catch(throwError);
