type RgbType = Readonly<{blue: number; green: number; red: number}>;

export function parseColor(color: string): RgbType {
    const trimmed = color.trim();

    // #RGB / #RRGGBB
    const hexMatch = /^#?([\da-f]{3}|[\da-f]{6})$/iu.exec(trimmed);

    if (hexMatch) {
        const short = hexMatch.at(1) ?? "";
        const hex =
            short.length === 3
                ? short.replace(/\S/giu, char => {
                      return `${char}${char}`;
                  })
                : short;

        return {
            blue: parseInt(hex.slice(4, 6), 16),
            green: parseInt(hex.slice(2, 4), 16),
            red: parseInt(hex.slice(0, 2), 16),
        };
    }

    // rgb(239 215 0) / rgb(239, 215, 0) / 239 215 0
    const numbers = trimmed.match(/\d+(?:\.\d+)?/gu);

    if (numbers && numbers.length >= 3) {
        return {
            blue: Number(numbers.at(2)),
            green: Number(numbers.at(1)),
            red: Number(numbers.at(0)),
        };
    }

    console.error(`parseColor: can not parse color "${color}"`);

    return {
        blue: 127,
        green: 127,
        red: 127,
    };
}
