const minimumDeltaTime = 60 * 1000 * 8; // 8 minutes
// eslint-disable-next-line jest/require-hook
let timeStampShowAds = Date.now() - minimumDeltaTime / 2;

export function showAds(): void {
    const currentTime = Date.now();
    const currentDataTime = currentTime - timeStampShowAds;

    if (currentDataTime > minimumDeltaTime) {
        timeStampShowAds = currentTime;
        if (typeof Android !== "undefined" && Android) {
            Android.displayInterstitial?.();
        }
    }
}
