import {useEffect, useRef} from "react";

import type {GameStateType} from "../../../../model/game/game-type";
import {getSuitTriggerList} from "../../../../model/game/trigger/trigger-condition";
import type {GameTriggerType} from "../../../../model/game/trigger/trigger-type";
import {useGameContext} from "../../../../provider/game/game-context";

export function ClientTrigger(): null {
    const {gameState, setGameState, pushAction} = useGameContext();
    const prevGameStateRef = useRef<GameStateType>(gameState);

    useEffect(() => {
        const triggerList = getSuitTriggerList({gameState, prevGameState: prevGameStateRef.current});
        prevGameStateRef.current = gameState;

        if (triggerList.length === 0) {
            return;
        }

        setGameState((currentGameState: GameStateType): GameStateType => {
            const triggerIdList = triggerList.map<string>((trigger: GameTriggerType): string => {
                return trigger.triggerId;
            });

            return {
                ...currentGameState,
                doneTriggerIsList: [...currentGameState.doneTriggerIsList, ...triggerIdList],
            };
        });

        triggerList.forEach((trigger: GameTriggerType) => {
            // eslint-disable-next-line  @typescript-eslint/no-floating-promises
            pushAction(trigger.action);
        });
    }, [gameState, pushAction, setGameState]);

    return null;
}
