// Bot rating coefficients: the type and the shipped defaults. Kept separate from bot-rate.ts
// (which is at the max-lines cap) and imported back by it; tune via the self-play tournament
// (readme.bot-tournament.md).

// A type alias on purpose (not an interface): aliases carry an implicit index signature, letting
// tooling (tournament config validation) view the config as Record<string, ...> without casts.
// eslint-disable-next-line @typescript-eslint/consistent-type-definitions
export type BotRateConfigType = {
    attackAdvantageThreshold: Record<"easy" | "hard" | "normal", number>;
    auraCoveredAllyRating: number;
    auraFrontlineDistance: number;
    enemyAttackFromHealthBuildingRating: number;
    enemyUnitAdditionalRating: number;
    fearlessEngageStepCount: number;
    fearlessViableAttackOnly: number;
    focusFire: Record<"easy" | "hard" | "normal", number>;
    generalThreatWeight: number;
    graveCountPerSorceress: number;
    groupEngageMinEnemyCount: number;
    groupEngageMode: Record<"easy" | "hard" | "normal", number>;
    groupEngageRadius: number;
    groupEngageSupportPerEnemy: number;
    healBuildingStepWeight: number;
    healthActionAdditionalRating: number;
    killBonus: number;
    minEnemyFarmCountForCatapult: number;
    minHealthToFight: Record<"easy" | "hard" | "normal", number>;
    minSoldierNeededCount: Record<"easy" | "hard" | "normal", number>;
    minimumWaterOnMapPart: number;
    occupyBuildingAdditionalRating: number;
    occupyBuildingStepWeight: number;
    onAvailableToOccupyBuildingBonus: number;
    onEnemyBuildingBonus: number;
    onHealsBuildingBonus: number;
    placeRateReducerOffset: number;
    raiseSkeletonPathQualification: number;
    saveGoldBaseChance: Record<"easy" | "hard" | "normal", number>;
    saveGoldChancePerOwnedFarm: number;
    saveGoldMaxChance: number;
    siegeEntrenchedBonus: number;
    siegeHealWeight: number;
    siegeIncomeWeight: number;
    stepRating: number;
    storeBuildingBonus: number;
};

export const defaultBotRateConfig: BotRateConfigType = {
    // Acceptable attack-advantage threshold, by bot difficulty. Hard re-tuned by self-play after
    // normal lost focus fire (2026-07, double metric): -7 beats the old 0 in the mirror (0.600) AND
    // vs NORMAL (0.600 against 0.550) — a slightly losing trade is fine when the army follows up;
    // the plateau holds through -8, -10 flips the mirror to 0.450, and bolder approach knobs
    // (fearlessViableAttackOnly 0, generalThreatWeight 0) win the mirror but lose to NORMAL.
    attackAdvantageThreshold: {
        easy: -30,
        // Hard nudged more aggressive (2026-07, -7 -> -8): accepts a slightly worse trade so it engages
        // sooner. -8 is the edge that keeps the hard-vs-easy pool guard green; the groupEngage gate is
        // what lets it be trade-hungry without feeding lone units into a crowd (aggressive WITH the numbers).
        hard: -8,
        normal: -15,
    },
    // Move-rating bonus, per FRONTLINE allied unit an aura carrier (wisp) covers from the candidate
    // square (rear-guard allies weigh less, see auraFrontlineDistance). Worth three movement steps
    // (stepRating) per full-weight ally, so the carrier trails the fighting group instead of charging
    // ahead alone, yet still follows the army toward the enemy. Applies to every difficulty: attack
    // simulation already values the aura's +attack, this makes the carrier actually provide it.
    auraCoveredAllyRating: 15,
    // A covered ally counts in full while within this path distance of the nearest enemy; farther out
    // its weight falls off hyperbolically (8 steps -> 1/2, 16 -> 1/4). The aura only pays off on allies
    // that are about to fight, so the carrier is not lured into baby-sitting the rear guard.
    auraFrontlineDistance: 4,
    // Penalty for moving onto a square an enemy can attack from a healing building.
    // eslint-disable-next-line id-length
    enemyAttackFromHealthBuildingRating: -1e6,
    // Priority tier for moving towards an enemy unit.
    enemyUnitAdditionalRating: 1e6,
    // The threat penalty is WAIVED on tiles within this many path steps of the closest enemy: a unit
    // committing to a fight is fearless, one loitering under fire far from its target still pays.
    // 0 = never waive. Self-play tuned (2026-07): 3 scores 0.600 with guards passing; 5+ (or a
    // near-zero generalThreatWeight) is bolder but loses the ladder to the NORMAL bot.
    fearlessEngageStepCount: 3,
    // 0 = off. 1 = the fearless zone above only admits units with at least one attack passing the
    // advantage filter this turn (never walk into enemy reach without the intent to strike; hopeless
    // units keep the threat penalty and back out of reach). 2 = mode 1 PLUS a hopeless unit (has
    // attacks this turn, all losing) does not walk toward the enemy at all — it holds the safest
    // nearby tile while heal / occupy goals take priority. Self-play tuned (2026-07): mode 2
    // scores 0.550 with guards passing.
    fearlessViableAttackOnly: 2,
    // Whether the difficulty runs the coordinated focus-fire pass (several units stacking their best
    // hits to finish ONE target this turn), 0 = off / 1 = on. Hard keeps it; easy never had it (the
    // easy bot is deliberately dumb); normal lost it on purpose (2026-07) — players read the gang-up
    // as unfair for a mid difficulty, and it made normal too strong (hard led it by only 0.650).
    // Tests restore it on normal to pin the focus-fire machinery itself.
    focusFire: {
        easy: 0,
        hard: 1,
        normal: 0,
    },
    // Per-point-of-incoming-damage penalty for stepping into an enemy's attack range while approaching
    // (hard bot only, waived near the enemy — see fearlessEngageStepCount). Kept SMALL relative to
    // stepRating: the old 2500 froze units one tile outside enemy reach forever. Self-play tuned
    // (2026-07): 0.5 keeps full strength and the least-exposed-tile tiebreak; 0 loses to NORMAL.
    generalThreatWeight: 0.5,
    // Counter-tier rule: keep one sorceress per this many graves on the board (floor(graves / this)) —
    // corpses are free skeletons. High value = rule off. Self-play tuned (2026-07): 3 scores 0.550
    // with minEnemyFarmCountForCatapult 3; 2 over-buys sorceresses and loses guard seats.
    graveCountPerSorceress: 3,
    // "Attack with the numbers" anti-suicide gate (see groupEngageMode). The gate only considers a
    // cluster of at least this many enemies near the tile the unit would fight from — a lone duel is
    // never gated, so single-target aggression is unaffected.
    groupEngageMinEnemyCount: 2,
    // Whether a unit refuses to COMMIT into an enemy group while heavily outnumbered, by bot difficulty
    // (0 = off). HARD only: instead of feeding a lone unit into 3+ enemies (the classic Balance turn 3-4
    // suicide — it dies without denting the enemy), the unit advances only to a STAGING tile just outside
    // the group's reach and waits; allies converge and they commit together once the numbers are close.
    // Off for easy/normal (a shared change shifts the difficulty ladder — see minSoldierNeededCount).
    // Self-play (2026-07): even the gentlest setting costs one hard-vs-easy pool seat (00125 p2, waived in
    // self-play-map-pool.test.ts) — the gate correctly declines a dive that only won vs the dumb easy bot.
    groupEngageMode: {
        easy: 0,
        hard: 1,
        normal: 0,
    },
    // Radius (Manhattan steps) around the fight tile in which enemies and supporting allies are counted.
    groupEngageRadius: 3,
    // Required allies (the engaging unit itself counts) per enemy in the cluster. 0.5 = commit unless
    // outnumbered worse than 2:1, i.e. only a lone unit facing 3+ is held back (a 1-vs-2 trade, where the
    // unit survives and deals damage, is still allowed — aggression preserved). A kill is always allowed
    // (removes one of the group), as is the last fighter on a team (a lone hero must still act). Self-play
    // (2026-07): 1.0 cost two easy pool seats, 0.5 costs one (waived) — the least-passive useful setting.
    groupEngageSupportPerEnemy: 0.5,
    // Weight of one step away from the building, balanced against how much health the building restores.
    healBuildingStepWeight: 5,
    // Priority tier for moving towards a healing building.
    healthActionAdditionalRating: 3e6,
    // Bonus added to an attack that kills the defender.
    killBonus: 1000,
    // The counter-tier catapult is bought only once the enemy team holds at least this many farms: a
    // 700-gold building-raker pays off against a broad economy. High value = rule off. Self-play tuned
    // (2026-07): 3 delays it out of the early game at no cost; dropping the rule scores 0.450 — keep it.
    minEnemyFarmCountForCatapult: 3,
    // Minimal health for a unit to fight, by bot difficulty. Hard tuned by self-play (2026-07,
    // double metric): 50 beats the old 65 in the mirror (0.550) AND vs NORMAL (14/20 instead of
    // 11/20) — retreating to heal at 65 kept leaving the front, feeding losses and the tier-A
    // forced soldier rebuy spiral that normal's tempo exploited.
    minHealthToFight: {
        easy: 1,
        hard: 50,
        normal: 35,
    },
    // All farm count / 3, but at least this many soldiers, by bot difficulty.
    minSoldierNeededCount: {
        easy: 2,
        hard: 2,
        normal: 2,
    },
    // If water is less than this share of the map part, do NOT buy a float unit.
    minimumWaterOnMapPart: 0.2,
    // Priority tier for moving towards a building to occupy.
    occupyBuildingAdditionalRating: 2e6,
    // Weight of one step away from the building, balanced against its money income. Tuned by
    // self-play tournament (2026-07): 8 beat the old 5 — preferring the CLOSER farm wins the early
    // expansion race.
    occupyBuildingStepWeight: 8,
    // Bonus for standing on a building, depending on its kind.
    onAvailableToOccupyBuildingBonus: 15,
    onEnemyBuildingBonus: 5,
    onHealsBuildingBonus: 10,
    // Added to stepRating to soften the place-defence bonus.
    placeRateReducerOffset: 3,
    // Lower value gives the path length more weight versus the place defence when raising a skeleton.
    raiseSkeletonPathQualification: 10,
    // Base chance (0..1) the bot banks its gold instead of buying yet another growth unit, so it does
    // not spam cheap soldiers / archers every single turn. Per bot difficulty: tuned by self-play
    // tournament (2026-07) — the HARD bot saving less (0.2) spends on units earlier and scores 0.600
    // against the previous shared 0.3 on the verified pool. Lower values (0.1-0.15) score the same or
    // better but lose the Barrier map to the EASY bot from the second seat, and a shared (all
    // difficulties) change breaks the difficulty ladder, so only hard deviates.
    saveGoldBaseChance: {
        easy: 0.3,
        hard: 0.2,
        normal: 0.3,
    },
    // Extra save chance for every farm the bot's own team holds: a stronger economy makes waiting for a
    // bigger unit worthwhile, so a farm-rich bot saves more readily. Clamped by saveGoldMaxChance.
    saveGoldChancePerOwnedFarm: 0.1,
    saveGoldMaxChance: 0.8,
    // Base tier that makes the bot concentrate fire on an enemy entrenched on a healing / income building.
    siegeEntrenchedBonus: 200,
    // Weight of the per-turn heal the building gives the entrenched enemy (treated as extra HP to grind through).
    siegeHealWeight: 3,
    // Weight of the enemy-team income denied by dislodging the entrenched enemy.
    siegeIncomeWeight: 4,
    // Weight of one step when rating a move.
    stepRating: 5,
    // Huge bonus that makes the bot prefer protecting a store from enemy occupation.
    storeBuildingBonus: 1000,
};

// The live config every rating function reads (via getBotRateConfig). Normally the defaults; runWithBotRateConfig swaps
// it for the duration of one callback so self-play tournaments can pit a CANDIDATE coefficient set
// against the current bot without forking the code.
// eslint-disable-next-line jest/require-hook
let botRateConfig: BotRateConfigType = defaultBotRateConfig;

// Run `callback` (typically one getMaxAction evaluation) with the given coefficient overrides on
// top of the defaults; the defaults are always restored afterwards, even on an exception. Nested
// Records (attackAdvantageThreshold, focusFire, minHealthToFight, ...) are replaced whole, not merged per key.
export function runWithBotRateConfig<ResultType>(
    configOverride: Partial<BotRateConfigType>,
    callback: () => ResultType
): ResultType {
    botRateConfig = {...defaultBotRateConfig, ...configOverride};

    try {
        return callback();
    } finally {
        botRateConfig = defaultBotRateConfig;
    }
}

// The coefficient set currently in effect; rating and buy logic must read the config through this
// getter (never import defaultBotRateConfig directly), or tournament overrides would not reach them.
export function getBotRateConfig(): BotRateConfigType {
    return botRateConfig;
}
