import {getSavedBotDifficult} from "../bot/bot-helper";
import {availableToBuyUnitTypeList, defaultUnitData} from "../unit/unit-const";
import {levelUnitData} from "../unit/unit-level";
import {
    GamePlayerColorIdEnum,
    GamePlayerIdEnum,
    GamePlayerTeamIdEnum,
    type GamePlayerType,
    GamePlayerTypeEnum,
} from "./player-type";

const {player1, player2, player3, player4, playerEmpty} = GamePlayerIdEnum;
const {red, blue, green, black, gray} = GamePlayerColorIdEnum;
const {team1, team2, team3, team4, teamEmpty} = GamePlayerTeamIdEnum;

export const playerColorList: Readonly<Array<GamePlayerColorIdEnum>> = [blue, red, green, black] as const;
export const gamePlayerIdList: Readonly<Array<GamePlayerIdEnum>> = [player1, player2, player3, player4] as const;
export const gamePlayerTeamIdList: Readonly<Array<GamePlayerTeamIdEnum>> = [team1, team2, team3, team4] as const;

// Per-player cap on unit health (a 0-100 scale). Lower values make that player's units weaker.
export const maxUnitHealthList: Readonly<Array<number>> = [defaultUnitData.health, 90, 80, 70, 60, 50] as const;

export const defaultMaxUnitHealth: number = maxUnitHealthList.at(0) ?? defaultUnitData.health;

// Per-player experience step per unit level (damage dealt needed to advance one level).
// A smaller step makes leveling faster, a larger one makes it slower.
export const unitLevelStepList: Readonly<Array<number>> = [25, 50, 75, 100, 200, 500, 1000] as const;

export const defaultUnitLevelStep: number = levelUnitData.base;

export const defaultPlayerData: Record<GamePlayerIdEnum, GamePlayerType> = {
    [player1]: {
        availableToBuyUnitList: availableToBuyUnitTypeList,
        gamePlayerColorId: blue,
        gamePlayerId: player1,
        gamePlayerTeamId: team1,
        money: 0,
        playerDifficulty: getSavedBotDifficult(),
        playerType: GamePlayerTypeEnum.human,
    },
    [player2]: {
        availableToBuyUnitList: availableToBuyUnitTypeList,
        gamePlayerColorId: red,
        gamePlayerId: player2,
        gamePlayerTeamId: team2,
        money: 0,
        playerDifficulty: getSavedBotDifficult(),
        playerType: GamePlayerTypeEnum.human,
    },
    [player3]: {
        availableToBuyUnitList: availableToBuyUnitTypeList,
        gamePlayerColorId: green,
        gamePlayerId: player3,
        gamePlayerTeamId: team3,
        money: 0,
        playerDifficulty: getSavedBotDifficult(),
        playerType: GamePlayerTypeEnum.human,
    },
    [player4]: {
        availableToBuyUnitList: availableToBuyUnitTypeList,
        gamePlayerColorId: black,
        gamePlayerId: player4,
        gamePlayerTeamId: team4,
        money: 0,
        playerDifficulty: getSavedBotDifficult(),
        playerType: GamePlayerTypeEnum.human,
    },
    [playerEmpty]: {
        availableToBuyUnitList: availableToBuyUnitTypeList,
        gamePlayerColorId: gray,
        gamePlayerId: playerEmpty,
        gamePlayerTeamId: teamEmpty,
        money: 0,
        playerDifficulty: getSavedBotDifficult(),
        playerType: GamePlayerTypeEnum.none,
    },
};
