import type {JSX} from "react";

import {SmallText} from "../../../../../layout/game-font/text/small-text";
import {IsRender} from "../../../../../layout/is-render/is-render";
import {getByPoint} from "../../../../../model/game/game-state/game-state";
import type {PointDataType} from "../../../../../model/game/game-type";
import {getLandscapeSize, getUnitBonusArmorByMoveType} from "../../../../../model/game/landscape/landscape-helper";
import {getPlayerMaxUnitLevel, getPlayerUnitLevelStep} from "../../../../../model/game/player/player-helper";
import {
    unitUnderPoisonArmorReduce,
    unitUnderPoisonAttackReduce,
    unitUnderWispAuraArmorBonus,
    unitUnderWispAuraAttackBonus,
} from "../../../../../model/game/unit/unit-const";
import {getUnitInfoByUnit} from "../../../../../model/game/unit/unit-helper";
import {getUnitLevelData, getUnitRank} from "../../../../../model/game/unit/unit-level";
import {getIsUnitPoisoned, getIsUnitUnderWispAura} from "../../../../../model/game/unit/unit-state";
import {getBonusArmorByLevel, getBonusAttackByLevel} from "../../../../../model/game/unit/unit-to-unit-attack";
import type {UnitInfoType} from "../../../../../model/game/unit/unit-type";
import {useGameContext} from "../../../../../provider/game/game-context";
import {Locale} from "../../../../../provider/locale/locale-context";
import {getImageListByUnit} from "../../client-game-unit/client-game-unit-item/client-game-unit-item-helper";
import * as clientUnitStatsStyle from "./client-unit-stats.scss";
import {unitStatsIcon} from "./image/client-unit-stats-icon";

// eslint-disable-next-line max-statements
export function ClientUnitStats(): JSX.Element | null {
    const {activePoint, gameState} = useGameContext();
    const pointData: PointDataType = getByPoint(activePoint, gameState);
    const {unit} = pointData;

    if (!unit) {
        return null;
    }

    const isUnderPoison = getIsUnitPoisoned(unit, gameState.stepCount);
    const isUnderWispAura = getIsUnitUnderWispAura(
        unit,
        gameState.playerList,
        gameState.unitList,
        getLandscapeSize(gameState.landscape)
    );
    const bonusArmorByPlaceAndMoveType: number = getUnitBonusArmorByMoveType(
        unit,
        gameState.landscape,
        gameState.buildingList
    );
    const buffNerfAttack: number =
        (isUnderPoison ? -unitUnderPoisonAttackReduce : 0) + (isUnderWispAura ? unitUnderWispAuraAttackBonus : 0);
    const buffNerfArmor: number =
        (isUnderPoison ? -unitUnderPoisonArmorReduce : 0) +
        (isUnderWispAura ? unitUnderWispAuraArmorBonus : 0) +
        bonusArmorByPlaceAndMoveType;
    const unitInfo: UnitInfoType = getUnitInfoByUnit(unit);
    const maxUnitLevel: number = getPlayerMaxUnitLevel(unit.gamePlayerId, gameState.playerList);
    const unitLevelStep: number = getPlayerUnitLevelStep(unit.gamePlayerId, gameState.playerList);
    const bonusArmorByLevel: number = getBonusArmorByLevel(unit.damageGiven, maxUnitLevel, unitLevelStep);
    const bonusAttackByLevel: number = getBonusAttackByLevel(unit.damageGiven, maxUnitLevel, unitLevelStep);
    const develData = getUnitLevelData(unit.damageGiven, maxUnitLevel, unitLevelStep);
    const {min: minAttack, max: maxAttack} = unitInfo.attack;
    const attackDataList: Array<number | string> =
        minAttack === maxAttack
            ? [minAttack + buffNerfAttack]
            : [minAttack + buffNerfAttack, "-", maxAttack + buffNerfAttack];
    const armorDataList: Array<number | string> = [unitInfo.armor + buffNerfArmor];
    const [unitImage] = getImageListByUnit(unit, gameState.playerList);

    if (buffNerfAttack) {
        attackDataList.push(buffNerfAttack > 0 ? " u" : " d");
    }

    if (bonusAttackByLevel) {
        attackDataList.push("+", bonusAttackByLevel);
    }

    if (buffNerfArmor) {
        armorDataList.push(buffNerfArmor > 0 ? " u" : " d");
    }

    if (bonusArmorByLevel) {
        armorDataList.push("+", bonusArmorByLevel);
    }

    return (
        <div className={clientUnitStatsStyle.client_unit_stats__wrapper}>
            <div className={clientUnitStatsStyle.client_unit_stats}>
                <img alt={unit.unitType} className={clientUnitStatsStyle.client_unit_stats__unit} src={unitImage.src} />
                <span className={clientUnitStatsStyle.client_unit_name}>
                    <Locale stringKey={getUnitRank(unit.unitType, develData.level, maxUnitLevel)} />
                </span>
            </div>

            <div className={clientUnitStatsStyle.client_unit_stats}>
                <img
                    alt="health"
                    className={clientUnitStatsStyle.client_unit_stats__icon}
                    src={unitStatsIcon.heart.src}
                />
                <SmallText
                    className={clientUnitStatsStyle.client_unit_stats__text}
                    scale={2}
                    text={unit.health.toString(10)}
                />

                <img
                    alt="attack"
                    className={clientUnitStatsStyle.client_unit_stats__icon}
                    src={unitStatsIcon.attack.src}
                />
                <SmallText
                    className={clientUnitStatsStyle.client_unit_stats__text}
                    scale={2}
                    text={attackDataList.join("")}
                />

                <img
                    alt="defence"
                    className={clientUnitStatsStyle.client_unit_stats__icon}
                    src={unitStatsIcon.defence.src}
                />
                <SmallText
                    className={clientUnitStatsStyle.client_unit_stats__text}
                    scale={2}
                    text={armorDataList.join("")}
                />
            </div>
            <div className={clientUnitStatsStyle.client_unit_stats}>
                <img
                    alt="level"
                    className={clientUnitStatsStyle.client_unit_stats__icon}
                    src={unitStatsIcon.level.src}
                />
                <SmallText
                    className={clientUnitStatsStyle.client_unit_stats__text}
                    scale={2}
                    text={`${(develData.level || "-").toString(10)} / ${maxUnitLevel}`}
                />
                <img
                    alt="level"
                    className={clientUnitStatsStyle.client_unit_stats__icon}
                    src={unitStatsIcon.levelUp.src}
                />
                <SmallText
                    className={clientUnitStatsStyle.client_unit_stats__text}
                    scale={2}
                    text={`${develData.experience.value} / ${develData.experience.to}`}
                />
                <IsRender isRender={isUnderPoison}>
                    <img
                        alt="under-poison"
                        className={clientUnitStatsStyle.client_unit_stats__icon}
                        src={unitStatsIcon.underPoison.src}
                    />
                </IsRender>
                <IsRender isRender={isUnderWispAura}>
                    <img
                        alt="under-wisp-aura"
                        className={clientUnitStatsStyle.client_unit_stats__icon}
                        src={unitStatsIcon.underWispAura.src}
                    />
                </IsRender>
            </div>
        </div>
    );
}
