/* global localStorage */
import type {GamePlayerColorIdEnum} from "../../model/game/player/player-type";
import {GameUnitTypeEnum} from "../../model/game/unit/unit-type";
import {getUnitImageSource} from "../../page/client/client-game/client-game-unit/image/unit-image";
import {getEnumValueEnsure} from "../../util/enum";
import {noop} from "../../util/function";
import {
    botDifficultInitMap,
    defaultBooleanSettingState,
    defaultLandscapeThemeOverride,
    defaultNumberSettingState,
    landscapeThemeSettingValueMap,
} from "./setting-const";
import type {
    BotDifficultEnum,
    LandscapeThemeSettingType,
    SettingContextSettingType,
    SettingContextType,
} from "./setting-type";

const settingLocalStorageKey = "setting-v1.2.0";

export function getSavedSettingData(): SettingContextSettingType {
    const rawString = localStorage.getItem(settingLocalStorageKey) ?? "";

    if (!rawString) {
        return {
            booleanSetting: {...defaultBooleanSettingState},
            // BotDifficult: BotDifficultEnum.normal,
            landscapeThemeOverride: defaultLandscapeThemeOverride,
            numberSetting: {...defaultNumberSettingState},
        };
    }

    // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
    const parsedRawData: Partial<SettingContextSettingType> = JSON.parse(rawString);

    return {
        booleanSetting: {
            ...defaultBooleanSettingState,
            ...(parsedRawData.booleanSetting ?? defaultBooleanSettingState),
        },
        /*
        BotDifficult: getEnumValueEnsure<BotDifficultEnum>(
            BotDifficultEnum,
            parsedRawData.botDifficult,
            BotDifficultEnum.normal
        ),
*/
        landscapeThemeOverride: getEnumValueEnsure<LandscapeThemeSettingType>(
            landscapeThemeSettingValueMap,
            parsedRawData.landscapeThemeOverride,
            defaultLandscapeThemeOverride
        ),
        numberSetting: {
            ...defaultNumberSettingState,
            ...(parsedRawData.numberSetting ?? defaultNumberSettingState),
        },
    };
}

export function saveSetting(setting: SettingContextSettingType): undefined {
    localStorage.setItem(settingLocalStorageKey, JSON.stringify(setting));
}

export function getDefaultSettingContextData(): SettingContextType {
    return {
        setBoolean: noop,
        setNumber: noop,
        setSetting: noop,
        setting: getSavedSettingData(),
    };
}

export function getBotDifficultImage(difficult: BotDifficultEnum, color: GamePlayerColorIdEnum): string {
    return getUnitImageSource(botDifficultInitMap[difficult], color);
}

export function getNonDoneMissionImage(color: GamePlayerColorIdEnum): string {
    return getUnitImageSource(GameUnitTypeEnum.skeleton, color);
}
