/* global HTMLSelectElement */

import type {JSX, SyntheticEvent} from "react";

import {serviceStyle} from "../../../../css/style";
import {buildingNameLangKeyMap, moneyBuildingTypeList} from "../../../../model/game/building/building-const";
import type {GameBuildingTypeEnum} from "../../../../model/game/building/building-type";
import {buildingHealthBonusList, buildingMoneyIncomeList} from "../../../../model/game/game-const";
import type {BuildingGameSettingsType} from "../../../../model/game/game-type";
import {useLocale} from "../../../../provider/locale/locale-context";
import {testId} from "../../../../test-id";
import {cls} from "../../../../util/css";
import * as clientLocalGameSetupStyle from "../client-local-game-setup.scss";
// import * as clientLocalGameSetupPlayerStyle from "../../client-local-game-setup/client-local-game-setup-player/client-local-game-setup-player.scss";

interface ClientLocalGameSetupBuildingPropsType {
    buildingType: GameBuildingTypeEnum;
    onChange: (buildingType: GameBuildingTypeEnum, setting: BuildingGameSettingsType) => void;
    setting: BuildingGameSettingsType;
}

export function ClientLocalGameSetupBuildingRow(props: ClientLocalGameSetupBuildingPropsType): JSX.Element {
    const {buildingType, setting, onChange} = props;
    const {getLocalizedString} = useLocale();
    const canEarnMoney: boolean = moneyBuildingTypeList.includes(buildingType);

    return (
        <tr data-building-type={buildingType} data-testid={testId.setupPage.buildingRow}>
            <td>
                <p className={clientLocalGameSetupStyle.client_local_game_setup__item_label}>
                    {getLocalizedString(buildingNameLangKeyMap[buildingType])}
                </p>
            </td>
            <td>
                <select
                    className={cls(serviceStyle.input__select, serviceStyle.input__select__right)}
                    data-testid={testId.setupPage.buildingHealSelect}
                    defaultValue={setting.healthBonus}
                    onChange={(evt: SyntheticEvent<HTMLSelectElement>): undefined => {
                        onChange(buildingType, {
                            ...setting,
                            healthBonus: Number.parseInt(evt.currentTarget.value, 10),
                        });
                    }}
                >
                    {buildingHealthBonusList.map<JSX.Element>((healthBonus: number): JSX.Element => {
                        return (
                            <option key={healthBonus} value={healthBonus}>
                                {healthBonus}
                            </option>
                        );
                    })}
                </select>
            </td>
            <td>
                {canEarnMoney ? (
                    <select
                        className={cls(serviceStyle.input__select, serviceStyle.input__select__right)}
                        defaultValue={setting.moneyIncome}
                        onChange={(evt: SyntheticEvent<HTMLSelectElement>): undefined => {
                            onChange(buildingType, {
                                ...setting,
                                moneyIncome: Number.parseInt(evt.currentTarget.value, 10),
                            });
                        }}
                    >
                        {buildingMoneyIncomeList.map<JSX.Element>((moneyIncome: number): JSX.Element => {
                            return (
                                <option key={moneyIncome} value={moneyIncome}>
                                    {moneyIncome}
                                </option>
                            );
                        })}
                    </select>
                ) : null}
            </td>
        </tr>
    );
}
