/* global document, HTMLDivElement, TouchEvent, MouseEvent, WheelEvent, KeyframeAnimationOptions */
import {useCallback, useEffect, useMemo, useRef, useState} from "react";

import type {PointType} from "../../model/game/point/point-type";
import {useSettingContext} from "../../provider/setting/setting-context";
import type {PromiseResolveType} from "../../util/promise";
import {isTouch} from "./use-gesture-const";
import {
    fitMovingData,
    fitValue,
    getChildMinMax,
    getSize,
    getStyleString,
    mouseEventToPoint,
    touchToPoint,
} from "./use-gesture-helper";
import type {
    MovingDataType,
    MovingLimitDataType,
    UseGestureConfigStateType,
    UseGestureConfigType,
    UseGestureHookType,
} from "./use-gesture-type";
import {usePreventGesture} from "./use-prevent-gesture";

// eslint-disable-next-line max-statements
export function useGesture(config: UseGestureConfigType): UseGestureHookType {
    usePreventGesture();

    const {
        setting: {
            numberSetting: {animationStepTime},
        },
    } = useSettingContext();
    const {childRef, wrapperRef, limit, defaultState} = config;
    const {point, zoom, multiplier} = limit;
    const {x: maxX, y: maxY} = point.max;
    const {x: minX, y: minY} = point.min;
    const {min: minZoom, max: maxZoom} = zoom;
    const {x: defaultX, y: defaultY, zoom: defaultZoom} = defaultState;
    const [currentState, setCurrentState] = useState<UseGestureConfigStateType>({
        x: defaultX,
        y: defaultY,
        zoom: defaultZoom,
    });

    const movingLimit: MovingLimitDataType = useMemo((): MovingLimitDataType => {
        return {
            maxX,
            maxY,
            maxZoom,
            minX,
            minY,
            minZoom,
        };
    }, [maxY, maxX, maxZoom, minZoom, minX, minY]);

    useEffect(() => {
        childRef.current.style.transform = getStyleString({
            x: defaultX,
            y: defaultY,
            zoom: defaultZoom,
        });
    }, [childRef, defaultX, defaultY, defaultZoom]);

    const childStartPointRef = useRef<PointType>({x: defaultX, y: defaultY});
    const childMovingPointRef = useRef<PointType>({x: defaultX, y: defaultY});
    const moveTouchStartPointRef = useRef<PointType>({x: 0, y: 0});
    const zoomTouchStartPointRef = useRef<[PointType, PointType]>([
        {x: 0, y: 0},
        {x: 0, y: 0},
    ]);
    const childStartZoomRef = useRef<Record<"zoom", number>>({zoom: defaultZoom});
    const childMovingZoomRef = useRef<Record<"zoom", number>>({zoom: defaultZoom});
    const mousePressedRef = useRef<Record<"isPressed", boolean>>({isPressed: false});

    const fitToFrame = useCallback(() => {
        const childMinMax = getChildMinMax(childRef.current, movingLimit);
        const fittedMovingData = fitMovingData(
            {...childMovingPointRef.current, ...childMovingZoomRef.current},
            childMinMax,
            0
        );

        childRef.current.style.transform = getStyleString(fittedMovingData);
        childStartPointRef.current.x = fittedMovingData.x;
        childStartPointRef.current.y = fittedMovingData.y;
        childStartZoomRef.current.zoom = fittedMovingData.zoom;
        childMovingPointRef.current.x = fittedMovingData.x;
        childMovingPointRef.current.y = fittedMovingData.y;
        childMovingZoomRef.current.zoom = fittedMovingData.zoom;

        setCurrentState({
            x: fittedMovingData.x,
            y: fittedMovingData.y,
            zoom: fittedMovingData.zoom,
        });
    }, [childRef, movingLimit]);

    useEffect(() => {
        fitToFrame();
    }, [fitToFrame]);

    useEffect(() => {
        const wrapperNode: HTMLDivElement = wrapperRef.current;
        let childMinMax = getChildMinMax(childRef.current, movingLimit);

        function onTouchStart(evt: TouchEvent): undefined {
            const firstTouch = evt.touches.item(0);
            const secondTouch = evt.touches.item(1);

            if (evt.touches.length === 1) {
                childMinMax = getChildMinMax(childRef.current, movingLimit);
            }

            if (firstTouch) {
                const firstPint = touchToPoint(firstTouch);

                moveTouchStartPointRef.current.x = firstPint.x;
                moveTouchStartPointRef.current.y = firstPint.y;
            }

            if (firstTouch && secondTouch) {
                zoomTouchStartPointRef.current[0] = touchToPoint(firstTouch);
                zoomTouchStartPointRef.current[1] = touchToPoint(secondTouch);
            }
        }

        function onTouchMove(evt: TouchEvent): undefined {
            const firstTouch = evt.touches.item(0);
            const secondTouch = evt.touches.item(1);

            if (firstTouch && secondTouch) {
                const [firstZoomPoint, secondZoomPoint] = zoomTouchStartPointRef.current;
                const lineBefore = getSize(firstZoomPoint, secondZoomPoint);
                const lineAfter = getSize(touchToPoint(firstTouch), touchToPoint(secondTouch));
                const deltaZoom = lineAfter / lineBefore;

                childMovingZoomRef.current.zoom = fitValue({
                    max: childMinMax.maxZoom,
                    min: childMinMax.minZoom,
                    multiplier,
                    value: childStartZoomRef.current.zoom * deltaZoom,
                });

                childRef.current.style.transform = getStyleString({
                    ...childMovingPointRef.current,
                    ...childMovingZoomRef.current,
                });

                setCurrentState((currentStateToReplace: UseGestureConfigStateType): UseGestureConfigStateType => {
                    return {
                        ...currentStateToReplace,
                        zoom: childMovingZoomRef.current.zoom,
                    };
                });
                return;
            }

            if (firstTouch && evt.touches.length === 1) {
                const firstPint = touchToPoint(firstTouch);

                const deltaX = moveTouchStartPointRef.current.x - firstPint.x;
                const deltaY = moveTouchStartPointRef.current.y - firstPint.y;

                childMovingPointRef.current.x = fitValue({
                    max: childMinMax.maxX,
                    min: childMinMax.minX,
                    multiplier,
                    value: childStartPointRef.current.x - deltaX,
                });

                childMovingPointRef.current.y = fitValue({
                    max: childMinMax.maxY,
                    min: childMinMax.minY,
                    multiplier,
                    value: childStartPointRef.current.y - deltaY,
                });

                childRef.current.style.transform = getStyleString({
                    ...childMovingPointRef.current,
                    ...childMovingZoomRef.current,
                });

                setCurrentState((currentStateToReplace: UseGestureConfigStateType): UseGestureConfigStateType => {
                    return {
                        ...currentStateToReplace,
                        ...childMovingPointRef.current,
                    };
                });
            }
        }

        function onTouchEnd(evt: TouchEvent): undefined {
            const firstTouch = evt.touches.item(0);
            const secondTouch = evt.touches.item(1);

            if (firstTouch && secondTouch) {
                zoomTouchStartPointRef.current[0] = touchToPoint(firstTouch);
                zoomTouchStartPointRef.current[1] = touchToPoint(secondTouch);
            } else {
                childStartZoomRef.current.zoom = childMovingZoomRef.current.zoom;
                zoomTouchStartPointRef.current[0] = {x: 0, y: 0};
                zoomTouchStartPointRef.current[1] = {x: 0, y: 0};
            }

            if (firstTouch) {
                const firstPint = touchToPoint(firstTouch);

                moveTouchStartPointRef.current.x = firstPint.x;
                moveTouchStartPointRef.current.y = firstPint.y;
            } else {
                childStartPointRef.current.x = childMovingPointRef.current.x;
                childStartPointRef.current.y = childMovingPointRef.current.y;
            }

            if (!firstTouch) {
                fitToFrame();
            }
        }

        if (isTouch) {
            wrapperNode.addEventListener("touchstart", onTouchStart, false);
            wrapperNode.addEventListener("touchmove", onTouchMove, false);
            wrapperNode.addEventListener("touchend", onTouchEnd, false);
            wrapperNode.addEventListener("touchcancel", onTouchEnd, false);
        }

        return (): void => {
            wrapperNode.removeEventListener("touchstart", onTouchStart, false);
            wrapperNode.removeEventListener("touchmove", onTouchMove, false);
            wrapperNode.removeEventListener("touchend", onTouchEnd, false);
            wrapperNode.removeEventListener("touchcancel", onTouchEnd, false);
        };
    }, [fitToFrame, multiplier, movingLimit, wrapperRef, childRef]);

    const animateGestureState = useCallback(
        async (updatedState: Partial<MovingDataType>): Promise<void> => {
            const filledNewState: MovingDataType = {
                ...childStartPointRef.current,
                ...childStartZoomRef.current,
                ...updatedState,
            };

            const transformFromPoint = {
                transform: getStyleString({...childStartPointRef.current, ...childStartZoomRef.current}),
            };

            const transformToPoint = {
                transform: getStyleString({
                    x: filledNewState.x * filledNewState.zoom,
                    y: filledNewState.y * filledNewState.zoom,
                    zoom: filledNewState.zoom,
                }),
            };

            const moveTransformList = [transformFromPoint, transformToPoint];

            const unitMoveTiming: KeyframeAnimationOptions = {
                duration: animationStepTime,
                easing: "ease-in-out",
                fill: "forwards",
                iterations: 1,
            };

            return new Promise((resolve: PromiseResolveType<void>) => {
                const animation = childRef.current.animate(moveTransformList, unitMoveTiming);

                animation.onfinish = (): undefined => {
                    childStartPointRef.current.x = filledNewState.x * filledNewState.zoom;
                    childStartPointRef.current.y = filledNewState.y * filledNewState.zoom;
                    childStartZoomRef.current.zoom = filledNewState.zoom;

                    childMovingZoomRef.current.zoom = childStartZoomRef.current.zoom;
                    childMovingPointRef.current.x = childStartPointRef.current.x;
                    childMovingPointRef.current.y = childStartPointRef.current.y;

                    childRef.current.style.transform = getStyleString({
                        ...childStartPointRef.current,
                        ...childStartZoomRef.current,
                    });
                    animation.cancel();
                    resolve();
                };
            });
        },
        [animationStepTime, childRef]
    );

    useEffect(() => {
        const wrapperNode: HTMLDivElement = wrapperRef.current;
        let childMinMax = getChildMinMax(childRef.current, movingLimit);

        function onMouseDown(evt: MouseEvent): undefined {
            const mousePoint = mouseEventToPoint(evt);

            mousePressedRef.current.isPressed = true;

            childMinMax = getChildMinMax(childRef.current, movingLimit);

            moveTouchStartPointRef.current.x = mousePoint.x;
            moveTouchStartPointRef.current.y = mousePoint.y;
        }

        function onMouseMove(evt: MouseEvent): undefined {
            if (!mousePressedRef.current.isPressed) {
                return;
            }

            const mousePoint = mouseEventToPoint(evt);
            const deltaX = moveTouchStartPointRef.current.x - mousePoint.x;
            const deltaY = moveTouchStartPointRef.current.y - mousePoint.y;

            childMovingPointRef.current.x = fitValue({
                max: childMinMax.maxX,
                min: childMinMax.minX,
                multiplier,
                value: childStartPointRef.current.x - deltaX,
            });

            childMovingPointRef.current.y = fitValue({
                max: childMinMax.maxY,
                min: childMinMax.minY,
                multiplier,
                value: childStartPointRef.current.y - deltaY,
            });

            childRef.current.style.transform = getStyleString({
                ...childMovingPointRef.current,
                ...childMovingZoomRef.current,
            });

            setCurrentState((currentStateToReplace: UseGestureConfigStateType): UseGestureConfigStateType => {
                return {
                    ...currentStateToReplace,
                    ...childMovingPointRef.current,
                };
            });
        }

        function onMouseUp(): undefined {
            mousePressedRef.current.isPressed = false;

            zoomTouchStartPointRef.current[0] = {x: 0, y: 0};
            zoomTouchStartPointRef.current[1] = {x: 0, y: 0};
            childStartPointRef.current.x = childMovingPointRef.current.x;
            childStartPointRef.current.y = childMovingPointRef.current.y;

            fitToFrame();
        }

        if (!isTouch) {
            wrapperNode.addEventListener("mousedown", onMouseDown, false);
            wrapperNode.addEventListener("mousemove", onMouseMove, false);
            document.body.addEventListener("mouseup", onMouseUp, false);
            document.body.addEventListener("mouseleave", onMouseUp, false);
        }

        return (): void => {
            wrapperNode.removeEventListener("mousedown", onMouseDown, false);
            wrapperNode.removeEventListener("mousemove", onMouseMove, false);
            document.body.removeEventListener("mouseup", onMouseUp, false);
            document.body.removeEventListener("mouseleave", onMouseUp, false);
        };
    }, [fitToFrame, multiplier, movingLimit, wrapperRef, childRef]);

    useEffect(() => {
        const wrapperNode: HTMLDivElement = wrapperRef.current;

        function onMouseWheel(evt: WheelEvent): undefined {
            const childMinMax = getChildMinMax(childRef.current, movingLimit);
            const {deltaY: mouseWheelDeltaY} = evt;

            if (!mouseWheelDeltaY) {
                return;
            }

            const zoomDirection: number = -mouseWheelDeltaY / Math.abs(mouseWheelDeltaY);

            // Const deltaZoom: number = (zoomDirection * (movingLimit.maxZoom - movingLimit.minZoom)) / 20;
            const deltaZoom: number = zoomDirection * 0.25;

            childMovingZoomRef.current.zoom = fitValue({
                max: childMinMax.maxZoom,
                min: childMinMax.minZoom,
                multiplier,
                value: childStartZoomRef.current.zoom + deltaZoom,
            });
            childStartZoomRef.current.zoom = childMovingZoomRef.current.zoom;

            childRef.current.style.transform = getStyleString({
                ...childMovingPointRef.current,
                ...childMovingZoomRef.current,
            });
            fitToFrame();
        }

        if (!isTouch) {
            wrapperNode.addEventListener("wheel", onMouseWheel, false);
        }

        return (): void => {
            wrapperNode.removeEventListener("wheel", onMouseWheel, false);
        };
    }, [fitToFrame, multiplier, movingLimit, wrapperRef, childRef]);

    const providedData: UseGestureHookType = useMemo((): UseGestureHookType => {
        return {animateGestureState, currentState};
    }, [animateGestureState, currentState]);

    return providedData;
}
