export function landscapeToMapFile(landscape: GameLandscapeType): string {
    let landscapeString = JSON.stringify(landscape);

    Object.entries(GameLandscapeItemEnum).forEach((entry: [string, string]) => {
        const [key, value] = entry;

        landscapeString = landscapeString.replace(new RegExp(`"${value}"`, "gu"), key);
    });

    return landscapeString;
}

export function landscapeThemeMapToMapFile(landscapeThemeMap: GameLandscapeThemeMapType): string {
    let landscapeThemeMapString = JSON.stringify(landscapeThemeMap);

    Object.entries(GameLandscapeThemeEnum).forEach((entry: [string, string]) => {
        const [key, value] = entry;

        landscapeThemeMapString = landscapeThemeMapString.replace(new RegExp(`"${value}"`, "gu"), key);
    });

    return landscapeThemeMapString;
}

export function buildingListToMapFile(buildingList: Array<GameBuildingType>): string {
    let buildingListString = JSON.stringify(buildingList);

    Object.entries(GameBuildingTypeEnum).forEach((entry: [string, string]) => {
        const [key, value] = entry;

        buildingListString = buildingListString.replace(new RegExp(`"${value}"`, "gu"), key);
    });

    Object.entries(GameBuildingStateEnum).forEach((entry: [string, string]) => {
        const [key, value] = entry;

        buildingListString = buildingListString.replace(new RegExp(`"${value}"`, "gu"), key);
    });

    Object.entries(GamePlayerIdEnum).forEach((entry: [string, string]) => {
        const [key, value] = entry;

        buildingListString = buildingListString.replace(new RegExp(`"${value}"`, "gu"), key);
    });

    return buildingListString;
}

export function unitListToMapFile(unitList: Array<GameUnitType>): string {
    let unitListString = JSON.stringify(unitList);

    Object.entries(GameUnitTypeEnum).forEach((entry: [string, string]) => {
        const [key, value] = entry;

        unitListString = unitListString
            .replace(new RegExp(`"${value}"`, "gu"), key)
            .replace(new RegExp(`"${value}-[^"]+?"`, "gu"), `getRandomStringWithPrefix(${key})`);
    });

    Object.entries(GamePlayerIdEnum).forEach((entry: [string, string]) => {
        const [key, value] = entry;

        unitListString = unitListString.replace(new RegExp(`"${value}"`, "gu"), key);
    });

    unitListString = unitListString.replace(
        new RegExp(`"health":\\s?${defaultUnitData.health},`, "gu"),
        "health: defaultUnitData.health,"
    );

    return unitListString;
}

export function graveListToMapFile(graveList: Array<GameGraveType>): string {
    // Graves hold only plain numeric fields (createdStepCount, x, y), so no enum substitution is needed.
    return JSON.stringify(graveList);
}

export function getIsDevelopmentDomain(): boolean {
    if (typeof location === "undefined") {
        return false;
    }

    return ["localhost", "ancientempire2.github.io"].includes(location.hostname);
}
