import {GameLandscapeThemeEnum} from "../../../../../model/game/landscape/landscape-type";
import {getImage} from "../../../../../util/image";
import graveAe1 from "./main/ae1/grave.png";
import graveAe2 from "./main/ae2/grave.png";
import graveDesert from "./main/desert/grave.png";
import graveSummer from "./main/summer/grave.png";
import graveSummer2 from "./main/summer2/grave.png";

const graveImageByTheme: Record<GameLandscapeThemeEnum, HTMLImageElement> = {
    [GameLandscapeThemeEnum.ae1]: getImage(graveAe1),
    [GameLandscapeThemeEnum.ae2]: getImage(graveAe2),
    [GameLandscapeThemeEnum.desert]: getImage(graveDesert),
    [GameLandscapeThemeEnum.summer]: getImage(graveSummer),
    [GameLandscapeThemeEnum.summer2]: getImage(graveSummer2),
};

export function getGraveImage(theme: GameLandscapeThemeEnum): HTMLImageElement {
    return graveImageByTheme[theme];
}
