/* global IS_PRODUCTION */

import {type JSX, useCallback, useEffect, useState} from "react";
import {type Location, Outlet, useBlocker, useNavigate} from "react-router-dom";
import {useDocumentVisibility} from "react-system-hook";

import {appRoute, fullPathToGameSetting, fullPathToUnitStore} from "../../../app/app-route";
import {useAudioPlayer} from "../../../hook/audio-player-hook/audio-player-hook";
import type {AudioPlayerConfigType} from "../../../hook/audio-player-hook/audio-player-type";
import {GameActionFacedSnackbar} from "../../../layout/game-faced-snackbar-list/game-action-faced-snackbar";
import {GameFacedSnackbar} from "../../../layout/game-faced-snackbar-list/game-faced-snackbar";
import {Page} from "../../../layout/page/page";
import {PageFooter} from "../../../layout/page/page-footer/page-footer";
import {UiButton} from "../../../layout/ui-button/ui-button";
import {gameTheme, storyTheme} from "../../../media/play-media";
import {getHeroPoint} from "../../../model/game/landscape/landscape-helper";
import {getPlayerByPlayerId} from "../../../model/game/player/player-helper";
import {GamePlayerTypeEnum} from "../../../model/game/player/player-type";
import type {PointType} from "../../../model/game/point/point-type";
import {getIsCompaniesMap, getIsSkirmishMap, getMapById, getShortMapInfoById} from "../../../model/map/map-helper";
import {getSavedGameList, type SavedGameType} from "../../../provider/game/action/save-game";
import {getAutoSavedGameList} from "../../../provider/game/action/save-game-auto";
import {useGameContext} from "../../../provider/game/game-context";
import {defaultStepCount} from "../../../provider/game/game-context-helper";
import {usePromptContext} from "../../../provider/prompt/prompt-context";
import {resolveLandscapeThemeOverride} from "../../../provider/setting/landscape-theme-override-helper";
import {useSettingContext} from "../../../provider/setting/setting-context";
import {showAds} from "../../../service/ads";
import {useOnMount} from "../../../service/use-on-mount";
import {testId} from "../../../test-id";
import {throwError} from "../../../util/error";
import {noop} from "../../../util/function";
import {ClientBot} from "./client-bot/client-bot";
import * as clientGameStyle from "./client-game.scss";
import {ClientGameAutoSave} from "./client-game-auto-save/client-game-auto-save";
import {ClientGameBottomStatusBar} from "./client-game-bottom-status-bar/client-game-bottom-status-bar";
import {ClientGameBuilding} from "./client-game-building/client-game-building";
import {ClientGameBuildingEffect} from "./client-game-building-effect/client-game-building-effect";
import {ClientGameClickHunter} from "./client-game-click-hunter/client-game-click-hunter";
import {ClientGameEffect} from "./client-game-effect/client-game-effect";
import {CompaniesEndGamePopup} from "./client-game-end-game-popup/companies-end-game-popup";
import {SkirmishEndGamePopup} from "./client-game-end-game-popup/skirmish-end-game-popup";
import {ClientGameEndTurnButton} from "./client-game-end-turn-button/client-game-end-turn-button";
import {ClientGameGrave} from "./client-game-grave/client-game-grave";
import {getRandomGamePageClassName} from "./client-game-helper";
import {ClientGameLandscape} from "./client-game-landscape/client-game-landscape";
import {ClientGameMenuPopup} from "./client-game-menu-popup/client-game-menu-popup";
import {ClientGameMoveBackButton} from "./client-game-move-back-button/client-game-move-back-button";
import {ClientGameNewTurnPopup} from "./client-game-new-turn-popup/client-game-new-turn-popup";
import {ClientGamePlayerIsDefeat} from "./client-game-player-is-defeat/client-game-player-is-defeat";
import {ClientGameCompanyStoryPopup} from "./client-game-start-game-popup/client-game-company-story-popup";
import {ClientGameStartGamePopup} from "./client-game-start-game-popup/client-game-start-game-popup";
import {ClientGameTelefrag} from "./client-game-telefrag/client-game-telefrag";
import {ClientGameUnit} from "./client-game-unit/client-game-unit";
import {ClientGameUnitFight} from "./client-game-unit-fight/client-game-unit-fight";
import {ClientGameViewContainer} from "./client-game-view-container/client-game-view-container";
import {ClientTrigger} from "./client-trigger/client-trigger";
import {ClientBuildingStats} from "./game-stats/client-building-stats/client-building-stats";
import {ClientUnitStats} from "./game-stats/client-unit-stats/client-unit-stats";
import {clientGameImage} from "./image/client-game-image";

// eslint-disable-next-line max-statements
export function ClientGame(): JSX.Element {
    const {
        moveViewToPoint,
        gameState,
        setIsGameRunning,
        isEnableEndTurnButton,
        setActivePoint,
        isGameRunning,
        isCompanyEnd,
        useGestureRef,
        loadGame,
        // setGameState,
    } = useGameContext();
    const navigate = useNavigate();
    const {prompt} = usePromptContext();
    const [isGameCompanyStoryOpen, setIsGameCompanyStoryOpen] = useState<boolean>(false);
    const [isGameCompanyBriefingOpen, setIsGameCompanyBriefingOpen] = useState<boolean>(false);
    const [isGameStarMessageOpen, setIsGameStarMessageOpen] = useState<boolean>(false);
    const [isGameMenuOpen, setIsGameMenuOpen] = useState<boolean>(false);
    const [musicPlayerState, setMusicPlayerState] = useState<AudioPlayerConfigType>(gameTheme);
    const isDocumentVisible = useDocumentVisibility();
    const [isBlockToExit, setIsBlockToExit] = useState<boolean>(true);
    const [gamePageClassName] = useState<string>((): string => {
        return getRandomGamePageClassName();
    });
    const {
        setting: {
            booleanSetting: {isAutoSaveEnable},
            landscapeThemeOverride,
        },
    } = useSettingContext();
    const forcedTheme = resolveLandscapeThemeOverride(gameState.mapId, landscapeThemeOverride);

    // show ads
    useEffect(() => {
        const {activeGamePlayerId, stepCount, playerList} = gameState;
        const currentPlayer = getPlayerByPlayerId(activeGamePlayerId, playerList);
        if (!currentPlayer) {
            console.error(`Can not get player by player id: ${activeGamePlayerId}`);
            return;
        }

        const {playerType} = currentPlayer;
        if (playerType === GamePlayerTypeEnum.human && stepCount > 10) {
            showAds();
        }
    }, [gameState]);

    // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition, @typescript-eslint/strict-boolean-expressions
    const telefragList = gameState.telefragList || [];
    const {play: playAmbient, pause: pauseAmbient} = useAudioPlayer(musicPlayerState);

    // check unexpected page refresh
    useEffect(() => {
        if (!isGameRunning) {
            return;
        }

        if (gameState.mapId) {
            return;
        }

        const autoSavedGameList: Array<SavedGameType> = getAutoSavedGameList();

        const lastAutoSave = autoSavedGameList.at(-1);

        if (lastAutoSave) {
            // eslint-disable-next-line @typescript-eslint/no-floating-promises
            loadGame(lastAutoSave.gameState);
            return;
        }

        const savedGameList: Array<SavedGameType> = getSavedGameList();

        const lastSave = savedGameList.at(-1);

        if (lastSave) {
            // eslint-disable-next-line @typescript-eslint/no-floating-promises
            loadGame(lastSave.gameState);
            return;
        }

        // eslint-disable-next-line react-hooks/set-state-in-effect
        setIsBlockToExit(false);
        navigate(-1)?.catch(throwError);
    }, [loadGame, isGameRunning, gameState, navigate]);

    useBlocker(
        (data: {
            currentLocation: Location<unknown>;
            historyAction: unknown;
            nextLocation: Location<unknown>;
        }): boolean => {
            const {nextLocation} = data;

            if (
                [fullPathToUnitStore, fullPathToGameSetting, appRoute.clientGame.path].includes(nextLocation.pathname)
            ) {
                return false;
            }

            if (!isBlockToExit) {
                return false;
            }

            prompt({
                header: "POPUP__DO_YOU_REALLY_WANT_TO_QUIT",
                index: 0,
                onNo: noop,
                onYes: () => {
                    setIsBlockToExit(false);
                    navigate(-1)?.catch(throwError);
                },
            });

            return isBlockToExit;
        }
    );

    useEffect(() => {
        playAmbient();
        if (isGameCompanyStoryOpen) {
            // eslint-disable-next-line react-hooks/set-state-in-effect
            setMusicPlayerState(storyTheme);
            return;
        }
        setMusicPlayerState(gameTheme);
    }, [playAmbient, isGameCompanyStoryOpen]);

    useEffect(() => {
        if (isDocumentVisible) {
            playAmbient();
            return;
        }

        pauseAmbient();
    }, [isDocumentVisible, pauseAmbient, playAmbient]);

    useEffect(() => {
        if (getIsSkirmishMap(gameState.mapId) && gameState.stepCount === defaultStepCount) {
            // eslint-disable-next-line react-hooks/set-state-in-effect
            setIsGameStarMessageOpen(true);
        }
    }, [gameState.mapId, gameState.stepCount]);

    useEffect(() => {
        // story
        // briefing
        // start game message
        if (!getIsCompaniesMap(gameState.mapId) || gameState.stepCount !== defaultStepCount) {
            return;
        }

        const {hasStory, hasBriefing} = getShortMapInfoById(gameState.mapId);

        if (hasStory) {
            // eslint-disable-next-line react-hooks/set-state-in-effect
            setIsGameCompanyStoryOpen(true);
            return;
        }

        if (hasBriefing) {
            setIsGameCompanyBriefingOpen(true);
            return;
        }

        setIsGameStarMessageOpen(true);
    }, [gameState.mapId, gameState.stepCount]);

    const gameCompanyStoryClose = useCallback(() => {
        const {hasBriefing} = getShortMapInfoById(gameState.mapId);

        setIsGameCompanyStoryOpen(false);

        if (hasBriefing) {
            setIsGameCompanyBriefingOpen(true);
            return;
        }
        setIsGameStarMessageOpen(true);
    }, [gameState.mapId]);

    const gameCompanyBriefingClose = useCallback(() => {
        setIsGameCompanyBriefingOpen(false);

        setIsGameStarMessageOpen(true);
    }, []);

    useOnMount(() => {
        const pointToMove: PointType | null = getHeroPoint(gameState.unitList);

        if (!pointToMove) {
            console.error("can not find hero");
            return;
        }

        setActivePoint(pointToMove);
        // eslint-disable-next-line @typescript-eslint/no-floating-promises
        moveViewToPoint(pointToMove);
    });

    useEffect(() => {
        setIsGameRunning(true);

        return (): void => {
            setIsGameRunning(false);
        };
    }, [setIsGameRunning]);

    return (
        <>
            <Page className={gamePageClassName}>
                <ClientGameViewContainer useGestureRef={useGestureRef}>
                    <ClientGameLandscape
                        forcedTheme={forcedTheme}
                        landscape={gameState.landscape}
                        landscapeThemeMap={gameState.landscapeThemeMap}
                    />
                    <ClientGameBuilding forcedTheme={forcedTheme} />
                    <ClientGameGrave forcedTheme={forcedTheme} />
                    <ClientGameUnit isMapEditor={false} />
                    <ClientGameBuildingEffect />
                    <ClientGameEffect />
                    <ClientGameClickHunter />
                </ClientGameViewContainer>

                <ClientGameUnitFight />

                <UiButton
                    className={clientGameStyle.client_game__menu_button}
                    iconSrc={clientGameImage.hammer.src}
                    isDisabled={!isEnableEndTurnButton}
                    isSquared
                    langKey="BATTLE_MENU__MENU"
                    onClick={(): undefined => {
                        setIsGameMenuOpen(!isGameMenuOpen);
                    }}
                />

                {isGameRunning ? <ClientBot /> : null}
                {isGameRunning ? <ClientTrigger /> : null}

                <ClientGameEndTurnButton />

                {IS_PRODUCTION === false ? (
                    <div
                        data-active-player-id={gameState.activeGamePlayerId}
                        data-step-count={gameState.stepCount}
                        data-testid={testId.gamePage.debug}
                        hidden
                    />
                ) : null}

                <div className={clientGameStyle.client_game__cell_stats}>
                    <ClientBuildingStats />
                    <ClientUnitStats />
                </div>

                <ClientGameStartGamePopup
                    isGameStarMessageOpen={isGameStarMessageOpen}
                    setIsGameStarMessageOpen={setIsGameStarMessageOpen}
                />

                <ClientGameCompanyStoryPopup
                    isGameCompanyStoryOpen={isGameCompanyStoryOpen}
                    setIsGameCompanyStoryOpen={gameCompanyStoryClose}
                />

                {isCompanyEnd ? null : <ClientGameNewTurnPopup />}

                {isGameRunning && telefragList.length === 0 ? (
                    <SkirmishEndGamePopup setIsBlockToExit={setIsBlockToExit} />
                ) : null}
                {isGameRunning && telefragList.length === 0 ? (
                    <CompaniesEndGamePopup setIsBlockToExit={setIsBlockToExit} />
                ) : null}

                <ClientGameMenuPopup
                    isOpen={isGameMenuOpen}
                    setIsGameMenuOpen={setIsGameMenuOpen}
                    setIsGameStarMessageOpen={setIsGameStarMessageOpen}
                />

                {isAutoSaveEnable && isGameRunning && isCompanyEnd === false ? <ClientGameAutoSave /> : null}

                {isGameRunning && isCompanyEnd === false ? <ClientGamePlayerIsDefeat /> : null}

                <ClientGameMoveBackButton />

                <GameActionFacedSnackbar />

                <GameFacedSnackbar
                    dataList={getMapById(gameState.mapId)?.briefingList ?? []}
                    isOpen={isGameCompanyBriefingOpen}
                    onHideLastItem={gameCompanyBriefingClose}
                    refId="from-game"
                />

                <PageFooter>
                    <ClientGameBottomStatusBar />
                </PageFooter>
            </Page>
            <Outlet />
            <ClientGameTelefrag />
        </>
    );
}
