/* global structuredClone */
import {type JSX, useCallback} from "react";
import {useNavigate} from "react-router-dom";

import {appRoute} from "../../../../app/app-route";
import {uiButtonImage} from "../../../../layout/ui-button/image/ui-button-image";
import {UiButton} from "../../../../layout/ui-button/ui-button";
import {getSavedBotDifficult} from "../../../../model/game/bot/bot-helper";
import {
    GamePlayerColorIdEnum,
    type GamePlayerType,
    GamePlayerTypeEnum,
} from "../../../../model/game/player/player-type";
import {gameMapToGameState} from "../../../../model/map/map-helper";
import type {GameMapType} from "../../../../model/map/map-type";
import {type CompanySaveStateType, getCompanySaveState} from "../../../../provider/game/action/companies-action";
import {useGameContext} from "../../../../provider/game/game-context";
import {Locale} from "../../../../provider/locale/locale-context";
import {getBotDifficultImage, getNonDoneMissionImage} from "../../../../provider/setting/setting-helper";
import {BotDifficultEnum} from "../../../../provider/setting/setting-type";
import {testId} from "../../../../test-id";
import {cls} from "../../../../util/css";
import {getEnumValueEnsure} from "../../../../util/enum";
import type {CompanyStateType} from "../client-companies-type";
import * as clientCompanyItemStyle from "./client-company-item.scss";

interface ClientSkirmishMapItemPropsType {
    readonly companyState: CompanyStateType;
    readonly isAvailable: boolean;
    readonly map: GameMapType;
}

export function ClientCompanyItem(props: ClientSkirmishMapItemPropsType): JSX.Element {
    const {isAvailable, map, companyState} = props;
    const {mapNameLangKey} = map;
    const {loadGame} = useGameContext();
    const navigate = useNavigate();
    const companySaveState: CompanySaveStateType = getCompanySaveState();
    const isMissionDone: boolean = companySaveState[map.mapId]?.isDone ?? false;
    const missionDoneDifficult: BotDifficultEnum = getEnumValueEnsure<BotDifficultEnum>(
        BotDifficultEnum,
        companySaveState[map.mapId]?.difficult,
        BotDifficultEnum.easy
    );

    const beginMission = useCallback(async () => {
        const savedBotDifficulty = getSavedBotDifficult();
        const gameState = gameMapToGameState(map, structuredClone<CompanyStateType>(companyState));

        gameState.playerList = gameState.playerList.map<GamePlayerType>(
            (playerInList: GamePlayerType): GamePlayerType => {
                if (playerInList.playerType === GamePlayerTypeEnum.bot) {
                    return {
                        ...playerInList,
                        playerDifficulty: savedBotDifficulty,
                    };
                }

                return playerInList;
            }
        );

        await loadGame(gameState);
        await navigate(appRoute.clientGame.path);
    }, [loadGame, navigate, companyState, map]);

    return (
        <div
            className={cls(
                clientCompanyItemStyle.client_company_item,
                isAvailable ? "" : clientCompanyItemStyle.client_company_item__disabled
            )}
            data-map-id={map.mapId}
            data-testid={testId.companiesPage.missionItem}
        >
            <img
                alt={missionDoneDifficult}
                className={clientCompanyItemStyle.client_company_item__difficult_icon}
                src={
                    isMissionDone
                        ? getBotDifficultImage(missionDoneDifficult, GamePlayerColorIdEnum.blue)
                        : getNonDoneMissionImage(GamePlayerColorIdEnum.red)
                }
            />
            <div className={clientCompanyItemStyle.client_company_item__left}>
                <button
                    className={clientCompanyItemStyle.client_company_item__map_name}
                    onClick={(): void => {
                        void beginMission();
                    }}
                    type="button"
                >
                    <Locale stringKey={mapNameLangKey} />
                </button>
            </div>
            <div className={clientCompanyItemStyle.client_company_item__right}>
                <UiButton
                    dataTestId={testId.companiesPage.missionFightButton}
                    iconSrc={uiButtonImage.sword.src}
                    isSquared
                    langKey="SETUP_SKIRMISH__FIGHT"
                    onClick={beginMission}
                />
            </div>
        </div>
    );
}
