import type {JSX} from "react";

import {appRoute} from "../../../app/app-route";
import {Page} from "../../../layout/page/page";
import {PageContent} from "../../../layout/page/page-content/page-content";
import {getRateAppSavedState} from "../../../layout/rate-app/rate-app-helper";
import {UiLink} from "../../../layout/ui-button/ui-link";
import {usePlayTitleTheme} from "../../../media/play-media";
import {isWasmInitialized} from "../../../model/game/unit/unit-path";
import * as clientDevStyle from "./client-dev.scss";
import {DevPageHeader} from "./dev-page-header";

// Dev-only page. Intentionally not localized - all text is Swedish.
export function ClientDev(): JSX.Element {
    usePlayTitleTheme();

    // The first run date is stored once (see rate-app-helper) and never overwritten.
    const {firstRunDate} = getRateAppSavedState();

    return (
        <Page>
            <DevPageHeader title="Utvecklare" />
            <PageContent hasBorder>
                <p className={clientDevStyle.client_dev__row}>
                    Build date (UTC+0):
                    <br />
                    {String(BUILD_DATE_H)}
                </p>
                <p className={clientDevStyle.client_dev__row}>
                    Datum för första start:
                    <br />
                    {firstRunDate || "okänt"}
                </p>
                <p className={clientDevStyle.client_dev__row}>
                    WebAssembly aktiverat: {isWasmInitialized ? "Ja" : "Nej"}
                </p>
                <div className={clientDevStyle.client_dev__link_wrapper}>
                    <UiLink href={appRoute.devMaps.path}>Alla kartor</UiLink>
                </div>
            </PageContent>
        </Page>
    );
}
