/* global HTMLImageElement */

import type {JSX} from "react";

import {fontBigImage} from "../image/font-image";
import {Text} from "./text";
import type {TextPropsType} from "./text-type";

export function BigText(props: TextPropsType): JSX.Element {
    const {text, className, scale, padStart, padEnd, animation} = props;

    return (
        <Text
            animation={animation}
            className={className}
            fontHeight={11}
            localImageMap={fontBigImage}
            padEnd={padEnd}
            padStart={padStart}
            scale={scale}
            text={text}
        />
    );
}
