import type {GameStateType} from "../../../model/game/game-type";
import {getPlayerByPlayerId} from "../../../model/game/player/player-helper";
import {applyAddUnitList, applyBuyUnit} from "../../../model/game/reducer/game-reducer";
import type {PromiseResolveType} from "../../../util/promise";
import {waitForNextFrame} from "../../../util/time";
import type {ActionArgumentType, GameAnimationType} from "../game-context-type";

export async function addUnitListAction(data: ActionArgumentType): Promise<void> {
    const {action, setGameState} = data;

    setGameState((currentGameState: GameStateType): GameStateType => {
        return applyAddUnitList(currentGameState, action);
    });

    await waitForNextFrame();
}

export async function buyUnitListAction(data: ActionArgumentType): Promise<void> {
    const {action, gameState, setGameState, setAnimationList, removeAnimationByAction} = data;
    const {buyUnitType} = action;
    const {activeGamePlayerId, playerList} = gameState;
    const player = getPlayerByPlayerId(activeGamePlayerId, playerList);

    if (!player) {
        console.error(`can not find player by id: ${activeGamePlayerId}`);
        return waitForNextFrame();
    }

    // eslint-disable-next-line @typescript-eslint/strict-boolean-expressions
    if (!buyUnitType) {
        console.error("buyUnitType is null");
        return waitForNextFrame();
    }

    return new Promise<void>((resolve: PromiseResolveType<void>) => {
        setAnimationList((animList: Array<GameAnimationType>): Array<GameAnimationType> => {
            return [
                ...animList,
                {
                    action,
                    animationOnFinish: (): void => {
                        void (async (): Promise<void> => {
                            setGameState((currentGameState: GameStateType): GameStateType => {
                                return applyBuyUnit(currentGameState, action);
                            });
                            removeAnimationByAction(action);
                            await waitForNextFrame();
                            resolve();
                        })();
                    },
                },
            ];
        });
    });
}
