export enum GameUnitMoveTypeEnum {
    float = "float",
    fly = "fly",
    walk = "walk",
}

export interface GameUnitType {
    // How many times this unit has attacked a building during the current turn. Reset to 0 on turn switch.
    attackedBuildingCount: number;
    // How many times this unit has attacked a unit during the current turn. Reset to 0 on turn switch.
    attackedUnitCount: number;
    damageGiven: number;
    damageReceived: number;
    deathCount: number;
    didFixBuilding: boolean;
    didOccupyBuilding: boolean;
    gamePlayerId: GamePlayerIdEnum;
    health: number;
    // How many times this unit has moved during the current turn. Reset to 0 on turn switch.
    movedCount: number;
    poisonTurnCount: number;
    // How many skeletons this unit has raised during the current turn. Reset to 0 on turn switch.
    raisedSkeletonCount: number;
    unitId: string;
    unitType: GameUnitTypeEnum;
    x: number;
    y: number;
}

export interface GameGraveType {
    createdStepCount: number;
    x: number;
    y: number;
}

