export enum UnitAppearAnimationNameEnum {
    simple = "simple",
    // fromGrave = "fromGrave",
}

export interface UnitInfoType {
    appearAnimationName: UnitAppearAnimationNameEnum;
    armor: number;
    attack: {
        max: number;
        min: number;
        range: number;
    };
    // How many times this unit type may attack buildings per turn (0 = cannot). Works with destroyBuildingList.
    attackBuildingCountPerTurn: number;
    attackPoisonCount: number;
    // How many times this unit type may attack units per turn (0 = cannot).
    attackUnitCountPerTurn: number;
    bonusAttackVersus: Record<GameUnitMoveTypeEnum, number>;
    bonusAttackVersusSkeleton: number;
    canAttackAfterMove: boolean;
    canBePoisoned: boolean;
    canFixBuilding: boolean;
    canMeleeAttack: boolean;
    cost: number;
    destroyBuildingList: Array<GameBuildingTypeEnum>;
    hasGrave: boolean;
    isHero: boolean;
    // Draws the golden commander outline on the map. Independent of isHero: set only for heroes whose
    // reused sprites don't already read as commanders (Saeth, Nezha, Jeffrey).
    isHeroMarked: boolean;
    isWispAuraAccept: boolean;
    langKey: {
        description: LangKeyType;
        name: LangKeyType;
    };
    // How many times this unit type may move per turn (0 = cannot move).
    moveCountPerTurn: number;
    moveSize: number;
    moveType: GameUnitMoveTypeEnum;
    occupyBuildingList: Array<GameBuildingTypeEnum>;
    // How many skeletons this unit type may raise per turn (0 = cannot raise). Works together with raiseSkeletonRange.
    raiseSkeletonCountPerTurn: number;
    raiseSkeletonRange: number;
    sortOrder: number;
    wispAuraRange: number;
}

export interface GameAllActionsType {
    attackUnitToBuildingPointList: Array<PointType>;
    attackUnitToUnitPointList: Array<PointType>;
    canFixBuilding: boolean;
    canOccupyBuilding: boolean;
    canOpenStore: boolean;
    moveBackAction: GameActionType | null;
    moveOnAllyPointList: Array<PointType>;
    movePathList: Array<MovePathType>;
    movePointList: Array<PointType>;
    raiseSkeletonPointList: Array<PointType>;
    unitCurrentPoint: PointType;
    unitId: string;
}
